-- Poems batch 58
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('598cb1ef-93c1-498d-a48e-2881058fe1d0','樂城歲日贈孟浩然','張子容','唐','唐诗','tang','','[]','土地窮甌越，風光肇建寅。',48,'全唐诗/poet.tang.5000.json','["土地窮甌越，風光肇建寅。", "插桃銷瘴癘，移竹近階墀。", "半是吳風俗，仍爲楚歲時。", "更逢習鑿齒，言在漢川湄。"]'),
('04a6d7f6-abe1-4d73-9e5d-762c5f4781e7','永嘉作','張子容','唐','唐诗','tang','','[]','拙宦從江左，投荒更海邊。',48,'全唐诗/poet.tang.5000.json','["拙宦從江左，投荒更海邊。", "山將孤嶼近，水共惡谿連。", "地濕梅多雨，潭蒸竹起煙。", "未應悲晚髪，炎瘴苦華年。"]'),
('640be62f-649f-4202-94e3-cbf57b6b2e0c','送孟八浩然歸襄陽二首 一','張子容','唐','唐诗','tang','','[]','東越相逢地，西亭送別津。',48,'全唐诗/poet.tang.5000.json','["東越相逢地，西亭送別津。", "風潮看解纜，雲海去愁人。", "鄉在桃林岸，山連楓樹春。", "因懷故園意，歸與孟家鄰。"]'),
('e4eb0fd5-78f5-4004-bed3-acd3a786062c','送孟八浩然歸襄陽二首 二','張子容','唐','唐诗','tang','','[]','杜門不欲出，久與世情疎。',48,'全唐诗/poet.tang.5000.json','["杜門不欲出，久與世情疎。", "以此爲長策，勸君歸舊廬。", "醉歌田舍酒，笑讀古人書。", "好是一生事，無勞獻子虛。"]'),
('42f24b70-ae4d-4633-9a78-d17e619e57bf','貶樂城尉日作','張子容','唐','唐诗','tang','','[]','竄謫邊窮海，川原近惡谿。',48,'全唐诗/poet.tang.5000.json','["竄謫邊窮海，川原近惡谿。", "有時聞虎嘯，無夜不猿啼。", "地暖花長發，巖高日易低。", "故鄉可憶處，遙指斗牛西。"]'),
('737d6307-8218-40b5-965e-be6a22e98ede','自樂城赴永嘉枉路泛白湖寄松陽李少府','張子容','唐','唐诗','tang','','[]','西行礙淺石，北轉入谿橋。',60,'全唐诗/poet.tang.5000.json','["西行礙淺石，北轉入谿橋。", "樹色煙輕重，湖光風動搖。", "百花亂飛雪，萬嶺疊青霄。", "猿挂臨潭篠，鷗迎出浦橈。", "惟應賞心客，茲路不言遙。"]'),
('0ab060e8-afe9-4870-a3b1-a91256bf6263','九日陪潤州邵使君登北固山','張子容','唐','唐诗','tang','','[]','五馬向西椒，重陽坐麗譙。',72,'全唐诗/poet.tang.5000.json','["五馬向西椒，重陽坐麗譙。", "徐州帶綠水，楚國在青霄。", "張幕連江樹，開筵接海潮。", "凌雲詞客語，迴雪無人嬌。", "梅福慚仙吏，羊公賞下僚。", "新豐酒舊美，況是菊花朝。"]'),
('355b1b8e-5bc5-4fc0-a6ed-7612cb49b91d','璧池望秋月','張子容','唐','唐诗','tang','','[]','涼夜窺清沼，池空水月秋。',72,'全唐诗/poet.tang.5000.json','["涼夜窺清沼，池空水月秋。", "滿輪沈玉鏡，半魄落銀鉤。", "蟾影搖輕浪，菱花渡淺流。", "漏移光漸潔，雲斂色偏浮。", "似璧悲三獻，疑珠怯再投。", "能持千里意，來照楚鄉愁。"]'),
('8faf26f4-8811-4c7a-b3b2-416d622b49c8','長安早春','張子容','唐','唐诗','tang','','["\u9ec4\u5c71"]','開國維東井，城池起北辰。',72,'全唐诗/poet.tang.5000.json','["開國維東井，城池起北辰。", "咸歌太平日，共樂建寅春。", "雪盡黃山樹，冰開黑水津。", "草迎金埒馬，花伴玉樓人。", "鴻漸看無數，鶯歌聽欲頻。", "何當桂枝擢，還及柳條新。"]'),
('0cf82a91-18a7-4f64-b1c3-c46289755e7b','贈司勳蕭郎中','張子容','唐','唐诗','tang','','[]','作相開黃閣，爲郎奏赤墀。',144,'全唐诗/poet.tang.5000.json','["作相開黃閣，爲郎奏赤墀。", "君臣道合體，父子貴同時。", "國以推賢答，家無內舉疑。", "鳳池真水鏡，蘭省得華滋。", "未覩風流日，先聞新賦詩。", "江山清謝朓，花木媚丘遲。", "吏部來何暮，王言念在茲。", "丹青無不可，霖雨亦相期。", "昔我投荒處，孤煙望島夷。", "羣鷗終日狎，落葉數年悲。", "漁父留歌詠，江妃入興詞。", "今將獻知己，相感勿吾欺。"]'),
('0544981f-b304-432b-a31a-6f0ee075e0e3','巫山','張子容','唐','唐诗','tang','','[]','巫嶺岧嶢天際重，佳期宿昔願相從。',32,'全唐诗/poet.tang.5000.json','["巫嶺岧嶢天際重，佳期宿昔願相從。", "朝雲暮雨連天暗，神女知來第幾峯。"]'),
('2f5ad030-5bc9-4111-9ca0-757f993ba796','除日','張子容','唐','唐诗','tang','','[]','臘月今知晦，流年此夕除。',48,'全唐诗/poet.tang.5000.json','["臘月今知晦，流年此夕除。", "拾樵供歲火，帖牖作春書。", "柳覺東風至，花疑小雪餘。", "忽逢雙鯉贈，言是上冰魚。"]'),
('b2267fa7-afcf-4584-9372-e3b40dfab931','清谿泛舟','張旭','唐','唐诗','tang','','[]','旅人倚征棹，薄暮起勞歌。',24,'全唐诗/poet.tang.5000.json','["旅人倚征棹，薄暮起勞歌。", "笑攬清谿月，清輝不厭多。"]'),
('1f28ab03-8388-4a2f-8c4f-3ce47789e221','桃花谿','張旭','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u63cf\u5199\u6c34", "\u5199\u666f", "\u6292\u60c5", "\u4e03\u8a00\u7edd\u53e5", "\u5199\u6c34"]','隱隱飛橋隔野煙，石磯西畔問漁船。',32,'全唐诗/poet.tang.5000.json','["隱隱飛橋隔野煙，石磯西畔問漁船。", "桃花盡日隨流水，洞在清谿何處邊。"]'),
('717dc2a3-1c78-49d9-a075-ed7c3b76ac77','山行留客','張旭','唐','唐诗','tang','','["\u6625\u666f", "\u53cb\u60c5"]','山光物態弄春輝，莫爲輕陰便擬歸。',32,'全唐诗/poet.tang.5000.json','["山光物態弄春輝，莫爲輕陰便擬歸。", "縱使晴明無雨色，入雲深處亦沾衣。"]'),
('435557f1-47d2-4a79-9628-7957533e5e71','春遊值雨','張旭','唐','唐诗','tang','','[]','欲尋軒檻列清尊，江上煙雲向晚昏。',32,'全唐诗/poet.tang.5000.json','["欲尋軒檻列清尊，江上煙雲向晚昏。", "須倩東風吹散雨，明朝却待入華園。"]'),
('eaebbaed-d62b-4827-b204-f47aa4b9ff98','春草','張旭','唐','唐诗','tang','','[]','春草青青萬里餘，邊城落日見離居。',32,'全唐诗/poet.tang.5000.json','["春草青青萬里餘，邊城落日見離居。", "情知海上三年別，不寄雲間一紙書。"]'),
('f3b9f51e-1c08-433d-84cb-7bfdd9a7868d','柳','張旭','唐','唐诗','tang','','[]','濯濯煙條拂地垂，城邊樓畔結春思。',32,'全唐诗/poet.tang.5000.json','["濯濯煙條拂地垂，城邊樓畔結春思。", "請君細看風流意，未減靈和殿裏時。"]'),
('a3e8bd2e-63df-4bbe-86af-891b31ed15d5','南山','賀朝','唐','唐诗','tang','','[]','湖北雨初晴，湖南山盡見。',48,'全唐诗/poet.tang.5000.json','["湖北雨初晴，湖南山盡見。", "巖巖石帆影，如得海風便。", "仙穴茅山峯，彩雲時一見。", "邀君共探此，異籙殘幾卷。"]'),
('0a167e23-f6f5-433d-93e7-0c4ffcb8cd9a','孤興','賀朝','唐','唐诗','tang','','[]','晴日暖珠箔，夭桃色正新。',72,'全唐诗/poet.tang.5000.json','["晴日暖珠箔，夭桃色正新。", "紅粉青鏡中，娟娟可憐嚬。", "君子在遐險，蕙心誰見珍。", "羅幕空掩晝，玉顏靜移春。", "江瑟語幽獨，再三情未申。", "黃鵠千里翅，芳音遲所因。"]'),
('54f3415b-fa5b-4137-b759-e7b5f5529011','從軍行','賀朝','唐','唐诗','tang','','[]','朔胡乘月寇邊城，軍書插羽刺中京。',262,'全唐诗/poet.tang.5000.json','["朔胡乘月寇邊城，軍書插羽刺中京。", "天子金壇拜飛將，單于玉塞振佳兵。", "騎射先鳴推任俠，龍韜決勝佇時英。", "聞有河湟客，愔愔理帷帟。", "常山啓霸圖，汜水先天策。", "銜珠浴鐵向桑乾，釁旗膏劒指烏丸。", "鳴雞已報關山曉，來雁遙傳沙塞寒。", "直爲甘心從苦節，隴頭流水鳴嗚咽。", "邊樹蕭蕭不覺春，天山漠漠長飛雪。", "魚麗陣接塞雲平，雁翼營通海月明。", "始看晉幕飛鵝入，旋聞齊壘啼烏聲。", "自從一戍燕支山，春光幾度晉陽關。", "金河未轉青絲騎，玉筯應啼紅粉顏。", "鴻歸燕相續，池邊芳草綠。", "已見氛清細柳營，莫更春歌落梅曲。", "烽沈竈減靜邊亭，海[晏]山空肅已寧。", "行望鳳京旋凱捷，重來麟閣畫丹青。"]'),
('aeec4960-975b-4a73-bd01-53a73eed56cd','賦得遊人久不歸','賀朝','唐','唐诗','tang','','[]','鄉關眇天末，引領悵懷歸。',48,'全唐诗/poet.tang.5000.json','["鄉關眇天末，引領悵懷歸。", "羇旅久淫滯，物色屢芳菲。", "稍覺出意盡，行看蓬鬢稀。", "如何千里外，佇立霑裳衣。"]'),
('e3433704-3894-47aa-9d84-3832b7ddc524','宿香山閣','賀朝','唐','唐诗','tang','','[]','暝上春山閣，梯雲宿半空。',48,'全唐诗/poet.tang.5000.json','["暝上春山閣，梯雲宿半空。", "軒窗閉潮海，枕席拂煙虹。", "朱網防棲鴿，紗燈護夕蟲。", "一聞雞唱曉，已見日曈曈。"]'),
('b1831721-fe6e-4e69-bd1f-f7623a2b714e','贈酒店胡姬','賀朝','唐','唐诗','tang','','[]','胡姬春酒店，弦管夜鏘鏘。',48,'全唐诗/poet.tang.5000.json','["胡姬春酒店，弦管夜鏘鏘。", "紅毾鋪新月，貂裘坐薄霜。", "玉盤初鱠鯉，金鼎正烹羊。", "上客無勞散，聽歌樂世娘。"]'),
('246e44be-c0e2-4d9b-a03f-c9a03601ba7f','賦得春鶯送友人二首 一','賀朝','唐','唐诗','tang','','[]','翅掩飛鶯舞，啼惱婕妤悲。',24,'全唐诗/poet.tang.5000.json','["翅掩飛鶯舞，啼惱婕妤悲。", "料取金閨意，因君問所思。"]'),
('7fe21131-5bae-46ef-bbe8-cec35cf31979','賦得春鶯送友人二首 二','賀朝','唐','唐诗','tang','','[]','流鶯拂繡羽，二月上林期。',24,'全唐诗/poet.tang.5000.json','["流鶯拂繡羽，二月上林期。", "待雪銷金禁，銜花向玉墀。"]'),
('f76ec11f-4009-4f44-9362-776f84e358d7','三日綠潭篇','萬齊融','唐','唐诗','tang','','[]','春潭滉漾接隋宮，宮闕連延潭水東。',160,'全唐诗/poet.tang.5000.json','["春潭滉漾接隋宮，宮闕連延潭水東。", "蘋苔嫩色涵波綠，桃李新花照底紅。", "垂菱布藻如妝鏡，麗日晴天相照暎。", "素影沈沈對蝶飛，金沙礫礫窺魚泳。", "佳人祓禊賞韶年，傾國傾城併可憐。", "拾翠總來芳樹下，踏青爭遶綠潭邊。", "公子王孫恣遊翫，沙陽水曲情無厭。", "禽浮似挹羽觴杯，鱗躍疑投水心劒。", "金鞍玉勒騁輕肥，落絮紅塵擁路飛。", "綠水殘霞催席散，畫樓初月待人歸。"]'),
('690277bc-c6d7-4fcf-9261-81910b5100e3','仗劒行','萬齊融','唐','唐诗','tang','','[]','昨夜星官動紫微，今年天子用武威。',76,'全唐诗/poet.tang.5000.json','["昨夜星官動紫微，今年天子用武威。", "登車一呼風雷動，遙震陰山撼巍巍。", "胡驕子，當見旄頭蝕應死。", "願騎單馬仗天威，挼取長繩縛虜歸。", "仗劒遙叱路傍子，匈奴頭血濺君衣。"]'),
('956b9e27-b65f-463c-8b7d-b933a02ccd80','贈別江頭','萬齊融','唐','唐诗','tang','','[]','東南飛鳥處，言是故鄉天。',48,'全唐诗/poet.tang.5000.json','["東南飛鳥處，言是故鄉天。", "江上風花晚，君行定幾千。", "計程頻破月，數別屢開年。", "明歲潯陽水，相思寄采蓮。"]'),
('ea154939-51ab-41f9-91f4-85b006a283c1','送陳七還廣陵','萬齊融','唐','唐诗','tang','','[]','風流誰代子，雖有舊無雙。',48,'全唐诗/poet.tang.5000.json','["風流誰代子，雖有舊無雙。", "歡酒言相送，愁弦意不降。", "落花馥河道，垂楊拂水窗。", "海潮與春夢，朝夕廣陵江。"]'),
('88512e94-1be0-4b4f-b65c-8f5890afd0b8','遊春','邢巨','唐','唐诗','tang','','[]','海岳三峯古，春皇二月寒。',48,'全唐诗/poet.tang.5000.json','["海岳三峯古，春皇二月寒。", "綠潭漁子釣，紅樹美人攀。", "弱蔓環沙嶼，飛花點石關。", "谿山遊未厭，琴酌弄晴灣。"]'),
('fbac5349-4f32-45be-8a68-276774d8c68e','遊宣州琴谿同武平一作','邢巨','唐','唐诗','tang','','[]','靈谿非人迹，仙意素所秉。',24,'全唐诗/poet.tang.5000.json','["靈谿非人迹，仙意素所秉。", "鱗嶺森翠微，澄潭照秋景。"]'),
('587422bf-52ac-4755-97fc-1b22ad6ae626','春江花月夜','張若虛','唐','唐诗','tang','','["\u957f\u6c5f", "\u601d\u5ff5", "\u6e05\u5546\u66f2\u8f9e", "\u6708\u4eae", "\u6625\u5929", "\u4e50\u5e9c"]','春江潮水連海平，海上明月共潮生。',288,'全唐诗/poet.tang.5000.json','["春江潮水連海平，海上明月共潮生。", "灩灩隨波千萬里，何處春江無月明？", "江流宛轉遶芳甸，月照花林皆似霰。", "空裏流霜不覺飛，汀上白沙看不見。", "江天一色無纖塵，皎皎空中孤月輪。", "江畔何人初見月，江月何年初照人？", "人生代代無窮已，江月年年秖相似。", "不知江月待何人？但見長江送流水。", "白雲一片去悠悠，青楓浦上不勝愁。", "誰家今夜扁舟子，何處相思明月樓？", "可憐樓上月裴回，應照離人妝鏡臺。", "玉戶簾中卷不去，擣衣砧上拂還來。", "此時相望不相聞，願逐月華流照君。", "鴻雁長飛光不度，魚龍潛躍水成文。", "昨夜閑潭夢落花，可憐春半不還家。", "江水流春去欲盡，江潭落月復西斜。", "斜月沈沈藏海霧，碣石瀟湘無限路。", "不知乘月幾人歸，落月搖情滿江樹。"]'),
('5b5fa0e4-45cb-4371-9141-4cd739574218','代答閨夢還','張若虛','唐','唐诗','tang','','["\u95fa\u6028"]','關塞年華早，樓臺別望違。',72,'全唐诗/poet.tang.5000.json','["關塞年華早，樓臺別望違。", "試衫著煖氣，開鏡覓春暉。", "燕入窺羅幕，蜂來上畫衣。", "情催桃李豔，心寄管弦飛。", "妝洗朝相待，風花暝不歸。", "夢魂何處入，寂寂掩重扉。"]'),
('ff988a4c-5dba-4907-99c3-c0960e7e7566','洪州客舍寄柳博士芳','薛業','唐','唐诗','tang','','[]','去年燕巢主人屋，今年花發路傍枝。',32,'全唐诗/poet.tang.5000.json','["去年燕巢主人屋，今年花發路傍枝。", "年年爲客不到舍，舊國存亡那得知。"]'),
('213e4cab-d7a1-4e33-a8c9-c20c50226dd8','晚秋贈張折衝','薛業','唐','唐诗','tang','','[]','都尉今無事，時清但閉關。',48,'全唐诗/poet.tang.5000.json','["都尉今無事，時清但閉關。", "夜霜戎馬瘦，秋草射堂閑。", "位以穿楊得，名因折桂還。", "馮唐真不遇，歎息鬢毛斑。"]'),
('905d012f-ac6d-4ee2-996d-7bd8a9cda463','和左司張員外自洛使入京中路先赴長安逢立春日贈韋侍御等諸公','孫逖','唐','唐诗','tang','','[]','拜郎登省闥，奉使馳車乘。',72,'全唐诗/poet.tang.5000.json','["拜郎登省闥，奉使馳車乘。", "遙瞻使者星，便是郎官應。", "臺妙時相許，皇華德彌稱。", "二陝聽風謠，三秦望形勝。", "此中暌益友，是日多詩興。", "寒盡歲陰催，春歸物華證。"]'),
('3d8f4974-52ac-48d7-9c0e-ba35e3341c87','和登會稽山','孫逖','唐','唐诗','tang','','[]','稽山碧湖上，勢入東溟盡。',120,'全唐诗/poet.tang.5000.json','["稽山碧湖上，勢入東溟盡。", "煙景晝清明，九峰爭隱嶙。", "望中厭朱紱，俗內探玄牝。", "野老聽鳴騶，山童擁行軫。", "仙花寒未落，古蔓柔堪引。", "竹磵入山多，松崖向天近。", "雲從海天去，日就江村隕。", "能賦丘嘗聞，和歌參不敏。", "冥搜信沖漠，多士期標準。", "願奉濯纓心，長謠反招隱。"]'),
('45b5a565-7c75-4e92-8d2a-704146d86a85','送楊法曹按括州','孫逖','唐','唐诗','tang','','[]','東海天台山，南方縉雲驛。',48,'全唐诗/poet.tang.5000.json','["東海天台山，南方縉雲驛。", "溪澄問人隱，巖險煩登陟。", "潭壑隨星使，軒車繞春色。", "儻尋琪樹人，爲報長相憶。"]'),
('4f0ad4d3-f709-4a2c-b05f-e63dca3e6cef','葛山潭','孫逖','唐','唐诗','tang','','[]','圓潭寫流月，晴明涵萬象。',48,'全唐诗/poet.tang.5000.json','["圓潭寫流月，晴明涵萬象。", "仙翁何時還，綠水空蕩漾。", "涼哉草木腓，白露沾人衣。", "猶醉空山裏，時聞笙鶴飛。"]'),
('288c52fa-ce01-48c7-ae4a-760381fef23f','丹陽行','孫逖','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','丹陽古郡洞庭陰，落日扁舟此路尋。',260,'全唐诗/poet.tang.5000.json','["丹陽古郡洞庭陰，落日扁舟此路尋。", "傳是東南舊都處，金陵中斷碧江深。", "在昔風塵起，京都亂如燬。", "雙闕戎虜間，千門戰場裏。", "傳聞一馬化爲龍，南渡衣冠亦願從。", "石頭橫帝里，京口拒戎鋒。", "青楓林下迴天蹕，杜若洲前轉國容。", "都門不見河陽樹，輦道唯聞建業鐘。", "中原悠悠幾千里，欲掃欃槍未云已。", "英雄傾奪何紛然，一盛一衰如逝川。", "可憐宮觀重江裏，金鏡相傳三百年。", "自從龍見聖人出，六合車書混爲一。", "昔年王氣今何在，併向長安就堯日。", "荆榛古木閉荒阡，共道繁華不復全。", "赤縣唯餘江樹月，黃圖半入海人煙。", "暮來山水登臨遍，覽古愁吟淚如霰。", "唯有空城多白雲，春風淡蕩無人見。"]'),
('339e0169-abf5-49fb-be2a-704a9a4a1396','山陰縣西樓','孫逖','唐','唐诗','tang','','[]','都邑西樓芳樹間，逶迤霽色遶江山。',64,'全唐诗/poet.tang.5000.json','["都邑西樓芳樹間，逶迤霽色遶江山。", "山月夜從公署出，江雲晚對訟庭還。", "誰知春色朝朝好，二月飛花滿江草。", "一見湖邊楊柳風，遙憶青青洛陽道。"]'),
('544ad2e6-3834-4f84-908c-5fcb06ee636d','夜宿浙江','孫逖','唐','唐诗','tang','','[]','扁舟夜入江潭泊，露白風高氣蕭索。',64,'全唐诗/poet.tang.5000.json','["扁舟夜入江潭泊，露白風高氣蕭索。", "富春渚上潮未還，天姥岑邊月初落。", "煙水茫茫多苦辛，更聞江上越人吟。", "洛陽城闕何時見，西北浮雲朝暝深。"]'),
('0565e377-860d-4848-abfe-ff6420c9409f','春日留別','孫逖','唐','唐诗','tang','','[]','春路逶迤花柳前，孤舟晚泊就人煙。',64,'全唐诗/poet.tang.5000.json','["春路逶迤花柳前，孤舟晚泊就人煙。", "東山白雲不可見，西陵江月夜娟娟。", "春江夜盡潮聲度，征帆遙從此中去。", "越國山川看漸無，可憐愁思江南樹。"]'),
('e2753516-44ff-4cc1-9936-bc13cc78602f','奉和四月三日上陽水窗賜宴應制得春字','孫逖','唐','唐诗','tang','','[]','今日逢初夏，歡遊續舊旬。',48,'全唐诗/poet.tang.5000.json','["今日逢初夏，歡遊續舊旬。", "氣和先作雨，恩厚別成春。", "鳳吹臨清洛，龍輿下紫宸。", "此中歌在藻，還見躍潛鱗。"]'),
('ccff76d6-4bd6-4bb3-a4b0-59c2c766f9f7','奉和登會昌山應制','孫逖','唐','唐诗','tang','','[]','巖磴列雲旗，吾君訪道時。',48,'全唐诗/poet.tang.5000.json','["巖磴列雲旗，吾君訪道時。", "乾行萬物覩，日馭六龍遲。", "望遠迴天顧，登高動睿詞。", "願因山作壽，長保會昌期。"]'),
('1541ca51-f544-437b-bb53-0d55627ab52d','正月十五日夜應制','孫逖','唐','唐诗','tang','','[]','洛城三五夜，天子萬年春。',48,'全唐诗/poet.tang.5000.json','["洛城三五夜，天子萬年春。", "綵仗移雙闕，瓊筵會九賓。", "舞成蒼頡字，燈作法王輪。", "不覺東方日，遙垂御藻新。"]'),
('1f3198af-1f07-47c0-a87f-5e3cc5ebcb26','奉和御製登鴛鴦樓即目應制','孫逖','唐','唐诗','tang','','[]','玉輦下離宮，瓊樓上半空。',48,'全唐诗/poet.tang.5000.json','["玉輦下離宮，瓊樓上半空。", "方巡五年狩，更闢四門聰。", "井邑觀秦野，山河念禹功。", "停鑾留睿作，軒檻起南風。"]'),
('ff99e0d0-d60c-48e0-ac5c-38b24a0eeb30','進船泛洛水應制','孫逖','唐','唐诗','tang','','[]','禁園紆睿覽，仙櫂叶時游。',48,'全唐诗/poet.tang.5000.json','["禁園紆睿覽，仙櫂叶時游。", "洛北風花樹，江南彩畫舟。", "芳生蘭蕙草，春入鳳凰樓。", "興盡離宮暮，煙光起夕流。"]'),
('7bb94dce-f83f-4659-9d16-dcbad1592865','和常州崔使君寒食夜','孫逖','唐','唐诗','tang','','[]','聞道清明近，春庭向夕闌。',48,'全唐诗/poet.tang.5000.json','["聞道清明近，春庭向夕闌。", "行遊晝不厭，風物夜宜看。", "斗柄更初轉，梅香暗裏殘。", "無勞秉華燭，清月在南端。"]'),
('d8cd2910-f2b2-45b6-8ff3-727e7e416b21','和韋兄春日南亭宴兄弟','孫逖','唐','唐诗','tang','','[]','臺閣升高位，園林隔舊鄉。',48,'全唐诗/poet.tang.5000.json','["臺閣升高位，園林隔舊鄉。", "忽聞歌棣萼，還比報瓊芳。", "門向宜春近，郊連御宿長。", "德星常有會，相望在文昌。"]'),
('27740b09-a53f-40ec-8e6c-ec678db07f41','奉和崔司馬遊雲門寺','孫逖','唐','唐诗','tang','','[]','繫馬清溪樹，禪門春氣濃。',48,'全唐诗/poet.tang.5000.json','["繫馬清溪樹，禪門春氣濃。", "香臺花下出，講坐竹間逢。", "覺路山童引，經行谷鳥從。", "更言窮寂滅，回策上南峰。"]'),
('c99ccfe1-f1eb-4573-9c6b-4611359f3df9','酬萬八賀九雲門下歸溪中作','孫逖','唐','唐诗','tang','','[]','晚從靈境出，林壑曙雲飛。',48,'全唐诗/poet.tang.5000.json','["晚從靈境出，林壑曙雲飛。", "稍覺清溪盡，回瞻畫剎微。", "獨園餘興在，孤櫂宿心違。", "更憶登攀處，天香滿袖歸。"]'),
('4fa85826-eacc-420c-971e-9ce5f3d353ed','春初送呂補闕往西嶽勒碑得雲字','孫逖','唐','唐诗','tang','','["\u534e\u5c71"]','刻石記天文，朝推谷子雲。',48,'全唐诗/poet.tang.5000.json','["刻石記天文，朝推谷子雲。", "篋中緘聖札，巖下揖神君。", "語別梅初豔，爲期草欲薰。", "往來春不盡，離思莫氛氳。"]'),
('fb4e38f6-9e29-4a9c-b209-a3039bde1a1f','送越州裴參軍充使入京','孫逖','唐','唐诗','tang','','[]','日落川徑寒，離心苦未安。',48,'全唐诗/poet.tang.5000.json','["日落川徑寒，離心苦未安。", "客愁西向盡，鄉夢北歸難。", "霜果林中變，秋花水上殘。", "明朝渡江後，雲物向南看。"]'),
('403b2fa0-1735-499d-8d34-3ab711de3c05','送周判官往台州','孫逖','唐','唐诗','tang','','[]','吾宗長作賦，登陸訪天台。',48,'全唐诗/poet.tang.5000.json','["吾宗長作賦，登陸訪天台。", "星使行看入，雲仙意轉催。", "飲冰攀璀璨，驅傳歷莓苔。", "日暮東郊別，真情去不回。"]'),
('5bd0fc18-bedb-4192-a865-06b3578c688e','送魏騎曹充宇文侍御判官分按山南','孫逖','唐','唐诗','tang','','[]','雲雨陽臺路，光華驛騎巡。',48,'全唐诗/poet.tang.5000.json','["雲雨陽臺路，光華驛騎巡。", "勸農開夢土，恤隱惠荆人。", "樓迥吟黃鶴，江長望白蘋。", "觀風布明詔，更是漢南春。"]'),
('72694080-ba9a-4632-9b7e-3a62cac101fb','送蘇郎中綰出佐荆州','孫逖','唐','唐诗','tang','','[]','神仙久留滯，清切佇飛翻。',48,'全唐诗/poet.tang.5000.json','["神仙久留滯，清切佇飛翻。", "忽佐南方牧，何時西掖垣。", "高車自蘭省，便道出荆門。", "不見河梁別，空銷郢路魂。"]'),
('bc8129c5-f76f-4530-a5df-847d4b6f59dd','冬末送魏起居赴京','孫逖','唐','唐诗','tang','','[]','大名將起魏，良史更逢遷。',48,'全唐诗/poet.tang.5000.json','["大名將起魏，良史更逢遷。", "驛騎朝丹闕，關亭望紫煙。", "西京春色近，東觀物華偏。", "早赴王正月，揮毫記首年。"]'),
('ee037111-955b-4523-9280-294c7a2c39ac','送李補闕攝御史充河西節度判官','孫逖','唐','唐诗','tang','','[]','昔年叨補衮，邊地亦埋輪。',48,'全唐诗/poet.tang.5000.json','["昔年叨補衮，邊地亦埋輪。", "官序慙先達，才名畏後人。", "西戎雖獻款，上策恥和親。", "早赴前軍幕，長清外域塵。"]'),
('d49d11e5-8585-4003-807e-4357323c1c2e','送趙評事攝御史監軍嶺南','孫逖','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','議獄持邦典，臨戎假憲威。',48,'全唐诗/poet.tang.5000.json','["議獄持邦典，臨戎假憲威。", "風從閶闔去，霜入洞庭飛。", "篁竹迎金鼓，樓船引繡衣。", "明年拜真月，南斗使星歸。"]'),
('006e732d-2d15-42cf-9e0e-1c9282fd9e30','送靳十五侍御使蜀','孫逖','唐','唐诗','tang','','[]','天使出霜臺，行人擇吏才。',48,'全唐诗/poet.tang.5000.json','["天使出霜臺，行人擇吏才。", "傳車春色送，離興夕陽催。", "驛遶巴江轉，關迎劒道開。", "西南一何幸，前後二龍來。"]'),
('6bfafcb5-a3c8-43b7-892d-179ca8445df4','送李給事歸徐州覲省','孫逖','唐','唐诗','tang','','[]','列位登青瑣，還鄉復綵衣。',48,'全唐诗/poet.tang.5000.json','["列位登青瑣，還鄉復綵衣。", "共言晨省日，便是晝遊歸。", "春水經梁宋，晴山入海沂。", "莫愁東路遠，四牡正騑騑。"]'),
('2668872b-5c8a-45af-9a09-ea9314b30f6e','送杜侍御赴上都','孫逖','唐','唐诗','tang','','[]','避馬臺中貴，登車嶺外遙。',48,'全唐诗/poet.tang.5000.json','["避馬臺中貴，登車嶺外遙。", "還因貢賦禮，來謁大明朝。", "地入商山路，鄉連渭水橋。", "承恩返南越，尊酒重相邀。"]'),
('e731f0bb-24f2-42fb-ac7a-a79bbe04858a','送張環攝御史監南選','孫逖','唐','唐诗','tang','','[]','漢使得張綱，威名攝遠方。',48,'全唐诗/poet.tang.5000.json','["漢使得張綱，威名攝遠方。", "恩霑柱下史，榮比選曹郎。", "江帶黔中闊，山連峽水長。", "莫愁炎暑地，秋至有嚴霜。"]'),
('da73c986-de69-47b7-9357-1e98cb5c8ec7','宴越府陳法曹西亭','孫逖','唐','唐诗','tang','','[]','公府西巖下，紅亭間白雲。',48,'全唐诗/poet.tang.5000.json','["公府西巖下，紅亭間白雲。", "雪梅初度臘，煙竹稍迎曛。", "水木涵澄景，簾櫳引霽氛。", "江南歸思逼，春鴈不堪聞。"]'),
('05b87ce2-d432-48d8-ae41-e3328cb6008a','同邢判官尋龍湍觀歸湖中','孫逖','唐','唐诗','tang','','[]','星使下仙京，雲湖喜晝晴。',48,'全唐诗/poet.tang.5000.json','["星使下仙京，雲湖喜晝晴。", "更從探穴處，還作櫂歌行。", "絲管荷風入，簾帷竹氣清。", "莫愁歸路遠，水月夜虛明。"]'),
('c7854620-bcc1-428e-8b83-a853d86a46df','尋龍湍','孫逖','唐','唐诗','tang','','[]','仙穴尋遺跡，輕舟愛水鄉。',48,'全唐诗/poet.tang.5000.json','["仙穴尋遺跡，輕舟愛水鄉。", "溪流一曲盡，山路九峰長。", "漁父歌金洞，江妃舞翠房。", "遙憐葛仙宅，真氣共微茫。"]'),
('61405096-5464-46ed-8161-8eb533ee4a46','宿雲門寺閣','孫逖','唐','唐诗','tang','','[]','香閣東山下，煙花象外幽。',48,'全唐诗/poet.tang.5000.json','["香閣東山下，煙花象外幽。", "懸燈千嶂夕，卷幔五湖秋。", "畫壁餘鴻鴈，紗窓宿斗牛。", "更疑天路近，夢與白雲遊。"]'),
('3f3b6888-5e5f-4932-83c7-616ad697aebe','揚子江樓','孫逖','唐','唐诗','tang','','[]','揚子何年邑，雄圖作楚關。',50,'全唐诗/poet.tang.5000.json','["揚子何年邑，雄圖作楚關。", "江連二妃渚，雲近八公山。", "驛道[青]楓外，人煙綠嶼間。", "晚來潮正滿，數處落帆還。"]'),
('dc969e93-b520-4127-868f-c4e000652ab3','淮陰夜宿二首 一','孫逖','唐','唐诗','tang','','[]','水國南無畔，扁舟北未期。',48,'全唐诗/poet.tang.5000.json','["水國南無畔，扁舟北未期。", "鄉情淮上失，歸夢郢中疑。", "木落知寒近，山長見日遲。", "客行心緒亂，不及洛陽時。"]'),
('103fde91-0c2f-4bc6-8502-de2bf38b26f2','淮陰夜宿二首 二','孫逖','唐','唐诗','tang','','[]','永夕臥煙塘，蕭條天一方。',48,'全唐诗/poet.tang.5000.json','["永夕臥煙塘，蕭條天一方。", "秋風淮水落，寒夜楚歌長。", "宿莽非中土，鱸魚豈我鄉。", "孤舟行已倦，南越尚茫茫。"]'),
('46354a02-69ce-43b9-afd7-12a7b49ae671','下京口埭夜行','孫逖','唐','唐诗','tang','','[]','孤帆度綠氛，寒浦落紅曛。',48,'全唐诗/poet.tang.5000.json','["孤帆度綠氛，寒浦落紅曛。", "江樹朝來出，吳歌夜漸聞。", "南溟接潮水，北斗近鄉雲。", "行役從茲去，歸情入鴈羣。"]'),
('73a77401-6195-4226-9dd5-1d4bff2edbe8','山行遇雨','孫逖','唐','唐诗','tang','','[]','驟雨晝氤氳，空天望不分。',48,'全唐诗/poet.tang.5000.json','["驟雨晝氤氳，空天望不分。", "暗山唯覺電，窮海但生雲。", "涉澗猜行潦，緣崖畏宿氛。", "夜來江月霽，櫂唱此中聞。"]'),
('15e71264-4ba0-4dfb-9fe1-e874cc5f0063','夜到潤州','孫逖','唐','唐诗','tang','','[]','夜入丹陽郡，天高氣象秋。',48,'全唐诗/poet.tang.5000.json','["夜入丹陽郡，天高氣象秋。", "海隅雲漢轉，江畔火星流。", "城郭傳金柝，閭閻閉綠洲。", "客行凡幾夜，新月再如鉤。"]'),
('8665cd4a-9bc7-40d8-8ea5-8ac3b866d15c','和常州崔使君詠後庭梅二首 一','孫逖','唐','唐诗','tang','','[]','聞唱梅花落，江南春意深。',48,'全唐诗/poet.tang.5000.json','["聞唱梅花落，江南春意深。", "更傳千里外，來入越人吟。", "弱幹紅妝倚，繁香翠羽尋。", "庭中自公日，歌舞向芳陰。"]'),
('0f9fd0ad-8527-4d0a-8ad1-c8c07c0a8131','和常州崔使君詠後庭梅二首 二','孫逖','唐','唐诗','tang','','[]','梅院重門掩，遙遙歌吹邊。',48,'全唐诗/poet.tang.5000.json','["梅院重門掩，遙遙歌吹邊。", "庭深人不見，春至曲能傳。", "花落彈棋處，香來薦枕前。", "使君停五馬，行樂此中偏。"]'),
('f35caecc-8e5c-40ca-a748-223a43ca910c','同和詠樓前海石榴二首 一','孫逖','唐','唐诗','tang','','[]','客自新亭郡，朝來數物華。',48,'全唐诗/poet.tang.5000.json','["客自新亭郡，朝來數物華。", "傳君妓樓好，初落海榴花。", "露色珠簾映，香風粉壁遮。", "更宜林下雨，日晚逐行車。"]'),
('712aa8b3-855c-4714-b45e-663d6fa5a374','同和詠樓前海石榴二首 二','孫逖','唐','唐诗','tang','','[]','海上移珍木，樓前詠所思。',48,'全唐诗/poet.tang.5000.json','["海上移珍木，樓前詠所思。", "遙聞下車日，正在落花時。", "舊綠香行蓋，新紅洒步綦。", "從來寒不易，終見久逾滋。"]'),
('48e266b7-ec77-4468-88c8-4dda6f4bf22a','故右丞相贈太師燕文貞公挽詞二首 一','孫逖','唐','唐诗','tang','','[]','海內文章伯，朝端禮樂英。',48,'全唐诗/poet.tang.5000.json','["海內文章伯，朝端禮樂英。", "一言興寶運，三入濟羣生。", "命與才相偶，年將位不幷。", "台星忽已坼，流慟軫皇情。"]'),
('c1bda0f6-5c48-45c6-886a-f68c8781f606','故右丞相贈太師燕文貞公挽詞二首 二','孫逖','唐','唐诗','tang','','[]','甲第三重戟，高門四列侯。',48,'全唐诗/poet.tang.5000.json','["甲第三重戟，高門四列侯。", "已成冠蓋里，更有鳳皇樓。", "人世方爲樂，生涯遽若休。", "空餘掌綸地，傳慶百千秋。"]'),
('c408c2f1-63a3-41f0-8685-70aee6c960b0','故陳州刺史贈兵部尚書韋公挽詞','孫逖','唐','唐诗','tang','','[]','奕葉金章貴，連枝鼎位尊。',48,'全唐诗/poet.tang.5000.json','["奕葉金章貴，連枝鼎位尊。", "台庭爲鳳穴，相府是鴒原。", "世閱空悲命，泉幽不返魂。", "惟餘漢臣史，繼術贊韋門。"]'),
('0a0ea00a-a8fa-46e7-8efb-c15ce169c82f','故程將軍妻南陽郡夫人樊氏挽歌','孫逖','唐','唐诗','tang','','[]','德配程休甫，名高魯季姜。',48,'全唐诗/poet.tang.5000.json','["德配程休甫，名高魯季姜。", "寵榮蒼玉珮，宴夢鬱金堂。", "白日期偕老，幽泉忽悼亡。", "國風猶在詠，江漢近南陽。"]'),
('3887366a-5ca5-4e31-a43a-276ecef05990','和上巳連寒食有懷京洛','孫逖','唐','唐诗','tang','','[]','天津御柳碧遙遙，軒騎相從半下朝。',64,'全唐诗/poet.tang.5000.json','["天津御柳碧遙遙，軒騎相從半下朝。", "行樂光輝寒食借，太平歌舞晚春饒。", "紅妝樓下東郊道，青草洲邊南渡橋。", "坐見司空掃西第，看君侍從落花朝。"]'),
('af0e436f-57cb-4972-a24a-c8ecc6a328a2','和左司張員外自洛使入京中路先赴長安逢立春日贈韋侍御等諸公','孫逖','唐','唐诗','tang','','[]','忽覩雲間數鴈回，更逢山上正花開。',64,'全唐诗/poet.tang.5000.json','["忽覩雲間數鴈回，更逢山上正花開。", "河邊淑氣迎芳草，林下輕風待落梅。", "秋憲府中高唱入，春卿署裏和歌來。", "共言東閣招賢地，自有西征謝傅才。"]'),
('4761e170-dc78-41ae-816d-0410a6c2bfa8','和崔司馬登稱心山寺','孫逖','唐','唐诗','tang','','[]','郡府乘休日，王城訪道初。',120,'全唐诗/poet.tang.5000.json','["郡府乘休日，王城訪道初。", "覺花迎步履，香草藉行車。", "倚閣觀無際，尋山坐太虛。", "巖空迷禹跡，海靜望秦餘。", "翡翠巢珠網，鵾雞間綺疏。", "地靈資淨土，水若護真如。", "寶樹誰攀折，禪雲自卷舒。", "晴分五湖勢，煙合九夷居。", "生滅紛無象，窺臨已得魚。", "嘗聞寶刀贈，今日奉瓊琚。"]'),
('e3cb24d4-7cc5-47af-bcc5-1cfb41c03f3d','奉和李右相中書壁畫山水','孫逖','唐','唐诗','tang','','[]','廟堂多暇日，山水契中情。',96,'全唐诗/poet.tang.5000.json','["廟堂多暇日，山水契中情。", "欲寫高深趣，還因藻繪成。", "九江臨戶牖，三峽繞檐楹。", "花柳窮年發，煙雲逐意生。", "能令萬里近，不覺四時行。", "氣染荀香馥，光含樂鏡清。", "詠歌齊出處，圖畫表沖盈。", "自保千年遇，何論八載榮。"]'),
('d6c82554-53e1-411c-9211-20bdc5147204','奉和李右相賞會昌林亭','孫逖','唐','唐诗','tang','','[]','賢相初陪蹕，靈山本降神。',72,'全唐诗/poet.tang.5000.json','["賢相初陪蹕，靈山本降神。", "作京雄近縣，開閣寵平津。", "地勝林亭好，時清宴賞頻。", "百泉縈草木，萬井布郊畛。", "德與春和盛，功將造化鄰。", "還嗤渭濱叟，歲晚獨垂綸。"]'),
('c4b4899e-7941-49e6-8f62-4f84e97031f6','和左衞武倉曹衞中對雨創韻贈右衞李騎曹','孫逖','唐','唐诗','tang','','[]','林父同官意，宣尼久敬交。',120,'全唐诗/poet.tang.5000.json','["林父同官意，宣尼久敬交。", "文場刊玉篆，武事掌金鐃。", "道合宜連茹，時清豈繫匏。", "克勤居簿領，多暇屏讙譊。", "美酒懷公讌，玄談俟客嘲。", "薄雲生北闕，飛雨自西郊。", "院暑便清曠，庭蕪覺漸苞。", "高門關詎閉，逸韻柱難膠。", "枳棘鸞無歎，椅梧鳳必巢。", "忽聞徵竝作，觀海媿堂坳。"]'),
('dc8e091b-eb56-45e2-8089-d508fa1a6aaa','送新羅法師還國','孫逖','唐','唐诗','tang','','[]','異域今無外，高僧代所稀。',72,'全唐诗/poet.tang.5000.json','["異域今無外，高僧代所稀。", "苦心歸寂滅，宴坐得精微。", "持鉢何年至，傳燈是日歸。", "上卿揮別藻，中禁下禪衣。", "海闊杯還度，雲遙錫更飛。", "此行迷處所，何以慰虔祈。"]'),
('c59a3ffd-f125-4524-8a04-b1b95ad2a55d','送趙大夫護邊','孫逖','唐','唐诗','tang','','["\u9ec4\u6cb3"]','外域分都護，中臺命職方。',96,'全唐诗/poet.tang.5000.json','["外域分都護，中臺命職方。", "欲傳清廟略，先取劇曹郎。", "已佩登壇印，猶懷伏奏香。", "百壺開祖餞，駟牡戒戎裝。", "青海連西掖，黃河帶北涼。", "關山瞻漢月，戈劒宿胡霜。", "體國才先著，論兵策復長。", "果持文武術，還繼杜當陽。"]'),
('814d2107-c19e-4287-87cb-e17cde697893','立秋日題安昌寺北山亭','孫逖','唐','唐诗','tang','','[]','樓觀倚長霄，登攀及霽朝。',96,'全唐诗/poet.tang.5000.json','["樓觀倚長霄，登攀及霽朝。", "高如石門頂，勝擬赤城標。", "天路雲虹近，人寰氣象遙。", "山圍伯禹廟，江落伍胥潮。", "徂暑迎秋薄，涼風是日飄。", "果林餘苦李，萍水覆甘蕉。", "覽古嗟夷漫，凌空愛泬寥。", "更聞金剎下，鐘梵晚蕭蕭。"]'),
('b595c6c8-9229-474b-8d80-0cc988c8a1f6','登越州城','孫逖','唐','唐诗','tang','','[]','越嶂繞層城，登臨萬象清。',72,'全唐诗/poet.tang.5000.json','["越嶂繞層城，登臨萬象清。", "封圻滄海合，廛市碧湖明。", "曉日漁歌滿，芳春櫂唱行。", "山風吹美箭，田雨潤香秔。", "代閱英靈盡，人閑吏隱幷。", "贈言王逸少，已見曲池平。"]'),
('70185202-25af-412a-b5f9-5dc38903619d','江行有懷','孫逖','唐','唐诗','tang','','[]','秋水明川路，輕舟轉石圻。',72,'全唐诗/poet.tang.5000.json','["秋水明川路，輕舟轉石圻。", "霜多山橘熟，寒至浦禽稀。", "飛席乘風勢，迴流蕩日暉。", "晝行疑海若，夕夢識江妃。", "野霽看吳盡，天長望洛非。", "不知何歲月，一似暮潮歸。"]'),
('6c7fd6e3-4956-4dad-9c0d-d336cb609602','長洲苑','孫逖','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','吳王初鼎峙，羽獵騁雄才。',120,'全唐诗/poet.tang.5000.json','["吳王初鼎峙，羽獵騁雄才。", "輦道閶門出，軍容茂苑來。", "山從列嶂轉，江自繞林迴。", "劒騎緣汀入，旌門隔嶼開。", "合離紛若電，馳逐溢成雷。", "勝地虞人守，歸舟漢女陪。", "可憐夷漫處，猶在洞庭隈。", "山靜吟猿父，城空應雉媒。", "戎行委喬木，馬跡盡黃埃。", "攬涕問遺老，繁華安在哉。"]'),
('d1f7ade0-dbf7-42e2-8245-410f06dcb360','和詠廨署有櫻桃','孫逖','唐','唐诗','tang','','[]','上林天禁裏，芳樹有紅櫻。',72,'全唐诗/poet.tang.5000.json','["上林天禁裏，芳樹有紅櫻。", "江國今來見，君門春意生。", "香從花綬轉，色繞佩珠明。", "海鳥銜初實，吳姬掃落英。", "切將稀取貴，羞與衆同榮。", "爲此堪攀折，芳蹊處處成。"]'),
('cc65010e-e74e-4882-8d76-e1423ed0b200','同洛陽李少府觀永樂公主入蕃','孫逖','唐','唐诗','tang','','[]','邊地鶯花少，年來未覺新。',24,'全唐诗/poet.tang.5000.json','["邊地鶯花少，年來未覺新。", "美人天上落，龍塞始應春。"]'),
('7c775b87-805f-45d4-954e-d0a747ad4c79','途中口號','孫逖','唐','唐诗','tang','','[]','鄴城東北望陵臺，珠翠繁華去不迴。',32,'全唐诗/poet.tang.5000.json','["鄴城東北望陵臺，珠翠繁華去不迴。", "無復新妝豔紅粉，空餘故壟滿青苔。"]'),
('67866d08-d669-45e3-b804-ec3192aaf75f','晦日湖塘','孫逖','唐','唐诗','tang','','[]','吉日初成晦，方塘遍是春。',48,'全唐诗/poet.tang.5000.json','["吉日初成晦，方塘遍是春。", "落花迎二月，芳樹歷三旬。", "公子能留客，巫陽好解神。", "夜還何慮暗，秉燭向城闉。"]'),
('618b91b5-13b0-415c-8402-0fa9ab341591','句','孫逖','唐','唐诗','tang','','[]','野煙出爐上，山花落鏡中。',12,'全唐诗/poet.tang.5000.json','["野煙出爐上，山花落鏡中。"]'),
('7dc010f6-30c6-4041-a0f5-3b8f33c6e46e','從軍行','崔國輔','唐','唐诗','tang','','[]','塞北胡霜下，營州索兵救。',48,'全唐诗/poet.tang.5000.json','["塞北胡霜下，營州索兵救。", "夜裏偷道行，將軍馬亦瘦。", "刀光照塞月，陣色明如晝。", "傳聞賊滿山，已共前鋒鬬。"]'),
('911c8a71-d6a7-4639-8797-712e47ac1e75','雜詩','崔國輔','唐','唐诗','tang','','[]','逢著平樂兒，論交鞍馬前。',48,'全唐诗/poet.tang.5000.json','["逢著平樂兒，論交鞍馬前。", "與酤一斗酒，恰用十千錢。", "後余在關內，作事多迍邅。", "何肯相救援，徒聞寶劒篇。"]'),
('d324e92c-f390-46f6-805e-f1dcd7e81f71','古意','崔國輔','唐','唐诗','tang','','[]','紅荷楚水曲，彪炳爍晨霞。',48,'全唐诗/poet.tang.5000.json','["紅荷楚水曲，彪炳爍晨霞。", "未得兩回摘，秋風吹却花。", "時芳不待妾，玉珮無處誇。", "悔不盛年時，嫁與青樓家。"]'),
('cc2e8cd5-0782-414e-bda7-c79da4b3bb34','宿法華寺','崔國輔','唐','唐诗','tang','','[]','松雨時復滴，寺門清且涼。',48,'全唐诗/poet.tang.5000.json','["松雨時復滴，寺門清且涼。", "此心竟誰證，回憩支公牀。", "壁畫感靈跡，龕經傳異香。", "獨遊寄象外，忽忽歸南昌。"]'),
('8b06879a-c2fb-4643-8115-c6603a019834','題豫章館','崔國輔','唐','唐诗','tang','','[]','楊柳映春江，江南轉佳麗。',84,'全唐诗/poet.tang.5000.json','["楊柳映春江，江南轉佳麗。", "吳門綠波裏，越國青山際。", "遊宦常往來，津亭暫臨憩。", "驛前蒼石沒，浦外湖沙細。", "向晚宴且久，孤舟冏然逝。", "雲留西北客，氣歇東南帝。", "獨有萋萋心，誰知怨芳歲。"]'),
('8a71bbdb-daeb-496b-84f0-38dd78f8d49a','石頭灘作','崔國輔','唐','唐诗','tang','','[]','悵矣秋風時，余臨石頭瀨。',108,'全唐诗/poet.tang.5000.json','["悵矣秋風時，余臨石頭瀨。", "因高見遠境，盡此數州內。", "羽山數點青，海岸雜光碎。", "離離樹木少，漭漭湖波大。", "日暮千里帆，南飛落天外。", "須臾遂入夜，楚色有微靄。", "尋遠跡已窮，遺榮事多昧。", "一身猶未理，安得濟時代。", "且泛朝夕潮，荷衣蕙爲帶。"]'),
('24a802b4-2dfd-40c4-b656-a59bc27c1d30','漂母岸','崔國輔','唐','唐诗','tang','','[]','泗水入淮處，南邊古岸存。',120,'全唐诗/poet.tang.5000.json','["泗水入淮處，南邊古岸存。", "秦時有漂母，於此飯王孫。", "王孫初未遇，寄食何足論。", "後爲楚王來，黃金答母恩。", "事跡遺在此，空傷千載魂。", "茫茫水中渚，上有一孤墩。", "遙望不可到，蒼蒼煙樹昏。", "幾年崩冢色，每日落潮痕。", "古地多陻圮，時哉不敢言。", "向夕淚霑裳，遂宿蘆洲村。"]'),
('0aad9c33-abf8-4236-8508-9907bf16abb9','對酒吟','崔國輔','唐','唐诗','tang','','[]','行行日將夕，荒村古冢無人跡。',62,'全唐诗/poet.tang.5000.json','["行行日將夕，荒村古冢無人跡。", "蒙籠荆棘一鳥吟，屢唱提壺沽酒喫。", "古人不達酒不足，遺恨精靈傳此曲。", "寄言世上諸少年，平生且盡杯中醁。"]'),
('46e89ba4-b83f-4183-af4a-1267b3a5afa4','奉和華清宮觀行香應制','崔國輔','唐','唐诗','tang','','[]','天子蘂珠宮，樓臺碧落通。',48,'全唐诗/poet.tang.5000.json','["天子蘂珠宮，樓臺碧落通。", "豫遊皆汗漫，齋處即崆峒。", "雲物三光裏，君臣一氣中。", "道言何所說，寶曆自無窮。"]'),
('7b9796ac-c26f-4488-ab95-c574f1d07966','七夕','崔國輔','唐','唐诗','tang','','[]','太守仙潢族，含情七夕多。',48,'全唐诗/poet.tang.5000.json','["太守仙潢族，含情七夕多。", "扇風生玉漏，置水寫銀河。", "閣下陳書籍，閨中曝綺羅。", "遙思漢武帝，青鳥幾時過。"]'),
('55ac392c-ebd3-4fdb-a9c5-9f0b6c6c0a1d','宿范浦','崔國輔','唐','唐诗','tang','','[]','月暗潮又落，西陵渡暫停。',48,'全唐诗/poet.tang.5000.json','["月暗潮又落，西陵渡暫停。", "村煙和海霧，舟火亂江星。", "路轉定山遶，塘連范浦橫。", "鴟夷近何去，空山臨滄溟。"]'),
('031834a5-d244-4311-8c23-9b1c1018960d','奉和聖製上巳祓禊應制','崔國輔','唐','唐诗','tang','','[]','元巳秦中節，吾君灞上遊。',72,'全唐诗/poet.tang.5000.json','["元巳秦中節，吾君灞上遊。", "鳴鑾通禁苑，別館遶芳洲。", "鵷鷺千官列，魚龍百戲浮。", "桃花春欲盡，穀雨夜來收。", "慶向堯樽祝，歡從楚棹謳。", "逸詩何足對，窅作掩東周。"]'),
('81588847-ae7f-410b-91b7-56441ccdb81a','九日侍宴應制','崔國輔','唐','唐诗','tang','','[]','運偶千年聖，時傳九日神。',72,'全唐诗/poet.tang.5000.json','["運偶千年聖，時傳九日神。", "堯樽列鐘鼓，漢闕闢鉤陳。", "金籙三清降，瓊筵五老巡。", "始驚蘭佩出，復詠柏梁新。", "雲鴈樓前晚，霜花酒裏春。", "歡娛無限極，書劒太平人。"]'),
('91abfcf4-bf83-443d-976f-11f3b1b332f1','杭州北郭戴氏荷池送侯愉','崔國輔','唐','唐诗','tang','','[]','秋近萬物肅，況當臨水時。',72,'全唐诗/poet.tang.5000.json','["秋近萬物肅，況當臨水時。", "折花贈歸客，離緒斷荷絲。", "誰謂江國永，故人感在茲。", "道存過北郭，情極望東菑。", "喬木故園意，鳴蟬窮巷悲。", "扁舟竟何待，中路每遲遲。"]'),
('2483104b-9d1a-4376-b4af-a864212d0c9d','怨詞二首 一','崔國輔','唐','唐诗','tang','','[]','妾有羅衣裳，秦王在時作。',24,'全唐诗/poet.tang.5000.json','["妾有羅衣裳，秦王在時作。", "爲舞春風多，秋來不堪著。"]'),
('fba61e93-f905-49a8-b475-cb412860149e','怨詞二首 二','崔國輔','唐','唐诗','tang','','[]','樓頭桃李疎，池上芙蓉落。',24,'全唐诗/poet.tang.5000.json','["樓頭桃李疎，池上芙蓉落。", "織錦猶未成，蛩聲入羅幕。"]'),
('fd485fea-3025-4224-b8fb-769d56b6cf9a','古意二首 一','崔國輔','唐','唐诗','tang','','[]','玉籠薰繡裳，著罷眠洞房。',24,'全唐诗/poet.tang.5000.json','["玉籠薰繡裳，著罷眠洞房。", "不能春風裏，吹却蘭麝香。"]'),
('fd57a389-60f1-4019-8b90-bd21ae638695','古意二首 二','崔國輔','唐','唐诗','tang','','[]','種棘遮蘼蕪，畏人來采殺。',24,'全唐诗/poet.tang.5000.json','["種棘遮蘼蕪，畏人來采殺。", "比至狂夫還，看看幾花發。"]'),
('b4dab7be-0e5d-4470-b2f4-f611a16a2d5e','襄陽曲二首 一','崔國輔','唐','唐诗','tang','','[]','蕙草嬌紅萼，時光舞碧雞。',24,'全唐诗/poet.tang.5000.json','["蕙草嬌紅萼，時光舞碧雞。", "城中美年少，相見白銅鞮。"]'),
('fa4076ef-ddda-4c26-ae49-657fba2c3f86','襄陽曲二首 二','崔國輔','唐','唐诗','tang','','[]','少年襄陽地，來往襄陽城。',24,'全唐诗/poet.tang.5000.json','["少年襄陽地，來往襄陽城。", "城中輕薄子，知妾解秦箏。"]'),
('ee46821d-7fb8-4918-9e62-558c884245b6','魏宮詞','崔國輔','唐','唐诗','tang','','[]','朝日照紅妝，擬上銅雀臺。',24,'全唐诗/poet.tang.5000.json','["朝日照紅妝，擬上銅雀臺。", "畫眉猶未了，魏帝使人催。"]'),
('dfedded9-b444-499e-8547-d80a5d51feb7','長信草','崔國輔','唐','唐诗','tang','','[]','長信宮中草，年年愁處生。',24,'全唐诗/poet.tang.5000.json','["長信宮中草，年年愁處生。", "故侵珠履跡，不使玉階行。"]'),
('02f837a3-fc08-4aed-9e43-dbbaa58e6086','長樂少年行','崔國輔','唐','唐诗','tang','','[]','遺却珊瑚鞭，白馬驕不行。',24,'全唐诗/poet.tang.5000.json','["遺却珊瑚鞭，白馬驕不行。", "章臺折楊柳，春日路傍情。"]'),
('3f4a0b12-ce76-43f9-8e9d-907a0e944e32','湖南曲','崔國輔','唐','唐诗','tang','','[]','湖南送君去，湖北送君歸。',24,'全唐诗/poet.tang.5000.json','["湖南送君去，湖北送君歸。", "湖裏鴛鴦鳥，雙雙他自飛。"]'),
('a7fbf620-dd82-49d4-afea-a987715c3844','中流曲','崔國輔','唐','唐诗','tang','','[]','歸時日尚早，更欲向芳洲。',24,'全唐诗/poet.tang.5000.json','["歸時日尚早，更欲向芳洲。", "渡口水流急，迴船不自由。"]'),
('3fcc8c9e-bbec-450c-9033-ec6376597cb8','王孫遊','崔國輔','唐','唐诗','tang','','[]','自與王孫別，頻看黃鳥飛。',24,'全唐诗/poet.tang.5000.json','["自與王孫別，頻看黃鳥飛。", "應由春草誤，著處不成歸。"]'),
('3ee149ba-d872-4f5d-adbc-a401a261e172','采蓮曲','崔國輔','唐','唐诗','tang','','[]','玉漵花爭發，金塘水亂流。',24,'全唐诗/poet.tang.5000.json','["玉漵花爭發，金塘水亂流。", "相逢畏相失，並著采蓮舟。"]'),
('8259dd89-196f-464b-8a94-1655dc7431a3','子夜冬歌','崔國輔','唐','唐诗','tang','','[]','寂寥抱冬心，裁羅又褧褧。',24,'全唐诗/poet.tang.5000.json','["寂寥抱冬心，裁羅又褧褧。", "夜久頻挑燈，霜寒剪刀冷。"]'),
('7c2c8e94-7297-462c-897a-b737ca886654','麗人曲','崔國輔','唐','唐诗','tang','','[]','紅顏稱絕代，欲並真無侶。',24,'全唐诗/poet.tang.5000.json','["紅顏稱絕代，欲並真無侶。", "獨有鏡中人，由來自相許。"]'),
('861898e7-b6b0-4805-9bc4-a6b6a1ca55a0','小長干曲','崔國輔','唐','唐诗','tang','','[]','月暗送潮風，相尋路不通。',24,'全唐诗/poet.tang.5000.json','["月暗送潮風，相尋路不通。", "菱歌唱不徹，知在此塘中。"]'),
('2bb965aa-61a7-47be-8dab-6e3874139c7f','王昭君','崔國輔','唐','唐诗','tang','','[]','漢使南還盡，胡中妾獨存。',24,'全唐诗/poet.tang.5000.json','["漢使南還盡，胡中妾獨存。", "紫臺綿望絕，秋草不堪論。"]'),
('e052475d-0dd9-44e6-b9a3-3ebe4a5fcc49','秦女卷衣','崔國輔','唐','唐诗','tang','','[]','雖入秦帝宮，不上秦帝牀。',24,'全唐诗/poet.tang.5000.json','["雖入秦帝宮，不上秦帝牀。", "夜夜玉窗裏，與他卷衣裳。"]'),
('f8dded1a-e08b-46c9-a122-a2a44444a484','今別離','崔國輔','唐','唐诗','tang','','[]','送別未能旋，相望連水口。',24,'全唐诗/poet.tang.5000.json','["送別未能旋，相望連水口。", "船行欲映洲，幾度急搖手。"]'),
('71017886-3624-4798-8226-60ea3b816a52','衞豔詞','崔國輔','唐','唐诗','tang','','[]','淇上桑葉青，青樓含白日。',24,'全唐诗/poet.tang.5000.json','["淇上桑葉青，青樓含白日。", "比時遙望君，車馬城中出。"]'),
('75f247a1-875a-48dd-87c2-6e8cd5c13140','渭水西別李崙','崔國輔','唐','唐诗','tang','','[]','隴右長亭堠，山陰古塞秋。',24,'全唐诗/poet.tang.5000.json','["隴右長亭堠，山陰古塞秋。", "不知嗚咽水，何事向西流。"]'),
('c1628d48-46e3-4330-a5fd-7e81bc261629','古意','崔國輔','唐','唐诗','tang','','[]','淨掃黃金階，飛霜皎如雪。',24,'全唐诗/poet.tang.5000.json','["淨掃黃金階，飛霜皎如雪。", "下簾彈箜篌，不忍見秋月。"]'),
('c034f0a0-07a1-4254-a4ae-b7411adad5a8','送韓十四被魯王推遞往濟南府','崔國輔','唐','唐诗','tang','','[]','西候情何極，南冠怨有餘。',24,'全唐诗/poet.tang.5000.json','["西候情何極，南冠怨有餘。", "梁王雖好事，不察獄中書。"]'),
('78a84f2a-d55a-4449-8d62-65f0affd23ec','白紵辭二首 一','崔國輔','唐','唐诗','tang','','[]','洛陽梨花落如霰，河陽桃葉生復齊。',32,'全唐诗/poet.tang.5000.json','["洛陽梨花落如霰，河陽桃葉生復齊。", "坐惜玉樓春欲盡，紅綿粉絮裛妝啼。"]'),
('324495ad-2db6-4a39-a9c0-e208bd91d828','白紵辭二首 二','崔國輔','唐','唐诗','tang','','[]','董賢女弟在椒風，窈窕繁華貴後宮。',32,'全唐诗/poet.tang.5000.json','["董賢女弟在椒風，窈窕繁華貴後宮。", "璧帶金釭皆翡翠，一朝零落變成空。"]'),
('c05b9b5e-b07f-4fad-a6c1-26bb8d32fd12','九日','崔國輔','唐','唐诗','tang','','[]','江邊楓落菊花黃，少長登高一望鄉。',32,'全唐诗/poet.tang.5000.json','["江邊楓落菊花黃，少長登高一望鄉。", "九日陶家雖載酒，三年楚客已霑裳。"]'),
('576f5b8e-d99e-43ed-b238-3890abc782c6','王昭君','崔國輔','唐','唐诗','tang','','[]','一回望月一回悲，望月月移人不移。',32,'全唐诗/poet.tang.5000.json','["一回望月一回悲，望月月移人不移。", "何時得見漢朝使，爲妾傳書斬畫師。"]'),
('dfc7ba4a-f19d-48d3-8a9b-5b4f47a0b880','孤寢怨','崔珪','唐','唐诗','tang','','[]','征戍動經年，含情拂玳筵。',48,'全唐诗/poet.tang.5000.json','["征戍動經年，含情拂玳筵。", "花飛織錦處，月落擣衣邊。", "燈暗愁孤坐，牀空怨獨眠。", "自君遼海去，玉匣閉春弦。"]'),
('1e51f8be-4533-4312-b0c0-919d4fff2f1c','題武陵草堂','楊浚','唐','唐诗','tang','','[]','草堂列仙樓，上在青山頂。',96,'全唐诗/poet.tang.5000.json','["草堂列仙樓，上在青山頂。", "戶外窺數峯，階前對雙井。", "雨來花盡濕，風度松初冷。", "登棧行不疲，入谿語彌靜。", "云能去塵服，兼欲事金鼎。", "正直心所存，諂諛長自省。", "適知幽遁趣，已覺煩慮屏。", "更愛雲林間，吾將臥南潁。"]'),
('1b37b851-52a1-475a-bed6-7a83fc044ad6','廣武懷古','楊浚','唐','唐诗','tang','','[]','河水城下流，登城望彌愜。',72,'全唐诗/poet.tang.5000.json','["河水城下流，登城望彌愜。", "海雲飛不斷，岸草綠相接。", "龍門無舊塲，武牢有遺堞。", "扼喉兵易守，捫指計何捷。", "天奪項氏謀，卒成漢家業。", "鄉山遙可見，西顧淚盈睫。"]'),
('995c93fb-a158-4af9-95f4-7005caf418e3','贈李郎中','楊浚','唐','唐诗','tang','','[]','仙郎早朝退，直省臥南軒。',72,'全唐诗/poet.tang.5000.json','["仙郎早朝退，直省臥南軒。", "院竹自成賞，階庭寂不喧。", "焚香開後閣，起草閉前門。", "禮樂風流美，光華星位尊。", "榮兼朱紱貴，交乃布衣存。", "是日登龍客，無忘君子恩。"]'),
('d4c038d9-521f-4d90-8e61-d90cf5ae0174','詠王大娘戴卒','劉晏','唐','唐诗','tang','','[]','樓前百戲競爭新，唯有長竿妙入神。',34,'全唐诗/poet.tang.5000.json','["樓前百戲競爭新，唯有長竿妙入神。", "誰謂綺羅[翻]有力，猶自嫌輕更著人。"]'),
('102198f6-fc4f-4183-8e98-85df362362bb','享太廟樂章','劉晏','唐','唐诗','tang','','[]','漢祚惟永，神功中興。',40,'全唐诗/poet.tang.5000.json','["漢祚惟永，神功中興。", "夙驅氛祲，天覆黎蒸。", "三光再朗，庶績其凝。", "重熙累葉，景命是膺。"]'),
('b613132b-0a83-44e3-84c0-083d6f47ae96','鴻門行','袁瓘','唐','唐诗','tang','','[]','少年買意氣，百金不辭費。',264,'全唐诗/poet.tang.5000.json','["少年買意氣，百金不辭費。", "學劒西入秦，結交北遊魏。", "秦魏多豪人，與代亦殊倫。", "由來不相識，皆是暗相親。", "寶馬青絲轡，狐裘貂鼠服。", "晨過劇孟游，暮投咸陽宿。", "然諾本云云，諸侯莫不聞。", "猶思百戰術，更逐李將軍。", "始從灞陵下，遙遙度朔野。", "北風聞楚歌，南庭見胡馬。", "胡馬秋正肥，相邀夜合圍。", "戰酣烽火滅，路斷救兵稀。", "白刃縱橫逼，黃塵飛不息。", "虜騎血灑衣，單于淚沾臆。", "獻凱雲臺中，自言塞上雄。", "將軍行失勢，部曲遂無功。", "新人不如舊，舊人不相救。", "萬里長飄颻，十年計不就。", "棄置難重論，驅馬度鴻門。", "行看楚漢事，不覺風塵昏。", "寶劒中夜撫，悲歌聊自舞。", "此曲不可終，曲終淚如雨。"]'),
('0dc587aa-2bc9-4f31-aa81-9165ed6e39c4','惠文太子挽歌','袁瓘','唐','唐诗','tang','','[]','寒仗丹旄引，陰堂白日違。',48,'全唐诗/poet.tang.5000.json','["寒仗丹旄引，陰堂白日違。", "暗燈明象物，畫水濕靈衣。", "羽化淮王去，仙迎太子歸。", "空餘燕銜土，朝夕向陵飛。"]'),
('793e5224-1879-4e24-b316-e772c935a6a4','從軍行','李昂','唐','唐诗','tang','','["\u4e50\u5e9c", "\u8fb9\u585e"]','漢家未得燕支山，征戍年年沙朔間。',312,'全唐诗/poet.tang.5000.json','["漢家未得燕支山，征戍年年沙朔間。", "塞下長驅汗血馬，雲中恆閉玉門關。", "陰山翰海千萬里，此日桑河凍流水。", "稽洛川邊胡騎來，漁陽戍裏烽煙起。", "長途羽檄何相望，天子按劒思北方。", "羽林練士拭金甲，將軍校戰出玉堂。", "幽陵異域風煙改，亭障連連古今在。", "夜聞鴻雁南渡河，曉望旌旗北臨海。", "塞沙飛淅瀝，遙裔連窮磧。", "玄漠雲平初合陣，西山月出聞鳴鏑。", "城南百戰多苦辛，路傍死臥黃沙人。", "戎衣不脫隨霜雪，汗馬䟃𧽼長被鐵。", "楊葉樓中不寄書，蓮花劒上空流血。", "匈奴未滅不言家，驅逐行行邊徼賒。", "歸心海外見明月，別思天邊夢落花。", "天邊迴望何悠悠，芳樹無人渡隴頭。", "春雲不變陽關雪，桑葉先知胡地秋。", "田疇不賣盧龍策，竇憲思勒燕然石。", "麾兵靜北垂，此日交河湄。", "欲令塞上無干戚，會待單于繫頸時。"]'),
('4813666e-41fc-406f-9d4d-8029b21b0543','賦戚夫人楚舞歌','李昂','唐','唐诗','tang','','[]','定陶城中是妾家，妾年二八顏如花。',256,'全唐诗/poet.tang.5000.json','["定陶城中是妾家，妾年二八顏如花。", "閨中歌舞未終曲，天下死人如亂麻。", "漢王此地因征戰，未出簾櫳人已薦。", "風花菡萏落轅門，雲雨裴回入行殿。", "日夕悠悠非舊鄉，飄飄處處逐君王。", "閨門向裏通歸夢，銀燭迎來在戰場。", "相從顧恩不顧己，何異浮萍寄深水。", "逐戰曾迷隻輪下，隨君幾陷重圍裏。", "此時平楚復平齊，咸陽宮闕到關西。", "珠簾夕殿聞鐘磬，白日秋天憶鼓鼙。", "君王縱恣翻成誤，呂后由來有深妬。", "不奈君王容鬢衰，相存相顧能幾時。", "黃泉白骨不可報，雀釵翠羽從此辭。", "君楚歌兮妾楚舞，脉脉相看兩心苦。", "曲未終兮袂更揚，君流涕兮妾斷腸。", "已見儲君歸惠帝，徒留愛子付周昌。"]'),
('e4411499-60dd-459f-9247-ed4606232249','句','李昂','唐','唐诗','tang','','[]','耳臨清渭洗，心向白雲閑。',12,'全唐诗/poet.tang.5000.json','["耳臨清渭洗，心向白雲閑。"]'),
('78ca6b46-189b-425f-968e-e920be6ec2cb','夏晚初霽南省寓直用餘字','厙狄履溫','唐','唐诗','tang','','[]','薄宦因時泰，涼宵寓直初。',120,'全唐诗/poet.tang.5000.json','["薄宦因時泰，涼宵寓直初。", "沈沈仙閣閉，的的暗更徐。", "霽色連空上，炎氛入夜除。", "星迴南斗落，月度北窗虛。", "待漏殘燈照，含芳襲氣餘。", "寐來冠不解，奏罷草仍書。", "幕府慙良策，明曹媿散樗。", "命輕徒有報，義重更難疎。", "燕廈欣成託，鵷行濫所如。", "晨趨當及早，復此戒朝車。"]'),
('79835934-e491-4207-9b1f-e2ca84d2583b','同皇甫兵曹天官寺浴室新成招友人賞會','寇坦','唐','唐诗','tang','','[]','溫室歡初就，蘭交托勝因。',48,'全唐诗/poet.tang.5000.json','["溫室歡初就，蘭交托勝因。", "共聽無漏法，兼濯有爲塵。", "水潔三空性，香沾四大身。", "清心多善友，頌德慰同人。"]'),
('82ee3cd4-d4dd-4d26-96d8-c9bfcec45aa2','同張少府和厙狄員外夏晚初霽南省寓直時兼充節度判官之作','寇坦','唐','唐诗','tang','','[]','黃綬歸休日，仙郎復奏餘。',120,'全唐诗/poet.tang.5000.json','["黃綬歸休日，仙郎復奏餘。", "晏居當夏晚，寓直會晴初。", "露散星文發，雲披水鏡虛。", "高才推獨唱，嘉會喜連茹。", "月色搖春闥，香煙靄暝廬。", "千門傳夜警，萬象照階除。", "少孺嘉能賦，文強閱賜書。", "兼曹謀未展，入幕志方攄。", "爲奉靈臺帛，恭先待漏車。", "貞標不可仰，空此樂樵漁。"]'),
('2aaabec5-7f97-4d5e-9a0c-b418cfbc7eee','詠銅柱','李休烈','唐','唐诗','tang','','[]','天門街裏倒天樞，火急先須卸火珠。',32,'全唐诗/poet.tang.5000.json','["天門街裏倒天樞，火急先須卸火珠。", "計合一條絲線挽，何勞兩縣索人夫。"]'),
('5b18b761-a4fe-4ccb-b1e2-978566267463','送賀監歸四明應制','李林甫','唐','唐诗','tang','','[]','挂冠知止足，豈獨漢疏賢。',48,'全唐诗/poet.tang.5000.json','["挂冠知止足，豈獨漢疏賢。", "入道求真侶，辭恩訪列仙。", "睿文含日月，宸翰動雲煙。", "鶴駕吳鄉遠，遙遙南斗邊。"]'),
('de563514-6444-4aa3-b6e2-917abb4e062c','奉和聖製次瓊岳應制','李林甫','唐','唐诗','tang','','[]','東幸從人望，西巡順物回。',48,'全唐诗/poet.tang.5000.json','["東幸從人望，西巡順物回。", "雲收二華出，天轉五星來。", "十月農初罷，三驅禮復開。", "更看瓊岳上，佳氣接神臺。"]'),
('62840254-fc80-4bdc-95dc-b88f0807dcc7','秋夜望月憶韓席等諸侍郎因以投贈','李林甫','唐','唐诗','tang','','[]','秋天碧雲夜，明月懸東方。',120,'全唐诗/poet.tang.5000.json','["秋天碧雲夜，明月懸東方。", "皓皓庭際色，稍稍林下光。", "桂華澄遠近，璧彩散池塘。", "鴻雁飛難度，關山曲易長。", "揆予秉孤直，虛薄忝文昌。", "握鏡慚先照，持衡媿後行。", "多才衆君子，載筆久詞場。", "作賦推潘岳，題詩許謝康。", "當時陪宴語，今夕恨相望。", "願欲接高論，清晨朝建章。"]'),
('f4066262-a7bc-4f6a-8bb5-46a56d2ffaff','流崖州至鬼門關作','楊炎','唐','唐诗','tang','','[]','一去一萬里，千知千不還。',24,'全唐诗/poet.tang.5000.json','["一去一萬里，千知千不還。", "崖州何處在？生度鬼門關。"]'),
('8a7ef146-2953-45fd-94da-ef92db24648f','贈元載歌妓','楊炎','唐','唐诗','tang','','[]','雪面淡眉天上女，鳳簫鸞翅欲飛去。',32,'全唐诗/poet.tang.5000.json','["雪面淡眉天上女，鳳簫鸞翅欲飛去。", "玉山翹翠步無塵，楚腰如柳不勝春。"]'),
('62d3110d-6e4e-40f8-96b6-4b97fe6dfa41','別妻王韞秀','元載','唐','唐诗','tang','','[]','年來誰不厭龍鍾，雖在侯門似不容。',32,'全唐诗/poet.tang.5000.json','["年來誰不厭龍鍾，雖在侯門似不容。", "看取海山寒翠樹，苦遭霜霰到秦封。"]'),
('9a09a52a-54da-4cd6-9111-dcb20b85da56','賦得雲生棟梁間','陳希烈','唐','唐诗','tang','','[]','一片蒼梧意，氤氳生棟梁。',48,'全唐诗/poet.tang.5000.json','["一片蒼梧意，氤氳生棟梁。", "下簾山足暗，開戶日添光。", "偏使衣裘潤，能令枕簟涼。", "無心伴行雨，何必夢荆王。"]'),
('109698aa-a812-4258-aa7f-43a8708c63f9','奉和聖製三月三日','陳希烈','唐','唐诗','tang','','[]','上巳迂龍駕，中流泛羽觴。',72,'全唐诗/poet.tang.5000.json','["上巳迂龍駕，中流泛羽觴。", "酒因朝太子，詩爲樂賢王。", "錦纜方舟渡，瓊筵大樂張。", "風搖垂柳色，花發異林香。", "野老歌無事，朝臣飲歲芳。", "皇情被羣物，中外洽恩光。"]'),
('291e1334-8c23-495d-b9fc-3b90cd89d2d1','省試白雲起封中','陳希烈','唐','唐诗','tang','','["\u6cf0\u5c71"]','千年泰山頂，雲起漢王封。',72,'全唐诗/poet.tang.5000.json','["千年泰山頂，雲起漢王封。", "不作奇峰狀，寧分觸石容。", "爲霖雖易得，表聖自難逢。", "冉冉排空上，依依疊影重。", "素光非曳練，靈貺是從龍。", "豈學無心出，東西任所從。"]'),
('2840b0a9-5b1c-462e-8069-c5b5d5a96dbf','朗月行','張漸','唐','唐诗','tang','','[]','朗月照簾幌，清夜有餘姿。',120,'全唐诗/poet.tang.5000.json','["朗月照簾幌，清夜有餘姿。", "洞房怨孤枕，挾琴愛前墀。", "萱草已數葉，梨花復徧枝。", "去歲草始榮，與君新相知。", "今年花未落，誰分生別離。", "代情難重論，人事好乖移。", "合比月華滿，分同月易虧。", "虧月當再圓，人別星隕天。", "吾欲竟此曲，意深不可傳。", "歎息孤鸞鳥，傷心明鏡前。"]'),
('038a1005-ef07-47c0-b438-0dc4667d709c','曉次荆江','宋昱','唐','唐诗','tang','','[]','孤舟大江水，水涉無昏曙。',72,'全唐诗/poet.tang.5000.json','["孤舟大江水，水涉無昏曙。", "雨暗迷津時，雲生望鄉處。", "漁翁閑自樂，樵客紛多慮。", "秋色湖上山，歸心日邊樹。", "徒稱竹箭美，未得楓林趣。", "向夕垂釣還，吾從落潮去。"]'),
('700474d8-74f7-49ba-934c-bf5e02d2c469','題石窟寺','宋昱','唐','唐诗','tang','','[]','梵宇開金地，香龕鑿鐵圍。',72,'全唐诗/poet.tang.5000.json','["梵宇開金地，香龕鑿鐵圍。", "影中羣象動，空裏衆靈飛。", "簷牖籠朱旭，房廊挹翠微。", "瑞蓮生佛步，瑤樹挂天衣。", "邀福功雖在，興王代久非。", "誰知雲朔外，更覩化胡歸。"]'),
('bba2337f-5b4d-4097-ab92-f1f326570a15','樟亭觀濤','宋昱','唐','唐诗','tang','','[]','濤來勢轉雄，獵獵駕長風。',144,'全唐诗/poet.tang.5000.json','["濤來勢轉雄，獵獵駕長風。", "雷震雲霓裏，山飛霜雪中。", "激流起平地，吹澇上侵空。", "翕闢乾坤異，盈虛日月同。", "艅艎從陸起，洲浦隔阡通。", "跳沫噴巖翠，翻波帶景紅。", "怒湍初抵北，却浪復歸東。", "寂聽堪增勇，晴看自發蒙。", "伍生傳或謬，枚叟說難窮。", "來信應無已，申威亦匪躬。", "衝騰如決勝，迴合似相攻。", "委質任平視，誰能涯始終。"]'),
('5aadd6d4-f0b6-4719-9be5-fd6c9548276e','贈程秘書','盧象','唐','唐诗','tang','','[]','客自岐陽來，吐音若鳴鳳。',96,'全唐诗/poet.tang.5000.json','["客自岐陽來，吐音若鳴鳳。", "孤飛畏不偶，獨立誰見用。", "忽從被褐中，召入承明宮。", "聖人借顏色，言事無不通。", "殷勤拯黎庶，感激論諸公。", "將相猜賈誼，圖書歸馬融。", "顧余久寂寞，一歲麒麟閣。", "且共歌太平，勿嗟名宦薄。"]'),
('44dcaf68-5d78-471d-86a7-daaef4152648','家叔徵君東溪草堂二首 一','盧象','唐','唐诗','tang','','[]','開山十餘里，青壁森相倚。',96,'全唐诗/poet.tang.5000.json','["開山十餘里，青壁森相倚。", "欲識堯時天，東溪白雲是。", "雷聲轉幽壑，雲氣杳流水。", "澗影生龍蛇，巖端翳檉梓。", "大道終不易，君恩曷能已。", "鶴羨無老時，龜言攝生理。", "浮年笑六甲，元化潛一指。", "未暇掃雲梯，空慙阮氏子。"]'),
('2bdfb409-2374-4a99-8afa-65d6dcef8311','家叔徵君東溪草堂二首 二','盧象','唐','唐诗','tang','','[]','今朝共遊者，得性閑未歸。',72,'全唐诗/poet.tang.5000.json','["今朝共遊者，得性閑未歸。", "已到仙人家，莫驚鷗鳥飛。", "水深嚴子釣，松挂巢父衣。", "雲氣轉幽寂，溪流無是非。", "名理未足羨，腥臊詎所希。", "自惟負貞意，何歲當食薇。"]'),
('88a1c3c5-57ec-4b3b-8dac-f697baa68182','鄉試後自鞏還田家因謝鄰友見過之作','盧象','唐','唐诗','tang','','[]','雞鳴出東邑，馬倦登南巒。',96,'全唐诗/poet.tang.5000.json','["雞鳴出東邑，馬倦登南巒。", "落日見桑柘，翳然丘中寒。", "鄰家多舊識，投暝來相看。", "且問春稅苦，兼陳行路難。", "園場近陰壑，草木易凋殘。", "峰晴雪猶積，澗深冰已團。", "浮名知何用，歲晏不成歡。", "置酒共君飲，當歌聊自寬。"]'),
('a8c3e791-7f9d-4a6e-baf7-664109545d72','青雀歌','盧象','唐','唐诗','tang','','[]','啾啾青雀兒，飛來飛去仰天池。',30,'全唐诗/poet.tang.5000.json','["啾啾青雀兒，飛來飛去仰天池。", "逍遙飲啄安涯分，何假扶搖九萬爲。"]'),
('5be96530-0656-42e0-bf69-a0c7a9c73a58','雜詩二首 一','盧象','唐','唐诗','tang','','[]','家居五原上，征戰是平生。',48,'全唐诗/poet.tang.5000.json','["家居五原上，征戰是平生。", "獨負山西勇，誰當塞下名。", "死生遼海戰，雨雪薊門行。", "諸將封侯盡，論功獨不成。"]'),
('efaef8c1-a7b0-424d-87bd-44283b6c4fb8','雜詩二首 二','盧象','唐','唐诗','tang','','[]','君家御溝上，垂柳夾朱門。',48,'全唐诗/poet.tang.5000.json','["君家御溝上，垂柳夾朱門。", "列鼎會中貴，鳴珂朝至尊。", "死生在片議，窮達由一言。", "須識苦寒士，莫矜狐白溫。"]'),
('78da6a5c-2ed0-4db7-bece-86a9486aa6ac','贈廣川馬先生','盧象','唐','唐诗','tang','','[]','經書滿腹中，吾識廣川翁。',48,'全唐诗/poet.tang.5000.json','["經書滿腹中，吾識廣川翁。", "年老甘無位，家貧懶發蒙。", "人歸洙泗學，歌盛舞雩風。", "願接諸生禮，三年事馬融。"]'),
('dd6d6203-ced1-4e25-9d43-7e45918f476c','峽中作','盧象','唐','唐诗','tang','','[]','高唐幾百里，樹色接陽臺。',48,'全唐诗/poet.tang.5000.json','["高唐幾百里，樹色接陽臺。", "晚見江山霽，宵聞風雨來。", "雲從三峽起，天向數峰開。", "靈境信難見，輕舟那可回。"]'),
('3d82c039-389b-4cc3-8253-3c305c66fb44','竹里館','盧象','唐','唐诗','tang','','[]','江南冰不閉，山澤氣潛通。',48,'全唐诗/poet.tang.5000.json','["江南冰不閉，山澤氣潛通。", "臘月聞山鳥，寒崖見蟄熊。", "柳林春半合，荻笋亂無叢。", "回首金陵岸，依依向北風。"]'),
('7747363c-1d8d-4f81-9c07-575b27800460','永城使風','盧象','唐','唐诗','tang','','[]','長風起秋色，細雨含落暉。',48,'全唐诗/poet.tang.5000.json','["長風起秋色，細雨含落暉。", "夕鳥向林去，晚帆相逐飛。", "蟲聲出亂草，水氣薄行衣。", "一別故鄉道，悠悠今始歸。"]'),
('d7b7da24-eab2-4d9f-9fed-bf10c751c1ed','和徐侍郎叢篠詠','盧象','唐','唐诗','tang','','[]','中禁夕沈沈，幽篁別作林。',48,'全唐诗/poet.tang.5000.json','["中禁夕沈沈，幽篁別作林。", "色連雞樹近，影落鳳池深。", "爲重凌霜節，能虛應物心。", "年年承雨露，長對紫庭陰。"]'),
('f13c70c7-8ae8-48dd-b105-f17276e3bfe3','駕幸溫泉','盧象','唐','唐诗','tang','','[]','傳聞聖主幸新豐，清蹕鳴鑾出禁中。',66,'全唐诗/poet.tang.5000.json','["傳聞聖主幸新豐，清蹕鳴鑾出禁中。", "細草終朝隨步輦，垂楊幾處繞行宮。", "千官扈從驪山北，萬國來朝渭水東。", "此日小臣徒獻賦，漢家誰復重[揚]雄。"]'),
('ea9b31db-da7c-47aa-9717-71ba2ebfe377','奉和張使君宴加朝散','盧象','唐','唐诗','tang','','[]','佐理星辰貴，分榮渙汗深。',72,'全唐诗/poet.tang.5000.json','["佐理星辰貴，分榮渙汗深。", "言從大夫後，用荅聖人心。", "騎擁軒裳客，鸞驚翰墨林。", "停杯歌麥秀，秉燭醉棠陰。", "爽氣凌秋笛，輕寒散暝砧。", "秪應將四子，講德謝知音。"]'),
('67d60c2f-ad7a-4101-a782-7e9cb01e570e','贈張均員外','盧象','唐','唐诗','tang','','[]','公門世緒昌，才子冠裴王。',96,'全唐诗/poet.tang.5000.json','["公門世緒昌，才子冠裴王。", "出自平津邸，還爲吏部郎。", "神仙餘氣色，列宿動輝光。", "夜直南宮靜，朝趨北禁長。", "時人歸水鏡，明主賜衣裳。", "翰苑飛鸚鵡，天池待鳳凰。", "承歡疇日顧，未紀後時傷。", "去去圖南遠，微才幸不忘。"]'),
('870e3c4a-aad8-4894-9aea-4b370f85f1c3','送祖詠','盧象','唐','唐诗','tang','','[]','田家宜伏臘，歲晏子言歸。',60,'全唐诗/poet.tang.5000.json','["田家宜伏臘，歲晏子言歸。", "石路雪初下，荒村雞共飛。", "東原多煙火，北澗隱寒暉。", "滿酌野人酒，倦聞鄰女機。", "胡爲困樵采，幾日罷朝衣。"]'),
('a44bdecf-5ede-48fe-b212-ffdd445c7ed0','送綦毋潛','盧象','唐','唐诗','tang','','[]','夫君不得意，本自滄海來。',96,'全唐诗/poet.tang.5000.json','["夫君不得意，本自滄海來。", "高足未云騁，虛舟空復迴。", "淮南楓葉落，灞岸桃花開。", "出處暫爲耳，沈浮安繫哉。", "如何天覆物，還遣世遺才。", "欲識秦將漢，嘗聞王與裴。", "離筵對寒食，別雨乘春雷。", "會有徵書到，荷衣且漫裁。"]'),
('b1d4ecde-af9a-42b3-a9b6-00369331957a','送趙都護赴安西','盧象','唐','唐诗','tang','','[]','下客候旌麾，元戎復在斯。',96,'全唐诗/poet.tang.5000.json','["下客候旌麾，元戎復在斯。", "門開都護府，兵動羽林兒。", "黠虜多翻覆，謀臣有別離。", "智同天所授，恩共日相隨。", "漢使開賓幕，胡笳送酒巵。", "風霜迎馬首，雨雪事魚麗。", "上策應無戰，深情屬載馳。", "不應行萬里，明主寄安危。"]'),
('a351ea47-24d1-4371-99e1-9b67d41e6b92','追涼歷下古城西北隅此地有清泉喬木','盧象','唐','唐诗','tang','','[]','謝朓出華省，王祥貽佩刀。',120,'全唐诗/poet.tang.5000.json','["謝朓出華省，王祥貽佩刀。", "前賢真可慕，衰病意空勞。", "貞悔不自卜，遊隨共爾曹。", "未能齊得喪，時復誦離騷。", "閑蔭七賢地，醉餐三士桃。", "蒼苔虞舜井，喬木古城壕。", "漁父偏相狎，堯年不可逃。", "蟬鳴秋雨霽，雲白曉山高。", "咫尺傳雙鯉，吹噓借一毛。", "故人皆得路，誰肯念同袍。"]'),
('53e554ae-c6f6-4c94-98ef-af18f928df65','戲贈邵使君張郎','盧象','唐','唐诗','tang','','[]','少婦石榴裙，新妝白玉面。',24,'全唐诗/poet.tang.5000.json','["少婦石榴裙，新妝白玉面。", "能迷張公子，不許時相見。"]'),
('90b23220-6f8f-4c62-9308-fc6a0ce4212a','同王維過崔處士林亭','盧象','唐','唐诗','tang','','[]','映竹時聞轉轆轤，當窗只見網蜘蛛。',32,'全唐诗/poet.tang.5000.json','["映竹時聞轉轆轤，當窗只見網蜘蛛。", "主人非病常高臥，環堵蒙籠一老儒。"]'),
('a6306074-ffac-44d0-848d-eb72dfc04a9b','寄河上段十六','盧象','唐','唐诗','tang','','[]','與君相識即相親，聞道君家住孟津。',32,'全唐诗/poet.tang.5000.json','["與君相識即相親，聞道君家住孟津。", "爲見行舟試借問，客中時有洛陽人。"]'),
('f4d4f345-0f61-475f-8195-c0e3f6b54584','寒食','盧象','唐','唐诗','tang','','[]','子推言避世，山火遂焚身。',72,'全唐诗/poet.tang.5000.json','["子推言避世，山火遂焚身。", "四海同寒食，千秋爲一人。", "深冤何用道，峻跡古無鄰。", "魂魄山河氣，風雷御宇神。", "光煙榆柳滅，怨曲龍虵新。", "可歎文公霸，平生負此臣。"]'),
('2689fa9d-0e60-4e45-a7e1-4a621c6372fe','八月十五日象自江東止田園移莊慶會未幾歸汶上小弟幼妹尤嗟其別兼賦是詩三首 一','盧象','唐','唐诗','tang','','[]','謝病始告歸，依然入桑梓。',108,'全唐诗/poet.tang.5000.json','["謝病始告歸，依然入桑梓。", "家人皆佇立，相候衡門裏。", "疇類皆長年，成人舊童子。", "上堂家慶畢，願與親姻邇。", "論舊或餘悲，思存且相喜。", "田園轉蕪沒，但有寒泉水。", "衰柳日蕭條，秋光清邑里。", "入門乍如客，休騎非便止。", "中飲顧王程，離憂從此始。"]'),
('13c9fada-ca33-4437-b291-69207a959dc5','八月十五日象自江東止田園移莊慶會未幾歸汶上小弟幼妹尤嗟其別兼賦是詩三首 二','盧象','唐','唐诗','tang','','[]','兩妹日長成，雙鬟將及人。',48,'全唐诗/poet.tang.5000.json','["兩妹日長成，雙鬟將及人。", "已能持寶瑟，自解掩羅巾。", "念昔別時小，未知疎與親。", "今來識離恨，掩淚方殷勤。"]'),
('608f7819-e672-459f-9cbb-b6b3473c326f','八月十五日象自江東止田園移莊慶會未幾歸汶上小弟幼妹尤嗟其別兼賦是詩三首 三','盧象','唐','唐诗','tang','','[]','小弟更孩幼，歸來不相識。',48,'全唐诗/poet.tang.5000.json','["小弟更孩幼，歸來不相識。", "同居雖漸慣，見人猶默默。", "宛作越人言，殊鄉甘水食。", "別此最爲難，淚盡有餘憶。"]'),
('aba73175-2c2d-41fa-ad97-c9b241417c2a','歎白髮','盧象','唐','唐诗','tang','','[]','我年一何長，鬢髮日已白。',48,'全唐诗/poet.tang.5000.json','["我年一何長，鬢髮日已白。", "俛仰天地間，能爲幾時客。", "惆悵故山雲，裴回空日夕。", "何事與時人，東城復南陌。"]'),
('d305a948-9e29-44d8-9298-1c7a637ca876','早秋宴張郎中海亭即事','盧象','唐','唐诗','tang','','[]','邑有弦歌宰，翔鸞狎野鷗。',48,'全唐诗/poet.tang.5000.json','["邑有弦歌宰，翔鸞狎野鷗。", "眷言華省舊，暫滯海池遊。", "鬱島藏深竹，前谿對舞樓。", "更聞書即事，雲物是新秋。"]'),
('b3951125-52da-4ea2-bd12-c36d6e8f1e98','句','盧象','唐','唐诗','tang','','[]','吳越山多秀，新安江甚清。',44,'全唐诗/poet.tang.5000.json','["吳越山多秀，新安江甚清。", "書名會粹才偏逸，酒號屠蘇味更醇。", "初疑輕煙淡古松，又似山開萬仞峰。"]'),
('bedfaf3c-db06-4b7d-9435-a55e394bf8f7','嵩山十志十首 其一','盧鴻一','唐','唐诗','tang','','[]','山爲宅兮草爲堂，芝蘭兮葯房。',70,'全唐诗/poet.tang.5000.json','["山爲宅兮草爲堂，芝蘭兮葯房。", "羅蘼蕪兮拍薜荔，荃壁兮蘭砌。", "蘼蕪薜荔兮成草堂，陰陰邃兮馥馥香。", "中有人兮信宜常，讀金書兮飲玉漿，童顏幽操兮不易長。"]'),
('f2d94964-b281-4dab-b7d0-6f1c2b3a35f1','嵩山十志十首 其二','盧鴻一','唐','唐诗','tang','','[]','天門豁兮仙臺聳，傑屹崒兮零澒湧。',77,'全唐诗/poet.tang.5000.json','["天門豁兮仙臺聳，傑屹崒兮零澒湧。", "窮三休兮曠一觀，忽若登崑崙兮中期汗漫仙。", "聳天關兮倒景臺，鯊顥氣兮軼囂埃。", "皎皎之子兮自獨立，雲可朋兮赮可吸，曾何榮辱之所及。"]'),
('07f7646b-27e6-4ba1-b033-848578a238a1','嵩山十志十首 其三','盧鴻一','唐','唐诗','tang','','[]','紫巖隈兮青谿側，雲松煙蔦兮千古色。',77,'全唐诗/poet.tang.5000.json','["紫巖隈兮青谿側，雲松煙蔦兮千古色。", "芳靃蘼兮蔭蒙蘢，幽人構館兮在其中。", "靃蘼蒙蘢兮開樾館，臥風霄兮坐赮旦。", "粵有賓兮時戾止，樵蘇不爨兮清淡已，永歲終朝兮常若此。"]'),
('27a2907f-b550-4a46-8973-4e24d5e19dbf','嵩山十志十首 其四','盧鴻一','唐','唐诗','tang','','[]','臨泱漭兮背青熒，吐雲煙兮合窅冥。',76,'全唐诗/poet.tang.5000.json','["臨泱漭兮背青熒，吐雲煙兮合窅冥。", "怳欻翕兮杳幽靄，意縹緲兮羣仙會。", "窅冥仙會兮枕煙庭，竦魂形兮凝視聽。", "聞夫至誠必感兮祈此巔，契顥氣，養丹田，終彷像兮覯靈仙。"]'),
('64d377ec-aa69-468e-8c30-2ccc80b3fbd2','嵩山十志十首 其五','盧鴻一','唐','唐诗','tang','','[]','水攢衝兮石叢聳，煥雲錦兮噴洶湧。',73,'全唐诗/poet.tang.5000.json','["水攢衝兮石叢聳，煥雲錦兮噴洶湧。", "苔駮犖兮草夤緣，芳冪冪兮瀨濺濺。", "石攢叢兮雲錦淙，波連珠兮文沓綘。", "有潔冥者媚此幽，漱靈液兮樂天休，實獲我心兮夫何求。"]'),
('4931b852-e4fd-4473-b014-6308390904a6','嵩山十志十首 其六','盧鴻一','唐','唐诗','tang','','[]','霏微陰壑兮氣騰虹，迤邐危磴兮上凌空。',78,'全唐诗/poet.tang.5000.json','["霏微陰壑兮氣騰虹，迤邐危磴兮上凌空。", "青霞杪兮紫雲垂，鸞歌鳳舞兮吹參差。", "鸞吹鳳舞兮期仙磴，鴻駕迎兮瑤華贈。", "山中人兮好神仙，想像聞此兮欲升煙，鑄月煉液兮竚還年。"]'),
('c06b734d-acb4-4a0a-ba70-e9ba22f1678f','嵩山十志十首 其七','盧鴻一','唐','唐诗','tang','','[]','靈磯盤礴兮溜奔錯漱，冷風兮鎮冥壑。',77,'全唐诗/poet.tang.5000.json','["靈磯盤礴兮溜奔錯漱，冷風兮鎮冥壑。", "研苔滋兮泉珠潔，一飲一憩兮氣想滅。", "磷漣清淬兮滌煩磯，靈仙境兮仁智歸。", "中有琴兮徽以玉，峨峨湯湯兮彈此曲，寄聲知音兮同所欲。"]'),
('4699c6a4-e9cb-4315-85ae-882145bdc345','嵩山十志十首 其八','盧鴻一','唐','唐诗','tang','','[]','青崖陰兮月磵曲，重幽疊邃兮隱淪躅。',74,'全唐诗/poet.tang.5000.json','["青崖陰兮月磵曲，重幽疊邃兮隱淪躅。", "草樹緜冪兮翠蒙蘢，當其無兮庭在中。", "當無有用兮冪翠庭，神可谷兮道可冥。", "有幽人兮張素琴，皇徽兮綠水陰，德之愔兮澹多心。"]'),
('18e37bbe-ca89-418c-b448-a5fd41e4d72c','嵩山十志十首 其九','盧鴻一','唐','唐诗','tang','','[]','嵐氣肅兮巖翠冥，空陰虛兮戶芳迎。',73,'全唐诗/poet.tang.5000.json','["嵐氣肅兮巖翠冥，空陰虛兮戶芳迎。", "披蕙帳兮促蘿筵，談空空兮覈元元。", "蕙帳蘿筵兮洞元室，祕而幽兮真可吉。", "返自然兮道可冥，澤妙思兮草玄經，結幽門兮在黃庭。"]'),
('7e6bfc79-bfdb-4645-a08b-855124e0e02b','嵩山十志十首 其十','盧鴻一','唐','唐诗','tang','','[]','水碧色兮石金光，灩熠熠兮濙湟湟。',72,'全唐诗/poet.tang.5000.json','["水碧色兮石金光，灩熠熠兮濙湟湟。", "泉葩映兮煙蔦臨，紅灼灼，翠陰陰。", "翠相鮮兮金碧潭，霜天洞兮煙景涵。", "有幽人兮好冥絕，炳其煥兮凝其潔，悠悠千古長不滅。"]'),
('06a2961a-ef57-431e-ba01-70fb91a5feac','書殿賜宴應制','徐安貞','唐','唐诗','tang','','[]','校文常近日，賜宴忽升天。',48,'全唐诗/poet.tang.5000.json','["校文常近日，賜宴忽升天。", "酒正傳桮至，饔人捧案前。", "玉階鳴溜水，清閣引歸煙。", "共惜芸香暮，春風幾萬年。"]'),
('f3b708f8-cfaa-4fad-81bd-7219ca1f10ec','從駕溫泉宮','徐安貞','唐','唐诗','tang','','[]','神女調溫液，年年待聖人。',48,'全唐诗/poet.tang.5000.json','["神女調溫液，年年待聖人。", "試開臨水殿，來洗屬車塵。", "暖氣隨明主，恩波浹近臣。", "靈威自無極，從此獻千春。"]'),
('bc54c1fe-7d4f-447d-bc10-258279a903a9','送呂向補闕西岳勒碑','徐安貞','唐','唐诗','tang','','[]','聖作西山頌，君其出使年。',48,'全唐诗/poet.tang.5000.json','["聖作西山頌，君其出使年。", "勒碑懸日月，驅傳接雲煙。", "寒盡函關路，春歸洛水邊。", "別離能幾許，朝暮玉墀前。"]'),
('f822b44c-7b45-4b63-9b1f-cd1a0b05a697','送丹陽採訪','徐安貞','唐','唐诗','tang','','[]','郡縣分南國，皇華出聖朝。',48,'全唐诗/poet.tang.5000.json','["郡縣分南國，皇華出聖朝。", "爲憐鄉櫂近，不道使車遙。", "舊俗吳三讓，遺風漢六條。", "願言除疾苦，天子聽歌謠。"]'),
('0e108e6e-25e0-4682-b0c6-c985af3c67f4','送王判官','徐安貞','唐','唐诗','tang','','[]','明月開三峽，花源出五谿。',48,'全唐诗/poet.tang.5000.json','["明月開三峽，花源出五谿。", "城池青壁裏，煙火綠林西。", "不畏王程促，惟愁仙路迷。", "巴東下歸櫂，莫待夜猨啼。"]'),
('4e35fd03-8317-42aa-8fde-a4f8171411a5','題襄陽圖','徐安貞','唐','唐诗','tang','','[]','畫得襄陽郡，依然見昔遊。',48,'全唐诗/poet.tang.5000.json','["畫得襄陽郡，依然見昔遊。", "峴山思駐馬，漢水憶迴舟。", "丹壑常含霽，青林不換秋。", "圖書空咫尺，千里意悠悠。"]'),
('ff975ce0-5934-4829-b0f2-2137e35c372e','程將軍夫人挽詩','徐安貞','唐','唐诗','tang','','[]','琴瑟調雙鳳，和鳴不獨飛。',48,'全唐诗/poet.tang.5000.json','["琴瑟調雙鳳，和鳴不獨飛。", "正歌春可樂，行泣露先晞。", "環珮聲猶在，房櫳夢不歸。", "將軍休沐日，誰勸著新衣。"]'),
('46a4f158-95b7-46f9-90f9-78bc571ae001','奉和喜雪應制','徐安貞','唐','唐诗','tang','','[]','兩宮齋祭近登臨，雨雪紛紛天晝陰。',64,'全唐诗/poet.tang.5000.json','["兩宮齋祭近登臨，雨雪紛紛天晝陰。", "祗爲經寒無瑞色，頓教正月滿春林。", "蓬萊北上旌門暗，花萼南歸馬跡深。", "自有三農歌帝力，還將萬庾荅堯心。"]'),
('0f5c513a-ea5a-41f3-b2d2-972e2252bee5','聞鄰家理箏','徐安貞','唐','唐诗','tang','','[]','北斗橫天夜欲闌，愁人倚月思無端。',64,'全唐诗/poet.tang.5000.json','["北斗橫天夜欲闌，愁人倚月思無端。", "忽聞畫閣秦箏逸，知是鄰家趙女彈。", "曲成虛憶青蛾斂，調急遙憐玉指寒。", "銀鎖重關聽未闢，不如眠去夢中看。"]'),
('41868e28-4951-42ea-81a9-ad68ceec1b88','奉和聖製早度蒲津關','徐安貞','唐','唐诗','tang','','[]','仙掌臨秦甸，虹橋闢晉關。',72,'全唐诗/poet.tang.5000.json','["仙掌臨秦甸，虹橋闢晉關。", "兩都分地險，一曲度河灣。", "路得津門要，時稱古戍閑。", "城花春正發，岸柳曙堪攀。", "後乘猶臨水，前旌欲換山。", "長安迴望日，宸御六龍還。"]'),
('46e9e27f-0f28-4152-8c32-05d172246cfa','奉和聖製荅二相出雀鼠谷','徐安貞','唐','唐诗','tang','','[]','兩臣初入夢，二月扈巡邊。',72,'全唐诗/poet.tang.5000.json','["兩臣初入夢，二月扈巡邊。", "澗北寒猶在，山南春半傳。", "頌聲先奉御，辰象復回天。", "雲日明千里，旌旗照一川。", "柳陰低輦路，草色變新田。", "還望汾陽近，宸遊自窅然。"]'),
('250a51c8-4f9f-4591-8a80-2f9936a6df35','句','徐安貞','唐','唐诗','tang','','[]','暮雨衣猶濕，春風帆正開。',12,'全唐诗/poet.tang.5000.json','["暮雨衣猶濕，春風帆正開。"]'),
('d0e731e2-f5c3-412d-8aef-36ca8f5bf159','奉和聖製荅張說南出雀鼠谷','崔翹','唐','唐诗','tang','','[]','硤路繞河汾，晴光拂曙氛。',72,'全唐诗/poet.tang.5000.json','["硤路繞河汾，晴光拂曙氛。", "笳吟中嶺樹，仗入半峰雲。", "頓覺山原盡，平看邑里分。", "早行芳草迥，晚憩好風熏。", "嘉頌推英宰，春遊扈聖君。", "共欣承睿渥，日月照天文。"]'),
('72c5f082-92d4-4edf-9578-6b0d9188f80c','送友人使夷陵','崔翹','唐','唐诗','tang','','[]','猨鳴三峽裏，行客舊霑裳。',48,'全唐诗/poet.tang.5000.json','["猨鳴三峽裏，行客舊霑裳。", "復道從茲去，思君不暫忘。", "開襟春葉短，分手夏條長。", "獨有幽庭桂，年年空自芳。"]'),
('1b226af8-5d4f-42ba-8295-ed5c9c7617cc','鄭郎中山亭','崔翹','唐','唐诗','tang','','[]','篆筆飛章暇，園亭染翰游。',72,'全唐诗/poet.tang.5000.json','["篆筆飛章暇，園亭染翰游。", "地奇人境別，事遠俗塵收。", "書閣山雲起，琴齋澗月留。", "泉清鱗影見，樹密鳥聲幽。", "杜馥熏梅雨，荷香送麥秋。", "無勞置驛騎，文酒可相求。"]'),
('99c735da-a0c6-4e4a-95e9-df063087ef5b','奉和聖製荅張說扈從南出雀鼠谷','梁昇卿','唐','唐诗','tang','','[]','何意重關道，千年過聖皇。',72,'全唐诗/poet.tang.5000.json','["何意重關道，千年過聖皇。", "幽林承睿澤，閑客見清光。", "日御仙途遠，山靈壽域長。", "寒雲入晉薄，春樹隔汾香。", "國佐同時雨，天文屬歲陽。", "從來漢家盛，未若此巡方。"]'),
('f2e748c2-1c0f-4325-81dd-46e71e875e3f','白雲溪','吳鞏','唐','唐诗','tang','','[]','山徑入修篁，深林蔽日光。',48,'全唐诗/poet.tang.5000.json','["山徑入修篁，深林蔽日光。", "夏雲生嶂遠，瀑水引溪長。", "秀跡逢皆勝，清芬坐轉涼。", "回看玉樽夕，歸路賞前忘。"]'),
('bacafdae-4b3f-4a78-8061-931d80385e3a','題奉國寺','陸海','唐','唐诗','tang','','[]','新秋夜何爽，露下風轉淒。',24,'全唐诗/poet.tang.5000.json','["新秋夜何爽，露下風轉淒。", "一磐竹林外，千燈花塔西。"]'),
('6971df43-734e-4388-a8d5-1b495931f02e','題龍門寺','陸海','唐','唐诗','tang','','[]','窗燈林靄裏，聞磬水聲中。',24,'全唐诗/poet.tang.5000.json','["窗燈林靄裏，聞磬水聲中。", "更與龍華會，爐煙滿夕風。"]'),
('5aa758a5-a3f4-41e5-b96c-3849ad719b0e','句','陸海','唐','唐诗','tang','','[]','忽然一曲稱君心，破却中人百家產。',32,'全唐诗/poet.tang.5000.json','["忽然一曲稱君心，破却中人百家產。", "城外平人驅欲盡，帳中猶打衮花毬。"]'),
('5ba0b4c0-83ef-4b26-a295-dbd2d216573c','白牡丹','裴士淹','唐','唐诗','tang','','["\u548f\u7269", "\u548f\u7269\u8bd7", "\u7261\u4e39", "\u82b1", "\u8d5e\u7f8e", "\u5199\u82b1"]','長安年少惜春殘，爭認慈恩紫牡丹。',32,'全唐诗/poet.tang.5000.json','["長安年少惜春殘，爭認慈恩紫牡丹。", "別有玉盤乘露冷，無人起就月中看。"]'),
('354845c3-7b94-4e64-a220-7b15e747f294','和從叔祿愔元日早朝','李元操','唐','唐诗','tang','','[]','銅渾變秋節，玉律動年灰。',96,'全唐诗/poet.tang.5000.json','["銅渾變秋節，玉律動年灰。", "曖曖城霞旦，隱隱禁門開。", "衆靈湊仙府，百神朝帝臺。", "葉令雙鳧至，梁王駟馬來。", "戈鋋映林闕，歌管拂塵埃。", "保章望瑞氣，尚書免火災。", "冠冕多秀士，簪裾饒上才。", "誰憐張仲蔚，日暮反蒿萊。"]'),
('732e42d4-1fdf-4485-8c32-4cede895edc9','昭君怨','顧朝陽','唐','唐诗','tang','','[]','莫將鉛粉匣，不用鏡花光。',48,'全唐诗/poet.tang.5000.json','["莫將鉛粉匣，不用鏡花光。", "一去邊城路，何情更畫妝。", "影銷胡地月，衣盡漢宮香。", "妾死非關命，都緣怨斷腸。"]'),
('6b14551d-2650-480a-8bfd-4e38ec1c4f9e','西塞山下迴舟作','陶峴','唐','唐诗','tang','','["\u5e90\u5c71"]','匡廬舊業是誰主，吳越新居安此生。',64,'全唐诗/poet.tang.5000.json','["匡廬舊業是誰主，吳越新居安此生。", "白髮數莖歸未得，青山一望計還成。", "鴉翻楓葉夕陽動，鷺立蘆花秋水明。", "從此舍舟何所詣，酒旗歌扇正相迎。"]'),
('72fb2b39-9959-4985-8037-f4344492b1af','酬諸公見過','王維','唐','唐诗','tang','','[]','嗟予未喪，哀此孤生。',152,'全唐诗/poet.tang.5000.json','["嗟予未喪，哀此孤生。", "屏居藍田，薄地躬耕。", "歲[晏]輸稅，以奉粢盛。", "晨往東臯，草露未晞。", "暮看煙火，負擔來歸。", "我聞有客，足埽荆扉。", "簞食伊何，疈瓜抓棗。", "仰廁羣賢，皤然一老。", "媿無莞簟，班荆席藁。", "汎汎登陂，折彼荷花。", "靜觀素鮪，俯映白沙。", "山鳥羣飛，日隱輕霞。", "登車上馬，倏忽雲散。", "雀噪荒村，雞鳴空館。", "還復幽獨，重欷累歎。"]'),
('3e3f2512-69a6-42ae-ae02-da0f69b91237','奉和聖製登降聖觀與宰臣等同望應制','王維','唐','唐诗','tang','','[]','鳳扆朝碧落，龍圖耀金鏡。',96,'全唐诗/poet.tang.5000.json','["鳳扆朝碧落，龍圖耀金鏡。", "維嶽降二臣，戴天臨萬姓。", "山川八校滿，井邑三農竟。", "比屋皆可封，誰家不相慶。", "林疎遠村出，野曠寒山靜。", "帝城雲裏深，渭水天邊映。", "佳氣含風景，頌聲溢歌詠。", "端拱能任賢，彌彰聖君聖。"]'),
('cf09db89-6a90-49b1-8f84-6cb59100e579','奉和聖製御春明樓臨右相園亭賦樂賢詩應制','王維','唐','唐诗','tang','','[]','複道通長樂，青門臨上路。',96,'全唐诗/poet.tang.5000.json','["複道通長樂，青門臨上路。", "遙聞鳳吹喧，闇識龍輿度。", "褰旒明四目，伏檻紆三顧。", "小苑接侯家，飛甍暎宮樹。", "商山原上碧，滻水林端素。", "銀漢下天章，瓊筵承湛露。", "將非富人寵，信以平戎故。", "從來簡帝心，詎得迴天步。"]'),
('ba2e464c-6b0f-43f7-8b54-7669e226d8a0','奉和聖製送不蒙都護兼鴻臚卿歸安西應制','王維','唐','唐诗','tang','','[]','上卿增命服，都護揚歸斾。',72,'全唐诗/poet.tang.5000.json','["上卿增命服，都護揚歸斾。", "雜虜盡朝周，諸胡皆自鄶。", "鳴笳瀚海曲，按節陽關外。", "落日下河源，寒山靜秋塞。", "萬方氛祲息，六合乾坤大。", "無戰是天心，天心同覆載。"]'),
('fd3944f6-676d-4c8b-90ca-d694a69f30d9','扶南曲歌詞五首 一','王維','唐','唐诗','tang','','[]','翠羽流蘇帳，春眠曙不開。',36,'全唐诗/poet.tang.5000.json','["翠羽流蘇帳，春眠曙不開。", "羞從面色起，嬌逐語聲來。", "早向昭陽殿，君王中使催。"]'),
('200e8a61-6549-499e-99f4-3cb6a8172a6d','扶南曲歌詞五首 二','王維','唐','唐诗','tang','','[]','堂上青弦動，堂前綺席陳。',36,'全唐诗/poet.tang.5000.json','["堂上青弦動，堂前綺席陳。", "齊歌盧女曲，雙舞洛陽人。", "傾國徒相看，寧知心所親。"]'),
('628b0aeb-ace3-4f3b-b9af-419d426f3e3f','扶南曲歌詞五首 三','王維','唐','唐诗','tang','','[]','香氣傳空滿，妝華影箔通。',36,'全唐诗/poet.tang.5000.json','["香氣傳空滿，妝華影箔通。", "歌聞天仗外，舞出御樓中。", "日暮歸何處，花間長樂宮。"]'),
('236f6ed6-1bb0-4a8d-8e5b-23a124479863','扶南曲歌詞五首 四','王維','唐','唐诗','tang','','[]','宮女還金屋，將眠復畏明。',36,'全唐诗/poet.tang.5000.json','["宮女還金屋，將眠復畏明。", "入春輕衣好，半夜薄妝成。", "拂曙朝前殿，玉墀多珮聲。"]'),
('f085c143-e0b5-4598-a619-9b287fa463ae','扶南曲歌詞五首 五','王維','唐','唐诗','tang','','[]','朝日照綺窗，佳人坐臨鏡。',36,'全唐诗/poet.tang.5000.json','["朝日照綺窗，佳人坐臨鏡。", "散黛恨猶輕，插釵嫌未正。", "同心勿遽遊，幸待春妝竟。"]'),
('5a2d6357-424d-4ad8-a41e-73e2a4c8f570','隴西行','王維','唐','唐诗','tang','','["\u6218\u4e89", "\u8fb9\u585e"]','十里一走馬，五里一揚鞭。',36,'全唐诗/poet.tang.5000.json','["十里一走馬，五里一揚鞭。", "都護軍書至，匈奴圍酒泉。", "關山正飛雪，烽戍斷無煙。"]'),
('dbf3f482-6a67-41a8-85c5-4bb74ff9e446','從軍行','王維','唐','唐诗','tang','','["\u6218\u4e89", "\u8c6a\u8fc8", "\u8fb9\u585e"]','吹角動行人，喧喧行人起。',48,'全唐诗/poet.tang.5000.json','["吹角動行人，喧喧行人起。", "笳悲馬嘶亂，爭渡金河水。", "日暮沙漠陲，戰聲煙塵裏。", "盡繫名王頸，歸來獻天子。"]'),
('140031f2-d4e0-4555-b23b-92b10980f1ba','早春行','王維','唐','唐诗','tang','','["\u76f8\u601d", "\u54c0\u6028", "\u5199\u4eba", "\u95fa\u6028"]','紫梅發初遍，黃鳥歌猶澁。',96,'全唐诗/poet.tang.5000.json','["紫梅發初遍，黃鳥歌猶澁。", "誰家折楊女，弄春如不及。", "愛水看妝坐，羞人映花立。", "香畏風吹散，衣愁露霑濕。", "玉閨青門裏，日落香車入。", "游衍益相思，含啼向綵帷。", "憶君長入夢，歸晚更生疑。", "不及紅簷燕，雙棲綠草時。"]'),
('99c56ac4-c95e-4923-b0b8-b3809e62e1cf','早朝','王維','唐','唐诗','tang','','[]','皎潔明星高，蒼茫遠天曙。',48,'全唐诗/poet.tang.5000.json','["皎潔明星高，蒼茫遠天曙。", "槐霧暗不開，城鴉鳴稍去。", "始聞高閣聲，莫辨更衣處。", "銀燭已成行，金門儼騶馭。"]'),
('49f16d59-ce56-4ed7-b3b3-82571018a52a','獻始興公','王維','唐','唐诗','tang','','[]','寧棲野樹林，寧飲澗水流。',98,'全唐诗/poet.tang.5000.json','["寧棲野樹林，寧飲澗水流。", "不用坐[粱]肉，崎嶇見王侯。", "鄙哉匹夫節，布褐將白頭。", "任智誠則短，守任固其優。", "側聞大君子，安問黨與讐。", "所不賣公器，動爲蒼生謀。", "賤子跪自陳，可爲帳下不。", "感激有公議，曲私非所求。"]'),
('f24c33e3-89ea-4226-a9cf-b4a96e799784','贈從弟司庫員外絿','王維','唐','唐诗','tang','','[]','少年識事淺，強學干名利。',96,'全唐诗/poet.tang.5000.json','["少年識事淺，強學干名利。", "徒聞躍馬年，苦無出人智。", "即事豈徒言，累官非不試。", "既寡遂性歡，恐招負時累。", "清冬見遠山，積雪凝蒼翠。", "浩然出東林，發我遺世意。", "惠連素清賞，夙語塵外事。", "欲緩攜手期，流年一何駛。"]'),
('936413e8-e197-4c55-afdc-35cfd1766e28','座上走筆贈薛璩慕容損','王維','唐','唐诗','tang','','[]','希世無高節，絕跡有卑棲。',84,'全唐诗/poet.tang.5000.json','["希世無高節，絕跡有卑棲。", "君徒視人文，吾固和天倪。", "緬然萬物始，及與羣物齊。", "分地依后稷，用天信重黎。", "春風何豫人，令我思東溪。", "草色有佳意，花枝稍含荑。", "更待風景好，與君藉萋萋。"]'),
('2a1cc786-251a-45ef-8db5-57daaf8168c4','贈李頎','王維','唐','唐诗','tang','','[]','聞君餌丹砂，甚有好顏色。',60,'全唐诗/poet.tang.5000.json','["聞君餌丹砂，甚有好顏色。", "不知從今去，幾時生羽翼。", "王母翳華芝，望爾崑崙側。", "文螭從赤豹，萬里方一息。", "悲哉世上人，甘此羶腥食。"]'),
('bcfe7a85-54be-4bed-8184-2500df7f4f5f','贈劉藍田','王維','唐','唐诗','tang','','[]','籬間犬迎吠，出屋候荆扉。',48,'全唐诗/poet.tang.5000.json','["籬間犬迎吠，出屋候荆扉。", "歲晏輸井稅，山村人夜歸。", "晚田始家食，餘布成我衣。", "詎肯無公事，煩君問是非。"]'),
('c56ad009-5acd-4331-adc9-f529fdbb72bb','贈房盧氏琯','王維','唐','唐诗','tang','','[]','達人無不可，忘己愛蒼生。',120,'全唐诗/poet.tang.5000.json','["達人無不可，忘己愛蒼生。", "豈復少十室，弦歌在兩楹。", "浮人日已歸，但坐事農耕。", "桑榆鬱相望，邑里多雞鳴。", "秋山一何淨，蒼翠臨寒城。", "視事兼偃臥，對書不簪纓。", "蕭條人吏疎，鳥雀下空庭。", "鄙夫心所尚，晚節異平生。", "將從海岳居，守靜解天刑。", "或可累安邑，茅茨君試營。"]'),
('480b41ca-28dd-45c9-b5be-7c8720008f47','贈祖三詠','王維','唐','唐诗','tang','','[]','蟏蛸挂虛牖，蟋蟀鳴前除。',120,'全唐诗/poet.tang.5000.json','["蟏蛸挂虛牖，蟋蟀鳴前除。", "歲晏涼風至，君子復何如。", "高館闃無人，離居不可道。", "閑門寂已閉，落日照秋草。", "雖有近音信，千里阻河關。", "中復客汝潁，去年歸舊山。", "結交二十載，不得一日展。", "貧病子既深，契闊余不淺。", "仲秋雖未歸，暮秋以爲期。", "良會詎幾日，終日長相思。"]'),
('35fb081d-d481-41c6-8ef3-8eb84fae4134','春夜竹亭贈錢少府歸藍田','王維','唐','唐诗','tang','','["\u7530\u56ed\u8bd7", "\u5199\u666f", "\u7530\u56ed", "\u9690\u5c45"]','夜靜羣動息，時聞隔林犬。',36,'全唐诗/poet.tang.5000.json','["夜靜羣動息，時聞隔林犬。", "却憶山中時，人家澗西遠。", "羨君明發去，采蕨輕軒冕。"]'),
('076b8da6-83c1-41dc-8893-13425a6dc1e8','戲贈張五弟諲三首 一','王維','唐','唐诗','tang','','[]','吾弟東山時，心尚一何遠。',108,'全唐诗/poet.tang.5000.json','["吾弟東山時，心尚一何遠。", "日高猶自臥，鐘動始能飯。", "領上髪未梳，牀頭書不卷。", "清川興悠悠，空林對偃蹇。", "青苔石上淨，細草松下軟。", "窗外鳥聲閑，階前虎心善。", "徒然萬象多，澹爾太虛緬。", "一知與物平，自顧爲人淺。", "對君忽自得，浮念不煩遣。"]'),
('91b6c0f1-eabf-4fe6-9975-ed5a592f7b4f','戲贈張五弟諲三首 二','王維','唐','唐诗','tang','','[]','張弟五車書，讀書仍隱居。',84,'全唐诗/poet.tang.5000.json','["張弟五車書，讀書仍隱居。", "染翰過草聖，賦詩輕子虛。", "閉門二室下，隱居十年餘。", "宛是野人野，時從漁夫漁。", "秋風自蕭索，五柳高且疎。", "望此去人世，渡水向吾廬。", "歲晏同攜手，只應君與予。"]'),
('7fa97957-588a-4bdc-841b-05ddfcdc0d96','戲贈張五弟諲三首 三','王維','唐','唐诗','tang','','[]','設罝守毚兔，垂釣伺遊鱗。',96,'全唐诗/poet.tang.5000.json','["設罝守毚兔，垂釣伺遊鱗。", "此是安口腹，非關慕隱淪。", "吾生好清淨，蔬食去情塵。", "今子方豪蕩，思爲鼎食人。", "我家南山下，動息自遺身。", "入鳥不相亂，見獸皆相親。", "雲霞成伴侶，虛白侍衣巾。", "何事須夫子，邀予谷口真。"]'),
('521c50b8-4eac-4ee4-85a6-f06ac42ed74c','胡居士臥病遺米因贈','王維','唐','唐诗','tang','','[]','了觀四大因，根性何所有。',144,'全唐诗/poet.tang.5000.json','["了觀四大因，根性何所有。", "妄計苟不生，是身孰休咎。", "色聲何謂客，陰界復誰守。", "徒言蓮花目，豈惡楊枝肘。", "既飽香積飯，不醉聲聞酒。", "有無斷常見，生滅幻夢受。", "即病即實相，趨空定狂走。", "無有一法真，無有一法垢。", "居士素通達，隨宜善抖擻。", "牀上無氊臥，鎘中有粥否。", "齋時不乞食，定應空漱口。", "聊持數斗米，且救浮生取。"]'),
('f6f432a3-b716-4b40-965a-83eb0ce83c44','贈裴十迪','王維','唐','唐诗','tang','','[]','風景日夕佳，與君賦新詩。',84,'全唐诗/poet.tang.5000.json','["風景日夕佳，與君賦新詩。", "澹然望遠空，如意方支頤。", "春風動百草，蘭蕙生我籬。", "曖曖日暖閨，田家來致詞。", "欣欣春還臯，淡淡水生陂。", "桃李雖未開，荑萼滿芳枝。", "請君理還策，敢告將農時。"]'),
('0bebdd6d-6adb-42aa-9bc3-d3cf41c45687','與胡居士皆病寄此詩兼示學人二首 一','王維','唐','唐诗','tang','','[]','一興微塵念，橫有朝露身。',120,'全唐诗/poet.tang.5000.json','["一興微塵念，橫有朝露身。", "如是覩陰界，何方置我人。", "礙有固爲主，趣空寧捨賓。", "洗心詎懸解，悟道正迷津。", "因愛果生病，從貪始覺貧。", "色聲非彼妄，浮幻即吾真。", "四達竟何遣，萬殊安可塵。", "胡生但高枕，寂寞與誰鄰。", "戰勝不謀食，理齊甘負薪。", "予若未始異，詎論疎與親。"]'),
('e475dcae-9e34-4c68-b7b8-3c700418def0','與胡居士皆病寄此詩兼示學人二首 二','王維','唐','唐诗','tang','','[]','浮空徒漫漫，汎有定悠悠。',120,'全唐诗/poet.tang.5000.json','["浮空徒漫漫，汎有定悠悠。", "無乘及乘者，所謂智人舟。", "詎捨貧病域，不疲生死流。", "無煩君喻馬，任以我爲牛。", "植福祠迦葉，求仁笑孔丘。", "何津不鼓櫂，何路不摧輈。", "念此聞思者，胡爲多阻修。", "空虛花聚散，煩惱樹稀稠。", "滅相成無記，生心坐有求。", "降吳復歸蜀，不到莫相尤。"]'),
('2307887c-ece7-4f85-a263-b77871daa4d2','奉寄韋太守陟','王維','唐','唐诗','tang','','["\u601d\u5ff5", "\u6292\u60c5", "\u8d60\u53cb", "\u8fb9\u585e", "\u53cb\u4eba"]','荒城自蕭索，萬里山河空。',62,'全唐诗/poet.tang.5000.json','["荒城自蕭索，萬里山河空。", "天高秋日逈，嘹唳聞歸鴻。", "寒塘映衰草，高館落疎桐。", "臨此歲方[晏]，顧景詠悲翁。", "故人不可見，寂寞平陵東。"]'),
('edda303d-6668-407b-b213-8dbb0fffd9aa','林園即事寄舍弟紞','王維','唐','唐诗','tang','','[]','寓目一蕭散，銷憂冀俄頃。',108,'全唐诗/poet.tang.5000.json','["寓目一蕭散，銷憂冀俄頃。", "青草肅澄陂，白雲移翠嶺。", "後沔通河渭，前山包鄢郢。", "松含風裏聲，花對池中影。", "地多齊后㿉，人帶荆州癭。", "徒思赤筆書，詎有丹砂井。", "心悲常欲絕，髪亂不能整。", "青簟日何長，閑門晝方靜。", "頹思茅簷下，彌傷好風景。"]'),
('37c9123a-0681-4438-b663-ec71683726cf','至滑州隔河望黎陽憶丁三宇','王維','唐','唐诗','tang','','[]','隔河見桑柘，藹藹黎陽川。',48,'全唐诗/poet.tang.5000.json','["隔河見桑柘，藹藹黎陽川。", "望望行漸遠，孤峰沒雲煙。", "故人不可見，河水復悠然。", "賴有政聲遠，時聞行路傳。"]'),
('7dcc281d-d43e-499a-8927-8e044ea854b0','秋夜獨坐懷內弟崔興宗','王維','唐','唐诗','tang','','[]','夜靜羣動息，蟪蛄聲悠悠。',60,'全唐诗/poet.tang.5000.json','["夜靜羣動息，蟪蛄聲悠悠。", "庭槐北風響，日夕方高秋。", "思子整羽翰，及時當雲浮。", "吾生將白首，歲晏思滄州。", "高足在旦暮，肯爲南畝儔。"]'),
('1de387b1-582c-4f78-9aa1-d0e343d3ed4c','和使君五郎西樓望遠思歸','王維','唐','唐诗','tang','','[]','高樓望所思，目極情未畢。',72,'全唐诗/poet.tang.5000.json','["高樓望所思，目極情未畢。", "枕上見千里，窗中窺萬室。", "悠悠長路人，曖曖遠郊日。", "惆悵極浦外，迢遞孤煙出。", "能賦屬上才，思歸同下秩。", "故鄉不可見，雲水空如一。"]'),
('9250ba9d-bd94-4a04-b1c1-512158537ff3','酬黎居士淅川作','王維','唐','唐诗','tang','','[]','儂家真箇去，公定隨儂否。',48,'全唐诗/poet.tang.5000.json','["儂家真箇去，公定隨儂否。", "著處是蓮花，無心變楊柳。", "松龕藏藥裹，石脣安茶臼。", "氣味當共知，那能不攜手。"]'),
('53ad408a-348f-4d20-9036-d4bb67ead296','送魏郡李太守赴任','王維','唐','唐诗','tang','','["\u9ec4\u6cb3", "\u9001\u522b"]','與君伯氏別，又欲與君離。',120,'全唐诗/poet.tang.5000.json','["與君伯氏別，又欲與君離。", "君行無幾日，當復隔山陂。", "蒼茫秦川盡，日落桃林塞。", "獨樹臨關門，黃河向天外。", "前經洛陽陌，宛洛故人稀。", "故人離別盡，淇上轉驂騑。", "企予悲送遠，惆悵睢陽路。", "古木官渡平，秋城鄴宮故。", "想君行縣日，其出從如雲。", "遙思魏公子，復憶李將軍。"]'),
('7762fa57-7362-4dc5-ac5f-dbae7b4db5aa','送陸員外','王維','唐','唐诗','tang','','[]','郎署有伊人，居然古人風。',108,'全唐诗/poet.tang.5000.json','["郎署有伊人，居然古人風。", "天子顧河北，詔書除征東。", "拜手辭上官，緩步出南宮。", "九河平原外，七國薊門中。", "陰風悲枯桑，古塞多飛蓬。", "萬里不見虜，蕭條胡地空。", "無爲費中國，更欲邀奇功。", "遲遲前相送，握手嗟異同。", "行當對侯歸，肯訪商山翁。"]'),
('e22d5990-3037-4325-bb6a-a2146d3e8a8e','送宇文太守赴宣城','王維','唐','唐诗','tang','','["\u79bb\u522b"]','寥落雲外山，迢遞舟中賞。',60,'全唐诗/poet.tang.5000.json','["寥落雲外山，迢遞舟中賞。", "鐃吹發西江，秋空多清響。", "地迥古城蕪，月明寒潮廣。", "時賽敬亭神，復解罟師網。", "何處寄相思？南風吹五兩。"]'),
('a4371ef7-c1bd-4b60-af88-48b670052b84','送綦毋秘書棄官還江東','王維','唐','唐诗','tang','','[]','明時久不達，棄置與君同。',120,'全唐诗/poet.tang.5000.json','["明時久不達，棄置與君同。", "天命無怨色，人生有素風。", "念君拂衣去，四海將安窮。", "秋天萬里淨，日暮澄江空。", "清夜何悠悠，扣舷明月中。", "和光魚鳥際，澹爾蒹葭叢。", "無庸客昭世，衰鬢日如蓬。", "頑疎暗人事，僻陋遠天聰。", "微物縱可采，其誰爲至公。", "余亦從此去，歸耕爲老農。"]'),
('311012d6-2c74-4277-b53f-b8ef1cc54b9a','奉送六舅歸陸渾','王維','唐','唐诗','tang','','[]','伯舅吏淮泗，卓魯方喟然。',48,'全唐诗/poet.tang.5000.json','["伯舅吏淮泗，卓魯方喟然。", "悠哉自不競，退耕東臯田。", "條桑臘月下，種杏春風前。", "酌醴賦歸去，共知陶令賢。"]'),
('31cc87f3-da0f-421d-8674-8753530077e2','送別','王維','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u6292\u60c5", "\u5199\u666f", "\u53cb\u60c5", "\u9001\u522b"]','下馬飲君酒，問君何所之。',36,'全唐诗/poet.tang.5000.json','["下馬飲君酒，問君何所之。", "君言不得意，歸臥南山陲。", "但去莫復問，白雲無盡時。"]'),
('4b76b81d-f768-4aa8-b566-40d82160ce75','送張五歸山','王維','唐','唐诗','tang','','[]','送君盡惆悵，復送何人歸。',48,'全唐诗/poet.tang.5000.json','["送君盡惆悵，復送何人歸。", "幾日同攜手，一朝先拂衣。", "東山有茅屋，幸爲埽荆扉。", "當亦謝官去，豈令心事違。"]'),
('3ae49034-21b0-4273-98d3-fa7abf5a407d','齊州送祖三','王維','唐','唐诗','tang','','["\u9001\u522b", "\u611f\u4f24"]','相逢方一笑，相送還成泣。',48,'全唐诗/poet.tang.5000.json','["相逢方一笑，相送還成泣。", "祖帳已傷離，荒城復愁入。", "天寒遠山淨，日暮長河急。", "解纜君已遙，望君猶佇立。"]'),
('80997560-77bc-4730-b79d-2327a02f088a','送縉雲苗太守','王維','唐','唐诗','tang','','[]','手疏謝明主，腰章爲長吏。',48,'全唐诗/poet.tang.5000.json','["手疏謝明主，腰章爲長吏。", "方從會稽邸，更發汝南騎。", "按節下松陽，清江響鐃吹。", "露冕見三吳，方知百城貴。"]'),
('0b9a9e77-c255-4534-b29a-163153978ceb','送從弟蕃遊淮南','王維','唐','唐诗','tang','','[]','讀書復騎射，帶劒遊淮陰。',132,'全唐诗/poet.tang.5000.json','["讀書復騎射，帶劒遊淮陰。", "淮陰少年輩，千里遠相尋。", "高義難自隱，明時寧陸沈。", "島夷九州外，泉館三山深。", "席帆聊問罪，卉服盡成擒。", "歸來見天子，拜爵賜黃金。", "忽思鱸魚鱠，復有滄洲心。", "天寒蒹葭渚，日落雲夢林。", "江城下楓葉，淮上聞秋砧。", "送歸青門外，車馬去駸駸。", "惆悵新豐樹，空餘天際禽。"]'),
('e791098d-353d-4ae7-abb4-f632f596eacf','送高適弟耽歸臨淮作','王維','唐','唐诗','tang','','[]','少年客淮泗，落魄居下邳。',216,'全唐诗/poet.tang.5000.json','["少年客淮泗，落魄居下邳。", "遨遊向燕趙，結客過臨淄。", "山東諸侯國，迎送紛交馳。", "自爾厭游俠，閉戶方垂帷。", "深明戴家禮，頗學毛公詩。", "備知輕濟道，高臥陶唐時。", "聖主詔天下，賢人不得遺。", "公吏奉纁組，安車去茅茨。", "君王蒼龍闕，九門十二逵。", "羣公朝謁罷，冠劒下丹墀。", "野鶴終踉蹌，威鳳徒參差。", "或問理人術，但致還山詞。", "天書降北闕，賜帛歸東菑。", "都門謝親故，行路日逶遲。", "孤帆萬里外，淼漫將何之。", "江天海陵郡，雲日淮南祠。", "杳冥滄洲上，蕩漭無人知。", "緯蕭或賣藥，出處安能期。"]'),
('56bec3c2-9c0c-4d40-9750-2e28bdc9a20e','送綦毋潛落第還鄉','王維','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u9001\u522b", "\u4e94\u8a00\u53e4\u8bd7", "\u6170\u52c9", "\u53cb\u60c5"]','聖代無隱者，英靈盡來歸。',96,'全唐诗/poet.tang.5000.json','["聖代無隱者，英靈盡來歸。", "遂令東山客，不得顧采薇。", "既至君門遠，孰云吾道非。", "江淮度寒食，京洛縫春衣。", "置酒臨長道，同心與我違。", "行當浮桂櫂，未幾拂荆扉。", "遠樹帶行客，孤村當落暉。", "吾謀適不用，勿謂知音稀。"]'),
('4b2d6332-f295-45b4-9b7b-fefbea9fa4fa','送張舍人佐江州同薛璩十韻','王維','唐','唐诗','tang','','["\u5e90\u5c71"]','束帶趨承明，守官唯謁者。',120,'全唐诗/poet.tang.5000.json','["束帶趨承明，守官唯謁者。", "清晨聽銀蚪，薄暮辭金馬。", "受辭未嘗易，當是方知寡。", "清範何風流，高文有風雅。", "忽佐江上州，當自潯陽下。", "逆旅到三湘，長途應百舍。", "香爐遠峰出，石鏡澄湖瀉。", "董奉杏成林，陶潛菊盈把。", "范蠡常好之，廬山我心也。", "送君思遠道，欲以數行灑。"]'),
('331baa90-f69e-48ae-bd7b-42a18a038673','送韋大夫東京留守','王維','唐','唐诗','tang','','[]','人外遺世慮，空端結遐心。',192,'全唐诗/poet.tang.5000.json','["人外遺世慮，空端結遐心。", "曾是巢許淺，始知堯舜深。", "蒼生詎有物，黃屋如喬林。", "上德撫神運，沖和穆宸襟。", "雲雷康屯難，江海遂飛沈。", "天工寄人英，龍衮瞻君臨。", "名器苟不假，保釐固其任。", "素質貫方領，清景照華簪。", "慷慨念王室，從容獻官箴。", "雲旗蔽三川，畫角發龍吟。", "晨揚天漢聲，夕卷大河陰。", "窮人業已寧，逆虜遺之擒。", "然後解金組，拂衣東山岑。", "給事黃門省，秋光正沈沈。", "壯心與身退，老病隨年侵。", "君子從相訪，重玄其可尋。"]'),
('035eeb3b-429d-4d3c-a8e4-ab063632cfa3','資聖寺送甘二','王維','唐','唐诗','tang','','[]','浮生信如寄，薄宦夫何有。',48,'全唐诗/poet.tang.5000.json','["浮生信如寄，薄宦夫何有。", "來往本無歸，別離方此受。", "柳色藹春餘，槐陰清夏首。", "不覺御溝上，銜悲執桮酒。"]'),
('ce428916-fd85-430d-a8dc-1a5d10719a6c','留別山中溫古上人兄幷示舍弟縉','王維','唐','唐诗','tang','','[]','解薜登天朝，去師偶時哲。',96,'全唐诗/poet.tang.5000.json','["解薜登天朝，去師偶時哲。", "豈惟山中人，兼負松上月。", "宿昔同遊止，致身雲霞末。", "開軒臨潁陽，臥視飛鳥沒。", "好依盤石飯，屢對瀑泉渴。", "理齊小狎隱，道勝寧外物。", "舍弟官崇高，宗兄此削髪。", "荆扉但灑掃，乘閑當過歇。"]'),
('82838e54-b4dc-4663-91e8-60e0d4f0e9a2','觀別者','王維','唐','唐诗','tang','','["\u79bb\u522b", "\u65e0\u5948", "\u6f02\u6cca"]','青青楊柳陌，陌上別離人。',96,'全唐诗/poet.tang.5000.json','["青青楊柳陌，陌上別離人。", "愛子遊燕趙，高堂有老親。", "不行無可養，行去百憂新。", "切切委兄弟，依依向四鄰。", "都門帳飲畢，從此謝親賓。", "揮涕逐前侶，含悽動征輪。", "車徒望不見，時見起行塵。", "吾亦辭家久，看之淚滿巾。"]'),
('ae1402ee-2613-4d6b-9549-ab7ce6d368f6','別弟縉後登青龍寺望藍田山','王維','唐','唐诗','tang','','[]','陌上新離別，蒼茫四郊晦。',48,'全唐诗/poet.tang.5000.json','["陌上新離別，蒼茫四郊晦。", "登高不見君，故山復雲外。", "遠樹蔽行人，長天隱秋塞。", "心悲宦遊子，何處飛征蓋。"]'),
('9efa6600-aad3-4924-bf55-b9919dfaba62','別綦毋潛','王維','唐','唐诗','tang','','[]','端笏明光宮，歷稔朝雲陛。',96,'全唐诗/poet.tang.5000.json','["端笏明光宮，歷稔朝雲陛。", "詔刊延閣書，高議平津邸。", "適意偶輕人，虛心削繁禮。", "盛得江左風，彌工建安體。", "高張多絕弦，截河有清濟。", "嚴冬爽羣木，伊洛方清泚。", "渭水冰下流，潼關雪中啓。", "荷蓧幾時還，塵纓待君洗。"]'),
('28a952f3-fe21-4232-8e5d-a88de7fb638d','晦日遊大理韋卿城南別業四聲依次用各六韻 一','王維','唐','唐诗','tang','','[]','與世澹無事，自然江海人。',72,'全唐诗/poet.tang.5000.json','["與世澹無事，自然江海人。", "側聞塵外遊，解驂𨋗朱輪。", "平野照暄景，上天垂春雲。", "張組竟北阜，汎舟過東鄰。", "故鄉信高會，牢醴及佳辰。", "幸同擊壤樂，心荷堯爲君。"]'),
('f84ae8c9-b70b-41f0-9be3-e874c0e6c136','晦日遊大理韋卿城南別業四聲依次用各六韻 二','王維','唐','唐诗','tang','','[]','郊居杜陵下，永日同攜手。',72,'全唐诗/poet.tang.5000.json','["郊居杜陵下，永日同攜手。", "仁里靄川陽，平原見峰首。", "園廬鳴春鳩，林薄媚新柳。", "上卿始登席，故老前爲壽。", "臨當遊南陂，約略執桮酒。", "歸歟絀微官，惆悵心自咎。"]'),
('16469b22-3690-4c6a-b4f2-7c00e20706e5','晦日遊大理韋卿城南別業四聲依次用各六韻 三','王維','唐','唐诗','tang','','[]','冬中餘雪在，墟上春流駛。',72,'全唐诗/poet.tang.5000.json','["冬中餘雪在，墟上春流駛。", "風日暢懷抱，山川多秀氣。", "彫胡先晨炊，庖膾亦雲至。", "高情浪海嶽，浮生寄天地。", "君子外簪纓，埃塵良不啻。", "所樂衡門中，陶然忘其貴。"]'),
('fdd36dac-cff8-41ed-8cce-409f56c6634c','晦日遊大理韋卿城南別業四聲依次用各六韻 四','王維','唐','唐诗','tang','','[]','高館臨澄陂，曠然蕩心目。',72,'全唐诗/poet.tang.5000.json','["高館臨澄陂，曠然蕩心目。", "淡蕩動雲天，玲瓏映墟曲。", "鵲巢結空林，雉雊響幽谷。", "應接無閑暇，徘徊以躑躅。", "紆組上春堤，側弁倚喬木。", "弦望忽已晦，後期洲應綠。"]'),
('d0e4fe3e-e066-4dfb-97d3-ec55f756c172','冬日遊覽','王維','唐','唐诗','tang','','[]','步出城東門，試騁千里目。',84,'全唐诗/poet.tang.5000.json','["步出城東門，試騁千里目。", "青山橫蒼林，赤日團平陸。", "渭北走邯鄲，關東出函谷。", "秦地萬方會，來朝九州牧。", "雞鳴咸陽中，冠蓋相追逐。", "丞相過列侯，羣公餞光祿。", "相如方老病，獨歸茂陵宿。"]'),
('f0ba8b57-e9a2-4df2-8aa4-30c4dca0420c','華嶽','王維','唐','唐诗','tang','','["\u534e\u5c71"]','西嶽出浮雲，積雪在太清。',120,'全唐诗/poet.tang.5000.json','["西嶽出浮雲，積雪在太清。", "連天凝黛色，百里遙青冥。", "白日爲之寒，森沈華陰城。", "昔聞乾坤閉，造化生巨靈。", "右足踏方止，左手推削成。", "天地忽開拆，大河注東溟。", "遂爲西峙嶽，雄雄鎮秦京。", "大君包覆載，至德被羣生。", "上帝佇昭告，金天思奉迎。", "人祇望幸久，何獨禪云亭。"]'),
('d1640f3a-9511-434e-9ce2-9418275a67e6','同盧拾遺過韋給事東山別業二十韻給事首春休沐維已陪遊及乎是行亦預聞命會無車馬不果斯諾','王維','唐','唐诗','tang','','[]','托身侍雲陛，昧旦趨華軒。',240,'全唐诗/poet.tang.5000.json','["托身侍雲陛，昧旦趨華軒。", "遂陪鵷鴻侶，霄漢同飛翻。", "君子垂惠顧，期我於田園。", "側聞景龍際，親降南面尊。", "萬乘駐山外，順風祈一言。", "高陽多夔龍，荆山積璵璠。", "盛德啓前烈，大賢鍾後昆。", "侍郎文昌宮，給事東掖垣。", "謁帝俱來下，冠蓋盈丘樊。", "閨風首邦族，庭訓延鄉村。", "采地包山河，樹井竟川原。", "巖端回綺檻，谷口開朱門。", "階下羣峰首，雲中瀑水源。", "鳴玉滿春山，列筵先朝暾。", "會舞何颯沓，擊鐘彌朝昏。", "是時陽和節，清晝猶未暄。", "藹藹樹色深，嚶嚶鳥聲繁。", "顧己負宿諾，延頸慙芳蓀。", "蹇步守窮巷，高駕難攀援。", "素是獨往客，脫冠情彌敦。"]'),
('1c82ac88-be37-4052-9475-e18bfea0d175','藍田山石門精舍','王維','唐','唐诗','tang','','[]','落日山水好，漾舟信歸風。',144,'全唐诗/poet.tang.5000.json','["落日山水好，漾舟信歸風。", "探奇不覺遠，因以緣源窮。", "遙愛雲木秀，初疑路不同。", "安知清流轉，偶與前山通。", "捨舟理輕策，果然愜所適。", "老僧四五人，逍遙蔭松栢。", "朝梵林未曙，夜禪山更寂。", "道心及牧童，世事問樵客。", "暝宿長林下，焚香臥瑤席。", "澗芳襲人衣，山月暎石壁。", "再尋畏迷誤，明發更登歷。", "笑謝桃源人，花紅復來覿。"]'),
('a0576d39-c4ac-4608-a4e2-249b6c31fd1d','青谿','王維','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4e94\u8a00\u53e4\u8bd7", "\u6258\u7269\u5bc4\u60c5", "\u5c71\u6c34"]','言入黃花川，每逐青谿水。',72,'全唐诗/poet.tang.5000.json','["言入黃花川，每逐青谿水。", "隨山將萬轉，趣途無百里。", "聲喧亂石中，色靜深松裏。", "漾漾汎菱荇，澄澄映葭葦。", "我心素已閑，清川澹如此。", "請留盤石上，垂釣將已矣。"]'),
('f0383c43-fecf-4c6a-b3ed-23b157e237f5','崔濮陽兄季重前山興','王維','唐','唐诗','tang','','[]','秋色有佳興，況君池上閑。',72,'全唐诗/poet.tang.5000.json','["秋色有佳興，況君池上閑。", "悠悠西林下，自識門前山。", "千里橫黛色，數峰出雲間。", "嵯峨對秦國，合沓藏荆關。", "殘雨斜日照，夕嵐飛鳥還。", "故人今尚爾，歎息此頹顏。"]'),
('dcb17a74-9877-4337-9b01-b0fbd86a4f60','李處士山居','王維','唐','唐诗','tang','','[]','君子盈天階，小人甘自免。',48,'全唐诗/poet.tang.5000.json','["君子盈天階，小人甘自免。", "方隨鍊金客，林上家絕巘。", "背嶺花未開，入雲樹深淺。", "清晝猶自眠，山鳥時一囀。"]'),
('e298db89-5cd0-4349-97ff-2f3be4160d80','丁宇田家有贈','王維','唐','唐诗','tang','','[]','君心尚棲隱，久欲傍歸路。',132,'全唐诗/poet.tang.5000.json','["君心尚棲隱，久欲傍歸路。", "在朝每爲言，解印果成趣。", "晨雞鳴鄰里，羣動從所務。", "農夫行餉田，閨妾起縫素。", "開軒御衣服，散帙理章句。", "時吟招隱詩，或製閑居賦。", "新晴望郊郭，日暎桑榆暮。", "陰晝小苑城，微明渭川樹。", "揆予宅閭井，幽賞何由屢。", "道存終不忘，迹異難相遇。", "此時惜離別，再來芳菲度。"]'),
('204e287b-8194-4c2d-808b-11cc260412ae','渭川田家','王維','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4e94\u8a00\u53e4\u8bd7", "\u5f52\u9690", "\u7530\u56ed"]','斜陽照墟落，窮巷牛羊歸。',60,'全唐诗/poet.tang.5000.json','["斜陽照墟落，窮巷牛羊歸。", "野老念牧童，倚杖候荆扉。", "雉雊麥苗秀，蠶眠桑葉稀。", "田夫荷鋤至，相見語依依。", "即此羨閑逸，悵然吟式微。"]'),
('b8781d18-2288-48aa-9217-75487f4f75aa','春中田園作','王維','唐','唐诗','tang','','["\u6625\u5929", "\u7530\u56ed", "\u5199\u666f", "\u519c\u4e8b"]','屋上春鳩鳴，村邊杏花白。',48,'全唐诗/poet.tang.5000.json','["屋上春鳩鳴，村邊杏花白。", "持斧伐遠揚，荷鋤覘泉脈。", "歸燕識故巢，舊人看新曆。", "臨觴忽不御，惆悵遠行客。"]'),
('97fb7180-ab6c-4407-8b2e-7532ea276979','過李楫宅','王維','唐','唐诗','tang','','[]','閑門秋草色，終日無車馬。',60,'全唐诗/poet.tang.5000.json','["閑門秋草色，終日無車馬。", "客來深巷中，犬吠寒林下。", "散髪時未簪，道書行尚把。", "與我同心人，樂道安貧者。", "一罷宜城酌，還歸洛陽社。"]'),
('65cea96b-411f-4bc8-85aa-9febbeaa4d2c','韋侍郎山居','王維','唐','唐诗','tang','','[]','幸忝君子顧，遂陪塵外蹤。',72,'全唐诗/poet.tang.5000.json','["幸忝君子顧，遂陪塵外蹤。", "閑花滿巖谷，瀑水映杉松。", "啼鳥忽臨澗，歸雲時抱峰。", "良遊盛簪紱，繼跡多夔龍。", "詎枉青門道，胡聞長樂鐘。", "清晨去朝謁，車馬何從容。"]'),
('1cf746aa-75cb-4436-9674-9c3fada754fe','飯覆釜山僧','王維','唐','唐诗','tang','','[]','晚知清淨理，日與人羣疎。',84,'全唐诗/poet.tang.5000.json','["晚知清淨理，日與人羣疎。", "將候遠山僧，先期埽弊廬。", "果從雲峰裏，顧我蓬蒿居。", "藉草飯松屑，焚香看道書。", "然燈晝欲盡，鳴磬夜方初。", "一悟寂爲樂，此日閑有餘。", "思歸何必深，身世猶空虛。"]'),
('d6619574-2918-45bb-90a4-39c22b9b5636','謁璿上人','王維','唐','唐诗','tang','','[]','少年不足言，識道年已長。',120,'全唐诗/poet.tang.5000.json','["少年不足言，識道年已長。", "事往安可悔，餘生幸能養。", "誓從斷臂血，不復嬰世網。", "浮名寄纓珮，空性無羈鞅。", "夙承大導師，焚香此瞻仰。", "頹然居一室，覆載紛萬象。", "高柳早鸎啼，長廊春雨響。", "牀下阮家屐，窗前筇竹杖。", "方將見身雲，陋彼示天壤。", "一心在法要，願以無生獎。"]'),
('2d50ed5f-0e9d-48db-b114-589a3012f4c8','瓜園詩','王維','唐','唐诗','tang','','[]','余適欲鋤瓜，倚鋤聽叩門。',132,'全唐诗/poet.tang.5000.json','["余適欲鋤瓜，倚鋤聽叩門。", "鳴騶導驄馬，常從夾朱軒。", "窮巷正傳呼，故人儻相存。", "攜手追涼風，放心望乾坤。", "藹藹帝王州，宮觀一何繁。", "林端出綺道，殿頂搖華幡。", "素懷在青山，若值白雲屯。", "回風城西雨，返景原上村。", "前酌盈尊酒，往往聞清言。", "黃鸝囀深木，朱槿照中園。", "猶羨松下客，石上聞清猿。"]'),
('89676d14-1739-4aac-9641-c214f4d3aeb8','自大散以往深林密竹磴道盤曲四五十里至黃牛嶺見黃花川','王維','唐','唐诗','tang','','["\u6292\u60c5", "\u5199\u666f"]','危徑幾萬轉，數里將三休。',84,'全唐诗/poet.tang.5000.json','["危徑幾萬轉，數里將三休。", "回環見徒侶，隱暎隔林丘。", "颯颯松上雨，潺潺石中流。", "靜言深谿裏，長嘯高山頭。", "望見南山陽，白露靄悠悠。", "青臯麗已淨，綠樹鬱如浮。", "曾是厭蒙密，曠然銷人憂。"]'),
('beb41d16-0eee-4916-9f08-c08877959ea3','新晴野望','王維','唐','唐诗','tang','','["\u5199\u666f", "\u7530\u56ed"]','新晴原野曠，極目無氛垢。',48,'全唐诗/poet.tang.5000.json','["新晴原野曠，極目無氛垢。", "郭門臨渡頭，村樹連谿口。", "白水明田外，碧峰出山後。", "農月無閑人，傾家事南畝。"]'),
('04ef8f76-9308-42c0-913a-b83cad843362','宿鄭州','王維','唐','唐诗','tang','','["\u6292\u60c5", "\u65c5\u9014", "\u5b64\u5bc2", "\u5199\u666f"]','朝與周人辭，暮投鄭人宿。',96,'全唐诗/poet.tang.5000.json','["朝與周人辭，暮投鄭人宿。", "他鄉絕儔侶，孤客親僮僕。", "宛洛望不見，秋霖晦平陸。", "田父草際歸，村童雨中牧。", "主人東臯上，時稼遶茅屋。", "蟲思機杼悲，雀喧禾黍熟。", "明當渡京水，昨晚猶金谷。", "此去欲何言，窮邊狥微祿。"]'),
('df75cf4d-cacd-424a-b043-ebf95cb60639','早入滎陽界','王維','唐','唐诗','tang','','[]','汎舟入滎澤，茲邑乃雄藩。',72,'全唐诗/poet.tang.5000.json','["汎舟入滎澤，茲邑乃雄藩。", "河曲閭閻隘，川中煙火繁。", "因人見風俗，入境聞方言。", "秋野田疇盛，朝光市井喧。", "漁商波上客，雞犬岸旁村。", "前路白雲外，孤帆安可論。"]'),
('d72cee03-01b5-4d70-ab10-19cbe46761f0','渡河到清河作','王維','唐','唐诗','tang','','["\u5199\u666f", "\u6292\u60c5", "\u601d\u4e61", "\u9ec4\u6cb3"]','汎舟大河裏，積水窮天涯。',48,'全唐诗/poet.tang.5000.json','["汎舟大河裏，積水窮天涯。", "天波忽開拆，郡邑千萬家。", "行復見城市，宛然有桑麻。", "回瞻舊鄉國，淼漫連雲霞。"]'),
('7d2bb332-a03f-48b2-a067-cefc5ad927e2','苦熱','王維','唐','唐诗','tang','','[]','赤日滿天地，火雲成山嶽。',96,'全唐诗/poet.tang.5000.json','["赤日滿天地，火雲成山嶽。", "草木盡焦卷，川澤皆竭涸。", "輕紈覺衣重，密樹苦陰薄。", "莞簟不可近，絺綌再三濯。", "思出宇宙外，曠然在寥廓。", "長風萬里來，江海蕩煩濁。", "却顧身爲患，始知心未覺。", "忽入甘露門，宛然清涼樂。"]'),
('4ba4b85f-3539-42c6-8cd7-c054d79b9331','納涼','王維','唐','唐诗','tang','','[]','喬木萬餘株，清流貫其中。',72,'全唐诗/poet.tang.5000.json','["喬木萬餘株，清流貫其中。", "前臨大川口，豁達來長風。", "漣漪涵白沙，素鮪如遊空。", "偃臥盤石上，翻濤沃微躬。", "漱流復濯足，前對釣魚翁。", "貪餌凡幾許，徒思蓮葉東。"]'),
('4d6f83e9-8232-4db1-903e-f9e619df5ecb','西施詠','王維','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u4e94\u8a00\u53e4\u8bd7", "\u6000\u53e4", "\u5199\u4eba", "\u6000\u624d\u4e0d\u9047"]','豔色天下重，西施寧久微。',84,'全唐诗/poet.tang.5000.json','["豔色天下重，西施寧久微。", "朝仍越溪女，暮作吳宮妃。", "賤日豈殊衆，貴來方悟稀。", "邀人傅香粉，不自著羅衣。", "君寵益嬌態，君憐無是非。", "當時浣紗伴，莫得同車歸。", "持謝鄰家子，效顰安可希。"]'),
('90da06c8-4252-424a-89f3-f2e6c232e455','李陵詠','王維','唐','唐诗','tang','','[]','漢家李將軍，三代將門子。',120,'全唐诗/poet.tang.5000.json','["漢家李將軍，三代將門子。", "結髮有奇策，少年成壯士。", "長驅塞上兒，深入單于壘。", "旌旗列相向，簫鼓悲何已。", "日暮沙漠陲，戰聲煙塵裏。", "將令驕虜滅，豈獨名王侍。", "既失大軍援，遂嬰穹廬恥。", "少小蒙漢恩，何堪坐思此。", "深衷欲有報，投軀未能死。", "引領望子卿，非君誰相理。"]'),
('f0f00c03-fb54-408b-b62b-a11cc62461f2','濟上四賢詠 崔錄事','王維','唐','唐诗','tang','','[]','解印歸田里，賢哉此丈夫。',48,'全唐诗/poet.tang.5000.json','["解印歸田里，賢哉此丈夫。", "少年曾任俠，晚節更爲儒。", "遯跡東山下，因家滄海隅。", "已聞能狎鳥，余欲共乘桴。"]'),
('ce3ddd83-957f-45f5-8aab-8a64a9ec1972','濟上四賢詠 成文學','王維','唐','唐诗','tang','','[]','寶劒千金裝，登君白玉堂。',48,'全唐诗/poet.tang.5000.json','["寶劒千金裝，登君白玉堂。", "身爲平原客，家有邯鄲娼。", "使氣公卿坐，論心遊俠場。", "中年不得意，謝病客遊梁。"]'),
('00505454-90e0-4119-afa0-6771bedfe80f','濟上四賢詠 鄭霍二山人','王維','唐','唐诗','tang','','[]','翩翩繁華子，多出金張門。',96,'全唐诗/poet.tang.5000.json','["翩翩繁華子，多出金張門。", "幸有先人業，早蒙明主恩。", "童年且未學，肉食騖華軒。", "豈乏中林士，無人薦至尊。", "鄭公老泉石，霍子安丘樊。", "賣藥不二價，著書盈萬言。", "息陰無惡木，飲水必清源。", "吾賤不及議，斯人竟誰論。"]'),
('8d05b6e8-b232-40e7-a66d-41d8980f00d5','過太乙觀賈生房','王維','唐','唐诗','tang','','[]','昔余棲遯日，之子煙霞鄰。',96,'全唐诗/poet.tang.5000.json','["昔余棲遯日，之子煙霞鄰。", "共攜松葉酒，俱篸竹皮巾。", "攀林遍巖洞，采藥無冬春。", "謬以道門子，徵爲驂御臣。", "常恐丹液就，先我紫陽賓。", "夭促萬塗盡，哀傷百慮新。", "跡峻不容俗，才多反累真。", "泣對雙泉水，還山無主人。"]'),
('5233e44e-9520-4bf7-aaca-3b3a74dfe81e','燕子龕禪師','王維','唐','唐诗','tang','','[]','山中燕子龕，路劇羊腸惡。',204,'全唐诗/poet.tang.5000.json','["山中燕子龕，路劇羊腸惡。", "裂地競盤屈，插天多峭崿。", "瀑泉吼而噴，怪石看欲落。", "伯禹訪未知，五丁愁不鑿。", "上人無生緣，生長居紫閣。", "六時自搥磬，一飲常帶索。", "種田燒白雲，斫漆響丹壑。", "行隨拾栗猿，歸對巢松鶴。", "時許山神請，偶逢洞仙博。", "救世多慈悲，即心無行作。", "周商倦積阻，蜀物多淹泊。", "巖腹乍旁穿，澗脣時外拓。", "橋因倒樹架，柵值垂藤縛。", "鳥道悉已平，龍宮爲之涸。", "跳波誰揭厲，絕壁免捫摸。", "山木日陰陰，結跏歸舊林。", "一向石門裏，任君春草深。"]'),
('f5c07374-f4da-464b-9ada-768ab54a26ca','羽林騎閨人','王維','唐','唐诗','tang','','[]','秋月臨高城，城中管弦思。',60,'全唐诗/poet.tang.5000.json','["秋月臨高城，城中管弦思。", "離人堂上愁，稚子階前戲。", "出門復暎戶，望望青絲騎。", "行人過欲盡，狂夫終不至。", "左右寂無言，相看共垂淚。"]'),
('eb64acc5-84e1-47a7-ab81-7be5a12ad200','偶然作六首 一','王維','唐','唐诗','tang','','[]','楚國有狂夫，茫然無心想。',60,'全唐诗/poet.tang.5000.json','["楚國有狂夫，茫然無心想。", "散髪不冠帶，行歌南陌上。", "孔丘與之言，仁義莫能獎。", "未嘗肯問天，何事須擊壤。", "復笑采薇人，胡爲乃長往。"]'),
('8d960d46-327f-477c-a222-a211a6903034','偶然作六首 二','王維','唐','唐诗','tang','','[]','田舍有老翁，垂白衡門裏。',108,'全唐诗/poet.tang.5000.json','["田舍有老翁，垂白衡門裏。", "有時農事閑，斗酒呼鄰里。", "喧聒茅簷下，或坐或復起。", "短褐不爲薄，園葵固足美。", "動則長子孫，不曾向城市。", "五帝與三王，古來稱天子。", "干戈將揖讓，畢竟何者是。", "得意苟爲樂，野田安足鄙。", "且當放懷去，行行沒餘齒。"]'),
('979dd74e-b664-4042-9e94-8d2e9d92e2bd','偶然作六首 三','王維','唐','唐诗','tang','','[]','日夕見太行，沈吟未能去。',108,'全唐诗/poet.tang.5000.json','["日夕見太行，沈吟未能去。", "問君何以然，世網嬰我故。", "小妹日成長，兄弟未有娶。", "家貧祿既薄，儲蓄非有素。", "幾回欲奮飛，踟躕復相顧。", "孫登長嘯臺，松竹有遺處。", "相去詎幾許，故人在中路。", "愛染日已薄，禪寂日已固。", "忽乎吾將行，寧俟歲云暮。"]'),
('f1841dee-c465-42ed-83ec-a1e6c2ca8113','偶然作六首 四','王維','唐','唐诗','tang','','[]','陶潛任天真，其性頗躭酒。',120,'全唐诗/poet.tang.5000.json','["陶潛任天真，其性頗躭酒。", "自從棄官來，家貧不能有。", "九月九日時，菊花空滿手。", "中心竊自思，儻有人送否。", "白衣攜壺觴，果來遺老叟。", "且喜得斟酌，安問升與斗。", "奮衣野田中，今日嗟無負。", "兀傲迷東西，蓑笠不能守。", "傾倒強行行，酣歌歸五柳。", "生事不曾問，肯媿家中婦。"]'),
('4811841a-3063-4975-8f52-1420de15563a','偶然作六首 五','王維','唐','唐诗','tang','','[]','趙女彈箜篌，復能邯鄲舞。',84,'全唐诗/poet.tang.5000.json','["趙女彈箜篌，復能邯鄲舞。", "夫壻輕薄兒，鬬雞事齊主。", "黃金買歌笑，用錢不復數。", "許史相經過，高門盈四牡。", "客舍有儒生，昂藏出鄒魯。", "讀書三十年，腰間無尺組。", "被服聖人教，一生自窮苦。"]'),
('aad4f966-3ebe-4a5e-8765-ad80069cb851','偶然作六首 六','王維','唐','唐诗','tang','','[]','老來懶賦詩，惟有老相隨。',48,'全唐诗/poet.tang.5000.json','["老來懶賦詩，惟有老相隨。", "宿世謬詞客，前身應畫師。", "不能捨餘習，偶被世人知。", "名字本皆是，此心還不知。"]'),
('a99b9221-deac-4bf0-a6fa-31ce258ffcf8','寓言二首 一','王維','唐','唐诗','tang','','[]','朱紱誰家子，無乃金張孫。',72,'全唐诗/poet.tang.5000.json','["朱紱誰家子，無乃金張孫。", "驪駒從白馬，出入銅龍門。", "問爾何功德，多承明主恩。", "鬬雞平樂館，射雉上林園。", "曲陌車騎盛，高堂珠翠繁。", "奈何軒冕貴，不與布衣言。"]'),
('c1531bb4-4994-4f5b-a0cc-99bc730ef23e','寓言二首 二','王維','唐','唐诗','tang','','[]','君家御溝上，垂柳夾朱門。',48,'全唐诗/poet.tang.5000.json','["君家御溝上，垂柳夾朱門。", "列鼎會中貴，鳴珂朝至尊。", "生死在八議，窮達由一言。", "須識苦寒士，莫矜狐白溫。"]'),
('99e91369-92a3-4dcf-900c-e1424e2b8457','冬夜書懷','王維','唐','唐诗','tang','','[]','冬宵寒且永，夜漏宮中發。',48,'全唐诗/poet.tang.5000.json','["冬宵寒且永，夜漏宮中發。", "草白靄繁霜，木衰澄清月。", "麗服暎頹顏，朱燈照華髪。", "漢家方尚少，顧影慙朝謁。"]'),
('d119d041-829b-49c0-b8ae-66b2c58375c3','送康太守','王維','唐','唐诗','tang','','["\u9ec4\u9e64\u697c", "\u9001\u522b"]','城下滄江水，江邊黃鶴樓。',60,'全唐诗/poet.tang.5000.json','["城下滄江水，江邊黃鶴樓。", "朱闌將粉堞，江水映悠悠。", "鐃吹發夏口，使君居上頭。", "郭門隱楓岸，候吏趨蘆洲。", "何異臨川郡，還勞康樂侯。"]'),
('ee598cce-2501-42b3-8d77-1de2d9b58870','送權二','王維','唐','唐诗','tang','','[]','高人不可有，清論復何深。',72,'全唐诗/poet.tang.5000.json','["高人不可有，清論復何深。", "一見如舊識，一言知道心。", "明時當薄宦，解薜去中林。", "芳草空隱處，白雲餘故岑。", "韓侯久攜手，河嶽共幽尋。", "悵別千餘里，臨堂鳴素琴。"]'),
('ffdfd373-9e00-4759-b90d-f6d8da4a1d86','休假還舊業便使','王維','唐','唐诗','tang','','[]','謝病始告歸，依依入桑梓。',108,'全唐诗/poet.tang.5000.json','["謝病始告歸，依依入桑梓。", "家人皆竚立，相候衡門裏。", "時輩皆長年，成人舊童子。", "上堂嘉慶畢，顧與姻親齒。", "論舊忽餘悲，目存皆相喜。", "田園轉蕪沒，但有寒泉水。", "衰柳日蕭條，秋光清邑里。", "入門乍如客，休騎非便止。", "中飲顧王程，離憂從此始。"]'),
('821e9913-0746-4dc1-a151-28d8e511df86','歎白髪','王維','唐','唐诗','tang','','[]','我年一何長，鬢髪日已白。',48,'全唐诗/poet.tang.5000.json','["我年一何長，鬢髪日已白。", "俛仰天地間，能爲幾時客。", "惆悵故山雲，俳徊空日夕。", "何事與時人，東城復南陌。"]'),
('afc6f8c0-c818-411e-828f-1df966913431','別弟妹二首 一','王維','唐','唐诗','tang','','[]','兩妹日成長，雙鬟將及人。',48,'全唐诗/poet.tang.5000.json','["兩妹日成長，雙鬟將及人。", "已能持寶瑟，自解掩羅巾。", "念昔別時小，未知疎與親。", "今來始離恨，拭淚方殷勤。"]'),
('6d35e7dd-79cc-4d70-acda-d1cc9eab8fbf','別弟妹二首 二','王維','唐','唐诗','tang','','[]','小弟更孩幼，歸來不相識。',48,'全唐诗/poet.tang.5000.json','["小弟更孩幼，歸來不相識。", "同居雖漸慣，見人猶未覓。", "宛作越人語，殊甘水鄉食。", "別此最爲難，淚盡有餘憶。"]'),
('41355750-b4e1-4c5a-8fc6-17f4e8a7049e','哭殷遙','王維','唐','唐诗','tang','','[]','人生能幾何，畢竟歸無形。',120,'全唐诗/poet.tang.5000.json','["人生能幾何，畢竟歸無形。", "念君等爲死，萬事傷人情。", "慈母未及葬，一女纔十齡。", "泱漭寒郊外，蕭條聞哭聲。", "浮雲爲蒼茫，飛鳥不能鳴。", "行人何寂寞，白日自淒清。", "憶昔君在時，問我學無生。", "勸君苦不早，令君無所成。", "故人各有贈，又不及生平。", "負爾非一途，慟哭返柴荆。"]'),
('44b2376c-e68d-4b0d-a57a-564d868445cc','故南陽夫人樊氏挽歌','王維','唐','唐诗','tang','','[]','石窌恩榮重，金吾車騎盛。',48,'全唐诗/poet.tang.5000.json','["石窌恩榮重，金吾車騎盛。", "將朝每贈言，入室還相敬。", "疊鼓秋城動，懸旌寒日映。", "不言長不歸，環珮猶將聽。"]'),
('cc7cd11c-5e72-4620-a4ad-1f2aba14b7eb','夷門歌','王維','唐','唐诗','tang','','["\u6292\u60c5", "\u53d9\u4e8b", "\u8c6a\u653e"]','七雄雄雌猶未分，攻城殺將何紛紛。',96,'全唐诗/poet.tang.5000.json','["七雄雄雌猶未分，攻城殺將何紛紛。", "秦兵益圍邯鄲急，魏王不救平原君。", "公子爲嬴停駟馬，執轡愈恭意愈下。", "亥爲屠肆鼓刀人，嬴乃夷門抱關者。", "非但慷慨獻良謀，意氣兼將身命酬。", "向風刎頸送公子，七十老翁何所求。"]'),
('9afcb446-145c-44aa-b9e6-d0c9adce4fac','隴頭吟','王維','唐','唐诗','tang','','["\u60b2\u6124", "\u611f\u4f24", "\u8fb9\u585e"]','長安少年遊俠客，夜上戍樓看太白。',80,'全唐诗/poet.tang.5000.json','["長安少年遊俠客，夜上戍樓看太白。", "隴頭明月迥臨關，隴上行人夜吹笛。", "關西老將不勝愁，駐馬聽之雙淚流。", "身經大小百餘戰，麾下偏裨萬戶侯。", "蘇武纔爲典屬國，節旄落盡海西頭。"]'),
('d5d66aff-b6ae-48cc-9160-16b096d4ea49','老將行','王維','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4e50\u5e9c", "\u5199\u4eba", "\u65b0\u4e50\u5e9c\u8f9e", "\u8d5e\u9882"]','少年十五二十時，步行奪得胡馬射。',240,'全唐诗/poet.tang.5000.json','["少年十五二十時，步行奪得胡馬射。", "射殺中山白額虎，肯數鄴下黃鬚兒。", "一身轉戰三千里，一劒曾當百萬師。", "漢兵奮迅如霹靂，虜騎崩騰畏蒺藜。", "衞青不敗由天幸，李廣無功緣數奇。", "自從棄置便衰朽，世事磋跎成白首。", "昔時飛箭無全目，今日垂楊生左肘。", "路傍時賣故侯瓜，門前學種先生柳。", "蒼茫古木連窮巷，寥落寒山對虛牖。", "誓令疏勒出飛泉，不似潁川空使酒。", "賀蘭山下陣如雲，羽檄交馳日夕聞。", "節使三河募年少，詔書五道出將軍。", "試拂鐵衣如雪色，聊持寶劒動星文。", "願得燕弓射天將，恥令越甲鳴吳軍。", "莫嫌舊日雲中守，猶堪一戰取功勳。"]'),
('26836213-01c0-4a22-8d81-dc8a0e0793b2','燕支行','王維','唐','唐诗','tang','','[]','漢家天將才且雄，來時謁帝明光宮。',192,'全唐诗/poet.tang.5000.json','["漢家天將才且雄，來時謁帝明光宮。", "萬乘親推雙闕下，千官出餞五陵東。", "誓辭甲第金門裏，身作長城玉塞中。", "衞霍才堪一騎將，朝廷不數貳師功。", "趙魏燕韓多勁卒，關西俠少何咆勃。", "報讐只是聞嘗膽，飲酒不曾妨刮骨。", "畫戟雕戈白日寒，連旗大斾黃塵沒。", "疊鼓遙翻瀚海波，鳴笳亂動天山月。", "麒麟錦帶佩吳鉤，颯沓青驪躍紫騮。", "拔劒已斷天驕臂，歸鞍共飲月支頭。", "漢兵大呼一當百，虜騎相看哭且愁。", "教戰雖令赴湯火，終知上將先伐謀。"]'),
('3b847cf5-16b1-449d-a436-e5995c6433c4','桃源行','王維','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u5199\u666f", "\u4e50\u5e9c", "\u65b0\u4e50\u5e9c\u8f9e", "\u6c34"]','漁舟逐水愛山春，兩岸桃花夾去津。',256,'全唐诗/poet.tang.5000.json','["漁舟逐水愛山春，兩岸桃花夾去津。", "坐看紅樹不知遠，行盡青溪不見人。", "山口潛行始隈隩，山開曠望旋平陸。", "遙看一處攢雲樹，近入千家散花竹。", "樵客初傳漢姓名，居人未改秦衣服。", "居人共住武陵源，還從物外起田園。", "月明松下房櫳靜，日出雲中雞犬喧。", "驚聞俗客爭來集，競引還家問都邑。", "平明閭巷埽花開，薄暮漁樵乘水入。", "初因避地去人間，及至成仙遂不還。", "峽裏誰知有人事，世中遙望空雲山。", "不疑靈境難聞見，塵心未盡思鄉縣。", "出洞無論隔山水，辭家終擬長游衍。", "自謂經過舊不迷，安知峰壑今來變。", "當時只記入山深，青溪幾曲到雲林。", "春來遍是桃花水，不辨仙源何處尋。"]'),
('4925c861-b0f8-4b2f-923e-9cba2df1323e','洛陽女兒行','王維','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u751f\u6d3b", "\u5973\u5b50", "\u4e50\u5e9c", "\u65b0\u4e50\u5e9c\u8f9e"]','洛陽女兒對門居，纔可容顏十五餘。',160,'全唐诗/poet.tang.5000.json','["洛陽女兒對門居，纔可容顏十五餘。", "良人玉勒乘驄馬，侍女金盤鱠鯉魚。", "畫閣朱樓盡相望，紅桃綠柳垂簷向。", "羅幃送上七香車，寶扇迎歸九華帳。", "狂夫富貴在青春，意氣驕奢劇季倫。", "自憐碧玉親教舞，不惜珊瑚持與人。", "春窗曙滅九微火，九微片片飛花璅。", "戲罷曾無理曲時，妝成秪是薰香坐。", "城中相識盡繁華，日夜經過趙李家。", "誰憐越女顏如玉，貧賤江頭自浣紗。"]'),
('cccfccae-0f64-4573-91bc-acb8b452b10f','同崔傅答賢弟','王維','唐','唐诗','tang','','[]','洛陽才子姑蘇客，桂苑殊非故鄉陌。',128,'全唐诗/poet.tang.5000.json','["洛陽才子姑蘇客，桂苑殊非故鄉陌。", "九江楓樹幾回青，一片揚州五湖白。", "揚州時有下江兵，蘭陵鎮前吹笛聲。", "夜火人歸富春郭，秋風鶴唳石頭城。", "周郎陸弟爲儔侶，對舞前溪歌白紵。", "曲几書留小史家，草堂棋賭山陰墅。", "衣冠若話外臺臣，先數夫君席上珍。", "更聞臺閣求三語，遙想風流第一人。"]'),
('14831423-609e-4625-8bac-e9feb8e295a6','贈吳官','王維','唐','唐诗','tang','','[]','長安客舍熱如煮，無箇茗糜難御暑。',64,'全唐诗/poet.tang.5000.json','["長安客舍熱如煮，無箇茗糜難御暑。", "空搖白團其諦苦，欲向縹囊還歸旅。", "江鄉鯖鮓不寄來，秦人湯餅那堪許。", "不如儂家任挑達，草屩撈蝦富春渚。"]'),
('eff5a666-c3a6-4448-b913-f49e2c83154f','故人張諲工詩善易卜兼能丹青草隸頃以詩見贈聊獲酬之','王維','唐','唐诗','tang','','[]','不逐城東遊俠兒，隱囊紗帽坐彈棋。',96,'全唐诗/poet.tang.5000.json','["不逐城東遊俠兒，隱囊紗帽坐彈棋。", "蜀中夫子時開卦，洛下書生解詠詩。", "藥闌花逕衡門裏，時復據梧聊隱几。", "屏風誤點惑孫郎，團扇草書輕內史。", "故園高枕度三春，永日垂帷絕四鄰。", "自想蔡邕今已老，更將書籍使何人。"]'),
('7f232909-cb6c-4da8-afde-d3ff9fcea204','送崔五太守','王維','唐','唐诗','tang','','[]','長安廄吏來到門，朱文露網動行軒。',128,'全唐诗/poet.tang.5000.json','["長安廄吏來到門，朱文露網動行軒。", "黃花縣西九折坂，玉樹宮南五丈原。", "襃斜谷中不容幰，唯有白雲當露冕。", "子午山裏杜鵑啼，嘉陵水頭行客飯。", "劒門忽斷蜀川開，萬井雙流滿眼來。", "霧中遠樹刀州出，天際澄江巴字回。", "使君年紀三十餘，少年白皙專城居。", "欲持畫省郎官筆，回與臨邛父老書。"]'),
('a5a19b2c-d215-4b3e-8b8c-29d9da7bccce','寒食城東即事','王維','唐','唐诗','tang','','["\u63cf\u5199\u6c34", "\u95f2\u9002", "\u5199\u9e1f", "\u5199\u6c34", "\u9e1f"]','清溪一道穿桃李，演漾綠蒲涵白芷。',64,'全唐诗/poet.tang.5000.json','["清溪一道穿桃李，演漾綠蒲涵白芷。", "溪上人家凡幾家，落花半落東流水。", "蹴鞠屢過飛鳥上，鞦韆競出垂楊裏。", "少年分日作遨遊，不用清明兼上巳。"]'),
('5c1c99a1-8547-4ba2-8042-faf0dd239d45','不遇詠','王維','唐','唐诗','tang','','[]','北闕獻書寢不報，南山種田時不登。',96,'全唐诗/poet.tang.5000.json','["北闕獻書寢不報，南山種田時不登。", "百人會中身不預，五侯門前心不能。", "身投河朔飲君酒，家在茂陵平安否。", "且此登山復臨水，莫問春風動楊柳。", "今人昨人多自私，我心不說君應知。", "濟人然後拂衣去，肯作徒爾一男兒。"]'),
('3c1f36cc-dc3f-44a7-ab1c-34f97e057e19','贈裴迪','王維','唐','唐诗','tang','','[]','不相見，不相見來久。',46,'全唐诗/poet.tang.5000.json','["不相見，不相見來久。", "日日泉水頭，常憶同攜手。", "攜手本同心，復歎忽分襟。", "相憶今如此，相思深不深。"]'),
('5d7b188a-e9bb-41f3-b7ab-7e070b3e026e','青雀歌','王維','唐','唐诗','tang','','[]','青雀翅羽短，未能遠食玉山禾。',30,'全唐诗/poet.tang.5000.json','["青雀翅羽短，未能遠食玉山禾。", "猶勝黃雀爭上下，唧唧空倉復若何。"]'),
('52c39451-5a14-4c62-a790-0a69d52662e6','黃雀癡','王維','唐','唐诗','tang','','[]','黃雀癡，黃雀癡，謂言青鷇是我兒。',74,'全唐诗/poet.tang.5000.json','["黃雀癡，黃雀癡，謂言青鷇是我兒。", "一一口銜食，養得成毛衣。", "到大啁啾解游颺，各自東西南北飛。", "薄暮空巢上，羇雌獨自歸。", "鳳凰九雛亦如此，慎莫愁思顦顇損容輝。"]'),
('18c9eef7-5cf2-4f88-873a-e46708007e7f','新秦郡松樹歌','王維','唐','唐诗','tang','','[]','青青山上松，數里不見今更逢。',46,'全唐诗/poet.tang.5000.json','["青青山上松，數里不見今更逢。", "不見君，心相憶，此心向君君應識。", "爲君顏色高且閑，亭亭迥出浮雲間。"]'),
('f651e3ed-d3ff-4bbf-aae9-8e914cfe9780','楡林郡歌','王維','唐','唐诗','tang','','["\u9ec4\u6cb3"]','山頭松柏林，山下泉聲傷客心。',46,'全唐诗/poet.tang.5000.json','["山頭松柏林，山下泉聲傷客心。", "千里萬里春草色，黃河東流流不息。", "黃龍戍上游俠兒，愁逢漢使不相識。"]'),
('7ce06de3-1f97-464c-aac1-8dd5653e84f6','問寇校書雙谿','王維','唐','唐诗','tang','','[]','君家少室西，爲復少室東。',28,'全唐诗/poet.tang.5000.json','["君家少室西，爲復少室東。", "別來幾日今春風，新買雙谿定何似。"]'),
('c14dd5ba-9b76-484a-a6d9-850663f9a90c','寄崇梵僧','王維','唐','唐诗','tang','','[]','崇梵僧，崇梵僧，秋歸覆釜春不還。',48,'全唐诗/poet.tang.5000.json','["崇梵僧，崇梵僧，秋歸覆釜春不還。", "落花啼鳥紛紛亂，澗戶山窗寂寂閑。", "峽裏誰知有人事，郡中遙望空雲山。"]'),
('cb33081b-2ad0-4b9f-9e31-c9940ba378b8','同比部楊員外十五夜遊有懷靜者季','王維','唐','唐诗','tang','','[]','承明少休沐，建禮省文書。',160,'全唐诗/poet.tang.5000.json','["承明少休沐，建禮省文書。", "夜漏行人息，歸鞍落日餘。", "懸知三五夕，萬戶千門闢。", "夜出曙翻歸，傾城滿南陌。", "陌頭馳騁盡繁華，王孫公子五侯家。", "由來月明如白日，共道春燈勝百花。", "聊看侍中千寶騎，強識小婦七香車。", "香車寶馬共喧闐，箇裏多情俠少年。", "競向長楊柳市北，肯過精舍竹林前。", "獨有仙郎心寂寞，却將宴坐爲行樂。", "儻覺忘懷共往來，幸霑同舍甘藜藿。"]'),
('74e84c15-4f58-436b-9640-b673db2df2da','荅張五弟','王維','唐','唐诗','tang','','["\u7ec8\u5357\u5c71"]','終南有茅屋，前對終南山。',44,'全唐诗/poet.tang.5000.json','["終南有茅屋，前對終南山。", "終年無客常閉關，終日無心長自閑。", "不妨飲酒復垂釣，君但能來相往還。"]'),
('13c5f0b5-b891-4847-999c-eb566db07ca0','雪中憶李楫','王維','唐','唐诗','tang','','[]','積雪滿阡陌，故人不可期。',28,'全唐诗/poet.tang.5000.json','["積雪滿阡陌，故人不可期。", "長安千門復萬户，何處躞蹀黄金羈。"]'),
('d336b36a-0b88-422b-9a4e-4c695d168574','送李睢陽','王維','唐','唐诗','tang','','[]','將置酒，思悲翁。',196,'全唐诗/poet.tang.5000.json','["將置酒，思悲翁。", "使君去，出城東。", "麥漸漸，雉子斑。", "槐陰陰，到潼關。", "騎連連，車遲遲。", "心中悲，宋又遠。", "周間之，南淮夷。", "東齊兒，碎碎織練與素絲。", "遊人賈客信難持，五穀前熟方可爲。", "下車閉閤君當思，天子當殿儼衣裳。", "大官尚食陳羽觴，彤庭散綬垂鳴璫。", "黃紙詔書出東廂，輕紈疊綺爛生光。", "宗室子弟君最賢，分憂當爲百辟先。", "布衣一言相爲死，何況聖主恩如天。", "鸞聲噦噦魯侯旂，明年上計朝京師。", "須憶今日斗酒別，慎勿富貴忘我爲。"]'),
('9c86dd14-c343-4536-9713-93ac4edbbf8e','奉和聖製天長節賜宰臣歌應制','王維','唐','唐诗','tang','','[]','太陽升兮照萬方，開閶闔兮臨玉堂。',88,'全唐诗/poet.tang.5000.json','["太陽升兮照萬方，開閶闔兮臨玉堂。", "儼冕旒兮垂衣裳，金天淨兮麗三光。", "彤庭曙兮延八荒，德合天兮禮神徧。", "靈芝生兮慶雲見，唐堯后兮稷卨臣。", "匝宇宙兮華胥人，盡九服兮皆四鄰，乾降瑞兮坤降珍。"]'),
('2eff02ed-d245-4c86-bc91-6f67a72ac95c','登樓歌','王維','唐','唐诗','tang','','[]','聊上君兮高樓，飛甍鱗次兮在下。',164,'全唐诗/poet.tang.5000.json','["聊上君兮高樓，飛甍鱗次兮在下。", "俯十二兮通衢，綠槐參差兮車馬。", "却瞻兮龍首，前眺兮宜春。", "王畿鬱兮千里，山河壯兮咸秦。", "舍人下兮青宮，據胡牀兮書空。", "執戟疲於下位，老夫好隱兮牆東。", "亦幸有張伯英草聖兮龍騰蚪躍，擺長雲兮捩迴風。", "琥珀酒兮彫胡飯，君不御兮日將晚。", "秋風兮吹衣，夕鳥兮爭返。", "孤砧發兮東城，林薄暮兮蟬聲遠。", "時不可兮再得，君何爲兮偃蹇。"]'),
('179e62dd-8983-45c3-a3db-52d9bd1871af','雙黃鵠歌送別','王維','唐','唐诗','tang','','[]','天路來兮雙黃鵠，雲上飛兮水上宿。',108,'全唐诗/poet.tang.5000.json','["天路來兮雙黃鵠，雲上飛兮水上宿。", "撫翼和鳴整羽族，不得已，忽分飛。", "家在玉京朝紫微，主人臨水送將歸。", "悲笳嘹唳垂舞衣，賓欲散兮復相依。", "幾往返兮極浦，尚裴回兮落暉。", "岸上火兮相迎，將夜入兮邊城。", "鞍馬歸兮佳人散，悵離憂兮獨含情。"]'),
('86f8a6ad-c725-410f-8a90-d25413b3b82a','贈徐中書望終南山歌','王維','唐','唐诗','tang','','["\u7ec8\u5357\u5c71"]','晚下兮紫微，悵塵事兮多違。',26,'全唐诗/poet.tang.5000.json','["晚下兮紫微，悵塵事兮多違。", "駐馬兮雙樹，望青山兮不歸。"]'),
('39096ae6-97b3-422e-a1c6-f725d8f5c105','送友人歸山歌二首 一','王維','唐','唐诗','tang','','[]','山寂寂兮無人，又蒼蒼兮多木。',111,'全唐诗/poet.tang.5000.json','["山寂寂兮無人，又蒼蒼兮多木。", "羣龍兮滿朝，君何爲兮空谷。", "文寡和兮思深，道難知兮行獨。", "悅石上兮流泉，與松間兮草屋。", "入雲中兮養雞，上山頭兮抱犢。", "神與棗兮如瓜，虎賣杏兮收穀。", "愧不才兮妨賢，嫌既老兮貪祿。", "誓解印兮相從，何詹尹兮何卜。"]'),
('837924d5-03d4-4133-8031-d1f042686d65','送友人歸山歌二首 二','王維','唐','唐诗','tang','','[]','山中人兮欲歸，雲冥冥兮雨霏霏，水驚波兮翠菅靡。',93,'全唐诗/poet.tang.5000.json','["山中人兮欲歸，雲冥冥兮雨霏霏，水驚波兮翠菅靡。", "白鷺忽兮翻飛，君不可兮褰衣。", "山萬重兮一雲，混天地兮不分。", "樹晻曖兮氛氳，猿不見兮空聞。", "忽山西兮夕陽，見東臯兮遠村。", "平蕪綠兮千里，眇惆悵兮思君。"]'),
('1a6e884e-e9fb-4564-81f5-9b937d3c74b1','魚山神女祠歌 迎神','王維','唐','唐诗','tang','','[]','坎坎擊鼓，魚山之下。',58,'全唐诗/poet.tang.5000.json','["坎坎擊鼓，魚山之下。", "吹洞簫，望極浦，女巫進，紛屢舞。", "陳瑤席，湛清酤，風淒淒兮夜雨。", "不知神之來兮不來，使我心兮苦復苦。"]'),
('dfc946ec-a63e-44c4-82f8-09b02cc23ea0','魚山神女祠歌 送神','王維','唐','唐诗','tang','','[]','紛進舞兮堂前，目眷眷兮瓊筵。',61,'全唐诗/poet.tang.5000.json','["紛進舞兮堂前，目眷眷兮瓊筵。", "來不言兮意不傳，作暮雨兮愁空山。", "悲急管兮思繁弦，神之駕兮儼欲旋。", "倏雲收兮雨歇，山青青兮水潺湲。"]'),
('e7f7681d-2be9-4d46-8186-e3fe25b52634','白黿渦','王維','唐','唐诗','tang','','[]','南山之瀑水兮，激石瀥瀑似雷驚。',90,'全唐诗/poet.tang.5000.json','["南山之瀑水兮，激石瀥瀑似雷驚。", "人相對兮，不聞語聲。", "翻渦跳沫兮蒼苔濕，蘚老且厚，春草爲之不生。", "獸不敢驚動，鳥不敢飛鳴。", "白黿渦濤戲瀨兮，委身以縱橫。", "王人之仁兮，不網不釣，得遂性以生成。"]'),
('c5efed14-4e44-4656-9f21-c8e505dca5e2','宋進馬哀詞','王維','唐','唐诗','tang','','[]','背春涉夏兮，衆木藹以繁陰。',305,'全唐诗/poet.tang.5000.json','["背春涉夏兮，衆木藹以繁陰。", "連金華與玉堂兮，宮閣鬱其沈沈。", "百官並入兮，何語笑之啞啞。", "君獨靜嘿以傷心，草王言兮不得辭。", "我悲減思兮少時，僕夫命駕兮。", "出閶闔，歷通逵，陌上人兮如故。", "識不識兮往來，眼中不見兮吾兒。", "驂紫騮兮從青驪，低光垂彩兮。", "怳不知其所之，闢朱戶兮望華軒。", "意斯子兮候門，忽思瘞兮城南。", "心瞀亂兮重昏，仰訴天之不仁兮。", "家唯一身，身止一子。", "何胤嗣之不繁，就單尠而又死。", "將清白兮遺誰，問詩禮兮已矣。", "哀從中兮不可勝，豈暇料餘年兮復幾。", "日黯黯兮頹曄，鳥翩翩兮疾飛。", "邈窮天兮不返，疑有日兮來歸。", "靜言思兮永絕，復驚叫兮沾衣。", "客有弔之者曰：觀未始兮有物，同委蛻兮胡悲。", "且延陵兮未至，況西河兮不知。", "學無生兮庶可，幸能聽於吾師。"]'),
('de77fb82-ebdd-4065-b58c-7b9106f8b218','奉和聖製賜史供奉曲江讌應制','王維','唐','唐诗','tang','','[]','侍從有鄒枚，瓊筵就水開。',48,'全唐诗/poet.tang.5000.json','["侍從有鄒枚，瓊筵就水開。", "言陪柏梁宴，新下建章來。", "對酒山河滿，移舟草樹廻。", "天文同麗日，駐景惜行杯。"]'),
('35f90b91-f4ed-4776-80fe-d1eefb4ac7c9','從岐王過楊氏別業應教','王維','唐','唐诗','tang','','[]','楊子談經所，淮王載酒過。',48,'全唐诗/poet.tang.5000.json','["楊子談經所，淮王載酒過。", "興闌啼鳥換，坐久落花多。", "逕轉廻銀燭，林開散玉珂。", "嚴城時未啓，前路擁笙歌。"]'),
('c40e93c2-8d43-4a93-9687-6c0b5d45376b','從岐王夜宴衞家山池應教','王維','唐','唐诗','tang','','[]','座客香貂滿，宮娃綺幔張。',48,'全唐诗/poet.tang.5000.json','["座客香貂滿，宮娃綺幔張。", "澗花輕粉色，山月少燈光。", "積翠紗窗暗，飛泉繡戶涼。", "還將歌舞出，歸路莫愁長。"]'),
('ba12b5ab-ce4e-4a10-bd9d-a476ebe14289','早朝','王維','唐','唐诗','tang','','[]','柳暗百花明，春深五鳳城。',48,'全唐诗/poet.tang.5000.json','["柳暗百花明，春深五鳳城。", "城烏睥睨曉，宮井轆轤聲。", "方朔金門侍，班姬玉輦迎。", "仍聞遣方士，東海訪蓬瀛。"]'),
('ba54ac5b-a131-4af6-a7e0-938db34b82fb','同崔員外秋宵寓直','王維','唐','唐诗','tang','','[]','建禮高秋夜，承明候曉過。',48,'全唐诗/poet.tang.5000.json','["建禮高秋夜，承明候曉過。", "九門寒漏徹，萬井曙鐘多。", "月迥藏珠斗，雲消出絳河。", "更慙衰朽質，南陌共鳴珂。"]'),
('a2b4e8ca-92e3-4101-8a54-739b8f1d8184','輞川閑居贈裴秀才迪','王維','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u5199\u666f", "\u6292\u60c5", "\u79cb\u5929", "\u4e94\u8a00\u5f8b\u8bd7"]','寒山轉蒼翠，秋水日潺湲。',48,'全唐诗/poet.tang.5000.json','["寒山轉蒼翠，秋水日潺湲。", "倚杖柴門外，臨風聽暮蟬。", "渡頭餘落日，墟里上孤煙。", "復值接輿醉，狂歌五柳前。"]'),
('f61aa962-4d0c-4cd1-b96b-4c515fe4e229','寄荆州張丞相','王維','唐','唐诗','tang','','["\u6000\u4eba", "\u6292\u60c5", "\u5199\u4eba"]','所思竟何在，悵望深荆門。',48,'全唐诗/poet.tang.5000.json','["所思竟何在，悵望深荆門。", "舉世無相識，終身思舊恩。", "方將與農圃，藝植老丘園。", "目盡南飛鴈，何由寄一言。"]'),
('6e4d001d-ec19-4bef-886b-a49267ec88c8','冬晚對雪憶胡居士家','王維','唐','唐诗','tang','','["\u601d\u5ff5", "\u5199\u96ea", "\u51ac\u5929", "\u96ea"]','寒更傳曉箭，清鏡覽衰顏。',48,'全唐诗/poet.tang.5000.json','["寒更傳曉箭，清鏡覽衰顏。", "隔牖風驚竹，開門雪滿山。", "灑空深巷靜，積素廣庭閑。", "借問袁安舍，翛然尚閉關。"]'),
('91b9a8a5-a751-4edc-8d7d-9ba0ff428022','和尹諫議史館山池','王維','唐','唐诗','tang','','[]','雲館接天居，霓裳侍玉除。',48,'全唐诗/poet.tang.5000.json','["雲館接天居，霓裳侍玉除。", "春池百子外，芳樹萬年餘。", "洞有仙人籙，山藏太史書。", "君恩深漢帝，且莫上空虛。"]'),
('6688fe24-3774-4619-90c3-53f950a45bc7','奉和楊駙馬六郎秋夜即事','王維','唐','唐诗','tang','','[]','高樓月似霜，秋夜鬱金堂。',48,'全唐诗/poet.tang.5000.json','["高樓月似霜，秋夜鬱金堂。", "對坐彈盧女，同看舞鳳凰。", "少兒多送酒，小玉更焚香。", "結束平陽騎，明朝入建章。"]'),
('982ea77f-d54e-4520-84f6-e97d07590d24','酬虞部蘇員外過藍田別業不見留之作','王維','唐','唐诗','tang','','[]','貧居依谷口，喬木帶荒村。',48,'全唐诗/poet.tang.5000.json','["貧居依谷口，喬木帶荒村。", "石路枉廻駕，山家誰候門。", "漁舟膠凍浦，獵火燒寒原。", "唯有白雲外，疎鐘聞夜猿。"]'),
('656d7352-c966-4e3c-a716-31a5cf090fcd','酬比部楊員外暮宿琴臺朝躋書閣率爾見贈之作','王維','唐','唐诗','tang','','[]','舊簡拂塵看，鳴琴候月彈。',48,'全唐诗/poet.tang.5000.json','["舊簡拂塵看，鳴琴候月彈。", "桃源迷漢姓，松樹有秦官。", "空谷歸人少，青山背日寒。", "羨君棲隱處，遙望白雲端。"]'),
('5198b849-a7e1-41d8-8374-65023370cd27','酬嚴少尹徐舍人見過不遇','王維','唐','唐诗','tang','','[]','公門暇日少，窮巷故人稀。',48,'全唐诗/poet.tang.5000.json','["公門暇日少，窮巷故人稀。", "偶值乘籃轝，非關避白衣。", "不知炊黍谷，誰解埽荆扉。", "君但傾茶椀，無妨騎馬歸。"]'),
('65e9c24b-bdbd-4ef9-9e14-012c8fde79b8','酬張少府','王維','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u8d60\u522b", "\u53cb\u60c5", "\u89c4\u529d", "\u4e94\u8a00\u5f8b\u8bd7"]','晚年唯好靜，萬事不關心。',48,'全唐诗/poet.tang.5000.json','["晚年唯好靜，萬事不關心。", "自顧無長策，空知返舊林。", "松風吹解帶，山月照彈琴。", "君問窮通理，漁歌入浦深。"]'),
('ee7d6f1c-26d6-426e-91dc-5d7bd2189c77','酬賀四贈葛巾之作','王維','唐','唐诗','tang','','[]','野巾傳惠好，茲貺重兼金。',48,'全唐诗/poet.tang.5000.json','["野巾傳惠好，茲貺重兼金。", "嘉此幽棲物，能齊隱吏心。", "早朝方暫挂，晚沐復來簪。", "坐覺囂塵遠，思君共入林。"]'),
('b17ef599-916e-4d87-8f7c-c1076a9ff298','送丘爲落第歸江東','王維','唐','唐诗','tang','','["\u53cb\u4eba", "\u9001\u522b"]','憐君不得意，況復柳條春。',48,'全唐诗/poet.tang.5000.json','["憐君不得意，況復柳條春。", "爲客黃金盡，還家白髮新。", "五湖三畝宅，萬里一歸人。", "知爾不能薦，羞稱獻納臣。"]'),
('611a726a-ada6-47be-8b94-cee54bb07429','送李判官赴東江','王維','唐','唐诗','tang','','["\u7231\u56fd", "\u52b1\u5fd7", "\u9001\u522b"]','聞道皇華使，方隨皁蓋臣。',48,'全唐诗/poet.tang.5000.json','["聞道皇華使，方隨皁蓋臣。", "封章通左語，冠冕化文身。", "樹色分揚子，潮聲滿富春。", "遙知辨璧吏，恩到泣珠人。"]'),
('684f6b6f-c85c-4f04-968e-2b7beefae631','送封太守','王維','唐','唐诗','tang','','[]','忽解羊頭削，聊馳熊首轓。',48,'全唐诗/poet.tang.5000.json','["忽解羊頭削，聊馳熊首轓。", "揚舲發夏口，按節向吳門。", "帆暎丹陽郭，楓攢赤岸村。", "百村多候吏，露冕一何尊。"]'),
('d30a7f2e-6471-4693-ba4b-34a61ab73587','送嚴秀才還蜀','王維','唐','唐诗','tang','','[]','寧親爲令子，似舅即賢甥。',48,'全唐诗/poet.tang.5000.json','["寧親爲令子，似舅即賢甥。", "別路經花縣，還鄉入錦城。", "山臨青塞斷，江向白雲平。", "獻賦何時至，明君憶長卿。"]'),
('d00c9bb5-f0bd-4256-8ebf-adc87e90c16e','送張判官赴河西','王維','唐','唐诗','tang','','[]','單車曾出塞，報國敢邀勳。',48,'全唐诗/poet.tang.5000.json','["單車曾出塞，報國敢邀勳。", "見逐張征虜，今思霍冠軍。", "沙平連白雪，蓬卷入黃雲。", "慷慨倚長劒，高歌一送君。"]'),
('7d5d3072-6ffd-48c7-9f82-a4cebd7271a4','送岐州源長史歸','王維','唐','唐诗','tang','','[]','握手一相送，心悲安可論。',48,'全唐诗/poet.tang.5000.json','["握手一相送，心悲安可論。", "秋風正蕭索，客散孟嘗門。", "故驛通槐里，長亭下槿原。", "征西舊旌節，從此向河源。"]'),
('ae0f0690-88e2-4f08-8e30-ab9e370a1164','送張道士歸山','王維','唐','唐诗','tang','','[]','先生何處去，王屋訪茅君。',48,'全唐诗/poet.tang.5000.json','["先生何處去，王屋訪茅君。", "別婦留丹訣，驅雞入白雲。", "人間若剩住，天上復離羣。", "當作遼城鶴，仙歌使爾聞。"]'),
('709fec89-040a-4bd4-bded-75c329c91dce','同崔興宗送衡嶽瑗公南歸','王維','唐','唐诗','tang','','[]','言從石菌閣，新下穆陵關。',48,'全唐诗/poet.tang.5000.json','["言從石菌閣，新下穆陵關。", "獨向池陽去，白雲留故山。", "綻衣秋日裏，洗鉢古松間。", "一施傳心法，唯將戒定還。"]'),
('68a713ee-c23e-499f-be71-218e8c364da5','送錢少府還藍田','王維','唐','唐诗','tang','','[]','草色日向好，桃源人去稀。',48,'全唐诗/poet.tang.5000.json','["草色日向好，桃源人去稀。", "手持平子賦，目送老萊衣。", "每候山櫻發，時同海燕歸。", "今年寒食酒，應是返柴扉。"]'),
('a9ec004c-e03b-4135-aa37-95bf49b86444','送丘爲往唐州','王維','唐','唐诗','tang','','[]','宛洛有風塵，君行多苦辛。',48,'全唐诗/poet.tang.5000.json','["宛洛有風塵，君行多苦辛。", "四愁連漢水，百口寄隨人。", "槐色陰清晝，楊花惹暮春。", "朝端肯相送，天子繡衣臣。"]'),
('a0755edb-2d34-43e2-85d8-a75a715b65a0','送元中丞轉運江淮','王維','唐','唐诗','tang','','[]','薄賦歸天府，輕徭賴使臣。',48,'全唐诗/poet.tang.5000.json','["薄賦歸天府，輕徭賴使臣。", "歡霑賜帛老，恩及卷綃人。", "去問珠官俗，來經石𧉧春。", "東南御亭上，莫使有風塵。"]'),
('a2c5d189-883e-4d48-82fc-61d0a04236bf','送崔九興宗遊蜀','王維','唐','唐诗','tang','','[]','送君從此去，轉覺故人稀。',48,'全唐诗/poet.tang.5000.json','["送君從此去，轉覺故人稀。", "徒御猶廻首，田園方掩扉。", "出門當旅食，中路授寒衣。", "江漢風流地，遊人何歲歸。"]'),
('b56a658b-696b-448a-93a2-1bb65f90b6c1','送崔興宗','王維','唐','唐诗','tang','','[]','已恨親皆遠，誰憐友復稀。',48,'全唐诗/poet.tang.5000.json','["已恨親皆遠，誰憐友復稀。", "君王未西顧，遊宦盡東歸。", "塞迥山河淨，天長雲樹微。", "方同菊花節，相待洛陽扉。"]'),
('9a845660-3346-4206-9336-1e6b7153db6d','送平澹然判官','王維','唐','唐诗','tang','','[]','不識陽關路，新從定遠侯。',48,'全唐诗/poet.tang.5000.json','["不識陽關路，新從定遠侯。", "黃雲斷春色，畫角起邊愁。", "瀚海經年到，交河出塞流。", "須令外國使，知飲月氏頭。"]'),
('bb6bf278-e522-47eb-8259-c710c0704379','送劉司直赴安西','王維','唐','唐诗','tang','','["\u6292\u60c5", "\u613f\u671b", "\u5199\u666f", "\u53cb\u4eba"]','絕域陽關道，胡沙與塞塵。',48,'全唐诗/poet.tang.5000.json','["絕域陽關道，胡沙與塞塵。", "三春時有雁，萬里少行人。", "苜蓿隨天馬，葡萄逐漢臣。", "當令外國懼，不敢覓和親。"]'),
('c6891896-fb80-4094-9f60-9fc3fe1c63ec','送趙都督赴代州得青字','王維','唐','唐诗','tang','','["\u9001\u522b", "\u5bb4\u4f1a"]','天官動將星，漢上柳條青。',48,'全唐诗/poet.tang.5000.json','["天官動將星，漢上柳條青。", "萬里鳴刁斗，三軍出井陘。", "忘身辭鳳闕，報國取龍庭。", "豈學書生輩，窗間老一經。"]'),
('24572750-df7d-4576-bdfe-928bf9dac33c','送方城韋明府','王維','唐','唐诗','tang','','[]','遙思葭菼際，寥落楚人行。',48,'全唐诗/poet.tang.5000.json','["遙思葭菼際，寥落楚人行。", "高鳥長淮水，平蕪故郢城。", "使車聽雉乳，縣鼓應雞鳴。", "若見州從事，無嫌手板迎。"]'),
('9350d236-229a-4651-b41d-bfbd6c032ab6','送李員外賢郎','王維','唐','唐诗','tang','','[]','少年何處去，負米上銅梁。',48,'全唐诗/poet.tang.5000.json','["少年何處去，負米上銅梁。", "借問阿戎父，知爲童子郎。", "魚牋請詩賦，橦布作衣裳。", "薏苡扶衰病，歸來幸可將。"]'),
('263b4a33-fd51-47e1-b49a-d84dd99a2e0f','送梓州李使君','王維','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u53cb\u60c5", "\u9001\u522b", "\u4e94\u8a00\u5f8b\u8bd7"]','萬壑樹參天，千山響杜鵑。',48,'全唐诗/poet.tang.5000.json','["萬壑樹參天，千山響杜鵑。", "山中一夜雨，樹杪百重泉。", "漢女輸橦布，巴人訟芋田。", "文翁翻教授，不敢倚先賢。"]'),
('421ddc1d-95a0-40a6-97c2-014d3d97c210','送張五諲歸宣城','王維','唐','唐诗','tang','','[]','五湖千萬里，況復五湖西。',48,'全唐诗/poet.tang.5000.json','["五湖千萬里，況復五湖西。", "漁浦南陵郭，人家春穀谿。", "欲歸江淼淼，未到草萋萋。", "憶想蘭陵鎮，可宜猿更啼。"]'),
('694bd102-5a6f-47a2-97d1-27fabf6b1399','送友人南歸','王維','唐','唐诗','tang','','["\u53cb\u4eba", "\u9001\u522b", "\u6292\u6000"]','萬里春應盡，三江雁亦稀。',48,'全唐诗/poet.tang.5000.json','["萬里春應盡，三江雁亦稀。", "連天漢水廣，孤客郢城歸。", "鄖國稻苗秀，楚人菰米肥。", "懸知倚門望，遙識老萊衣。"]'),
('73fa0e49-e214-4a99-9c59-d020beb7e18e','送賀遂員外外甥','王維','唐','唐诗','tang','','[]','南國有歸舟，荆門泝上流。',48,'全唐诗/poet.tang.5000.json','["南國有歸舟，荆門泝上流。", "蒼茫葭菼外，雲水與昭丘。", "檣帶城烏去，江連暮雨愁。", "猿聲不可聽，莫待楚山秋。"]'),
('4787f534-eb1a-4c3b-a785-6e36eadf9f45','送楊長史赴果州','王維','唐','唐诗','tang','','["\u6292\u60c5", "\u9001\u522b", "\u5199\u666f"]','襃斜不容幰，之子去何之。',48,'全唐诗/poet.tang.5000.json','["襃斜不容幰，之子去何之。", "鳥道一千里，猿聲十二時。", "官橋祭酒客，山木女郎祠。", "別後同明月，君應聽子規。"]'),
('21a94a4d-4363-406a-8455-45434aa80f7c','送邢桂州','王維','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56", "\u9001\u522b", "\u53cb\u60c5"]','鐃吹喧京口，風波下洞庭。',48,'全唐诗/poet.tang.5000.json','["鐃吹喧京口，風波下洞庭。", "赭圻將赤岸，擊汰復揚舲。", "日落江湖白，潮來天地青。", "明珠歸合浦，應逐使臣星。"]'),
('a0673da1-9ab0-4ca7-a262-3bdcd45c6f32','送宇文三赴河西充行軍司馬','王維','唐','唐诗','tang','','[]','橫吹雜繁笳，邊風捲塞沙。',48,'全唐诗/poet.tang.5000.json','["橫吹雜繁笳，邊風捲塞沙。", "還聞田司馬，更逐李輕車。", "蒲類成秦地，莎車屬漢家。", "當令犬戎國，朝聘學昆邪。"]'),
('f5a33e9a-00ff-486e-b4e4-d52eba32f9f9','送孫二','王維','唐','唐诗','tang','','[]','郊外誰相送，夫君道術親。',48,'全唐诗/poet.tang.5000.json','["郊外誰相送，夫君道術親。", "書生鄒魯客，才子洛陽人。", "祖席依寒草，行車起暮塵。", "山川何寂寞，長望淚沾巾。"]'),
('840dc45d-0273-411b-b52d-4e9568469537','送崔三往密州覲省','王維','唐','唐诗','tang','','[]','南陌去悠悠，東郊不少留。',48,'全唐诗/poet.tang.5000.json','["南陌去悠悠，東郊不少留。", "同懷扇枕戀，獨念倚門愁。", "路遶天山雪，家臨海樹秋。", "魯連功未報，且莫蹈滄洲。"]'),
('31555526-5589-474b-b33a-fcfb3381111c','送孟六歸襄陽','王維','唐','唐诗','tang','','[]','杜門不復出，久與世情疎。',48,'全唐诗/poet.tang.5000.json','["杜門不復出，久與世情疎。", "以此爲良策，勸君歸舊廬。", "醉歌田舍酒，笑讀古人書。", "好是一生事，無勞獻子虛。"]'),
('4766aeff-eb87-4444-9a72-e55d7e835f3e','初出濟州別城中故人','王維','唐','唐诗','tang','','[]','微官易得罪，謫去濟川陰。',48,'全唐诗/poet.tang.5000.json','["微官易得罪，謫去濟川陰。", "執政方持法，明君照此心。", "閭閻河潤上，井邑海雲深。", "縱有歸來日，各愁年鬢侵。"]'),
('7a527e41-ccaf-442c-98ea-99ab9b11a3bf','與盧象集朱家','王維','唐','唐诗','tang','','[]','主人能愛客，終日有逢迎。',48,'全唐诗/poet.tang.5000.json','["主人能愛客，終日有逢迎。", "貰得新豐酒，復聞秦女箏。", "柳條疎客舍，槐葉下秋城。", "語笑且爲樂，吾將達此生。"]'),
('557a9515-893f-47a8-bb20-a386c086ae16','登裴秀才迪小臺','王維','唐','唐诗','tang','','[]','端居不出戶，滿目望雲山。',48,'全唐诗/poet.tang.5000.json','["端居不出戶，滿目望雲山。", "落日鳥邊下，秋原人外閑。", "遙知遠林際，不見此簷間。", "好客多乘月，應門莫上關。"]'),
('0bc50082-4b70-443f-8c86-2026f52fbbfd','遊李山人所居因題屋壁','王維','唐','唐诗','tang','','[]','世上皆如夢，狂來止自歌。',48,'全唐诗/poet.tang.5000.json','["世上皆如夢，狂來止自歌。", "問年松樹老，有地竹林多。", "藥倩韓康賣，門容尚子過。", "翻嫌枕席上，無那白雲何。"]'),
('f78c57ff-c6a6-4a18-9412-3024660d7cd0','看花','何元','唐','唐诗','tang','','[]','莫怪出門先驟馬，暮年常怨看花遲。',32,'全唐诗/poet.tang.50000.json','["莫怪出門先驟馬，暮年常怨看花遲。", "可憐盡日春山下，似雪如雲一萬枝。"]'),
('cbe1dc97-2607-4a70-a751-9e3ad31210e9','句','何元','唐','唐诗','tang','','[]','一望白雲千萬斷，箏聲日暮出花林。',144,'全唐诗/poet.tang.50000.json','["一望白雲千萬斷，箏聲日暮出花林。", "門外夕陽寒映竹，洞中秋水暗連山。", "鐘聲半夜香山雨，散入前林楓葉秋。", "寺臨飛鳥青山遠，徑轉幽蘿白日長。", "黃昏人到鐘聲裏，雲起龍池不見山。", "客來惆悵僧禪後，月出松門滿地霜。", "朔風寒日笳聲急，萬里遼城一段雲。", "滿山月色連溪下，林葉蕭蕭一夜霜。", "秦客訪花驚出洞，庾公看月誤登樓。"]'),
('740c1743-61f4-4694-908b-6737af54523d','春夜宿雲際寺','斐公衍','唐','唐诗','tang','','[]','境靜聞鐘聲易響，庭高見月影難沈。',32,'全唐诗/poet.tang.50000.json','["境靜聞鐘聲易響，庭高見月影難沈。", "青山解隔塵中事，流水能清物外心。"]'),
('32f67de2-74f6-4cd6-810f-9a587913d4af','句','斐公衍','唐','唐诗','tang','','[]','碧澗水流高殿影，青蘿風散晚鐘聲。',32,'全唐诗/poet.tang.50000.json','["碧澗水流高殿影，青蘿風散晚鐘聲。", "數片殘雲歸洞口，孤輪晴月挂山頭。"]'),
('1ba636ab-c4b0-4a0f-83ed-dd7a5b4c37cc','聽琴','蘇替','唐','唐诗','tang','','[]','絃中恨起湘山遠，指下情多楚峽流。',32,'全唐诗/poet.tang.50000.json','["絃中恨起湘山遠，指下情多楚峽流。", "危檻曲終雲影曙，高樓風定燭光秋。"]'),
('53dc188c-b67b-4e38-a59d-667eca3b351a','賞春','路半千','唐','唐诗','tang','','[]','暖日當頭催展菜，和風次第遣開花。',32,'全唐诗/poet.tang.50000.json','["暖日當頭催展菜，和風次第遣開花。", "呼童遠取溪心水，待客來煎柳眼茶。"]'),
('513f5985-8d0d-46fe-9552-1f87ce640a04','句','路半千','唐','唐诗','tang','','[]','蒼翠暗消三暑熱，孤高能鎖四時煙。',48,'全唐诗/poet.tang.50000.json','["蒼翠暗消三暑熱，孤高能鎖四時煙。", "綠楊近浦堪垂釣，翠竹當軒好韻琴。", "百舌乍啼鶯學語，分明聽在指頭邊。"]'),
('c3a5be94-820f-45d8-97f3-206d21ea3023','句','賀蘭暹','唐','唐诗','tang','','[]','玉貌自宜雙黛翠，桃花獨笑一枝春。',176,'全唐诗/poet.tang.50000.json','["玉貌自宜雙黛翠，桃花獨笑一枝春。", "秋水未鳴遊女佩，寒雲空滿望夫山。", "黃閣暮蟲羅戶牗，紫庭春草遍階墀。", "綠耳半蔓湘浦竹，驪文亂點武陵花。", "遼陽客路千峰引，薊北鄉心片月知。", "山雲渺渺川程遠，木葉蕭蕭鴈過初。", "回鴈不傳鄉信去，秋風偏向客衣寒。", "千峰黛色因晴出，百谷泉聲欲暮寒。", "黛色迥臨滄海上，泉聲遙落白雲中。", "喜遇近臣楊得意，慙非詞客馬相如。", "秋迎曉月鴻聲早，日暎深山水氣寒。"]'),
('618d535c-598c-409a-a42d-55c3f23f3b50','句','傅溫','唐','唐诗','tang','','[]','霜墜中天衣覺冷，月臨虛牗紙偏明。',80,'全唐诗/poet.tang.50000.json','["霜墜中天衣覺冷，月臨虛牗紙偏明。", "春風暗翦庭前樹，夜雨偷穿石上苔。", "曲水兩行排鴈齒，斜橋一道蹈龍鱗。", "山深野客如禪客，夜久松聲似雨聲。", "花疑漢女啼妝淚，水似吳娃笑弄箏。"]'),
('ee1ab06d-b324-4c5b-b753-7c456868315e','句','曹戵','唐','唐诗','tang','','[]','花映晝天當戶日，樹搖晴暮上階煙。',80,'全唐诗/poet.tang.50000.json','["花映晝天當戶日，樹搖晴暮上階煙。", "驚飛沙鳥紛紛雪，候信雲帆片片風。", "鳳唱一拋琴瑟韻，霓裳長謝綺羅春。", "秋澄上水無藏影，春泛遊雲不繫心。", "老松不見千年鶴，殘雪猶疑六月花。"]'),
('1e3918d8-62ce-464b-a6c6-7995e6bdc915','句','陳素風','唐','唐诗','tang','','[]','三行故柳藏鴉樹，一帶長波灌竹泉。',64,'全唐诗/poet.tang.50000.json','["三行故柳藏鴉樹，一帶長波灌竹泉。", "千門竹影聯春色，一段和光徹翠微。", "西陵古木年年老，南陌風光日日新。", "百寶鏡輪金翡翠，五雲絲網玉蜘蛛。"]'),
('b1a1ff68-af19-46ca-bf34-3e0f3e7594db','句','唐樞','唐','唐诗','tang','','[]','窗竹閑陰秋水薄，砌苔新色曉嵐鮮。',48,'全唐诗/poet.tang.50000.json','["窗竹閑陰秋水薄，砌苔新色曉嵐鮮。", "不待江□移入座，便開三峽水來聲。", "芳字八行清露重，珠牋一片碧雲輕。"]'),
('879a4911-0d8f-4798-8a56-d227e785b075','句','溫達','唐','唐诗','tang','','[]','三春種樹梅兼李，十月看書雪替螢。',48,'全唐诗/poet.tang.50000.json','["三春種樹梅兼李，十月看書雪替螢。", "原公舊路唯三徑，潘岳新年已二毛。", "山底採薇雲不厭，洞中栽樹鶴先知。"]'),
('a8093a0b-6fe1-4dbe-8b64-4d0db3b7fa56','句','盧條','唐','唐诗','tang','','[]','三徑雨來煙草合，一邱琴後濁醪傾。',32,'全唐诗/poet.tang.50000.json','["三徑雨來煙草合，一邱琴後濁醪傾。", "共話世情塵藹藹，每嗟人事水潺潺。"]'),
('b26c70e3-c04c-4f45-9ef7-fcf673f42b07','句','崔行檢','唐','唐诗','tang','','[]','紫籜粉成應漸密，白雲岑起未全高。',32,'全唐诗/poet.tang.50000.json','["紫籜粉成應漸密，白雲岑起未全高。", "慙愧交親問生事，一溪雲鳥滿牀書。"]'),
('e80064b6-d3e5-4d20-abe7-60c9275d929f','句','陳上卿','唐','唐诗','tang','','[]','門前蕭索青松老，雲裏逍遙白鶴閑。',32,'全唐诗/poet.tang.50000.json','["門前蕭索青松老，雲裏逍遙白鶴閑。", "波瀾晴泛三春色，桃李爭開兩岸芳。"]'),
('b8ffeb82-5d61-4c74-bacc-b4883ac448a6','句','王幹','唐','唐诗','tang','','[]','莫驚此地逢春早，祗爲長安近日邊。',16,'全唐诗/poet.tang.50000.json','["莫驚此地逢春早，祗爲長安近日邊。"]'),
('dbb5bd2b-cf77-40d4-852b-ee8bf64ed44a','句','樊寔','唐','唐诗','tang','','[]','仍憐一夜春風急，開盡瑤池萬樹花。',16,'全唐诗/poet.tang.50000.json','["仍憐一夜春風急，開盡瑤池萬樹花。"]'),
('0a1c76ca-80a1-4287-9426-58f88edadb10','句','張殷衡','唐','唐诗','tang','','[]','已被夭桃歡來醉，麯塵絲樹恨何人。',16,'全唐诗/poet.tang.50000.json','["已被夭桃歡來醉，麯塵絲樹恨何人。"]'),
('4d46e4f1-5c3a-436a-b376-7bacb9f4cdf9','句','殷穆','唐','唐诗','tang','','[]','藤拂石溪流水淨，風來雲寺過鐘微。',16,'全唐诗/poet.tang.50000.json','["藤拂石溪流水淨，風來雲寺過鐘微。"]'),
('adaf34f4-56bc-4f09-a5b2-849fd10bc12b','句','解叔祿','唐','唐诗','tang','','[]','千花苑外韶芳暖，一鳥山邊翠色寒。',16,'全唐诗/poet.tang.50000.json','["千花苑外韶芳暖，一鳥山邊翠色寒。"]'),
('44453641-b5bc-4375-b254-354c4c65dca3','句','石嚴','唐','唐诗','tang','','[]','炎氣擁爲衣上火，汗光流出腹中湯。',16,'全唐诗/poet.tang.50000.json','["炎氣擁爲衣上火，汗光流出腹中湯。"]'),
('3321c4d5-a6a0-42c3-b1da-c9791d43297b','句','張野人','唐','唐诗','tang','','[]','銅街陌柳條條翠，金谷園花片片燃。',16,'全唐诗/poet.tang.50000.json','["銅街陌柳條條翠，金谷園花片片燃。"]'),
('2ddb256c-92da-46aa-85c0-a9dda021c6f6','句','衛填','唐','唐诗','tang','','[]','明月開時山夜白，暖泉流處草冬青。',16,'全唐诗/poet.tang.50000.json','["明月開時山夜白，暖泉流處草冬青。"]'),
('f892f15d-b50c-46ac-b0cd-56f122feea7b','句','虞搆','唐','唐诗','tang','','[]','寒光乍退風猶切，春色新行柳未知。',16,'全唐诗/poet.tang.50000.json','["寒光乍退風猶切，春色新行柳未知。"]'),
