('0a64b37d-63fe-45fe-b831-7356624b9982','句','奉蚌','唐','唐诗','tang','','[]','綠蘿翦作三春柳，紅錦裁成二月花。',16,'全唐诗/poet.tang.50000.json','["綠蘿翦作三春柳，紅錦裁成二月花。"]'),
('add85a26-6caf-4763-97e7-6a02560b90f9','海陽泉','無名氏','唐','唐诗','tang','','[]','人誰無耽愛，各亦有所偏。',96,'全唐诗/poet.tang.50000.json','["人誰無耽愛，各亦有所偏。", "於吾喜尚中，不厭千萬泉。", "誠知湟水曲，遠在南海壖。", "自從得海陽，便欲終老焉。", "怪石狀五岳，旋迴枕深淵。", "激繁似湧雲，靜同冰鏡懸。", "吾欲以海陽，跨於河洛間。", "使彼雲林客，來遊皆忘還。"]'),
('403c7a2b-60e1-40c6-a140-3c5ef4edda34','曲石鳧','無名氏','唐','唐诗','tang','','[]','爲愛水石奇，不厭湖畔行。',84,'全唐诗/poet.tang.50000.json','["爲愛水石奇，不厭湖畔行。", "每登曲石鳧，則有遠興生。", "𢼨差半湖□，宛若龍象形。", "又如瑯琊臺，□盤枕滄溟。", "醉人入島來，將醉強爲醒。", "扣船復搖棹，學歌漁父聲。", "呼我上酒船，更深江海情。"]'),
('0a930cdc-ff52-4f42-9e58-48c8b692034b','望遠亭','無名氏','唐','唐诗','tang','','[]','泛湖勞水戲，飲漱厭清瀾。',72,'全唐诗/poet.tang.50000.json','["泛湖勞水戲，飲漱厭清瀾。", "來登望遠亭，心目又不閑。", "孤峯入座□，高嶺橫前軒。", "更復歡長風，蕭寥窗戶間。", "外物能擾人，吾將息其端。", "歸來湖中館，□戶聊自安。"]'),
('d827bbc7-2b82-4437-b81b-5e174dcdc134','石上閣','無名氏','唐','唐诗','tang','','[]','水石引我去，南湖復東壑。',96,'全唐诗/poet.tang.50000.json','["水石引我去，南湖復東壑。", "不厭隨竹陰，來登石上閣。", "磴道通石門，欹崖斷如鑿。", "飛梁架峯頭，夭矯虹霓若。", "下視竹木杪，仰見懸泉落。", "水聲兼松吹，音響參衆樂。", "時時爲霧雨，飄灑溼簾箔。", "吾欲棄簪纓，於茲守寂寞。"]'),
('e7960bed-e9f1-4bda-8547-d4441d20f40d','石上閣','無名氏','唐','唐诗','tang','','[]','石上搆層閣，便以石爲柱。',96,'全唐诗/poet.tang.50000.json','["石上搆層閣，便以石爲柱。", "千載□棟梁，豈有□危懼。", "苔壁絕人蹤，虹橋橫鳥路。", "攀涉愜所懷，幽奇未嘗遇。", "迥然半空裏，物象競相助。", "雲外見孤峯，林端懸瀑布。", "引望無不通，茲焉倍多趣。", "徒□欲忘歸，衣裳溼煙霧。"]'),
('a327b9a1-b7fd-4968-9629-14ccaeeba574','海陽湖','無名氏','唐','唐诗','tang','','[]','吾漲海陽泉，以爲海陽湖。',84,'全唐诗/poet.tang.50000.json','["吾漲海陽泉，以爲海陽湖。", "千峯在水中，狀類皆自殊。", "有如三神山，蒼蒼海上孤。", "又似洲島中，忽然見龍魚。", "引船過石間，隨興得所如。", "每有愜心處，沈吟復躊躇。", "吾恐天地間，怪異如此無。"]'),
('18e7a88d-bf1b-429f-8b94-c1d6a26bdf9a','海陽湖','無名氏','唐','唐诗','tang','','[]','閑遊愛湖廣，湖廣叢怪石。',96,'全唐诗/poet.tang.50000.json','["閑遊愛湖廣，湖廣叢怪石。", "迴合萬里勢，□□□□□。", "綠動若無底，波澄涵雲碧。", "鎔水復何如，昆池吾不易。", "茲境多所尚，親鄰道與釋。", "外望雖異門，中間不相隔。", "開鑿盡天然，智者留奇跡。", "我願長此遊，誰言一朝夕。"]'),
('ad2c9baa-86e8-46d6-bed1-b67032d5c2e9','盤石','無名氏','唐','唐诗','tang','','[]','海陽泉上山，巉巉盡殊狀。',60,'全唐诗/poet.tang.50000.json','["海陽泉上山，巉巉盡殊狀。", "忽然有平石，盤薄千峯上。", "寒泉匝石流，懸注幾千丈。", "有時厭泉湖，愛臨一長望。", "意出天地間，因爲逸民唱。"]'),
('6deb4308-0057-4c80-9ebf-1058617b1533','盤石','無名氏','唐','唐诗','tang','','[]','下山復上山，山勢凌雲空。',60,'全唐诗/poet.tang.50000.json','["下山復上山，山勢凌雲空。", "有石圓且平，疑是□□功。", "清淺繞細泉，陰森倚長松。", "幕幕生青苔，亭亭對遠峯。", "朝來暮未歸，愛□□□□。"]'),
('96794408-6f3c-47b3-87a2-f220755833a6','湖下溪','無名氏','唐','唐诗','tang','','[]','海陽湖下溪，夾峯多異石。',48,'全唐诗/poet.tang.50000.json','["海陽湖下溪，夾峯多異石。", "數步□□□，溶溶似雲白。", "竹陰入□裏，更覺溪已碧。", "吾欲漱斯流，長爲避時客。"]'),
('4eb9bf37-08a1-42c3-ba70-0b347fbf2d47','湖下溪','無名氏','唐','唐诗','tang','','[]','湖水下爲溪，溪小趣更幽。',60,'全唐诗/poet.tang.50000.json','["湖水下爲溪，溪小趣更幽。", "窈窕林中迴，清泠石上流。", "掩映成碧潭，遊戲見白鷗。", "岸傍古樹根，往往疑潛虬。", "野情隨所適，世事何沈浮。"]'),
('8f409370-fc92-4064-8e82-ffb9cf70a2fd','夕陽洞','無名氏','唐','唐诗','tang','','[]','順山高幾許，亭亭似人蹲。',84,'全唐诗/poet.tang.50000.json','["順山高幾許，亭亭似人蹲。", "左右自迴抱，抱中有清源。", "異石匝階墀，巉巉快四軒。", "憑几見城邑，一峯當石門。", "自從得茲洞，愛之忘朝昏。", "吾欲老於此，便爲海陽人。", "誰爲高世者，與我能修鄰。"]'),
('42036caf-49a8-4ae5-b6d1-a01ba961c5a6','遊海門峽','無名氏','唐','唐诗','tang','','[]','沿流二十里，始到海門山。',96,'全唐诗/poet.tang.50000.json','["沿流二十里，始到海門山。", "仰視見兩崖，有如萬蓋懸。", "逐上幾千仞，猶未窮絕顛。", "上有外士家，半巖得湖泉。", "湖□昏且來，意其通海焉。", "忽此見靈怪，踟蹰不能旋。", "開襟當海風，目送歸海船。", "恨不到羅浮，丹溪尋列仙。"]'),
('5fb84910-bb96-4a44-9be0-066444a6a2b1','句','無名氏','唐','唐诗','tang','','[]','月知溪靜尋常入，雲愛山高且暮歸。',256,'全唐诗/poet.tang.50000.json','["月知溪靜尋常入，雲愛山高且暮歸。", "風吹帆席隨雲卷，鳥壓花枝覆水低。", "匹馬路傍乘月別，孤帆波上入雲飛。", "蹴踘場邊芳草短，鞦韆樹下落花多。", "看樹只愁花落盡，聽鶯不覺馬行遲。", "攜樽藉草情無極，對水看雲興有餘。", "文戰不曾眉得白，酒醖長覺面先紅。", "風裏一聲天上落，世人皆向五雲看。", "仙花又別三千歲，暮雨已迷十二峯。", "滿枝帶露將何似，曾見瓊樓素面啼。", "翠葉偃風如翦彩，紅花含露似啼妝。", "青蘿帶霧依松古，綠竹含煙泛水光。", "書吏優遊山色裏，琴堂閑冷水聲中。", "鐘鳴月下長洲苑，露溼殘花鳥亂啼。", "花攢屋上紅珠顆，筍滿籬根紫玉簪。", "花舞野塘鋪地錦，鳥鳴江樹送春聲。"]'),
('96fdf055-b6c6-4ab1-800e-7262c770af3f','遊仙窟詩 贈崔十孃','張文成','唐','唐诗','tang','','[]','今朝忽見渠姿首，不覺殷勤著心口。',180,'全唐诗/poet.tang.50000.json','["今朝忽見渠姿首，不覺殷勤著心口。", "令人頻作許叮嚀，渠家太劇難求守。", "端坐剩心驚，愁來益不平。", "看時未必相看死，難時那許太難生。", "沈吟處幽室，相思轉成疾。", "自恨往還疎，誰肯交遊密。", "夜夜空知心失眼，朝朝無便投膠漆。", "園裏花開不避人，閨中面子翻羞出。", "如今寸步阻天津，伊處留心更覓新。", "莫言長有千金面，終歸變作一抄塵。", "生前有日但爲樂，死後無春更著人。", "祗可徜徉一生意，何須負持百年身。"]'),
('8dd82a35-8e1d-4b97-9cb1-ba1ba7da2af2','遊仙窟詩 又贈十孃','張文成','唐','唐诗','tang','','[]','薰香四面合，光色兩邊披。',240,'全唐诗/poet.tang.50000.json','["薰香四面合，光色兩邊披。", "錦障劃然卷，羅帷垂半欹。", "紅顏雜綠黛，無處不相宜。", "豔色浮妝粉，含香亂口脂。", "鬢欺蟬鬢非成鬢，眉笑蛾眉不見眉。", "見許實娉婷，何處不輕盈。", "可憐嬌裏面，可愛語中聲。", "婀娜腰支細細許，䁠䀨眼子長長馨。", "巧兒舊來攜未得，畫匠迎生模不成。", "相看未相識，傾城復傾國。", "迎風帔子鬱金香，照日裙裾石榴色。", "口上珊瑚耐拾取，頰裏芙蓉堪摘得。", "聞名腹肚已猖狂，見面精神更迷惑。", "心肝恰欲摧，踊躍不能裁。", "徐行步步香風散，欲語時時梅子開。", "靨疑織女留星去，眉似姮娥送月來。", "含嬌窈窕迎前出，忍笑嫈嫇返卻回。"]'),
('271db649-cf67-4c3e-aafd-eecd874e57a5','遊仙窟詩 詠崔五嫂','張文成','唐','唐诗','tang','','[]','奇異妍雅，貌特驚新。',166,'全唐诗/poet.tang.50000.json','["奇異妍雅，貌特驚新。", "眉間月出疑爭夜，頰上花開似鬬春。", "細腰偏愛轉，笑臉特宜嚬。", "真成物外奇稀物，實是人間斷絶人。", "自然能舉止，可念無方比。", "能令公子百重生，巧使王孫千迴死。", "黑雲裁兩鬢，白雪分雙齒。", "織成錦繡騏驎兒，判繡裙腰鸚鵡子。", "觸處盡開懷，何曾有不佳。", "機關大雅妙，行步絕𡟛娃。", "傍人一一丹羅韈，侍婢三三綠線鞵。", "黃龍透入黃金釧，白燕飛來白玉釵。"]'),
('2893058c-de87-4b31-9753-5ac056a456ec','遊仙窟詩 詠雙樹','張文成','唐','唐诗','tang','','[]','新華發兩樹，分香遍一林。',48,'全唐诗/poet.tang.50000.json','["新華發兩樹，分香遍一林。", "迎風轉細影，向日動輕陰。", "戲蜂時隱見，飛蝶遠追尋。", "承聞欲採摘，若箇動君心。"]'),
('044ac4dd-dc8a-40e1-b66a-264e3794a2a4','遊仙窟詩 詠雙樹荅文成','崔十孃','唐','唐诗','tang','','[]','暫遊雙樹下，遙見兩枝芳。',48,'全唐诗/poet.tang.50000.json','["暫遊雙樹下，遙見兩枝芳。", "向日俱翻影，迎風竝散香。", "戲蝶扶丹萼，遊蜂入紫房。", "人今總摘取，各著一邊箱。"]'),
('aa1eecf2-6057-4b74-adec-6e7db0b7b33e','遊仙窟詩 詠花','張文成','唐','唐诗','tang','','[]','風吹遍樹紫，日照滿地丹。',24,'全唐诗/poet.tang.50000.json','["風吹遍樹紫，日照滿地丹。", "若爲交暫折，擎就掌中看。"]'),
('729ccced-6852-44aa-90d5-aa952e7fab2f','遊仙窟詩 詠花','崔十孃','唐','唐诗','tang','','[]','映水俱知笑，成蹊竟不言。',24,'全唐诗/poet.tang.50000.json','["映水俱知笑，成蹊竟不言。", "即今無自在，高下任渠攀。"]'),
('2eecc300-b3e9-4168-b8b3-27a6f6e3c54c','遊仙窟詩 遊後園','張文成','唐','唐诗','tang','','[]','昔時過小苑，今朝戲後園。',48,'全唐诗/poet.tang.50000.json','["昔時過小苑，今朝戲後園。", "兩歲梅花匝，三春柳色繁。", "水明魚影靜，林翠鳥歌喧。", "何須杏樹嶺，即是桃花源。"]'),
('0e45ea9d-3d99-415f-9682-b707f616f239','遊仙窟詩 遊後園','崔十孃','唐','唐诗','tang','','[]','梅蹊命道士，桃澗佇神仙。',48,'全唐诗/poet.tang.50000.json','["梅蹊命道士，桃澗佇神仙。", "舊魚成大劒，新龜類小錢。", "水湄唯見柳，池曲且生蓮。", "欲知賞心處，桃花落眼前。"]'),
('e062740a-1ef6-4155-97bb-1909c7f67109','遊仙窟詩 遊後園','崔五嫂','唐','唐诗','tang','','[]','極目遊芳苑，相將對花林。',48,'全唐诗/poet.tang.50000.json','["極目遊芳苑，相將對花林。", "露凈山光出，池鮮樹影沈。", "落花時泛酒，歌鳥或鳴琴。", "是時日將夕，攜樽就樹陰。"]'),
('abf2e343-d272-4509-9f0b-dd68e46582d6','遊仙窟詩 代蜂子答十孃','張文成','唐','唐诗','tang','','[]','觸處尋芳樹，都慮少物華。',24,'全唐诗/poet.tang.50000.json','["觸處尋芳樹，都慮少物華。", "試從香處覓，正值可憐花。"]'),
('0f76e61f-912a-4308-b2dc-d419a3f51b38','遊仙窟詩 別文成','崔十孃','唐','唐诗','tang','','[]','別時終是別，春心不值春。',48,'全唐诗/poet.tang.50000.json','["別時終是別，春心不值春。", "羞見孤鸞影，悲看一騎塵。", "翠柳開眉色，紅桃亂臉新。", "此時君不在，嬌鶯弄殺人。"]'),
('0ae0dc2d-c794-4329-b3e2-ef0afc68d0fd','遊仙窟詩 別文成','崔五嫂','唐','唐诗','tang','','[]','此時經一去，誰知隔幾年。',48,'全唐诗/poet.tang.50000.json','["此時經一去，誰知隔幾年。", "雙鳧傷別緒，獨鶴慘離絃。", "怨起移酲後，愁生落醉前。", "若使人心密，莫惜馬蹄穿。"]'),
('aab30de0-434f-42ce-809c-ce09462c7d66','遊仙窟詩 別十孃','張文成','唐','唐诗','tang','','[]','忽然聞道別，愁來不自禁。',48,'全唐诗/poet.tang.50000.json','["忽然聞道別，愁來不自禁。", "眼下千行淚，腸懸一寸心。", "兩劒俄分匣，雙鳧忽異林。", "慇懃惜玉體，勿使外人侵。"]'),
('adc71e29-b959-4b09-a297-082a1623fd34','遊仙窟詩 揚州青銅鏡留與十孃','張文成','唐','唐诗','tang','','[]','仙人好負局，隱士屢潛觀。',48,'全唐诗/poet.tang.50000.json','["仙人好負局，隱士屢潛觀。", "映水菱花散，臨風竹影寒。", "月下時驚鵲，池邊獨舞鸞。", "若道人心變，從渠照膽看。"]'),
('ceb5d266-e41d-4d9b-b49d-fe831ba96d8c','遊仙窟詩 手中扇贈文成','崔十孃','唐','唐诗','tang','','[]','合歡遊璧水，同心侍華闕。',48,'全唐诗/poet.tang.50000.json','["合歡遊璧水，同心侍華闕。", "颯颯似朝風，團團如夜月。", "鸞姿侵霧起，鶴影排空發。", "希君掌中握，勿使恩情歇。"]'),
('b072fc1c-3d34-4aac-9f5a-389492301441','遊仙窟詩 送張郎','香兒','唐','唐诗','tang','','[]','丈夫存行跡，慇懃爲數來。',24,'全唐诗/poet.tang.50000.json','["丈夫存行跡，慇懃爲數來。", "莫作浮萍草，逐浪不知迴。"]'),
('26250798-9b7b-4b4e-92c2-abd9aae686b7','遊仙窟詩 贈十孃','張文成','唐','唐诗','tang','','[]','人去悠悠隔兩天，未審迢迢度幾年。',32,'全唐诗/poet.tang.50000.json','["人去悠悠隔兩天，未審迢迢度幾年。", "縱使身遊萬里外，終歸意在十孃邊。"]'),
('52a31a6f-766d-416e-aca8-9cfad2acade3','遊仙窟詩 答文成','崔十孃','唐','唐诗','tang','','[]','天涯地角知何處，玉體紅顏難再遇。',32,'全唐诗/poet.tang.50000.json','["天涯地角知何處，玉體紅顏難再遇。", "但令翅羽爲人生，會些高飛共君去。"]'),
('65721ef6-7ad2-406d-909f-2fde56aa0084','原','李嶠','唐','唐诗','tang','','[]','王粲銷憂日，江淹起恨年。',48,'全唐诗/poet.tang.50000.json','["王粲銷憂日，江淹起恨年。", "帶川遙綺錯，分隰迥阡眠。", "膴膴橫周甸，莓莓闕晉田。", "方知急難響，長在鶺鴒篇。"]'),
('c6fd124d-a2c7-40b6-a54f-0cc7543791cc','河','李嶠','唐','唐诗','tang','','[]','河出崑崙中，長波接漢空。',48,'全唐诗/poet.tang.50000.json','["河出崑崙中，長波接漢空。", "桃花生馬頰，竹箭入龍宮。", "德水千年變，榮光五色通。", "若披蘭葉檢，還沐土皇風。"]'),
('21dc9c0a-2c78-4268-8d76-58c50cc4c611','檄','李嶠','唐','唐诗','tang','','[]','羽檄本宣明，由來敷木聲。',48,'全唐诗/poet.tang.50000.json','["羽檄本宣明，由來敷木聲。", "聯翩通漢國，迢遞入燕營。", "毛義持書去，張儀韞璧行。", "曹風雖覺愈，陳草始知名。"]'),
('9f502d35-815f-4bb8-acf1-bae384137560','戈','李嶠','唐','唐诗','tang','','[]','富父舂喉日，殷辛漂杵年。',48,'全唐诗/poet.tang.50000.json','["富父舂喉日，殷辛漂杵年。", "曉霜含白刃，落影駐琱鋋。", "夕擯金門側，朝提玉塞前。", "願隨龍影度，橫陣彗雲邊。"]'),
('e8a1acb9-a691-4f29-bc84-cb6cb9abe539','簫','李嶠','唐','唐诗','tang','','[]','虞舜調清管，王褒賦雅音。',48,'全唐诗/poet.tang.50000.json','["虞舜調清管，王褒賦雅音。", "參差橫鳳翼，搜索動猿吟。", "靈鶴時來到，仙人幸見尋。", "爲聽楊柳曲，行役幾傷心。"]'),
('8eac90c7-4a21-4bbb-926e-42821178d108','素','李嶠','唐','唐诗','tang','','[]','濯手天津女，纖腰洛浦妃。',48,'全唐诗/poet.tang.50000.json','["濯手天津女，纖腰洛浦妃。", "魚腸遠方至，鴈足上林飛。", "妙奪鮫綃色，光騰月扇輝。", "非君下路去，誰賞故人機。"]'),
('a41c3fc8-666f-4d0f-859a-90ceebedf1b7','題梵書（伯三九八六）','唐明皇','唐','唐诗','tang','','[]','毫（鶴）立蛇形勢未休，五天文字鬼神愁。',207,'全唐诗/poet.tang.50000.json','["毫（鶴）立蛇形勢未休，五天文字鬼神愁。", "支那弟子無言語，穿耳胡僧笑點頭。", "（〖1〗這首詩雖不見《全唐詩》和《全唐詩逸》，在敦煌本沒有出現以前，是曾經廣泛流傳的。", "依余所知，最早的是一○七七年陝西咸甯縣臥龍寺的石刻本，但題太宗，不作玄宗。", "一三○八年河南登封縣的刻石，又題玄宗，不作太宗。", "敦煌本標題作《玄宗題梵書》，證明這首詩在唐末已經流傳，而且證明在唐末是題玄宗作的。", "石刻資料見於王昶的《金石萃編》卷一三七，錄附於後。", "）。"]'),
('026ded1c-0b0c-40bb-8f00-8ef1d6819b1e','唵字贊（義靜三藏於西天取得此梵書「唵」字，所在之地，一切鬼神，見聞者無不驚怖。）','唐明皇','唐','唐诗','tang','','[]','鶴立蛇行勢未休，五天文字鬼神愁。',88,'全唐诗/poet.tang.50000.json','["鶴立蛇行勢未休，五天文字鬼神愁。", "儒門弟子無人識，穿耳胡僧笑點頭。", "（〖1〗京兆住持十方福應禪院講經論傳戒沙門惟果立石。", "〖2〗大宋丁巳熙寧十年〖一○七七〗八月二十六日安石師刊。", "）。"]'),
('f1d76f18-ca54-433a-bae0-68d65786d57a','佛教梵文唵字唐玄宗書並讀（原刻石在河南登封，還有御製《老子讚》。） 一','唐明皇','唐','唐诗','tang','','[]','鶴立蛇形勢未休，五天文字鬼神愁。',162,'全唐诗/poet.tang.50000.json','["鶴立蛇形勢未休，五天文字鬼神愁。", "龍盤梵質層峯峭，鳳展翔儀乙卷收。", "正覺印同真聖道，邪魔交秘絕蹤由。", "儒門弟子應難識，碧眼胡僧笑點頭。", "（〖1〗至大元年〖一三○八〗中元日法三灑掃太原祖昭立石，德淵刻。", "〖2〗按石本以外，鈔本的流傳應該更多，筆記和方志內還有一些徵引。", "我所見到的有正德《中牟縣志》卷七，登載著唐太宗《題梵菴篆符》云：）。"]'),
('ee418f41-39c8-4cfa-ab8f-a94fcb09419b','佛教梵文唵字唐玄宗書並讀（原刻石在河南登封，還有御製《老子讚》。） 二','唐明皇','唐','唐诗','tang','','[]','鶴立蛇形勢未休，五尺文字鬼神愁。',72,'全唐诗/poet.tang.50000.json','["鶴立蛇形勢未休，五尺文字鬼神愁。", "儒門弟子無人識，穿耳胡僧笑點頭。", "（〖1〗現在根據最古的敦煌本補入，而把所知所見的石本刻本作爲附錄，以便參攷。", "）。"]'),
('85d6cff5-9f3f-4995-b8ea-884dc9d03979','度大臾（庾）嶺（其二伯三六一九）','宋之問','唐','唐诗','tang','','[]','城邊問官使：「早晚發西京？來日河橋柳，春條幾寸生？昆池水合淥，御苑草應青？」緩緩從頭說，教人眼暫明。',82,'全唐诗/poet.tang.50000.json','["城邊問官使：「早晚發西京？來日河橋柳，春條幾寸生？昆池水合淥，御苑草應青？」緩緩從頭說，教人眼暫明。", "（按《度大臾嶺》二首，《全唐詩》僅載「其一」，茲補「其二」。", "）。"]'),
('cb298b3c-6949-450d-9dca-01e72919410f','','崔湜','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.50000.json','["。"]'),
('d24578fd-65c6-490f-aa49-9866576f0638','責躬詩（斯二七一七下同）','崔湜','唐','唐诗','tang','','[]','嘗聞古人說：「正直神不欺。',175,'全唐诗/poet.tang.50000.json','["嘗聞古人說：「正直神不欺。", "」忠義恆獨守，堅貞每自持。", "効官已十載，理劇猶未期，獄聽除苛慘，刑章息滯疑。", "豈得保世業，諒以答明時；顧無白玉玷，忽負蒼蠅詩。", "扃固（錮）非所恥，幽寃誰爲辭！楚囚應積[□]，秦繫亦銜悲。", "永夜振衣坐，故人不在茲。", "流靈自蕪漫，芳草獨葳蕤。", "日月行無舍，平生志莫追。", "山林如道喪，州縣豈心期？", "助思紛何在，清神悵不怡。", "自憐暗成事，感歎興此詞。"]'),
('76a778ea-6aeb-46db-96dc-8cc5586ed23d','暮秋書懷','崔湜','唐','唐诗','tang','','[]','首夏別京輔，杪秋滯三河。',122,'全唐诗/poet.tang.50000.json','["首夏別京輔，杪秋滯三河。", "沉沉蓬萊閣，日夕鄉思多。", "霜剪涼墀蕙，風捎幽渚荷。", "歲芳坐淪歇，感此至微歌。", "（〖1〗按這一首，《全唐詩》卷三一作爲魏徵的詩，而《珠英集》作崔湜；《珠英集》應可據，故仍補入崔湜名下。", "第七句「淪歌」有誤，依《全唐詩》應作歇。", "）。"]'),
('34d12f77-9f60-4527-ba72-162036e2cffc','雜詩','崔湜','唐','唐诗','tang','','[]','鵲巢惡木巔，常窘一枝息；寧知猗（椅）[一]（原卷作「椅」）梧鳳，亦欲此栖宿！喈喈多好音，矯矯奮輕翼，上林豈不成，（蔣禮鴻〖簡稱「蔣」〗、項楚〖簡稱「項」〗皆云：',213,'全唐诗/poet.tang.50000.json','["鵲巢惡木巔，常窘一枝息；寧知猗（椅）[一]（原卷作「椅」）梧鳳，亦欲此栖宿！喈喈多好音，矯矯奮輕翼，上林豈不成，（蔣禮鴻〖簡稱「蔣」〗、項楚〖簡稱「項」〗皆云：「成」當作「茂」。", "原卷作「茂」。", "）胡爲戀幽仄？", "處陋仍莫保，居華固陵偪，下流不可居[二]斯言可佩服。", "（[一]俞平伯先生云：「『猗梧』當作『椅梧』。", "《詩·定之方中》：『椅桐梓漆。", "』」[二]劉盼遂先生云：「司馬遷《報任少卿書》云：負下未易居，下游多謗議，此合爲一句。", "」）。"]'),
('86d89182-c101-40df-9b8b-7cab7f877caf','九龍潭作','崔湜','唐','唐诗','tang','','[]','弱齡聞茲山，夢寐嘗所適。',377,'全唐诗/poet.tang.50000.json','["弱齡聞茲山，夢寐嘗所適。", "迨[□][一]此躋覽，（蔣云：「闕文應在『此』字下。", "」）依然是疇昔。", "結侶尋絕徑，周流觀奇迹。", "茲逢世所希，環令佨窮壁。", "（「令佨」，蔣、項皆校作「合抱」。", "項釋此句云：「謂九龍潭四面爲絕壁所環抱也。", "」）上有龍泉湧，百丈[□]潨射。", "伏溜至陰溝，盤渴沸嵌石。", "（「盤渴」，蔣、項皆校作「盤渦」。", "）逶迤環汀嶼，熠㷿洞金碧。", "（「熠㷿」，蔣、項皆校作「熠爚」。", "「洞」，項校作「洄」。", "）石蔓下離縷，雲蘿上綿冪。", "翫極不云厭，徘徊忽惡夕。", "清瀬飛絲篁，茂草代茵席。", "冷然聞鳳吹，（「冷然」，蔣、項皆校作「泠然。", "」）髣髴覯雲藉（際）[二]。", "（「雲藉」，蔣云「藉」爲「舄」字音近之借。", "舉《風俗通義》載王喬故事爲證。", "）顧音攜手人，誰爲挂冠客？（[一]句內脫一字，不知應在何處？茲依韻補於此。", "[二]俞云：「『雲藉』疑當作『雲籍』，仙籍之意。", "如改『際』字，失叶。", "」）。"]'),
('ba468d98-b39a-4222-9e9a-0dffba3bd70e','幽居（斯五五五。下同）','王勃','唐','唐诗','tang','','[]','澗戶風前竹，山空月下琴。',40,'全唐诗/poet.tang.50000.json','["澗戶風前竹，山空月下琴。", "（項疑「山空」爲「山窗」之誤。", "）唯餘兩□□，應盡百年心。"]'),
('762ce354-dc3c-4ea5-b585-8b71360262dd','寺中觀臥像','王勃','唐','唐诗','tang','','[]','淨宇流金□，直誠翳寶床。',24,'全唐诗/poet.tang.50000.json','["淨宇流金□，直誠翳寶床。", "自應歸寂滅，非是倦津梁。"]'),
('af38a8de-fe2b-48aa-a15d-ddd709b86967','詠漢武帝（斯二七一七下同）','王無競','唐','唐诗','tang','','[]','漢家中葉盛，六世有雄才。',198,'全唐诗/poet.tang.50000.json','["漢家中葉盛，六世有雄才。", "廐馬三十萬，國容何壯裁（哉）！東歷瑯琊郡，北上單于臺。", "好僊復寵戰，莫救茂陵●[一]。", "（蔣云「●」以作隈爲是，「隈」有敗壞之義。", "）（[一]「●」字不可識，疑當作「隈」。", "劉云：「『隈』當是煨之誤。」", "《說文》：煨，燼餘火也。", "茂陵雖未聞焚燒之事，然陳沈烱《經通天臺奏漢武帝表》云：「茂陵玉椀，遂出人間，雲凌故基，與原田而每每；扶風餘趾，帶陵阜而芒芒」，亦正是茂陵煨燼的寫照了。", "）。"]'),
('1d8e4563-8ca8-4e04-8e20-3c447be67061','駕幸長安奉使先往檢察','王無競','唐','唐诗','tang','','[]','奉使至京邑，戒塗歷險夷。',198,'全唐诗/poet.tang.50000.json','["奉使至京邑，戒塗歷險夷。", "首旬發定鼎[一]，再信過灞池。", "河山壯關輔，金火遞雄雌。", "文物淪霸運，靈符啟聖青。", "宸扆闊臨御，巡幸順謳思。", "城闕生光彩，草樹含榮滋。", "緹綺（騎）[二]紛沓襲，翠旗曳葳蕤。", "童幼聞明主，耆老感盛儀。", "輪袂交隱隱，廛陌滿熙熙。", "微臣昧所識，觀俗書此詞。", "（[一]劉云：「定鼎見《左傳》，成王定鼎於郟鄏，此處用以代表洛陽。", "又考唐代洛陽城郭南而第二門名定鼎門，爲西行必由門戶。", "」[二]依劉校。", "）。"]'),
('90aa8a94-85d4-45bd-963f-ed0551460210','滅胡','王無競','唐','唐诗','tang','','[]','漢軍屢北喪，胡馬遂南駈。',158,'全唐诗/poet.tang.50000.json','["漢軍屢北喪，胡馬遂南駈。", "羽書夜驚急，邊柝亂傳呼。", "鬬軍卻不進，關城勢已孤。", "黃雲塞沙落，（項云「落」當作「路」。", "蔣云「落」爲「聚落」、「村落」之「落」。", "）白刃斷交衢。", "朔霧圍未解，鑿山泉尚枯。", "伏波塞後援，都尉失前途。", "亭障多墮毀，金鏃無金（全）[一]軀。", "獨有山東客，上書圖滅胡。", "（[一]俞云：「第二『金』是『全』之誤。", "」）。"]'),
('48b11008-7807-402b-84eb-720ddb6cdcea','君子有所思行','王無競','唐','唐诗','tang','','[]','北上登渭原，南下望咸陽。',272,'全唐诗/poet.tang.50000.json','["北上登渭原，南下望咸陽。", "秦帝昔所據，按劍朝侯王。", "踐山𪟖（劃）郊郭，濬流固墉隍。", "左右羅將相，甲館臨康莊。", "曲臺連閣道，錦幕接洞房。", "荆國徵艷色，邯鄲選名倡。", "一彈入雲漢，再歌斷君腸。", "自矜青春日，王顏𢗞容光。", "（「王顏」，蔣、項皆云當作「玉顏」。", "「𢗞」，蔣云當作「恡」，惜也。", "原卷作「恡」。", "）安知綠苔滿，羅袖坐霑霜。", "聲侈遽衰歇，盛愛且離傷。", "豈唯毒身世，朝國亦淪亡。", "（「朝國」，項疑當作「邦國」。", "）物盈道先忌，（「物盈」，項云當作「惡盈」。", "）履謙宇允臧。", "獨有東陵子，種瓜青門旁。", "（[一]俞云：「『𢗞』乃『恡』之簡體，即『悋，吝』。", "」劉云：「當作『怯』。", "」）。"]'),
('9d0cd728-56f2-41da-a1cc-12e4fb8a2dbe','度嶺（二首。斯五五五） 一','閻朝隱','唐','唐诗','tang','','[]','嶺南流水嶺南流，嶺北遊人望嶺頭。',35,'全唐诗/poet.tang.50000.json','["嶺南流水嶺南流，嶺北遊人望嶺頭。", "感念鄉園不可□，肝腹（腸）一斷一廻愁。"]'),
('fd2e1b96-2dd3-4e6a-8705-ebce89553b61','度嶺（二首。斯五五五） 二','閻朝隱','唐','唐诗','tang','','[]','千重江水萬重山，毒瘴□氛道路間。',290,'全唐诗/poet.tang.50000.json','["千重江水萬重山，毒瘴□氛道路間。", "（「□氛」，項云闕字當是「氳」字。", "）迴首俛眉但下淚，不知何處是鄉關。", "（〖1〗這兩首詩的詩題辨不出來。", "《舊唐書》卷一百九十中《文苑傳》，說「張易之伏誅〖神龍元年，七○五〗，坐徙嶺外」。", "《新唐書》卷二百二《文藝傳》，又說他「景龍〖七○七--七○九〗初，自崖州遇赦還」。", "這兩首詩應該是他「遇赦還」時候作的。", "王仲聞先生云：「唐芮挺章《國秀集》卷上載宋之問七古一首，題云：《端州驛見杜審言王無竭沈佺青閻朝隱有題慨然成詠》。", "朝隱這兩首詩，殆即爲端州題壁，都是他們南徙時所作，也就都是宋之問所見的那些詩。", "」〖項考此二詩爲南徙時過大庾嶺作。", "與端州題壁詩無關。", "〗）。"]'),
('7817e697-f704-4146-9319-7bc34ee1af20','送友人向恬（括）[一]（原卷作「括」。）州（斯二七一七）','李適','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','委迤吳山雲，演漾洞庭水。',129,'全唐诗/poet.tang.50000.json','["委迤吳山雲，演漾洞庭水。", "青楓既愁人，白頻（蘋）亦靡靡。", "送君出京國，孤舟眇江氾。", "（「江氾」，蔣云當作「江汜」。", "）浮陽怨芳歲，況乃別行子。", "括蒼漲海壖，斯路天台[□]。", "我有巖中念，遙寄四明裏。", "（[一]劉云：「『恬』乃『括』之誤，今浙江麗水，唐避德宗諱改處州。", "」）。"]'),
('d41b6773-7e2e-4c43-8d20-26b33f411017','九日至江州問王使君（斯五五五）','蔡孚','唐','唐诗','tang','','[]','九日尋（潯）陽縣，門門有菊花。',180,'全唐诗/poet.tang.50000.json','["九日尋（潯）陽縣，門門有菊花。", "□□今送酒，（蔣云：「闕文二當爲『白衣』。", "」）若箇是陶家？", "（〖1〗按王使君疑指王勃，所以《全唐詩》卷五六把這一首編入王勃名下，恐怕不對。", "《全唐詩》的文字不盡相同，錄出以便參閱。", "〖項云：「唐代『使君』乃是對刺史的尊稱。", "王勃幷未擔任過這類官職。", "整『王使君』當另有其人。", "蓋王姓江州刺史也。", "」「或是王勃道出江州時。", "寫給王姓刺史的。", "」〗）。"]'),
('0dfd7481-431a-4f4c-87e3-f22f8faee2a9','九日','蔡孚','唐','唐诗','tang','','[]','九日重陽節，開門有菊花。',12,'全唐诗/poet.tang.50000.json','["九日重陽節，開門有菊花。"]'),
('90e6b2bd-069d-4dc5-9312-657142fa8d30','雜詩（伯三七七一。下同）','喬備','唐','唐诗','tang','','[]','蹔借金鎚秤，銜涕訴恩波。',120,'全唐诗/poet.tang.50000.json','["蹔借金鎚秤，銜涕訴恩波。", "君情將妾怨，稱取謂誰多？", "秋吹綾紈索[一]，（「綾」原卷作「淩」。", "）空閨生網羅。", "不期《流水引》，翻作《斷腸歌》？", "（[一]俞云：「『綾紈索』三字不可解，必有誤字。", "按下句句法，『綾』字當是一個動詞，疑當作『陵紈素』。", "」）。"]'),
('00809229-fe6e-48c6-9783-38a1cab1dfe1','秋夜巫山','喬備','唐','唐诗','tang','','[]','巫峽徘徊雨，陽臺潭[一]蕩雲。',82,'全唐诗/poet.tang.50000.json','["巫峽徘徊雨，陽臺潭[一]蕩雲。", "江山空窈窕，朝暮自氛氳。", "螢色寒秋露，猿啼清夜聞。", "唯憐夢魂遠，腸斷思紛紛。", "（[一]俞云：「『潭』當作『澹』。", "」劉云：「潭蕩雙聲字。", "」）。"]'),
('1bcc31b2-eb4e-4ef2-8393-8f7db818f4a9','死馬賦（伯三六一九）','劉希移','唐','唐诗','tang','','[]','連山四望何高高，良馬本代君子勞；燕地冰堅傷凍骨，胡天霜縮落縮寒毛。',554,'全唐诗/poet.tang.50000.json','["連山四望何高高，良馬本代君子勞；燕地冰堅傷凍骨，胡天霜縮落縮寒毛。", "願君迴來鄉山道，道傍青青饒美草；鞭策尋途未敢迷，希君少留卷（養）[二]疲老。", "（「卷」，原卷作「養」。", "）君其去去途未窮，悲鳴羸臥此山中；桃花零落三春月，桂枝摧折九秋風。", "昔是浮光疑曳練，常時躡景如流電；長揪塵闇形影遙，（「長揪」，蔣、項皆云當作「長楸」。", "）上策（林）[三]（「策」，原卷作「葉」。", "）日明蹤跡偏（徧）。", "漢女[四]彈弦怨離別，楚王興歌苦征戰；赤血霑霑（君）[五]君不知，白骨辭君君不見。", "少年馳射出幽幷，高秋搖落重橫行；雲中想見遊龍影，月下思聞飛鵲聲。", "千里相思浩如失，一代英雄從此畢；鹽車垂耳不知年，粧樓畫眉寧記日？", "高門待封杳無期，遷喬題柱即長辭；（「遷喬」，蔣校作「僊橋」，指成都昇僊橋，用《華陽國志》載司馬相如事。", "）八駿馳名終已矣，千金賣（買）骨復何時？", "（[一]劉希夷的詩在敦煌卷子裏面傳鈔的不少，如《白頭老翁》〖《全唐詩》作《代悲白頭翁》〗有三個寫本，並且題着劉希夷的名字。", "和《死馬賦》寫在同一卷子〖伯三六一九〗上的，還有《擣衣篇》和《北邙篇》〖《全唐詩》作《洛川懷古》〗，《擣衣篇》也題着劉希夷的名字。", "此題作「劉希移」，誤。", "[二]依俞、劉說。", "[三]依劉校。", "[四]劉云：「漢女謂烏孫公主，見石崇《王明君辭序》。", "」[五]依俞校。", "）。"]'),
('14e7127f-7e01-4dd1-a83a-66bb3708cb18','北邙篇（[一]伯二六七三斯二○四九伯二五四四）','劉希移','唐','唐诗','tang','','[]','南橋昏曉人萬萬[二]，北邙新故塚千千。',520,'全唐诗/poet.tang.50000.json','["南橋昏曉人萬萬[二]，北邙新故塚千千。", "自爲驕奢彼都邑，何圖零落此山顛。", "（「爲」，蔣、項皆云通「謂」字。", "）不知虛魄尋[三]歸路，但見殭屍委墓田。", "青松樂飲無容色，白骨生台（苔）[四]有歲年。", "地久□松摧爲薪，（項云闕字應是「青」字。", "）天長[五]白骨化爲塵。", "碧山明月徒自曉，黃居闇室不知晨。", "（「黃居」，蔣云當作「黃泉」。", "）漢家城廓（郭）[六]帝王州[七]，晉國衣棺（冠）車馬流。", "金國（谷）清（青）春珠騎（綺）舞，同（銅）堦碧樹玉人遊，雲起清盈驕畫閣，水堂明逈弄仙舟。", "始憶斷歌催一代，（「斷歌」，項云當作「短歌」。", "）娥（俄）悲長夜歷千秋。", "秋楓至兮冬雪明，春兩息兮夏雲生。", "墨池沙枯通草萬（蔓）[八]，粧樓凡（瓦）[九]盡向林傾。", "古篋重書宜筆跡，崩（路）[一○]臺鶴胃若弦聲。", "（「篋」，項云當作「{𥫗/巫/八}」，同「策」，謂簡書。", "「重書」，項云當作「蟲書」。", "「宜」，項云當作「疑」，與「若」「同義對舉」。", "）不信草經延墓（暮）[一一]齒，（「草經」，項疑當作「丹」，「丹經」與「青史」爲對。", "）惟求清（青）史列虛銘（名）。", "嗚呼哀哉洛陽道，相斯（思）相望蓬萊島，玉顏暉暉並是春，人髪青青未嘗老。", "星簾捲兮月牎開，鏡花搖兮山樹逈。", "（「迥」，蔣、項皆云當作「迴」。"]'),
('c60496bf-3e78-42af-b07f-5b4e85b20a30','長門怨（[一]伯三一九五二七四八）','魏奉古','唐','唐诗','tang','','[]','長安[二]桂殿倚空城，每至黃昏愁轉盈，舊來偏得君王意，今是無端寵愛輕。',370,'全唐诗/poet.tang.50000.json','["長安[二]桂殿倚空城，每至黃昏愁轉盈，舊來偏得君王意，今是無端寵愛輕。", "窈窕容華爲誰惜，長門一閉無行跡，聞道他人更可憐，懸知欲垢終無益。", "（「垢」，蔣、項皆云當作「妬」。", "二本原卷此字作「姤」。", "）星移北斗露凄凄，羅幔䄡䄡風入閨，（「䄡䄡」，項云當作「襜襜」）孤燈欲滅留殘焰，明月初團照夜啼。", "向月唯須影調逐，不如纔（疇）[三]昔同今（八）屋，雲浮彫練此城[四]遊，（「練」，蔣疑當作「棟」，項云當是「闌」字的形訛。", "「彫闌」同「雕欄」。", "）花綴珠衾紫臺宿。", "自從捐棄在深宮，君處芳音更不通，黃今（金）買得《長門賦》，祇爲寒床夜夜空。", "（[一]《樂府詩集》卷四十二載《長門怨》二十七首，作者二十三人，不及魏奉古。", "這首《長門怨》，好像宋代已經不很流傳了。", "[二]「長安」原卷作「長門」依伯二七四八號寫本改。", "[三]依俞說。", "[四]俞云：「此城疑北城，但未敢定。", "」）。"]'),
('5c169822-fbf9-4cc0-ade4-fcb945e1a05e','次河神廟虞參軍船先發余阻風不進寒夜旅泊（斯二七一七下同）','劉知幾','唐','唐诗','tang','','[]','朝謁馮夷詞（祠），夕投投孟津渚。',139,'全唐诗/poet.tang.50000.json','["朝謁馮夷詞（祠），夕投投孟津渚。", "風長川淼漫，河闊舟容與。", "迴首望歸途，連山曖相拒。", "落帆遵逈岸，輟榜依孤嶼。", "復值驚彼（波）息，戒徒候前侶。", "川路雖未遙，心期頓爲阻。", "沉沉落日暮，切切涼飈舉。", "白露濕寒葭，蒼烟晦平楚。", "啼猿響巖谷，淚鶴聞河溆。", "此時懷故人，依然愴行旅。", "何當欣既覯，鬱陶共君敍。"]'),
('63e84be7-734e-41a9-b173-4a79de070797','讀《漢書》作','劉知幾','唐','唐诗','tang','','[]','漢王有天下，欻起布衣中。',202,'全唐诗/poet.tang.50000.json','["漢王有天下，欻起布衣中。", "奮飛出草澤，嘯咤馭羣雄。", "淮陰既附鳯，黥彭亦攀龍，一朝逢運會，南面皆王公。", "魚得自忘筌，鳥盡必藏弓，咄嗟罹鼎俎，赤族無遺蹤。", "智裁（哉）張子房，處世獨爲工；功成薄愛（受）[一]賞，（「愛」，蔣云當作「爵」。", "）高舉追赤松。", "知止信無辱，身安道亦隆，悠悠[千]載後，擊抃（柝）[二]仰遺風。", "（「擊抃」，蔣、項皆云「抃」字不誤。", "）（[一][二]並依俞說。", "劉云：「左思《詠史》，功成不受爵。", "」）。"]'),
('aab41025-4350-4ee5-ae77-71dd10dd3913','詠史','劉知幾','唐','唐诗','tang','','[]','汎汎水中蓱，離離岸傍草，逐浪高復下，從風起還倒。',171,'全唐诗/poet.tang.50000.json','["汎汎水中蓱，離離岸傍草，逐浪高復下，從風起還倒。", "人生不若茲，處世安可保？", "遽瑗仕衛國，屈伸隨世道；方朔隱漢朝，易農以爲寶。", "飲啄得其性，從容成壽考。", "南國有狂生，形容獨枯槁，作賦刺椒蘭，投江溺流潦。", "達人無不可，委軍（運）推蒼昊；何爲明白（自）銷[一]，取譏於楚老？", "（[一]、王云：「『軍』疑應作『運』『白』疑應作『自』，用《漢書·龔勝傳》語。", "」）。"]'),
('01ca06cb-3a38-4948-b995-257d4d08785c','昭君怨（其三。斯五五五）','東方虬','唐','唐诗','tang','','[]','萬里胡風急，三秋[□]漢初。',61,'全唐诗/poet.tang.50000.json','["萬里胡風急，三秋[□]漢初。", "唯望南去雁，不肯爲傳書。", "（按這詩的其一、其二、其四三首已載《全唐詩》，故僅補「其三」一首。", "）。"]'),
('54f5b888-797c-4037-bf80-90cb08fa3434','成（城）南宴（斯五五五）','李行言','唐','唐诗','tang','','[]','禦（御）宿上林春欲盡，殘花弱柳任風吹。',35,'全唐诗/poet.tang.50000.json','["禦（御）宿上林春欲盡，殘花弱柳任風吹。", "鬬雞走馬□□□，樂煞長安遊俠兒。"]'),
('75e4f4e7-fd1f-4ce2-892f-3c9efedba600','宴盧十四南園得園韻（伯三七七一下同）','元希聲','唐','唐诗','tang','','[]','超遙乘暇景，灑散絕浮喧。',60,'全唐诗/poet.tang.50000.json','["超遙乘暇景，灑散絕浮喧。", "寫望峯雲出，開襟夏木繁。", "野人憐狎鳥，遊子愛芳蓀。", "臥篠低臨席，驚流注滿園。", "□然林下意，琴酌坐忘言。"]'),
('d4f5f7d8-629c-406e-b962-baf7efd628fb','贈皇甫侍御赴都（其二）','元希聲','唐','唐诗','tang','','[]','猗嗟衆珍，以況君子。',79,'全唐诗/poet.tang.50000.json','["猗嗟衆珍，以況君子。", "公侯之胄，必復其始。", "香器長材，溫儀峻峙。", "顯此元明，於斯備矣。", "（按此詩凡八首，已載《全唐詩》。", "惟「其二」缺末兩句，故依《珠英集》補全之。", "）。"]'),
('155d79c6-3d0c-46cf-9af0-5061e5f5692c','秋夜讌徐四山亭（伯三七七一）','楊齊悊','唐','唐诗','tang','','[]','卷言北山岑，（「卷言」，項云當作「眷言」。',150,'全唐诗/poet.tang.50000.json','["卷言北山岑，（「卷言」，項云當作「眷言」。", "）非謂靡遠尋。", "庭際有幽石，自然保遐心。", "月下池涼（涼池）[一]彩，（「下池」，蔣項皆云二字當互乙。", "蔣云「月池」與「風竹」相對，項云「涼彩」猶冷光也。", "）風竹來清音。", "樽酒古籍人意，蒼蒼寒露深。", "（[一]池涼二字當互倒，深是動詞。", "劉云：「『池』管作『遲』，待也。", "」）。"]'),
('3650f2d2-92e2-4f0a-b138-eaf4aa2a068d','奉使松府（伯三七七一。下同）','胡皓','唐','唐诗','tang','','[]','蜀山固地險，（項云「固」當作「匝」，形近而訛。',124,'全唐诗/poet.tang.50000.json','["蜀山固地險，（項云「固」當作「匝」，形近而訛。", "）漢水接天平。", "波濤去東別[一]，林嶂隱西傾[二]。", "露白蓬根斷，風秋草葉鳴。", "孤舟忽不見，垂淚坐盈盈。", "（[一]劉云：「東別謂大別也。", "《禹貢》漢水又區爲滄浪之水，至於大別。", "」[二]劉云：「西傾謂西傾山。", "」）。"]'),
('2b2ca32e-7c6d-45e6-8e2d-708a615f5a61','夜行黃花川','胡皓','唐','唐诗','tang','','[]','的的（旳旳）夜綿綿，斜斗歷高天。',40,'全唐诗/poet.tang.50000.json','["的的（旳旳）夜綿綿，斜斗歷高天。", "露浩空山月，風秋洞壑泉。", "飢鼯啼遠樹，暗鳥宿長川。"]'),
('88774b71-50aa-4c15-9d93-be2099d9221b','奉天田明府席餞別','胡皓','唐','唐诗','tang','','[]','屬城富才雄，文園餞席同。',60,'全唐诗/poet.tang.50000.json','["屬城富才雄，文園餞席同。", "此席何所餞？徭役五原中。", "疾沙亂飛雪，連車條轉蓬。", "雁歸寒塞近，客散祖亭空。", "日夕不遑次，蕭條鳴朔風。"]'),
('b90f5158-2d28-404b-acf2-86272ea4cd2f','答徐四蕭關別醉後見投','胡皓','唐','唐诗','tang','','[]','蕭關城南隴入雲，蕭關城北海生荒[一]。',79,'全唐诗/poet.tang.50000.json','["蕭關城南隴入雲，蕭關城北海生荒[一]。", "（蔣云：「荒」即「塵」字草書之誤。", "）咄嗟塞外同爲客，滿酌杯中一送君。", "（[一]劉云：「『荒』字不叶韻，不知是何字誤？", "」）。"]'),
('bfa5a23c-1308-4c76-9c25-6cd132afcdc9','春悲行（伯三七七一下同）','胡皓','唐','唐诗','tang','','[]','夜鵲南飛倦，鳴雞屢送晨，忽聞芳歲道（到），今日故園春。',172,'全唐诗/poet.tang.50000.json','["夜鵲南飛倦，鳴雞屢送晨，忽聞芳歲道（到），今日故園春。", "試上亭臺望，葐蒀（氛氳）江樹新。", "（項云「葐蒀」爲草木茂盛之貌，不煩改。", "）旳旳韶陽蕚，迢迢佳麗人，音容曠不接，景物徒相因。", "別怨如流水，移恩念積薪，垂淚三危露，心斵[一]（「斵」，原卷作「斷」。", "）二京塵。", "遠役鴻爲伴，荒亭鬼作隣，吾生殊卉木，顦顇此江濱。", "（[一]俞云：「『心斵』疑『心斷』。", "」）。"]'),
('b6814928-84c3-43d0-8c00-e0373f7371e7','渝州逢故人（「渝州」，原作「滁州」，從原卷改。）','胡皓','唐','唐诗','tang','','[]','共是他鄉客，俱爲失路人。',24,'全唐诗/poet.tang.50000.json','["共是他鄉客，俱爲失路人。", "自憐蓬髪改，不掩柳條春。"]'),
('91c421a1-f97b-4f7b-bc6e-6d2674892e3a','感春','胡皓','唐','唐诗','tang','','[]','試登高臺春，伏檻弄陽旭。',173,'全唐诗/poet.tang.50000.json','["試登高臺春，伏檻弄陽旭。", "紆寂融密思，韶和洗紛矚。", "林暖花意紅，墀薰草情綠。", "感物深自負，萋萋楊□□。", "（〖1〗右三首，載於伯三七七一《珠英集》殘卷的開端。", "原共五首，不著撰人。", "第四首《奉天田明府席餞別》第五首《答徐四蕭關別醉後見投》與後重出。", "已據重出部份的題名載入胡皓詩內。", "因疑前三首亦胡皓所作，故附於此。", "即非胡皓所作，亦必爲其他《珠英》學士的作品。", "）。"]'),
('53f18b68-b234-4e53-9d61-ee745c536566','詠螢（斯五五五）','蘇晉','唐','唐诗','tang','','[]','旳旳黃金色，□□白玉輝。',59,'全唐诗/poet.tang.50000.json','["旳旳黃金色，□□白玉輝。", "既能明自□，□用暗中飛。", "（蔣云兩句當作：「既能明自照，何用暗中飛？", "」與杜甫《倦夜》句式同。", "）。"]'),
('a25229bd-a72b-4d6d-a83b-d234738af8e7','揚子江夜宴（伯三六一九）','蔡希寂','唐','唐诗','tang','','[]','楚水夜潮平，仙舟燼燭明。',48,'全唐诗/poet.tang.50000.json','["楚水夜潮平，仙舟燼燭明。", "美人歌一曲，坐客不勝情。", "羅幕香風倦，紗巾舞袖輕；遨遊正得意，雲雨莫來迎。"]'),
('ed223f71-efc4-4457-b27d-3e49ff709b32','度巴硤（伯三六一九[一]）','李邕','唐','唐诗','tang','','[]','客從巴硤度（水渡）[二]，傳子（爾）訴（泝）行舟。',338,'全唐诗/poet.tang.50000.json','["客從巴硤度（水渡）[二]，傳子（爾）訴（泝）行舟。", "是日風波濟（霽）（蔣云「濟」有「止」意，《莊子》、《淮南子》中均有〖風濟〗的用法，不必改。", "），高塘（堂）[三]雨半收。", "青山滿蜀道，渌（綠）水向荆州。", "不作書相慰（問），何（誰）能散（慰）別愁。", "（皎然《詩式》卷三引「青山滿蜀道，渌水向荆州」二句，作「崔顥《別人》」。", "）（[一]按原卷載詩三首：一《綵雲篇》，二《度巴峽》，三《秋夜泊江渚》。", "第一首題下有李邕名。", "檢《全唐詩》第一第三兩首正是李邕作，但第一首詩題作「詠雲」，第三首殘。", "[二]按此詩見《全唐詩》二函九冊，謂爲崔顥作，題作『贈盧八象』。", "故此據敦煌卷先用互著例載入李邕，然後據《全唐詩》校其異文，凡九事。", "茲作說明於第一事下。", "[三]俞云：「『高塘』應作『高唐』，兩本俱誤。", "」）。"]'),
('3045d728-ed06-4040-8218-a63a9bc470f9','□□（伯三八八五[一]三六一九） 一','李邕','唐','唐诗','tang','','[]','忽（傳）[二]聞天子訪沉淪，萬里迢迢遠赴（懷書西入）秦。',143,'全唐诗/poet.tang.50000.json','["忽（傳）[二]聞天子訪沉淪，萬里迢迢遠赴（懷書西入）秦。", "早□（知）不用無媒客，悔度（恨別）江南楊柳春。", "（原卷題爲李邕作。", "按此詩亦見伯三六一九卷，亦無題。", "[二]此詩又見《全唐詩》第十一函第八冊，載入無名氏二。", "有異文四事，旁注者皆是。", "又原卷題李邕，自當有據，可正《全唐詩》入無名氏之誤。", "）。"]'),
('a9fd7c7d-17bd-4beb-bc24-d07823989496','□□（伯三八八五[一]三六一九） 二','李邕','唐','唐诗','tang','','[]','□□（明時）[一]奉遣出（別）皇（黃）州，行至漢陽南渡頭。',107,'全唐诗/poet.tang.50000.json','["□□（明時）[一]奉遣出（別）皇（黃）州，行至漢陽南渡頭。", "春風不解傳鄉信，江月偏能照客愁。", "（[一]此第二首，又見伯二五五五卷，校其缺字異文三事。", "又「渡頭」作「度」，「鄉信」作「香」，不及原卷〖伯三八八五〗之善。", "）。"]'),
('5afab607-f9f2-4494-9b2b-8d80c825f06c','寒食篇（伯三六○八[一]）','王冷然','唐','唐诗','tang','','[]','天運四時成一年，八節相迎盡可憐，秋貴重陽冬貴臘，不如寒食在春前。',573,'全唐诗/poet.tang.50000.json','["天運四時成一年，八節相迎盡可憐，秋貴重陽冬貴臘，不如寒食在春前。", "禁火初從太原起，風俗流傳幾千祀，算取去冬至時，一百五日今朝是。", "今年寒食勝常春，總緣天子在東巡，能令氣色隨河洛，斗覺風光商競逐人。", "上陽遙見青春見[二]，（「遙見」，原卷作「遙望」。", "）洛水橫流遶城殿，波上樓臺列岸明，風光所吹皆流遍。", "畫閣盈盈出半天，依稀雲裏見鞦韆，來疑神女從雲下，去似恆娥到月邊。", "金閨待看紅粧早，先過陌上垂楊好，花場共鬬汝南鷄，春遊遍[三]在東郊道。", "（「遍」，項云應作「偏」。", "）千金寶帳綴流蘇，簸瓌[四]還坐錦筵鋪，莫愁光景重窗闇，自有金瓶照乘珠。", "心移向者遊遨處，乘舟欲騁凌波步，池中弄水白鷼飛，樹下拋球彩鸎去。", "別殿前臨走馬臺，金鞍更送彩毬來。", "毬落畫樓攀柳取，枝[五]□（「枝□」，原卷作「枝搖」。", "）香徑踏花迴。", "良辰更重宜三月，能成晝夜芳菲節，今夜無明月作燈，街衢遊賞何曾歇。", "南有龍門對洛城，車馬傾都滿路行，縱使遨遊今日罷，明朝上（尚）自有清明。", "（[一]按這一卷子上載《夜燒篇》與《寒食篇》，詩調相同，並無作者姓氏。", "攷《全唐詩》王冷然有《夜光篇》，就是《夜燒篇》。", "因疑《寒食篇》亦王冷然作，因暫題王冷然名。", "[二]劉云：「第二『見』字讀爲『現』。", "」[三]劉云：「疑『徧』。", "」[四]劉云：「『瓌』當是『瓊』字之誤，骰子叫瓊。", "」[五]劉云：「『枝』當作『杖』，即擊球杖。", "」）。"]'),
('36373444-1ca8-43c3-8285-6d64d02f6ed0','馴鴿篇（幷序。伯二五五二下同）','李昂','唐','唐诗','tang','','[]','君不見賈誼寰中推逸才，⿰亻丸香坐處館常開。',339,'全唐诗/poet.tang.50000.json','["君不見賈誼寰中推逸才，⿰亻丸香坐處館常開。", "（⿰亻丸，蔣、項皆云應作「仇」。", "仇香爲後漢人，曾任主簿，此處借指賈季良。", "）栖鸞未即冲天去，馴鴿先能聽□□。", "（蔣云闕文爲「事來」二字，「聽事」即「廳事」。", "）亦聞無角巢君屋，諸處不栖如[一]擇林[二]。", "（「林」，原作「木」。", "）寧隨賀鷰空繞梁，爲逐遷鸎俱□□，風窻月戶清節凉，撫翼和鳴君子旁。", "雙影時時臨硯水，輕毛片片落書□。", "（蔣云闕文當爲「窗」字。", "）□君德，輝彩鮮鮮生羽翼；感君心，靈慶昭昭相應深。", "何必淮南投小吏，飛來□□化爲金[三]。", "（[一]俞云：「『如』疑『知』。", "」[二]劉云：「『林』當作『木』與屋爲韻。」", "《世說新語·語言篇》：李弘度說：「窮猿奔林，豈暇擇木。", "」[三]劉云：「《搜神記》張灝爲梁相，有鵲化爲一圓石，灝破之得一金印。", "」）。"]'),
('cdfe174e-7592-4beb-a924-6c1ced36f433','塞上聽彈胡笳作（幷序）','李昂','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.50000.json','["。"]'),
('061b5fe2-b247-4d80-88fb-c76b48027e5e','題雍丘崔明府丹竈（伯二五六七。下同）','李昂','唐','唐诗','tang','','[]','聞君小邑蹔鳴絃，隱几灰心有歲年。',64,'全唐诗/poet.tang.50000.json','["聞君小邑蹔鳴絃，隱几灰心有歲年。", "白石既燒應化鶴，黃金未熟且烹鮮。", "鑪中近染三花氣，樹裏新飛五色煙。", "伊尹即今須負鼎，王喬何事欲冲天。"]'),
('e4cbc085-d4d1-4b0c-b2af-de5365d7dd3e','睢陽送韋參軍還汾上（此公元昆任睢陽參軍）','李昂','唐','唐诗','tang','','[]','世業重籯金，青春映士林，文華兩孫楚，兄弟二曾參。',262,'全唐诗/poet.tang.50000.json','["世業重籯金，青春映士林，文華兩孫楚，兄弟二曾參。", "竹抱盧門[一]暗，山銜晉國深，預知汾水上，一雁有遺音。", "（[一]劉云：「盧門見《左傳》，宋國門名，此用以表睢陽。", "」）（〖1〗右李昂詩四首，同寫一卷上，但不在一處，原卷今亦裂爲兩截。", "前兩首在前截〖伯二五五二〗之末，題李昂名，其爲李昂作無疑。", "後兩首與《戚夫人楚舞歌》均在後截〖伯二五六七〗，並無撰人姓氏，因《唐詩紀事》以《楚舞歌》爲李昂作，羅振玉因定此兩首亦爲李昂作。", "《塞上聽彈胡笳》詩內的韋公可能和在睢陽送的韋參軍是一人，惑有一定關係，這也是把這兩詩定爲李昂作的一點小小旁證。", "）。"]'),
('c7b6e221-248c-4590-911f-3e4f06bdc66b','答韓丈[一]（「韓丈」，原卷作「韓大」。疑非韓滉。）（伯二五六七下同）','丘爲','唐','唐诗','tang','','[]','行人輩，莫相催，相看日暮何徘徊。',206,'全唐诗/poet.tang.50000.json','["行人輩，莫相催，相看日暮何徘徊。", "登孤舟，望遠水，殷勤留語勸求仕。", "疇昔主司曾見知，琳琅叢中拔一枝。", "且得免輪天子課，何能屈腰鄉里兒。", "長安落葉酒[二]，（「落葉」，原卷作「桒落」，「桒」爲「桑」的別寫。", "）或可此時望携手；官班眼（服）[三]色不相當，拂衣還作捕魚郎。", "（[一]《唐詩紀事》卷十七說丘爲八十多歲的時候丁了母憂，「觀察使韓滉以致仕官給禄」，韓滉大概就是這裏的韓丈。", "[二]劉云：「當是落桑酒。", "」[三]依劉校。", "）。"]'),
('356f89d3-b1d0-4b76-956b-c42e045dc4eb','辛四臥病舟中羣公招登慈和寺','丘爲','唐','唐诗','tang','','[]','柳色扁舟帶水陰，聞君臥疾引登臨。',64,'全唐诗/poet.tang.50000.json','["柳色扁舟帶水陰，聞君臥疾引登臨。", "憑高始見三吳勢，望遠因知四海心。", "山僧午後清禪洽，羣木晴初綠靄深。", "雲外翩翩飛鳥盡，令人宛自動歸吟。"]'),
('d7ee04a6-8848-407f-b1d9-d00416753eb2','對雨聞鸎','丘爲','唐','唐诗','tang','','[]','垂柳街頭百丈絲，杏花林處度黃鸝。',64,'全唐诗/poet.tang.50000.json','["垂柳街頭百丈絲，杏花林處度黃鸝。", "間關正在秦箏裏，歷亂偏傷楚客時。", "風傳一一聲來盡，雨濕雙雙飛去遲；羨爾能將戶客意，何如棲得上林枝。"]'),
('4752656e-b251-4f41-bc2c-f0ebbc5171f0','幽渚雲','丘爲','唐','唐诗','tang','','[]','漠漠雲在渚，無心去何從。',112,'全唐诗/poet.tang.50000.json','["漠漠雲在渚，無心去何從。", "（「何」下原卷衍「疑」字。", "）青連晚湖色，澹起秋煙客（容）[一]。", "（「客」，原卷作「容」，与王校合。", "）渡水上下白，歸山深淺重，來爲巫峽女，去逐葛川龍。", "勿爲長幽滯，當飛第一峯。", "（[一]依王仲聞先生校。", "）。"]'),
('beaafbbf-ccaa-400f-8a45-6bb0fe633d22','傷河龕老人[一]','丘爲','唐','唐诗','tang','','[]','老人甲子難計論，耳中白毛三十根。',360,'全唐诗/poet.tang.50000.json','["老人甲子難計論，耳中白毛三十根。", "釣魚幾年如一日，船舷數寸青苔痕。", "人生性命必歸正（止）[二]，（「正」，原卷作「止」。", "）精魂傷夫[三]向流水。", "（「魂」，伯二五六七卷作「魄」。", "）月如鈎在輪影中，風似人來𥭳（荻）聲裏。", "蒲葉高低沒釣磯，破舟仍繫綠楊枝。", "水流不爲人流去，魚樂寧知人樂時。", "土龕門前一行柳，獨引青絲織魚笱。", "柳花漠漠飛復飛，魚笱如今落誰手。", "余嗟老人多悲辛，老人昔日傷幾人；人情相掩且相歎，不喜河頭秋與春。", "（[一]此詩亦見伯二五四四卷，題作《老人篇》，但差白字太多。", "[二]依劉校。", "[三]「精魂傷夫」伯二五四四卷作「精醜香風」，俞云：「精魂傷夫」當從伯二五四四卷作「精魄」〖「醜」是「魄」誤〗，因此四字正和下文相應。", "精魄指月，下文「月如鈎在輪影中，風似人來荻聲裏」，足證「香風」二字不誤。", "劉校「『夫』當爲『失』字之誤」。", "）。"]'),
('a12826f5-7798-4527-9c1e-b4dbac17fe4d','謁河上公廟（伯三六一九）','祖詠','唐','唐诗','tang','','[]','河上公遺跡，跡涼在道邊。',50,'全唐诗/poet.tang.50000.json','["河上公遺跡，跡涼在道邊。", "草生空廟裏，□□□□□。", "□□□知聖，騰空更表仙。", "孝文皇帝後，《章句》至今傳。"]'),
('c7dae33e-003f-4f7e-9f78-2c8c7d7d7033','','王昌齡','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.50000.json','["。"]'),
('f2cbb821-c70e-43d5-a38f-2c6081516a2a','城旁□□[一]伯二五六七下同','王昌齡','唐','唐诗','tang','','[]','降奚能騎射，戰馬百餘匹，甲仗明寒川，霜□□□□。',187,'全唐诗/poet.tang.50000.json','["降奚能騎射，戰馬百餘匹，甲仗明寒川，霜□□□□。", "□□煞單于，薄暮紅旗出。", "城旁粗少年，驟馬垂長鞭，脫却□□□，□劍淪秋天。", "（項云「淪」疑當作「輪」，同掄。", "）匈奴不敢出，漠北開（閉）[三]甲煙。", "（[一]標題殘去二三字。", "按《全唐詩》昌齡有《城旁曲》，但內容與此全異。", "[二]余疑「開」爲「閉」誤，俞云：「煙塵四合則虜起，今匈奴不出，故開霽也。", "依平仄論亦宜平聲字，「開」字不誤。", "」）。"]'),
('d2cd5bff-c88b-445c-b93b-94aea8973023','題淨眼師房','王昌齡','唐','唐诗','tang','','[]','白鴿飛時日欲斜，禪房寂歷飲香茶。',72,'全唐诗/poet.tang.50000.json','["白鴿飛時日欲斜，禪房寂歷飲香茶。", "傾人城，傾人國，斬新剃頭青且黑。", "玉如意，金澡瓶，朱唇皓齒能誦經，吳音唤字更分明。", "日暮鐘聲相送出，袈裟掛着箔簾釘。"]'),
('62cc5942-6024-47fd-9815-b023deeea081','弔王將軍（伯二五六七[一]）','陶翰','唐','唐诗','tang','','[]','漂姚[二]北伐時，深入强千里。',214,'全唐诗/poet.tang.50000.json','["漂姚[二]北伐時，深入强千里。", "戰酣落日黃，軍敗鼓聲死。", "嘗聞漢飛將，可奪單于壘，今與山鬼隣，殘兵哭遼水。", "（殷璠天寶末編《河嶽英靈集》，收此詩於常建名下，幷在評語中引及。", "原卷於陶韓名下存詩九首，其一爲《古意》。", "《全唐詩》已收歸陶韓，其二即本詩，後七首均李白詩。", "據此推測，此詩似非陶韓作。", "）（[一]《中華文史論叢》編輯室云：「《弔王將軍》一詩《全唐詩》已收入《常建集》中。", "」劉說同。", "[二]漂姚指霍去病，《漢書》作「票」，或「驃」。", "）。"]'),
('6293174f-62cc-485b-b983-4676e47cedfd','得遇入京（伯三八一二）','劉長卿','唐','唐诗','tang','','[]','萬里南來喜復悲，生涯何幸有歸期。',210,'全唐诗/poet.tang.50000.json','["萬里南來喜復悲，生涯何幸有歸期。", "空庭葉散風搖落，舊邑人疏經亂離。", "巴路千山秋水在，江花獨樹夕陽微。", "爲君一話此中事，白首長沙知不知？", "（按《全唐詩》內長卿詩卷五與劉隨州集卷九〖四部叢刊本〗都有這首詩，題爲「自江西歸至舊任官舍贈袁贊府自經劉展平後」，但文句異同甚多，故破格載入，兼錄集本如下：「却見同官喜後悲，此生何幸有歸期。", "空庭客至逢搖落，舊邑人稀經亂離。", "湘路來過迴雁處，江城臥聽擣衣時。", "南方風土勞君問，賈誼長沙豈不知。", "」）。"]'),
('0d3c1304-a2bf-416c-a1b3-5b51c58c050a','詠青（伯二五六七）','孟浩然','唐','唐诗','tang','','[]','霧闢天光遠，春迴日道臨。',103,'全唐诗/poet.tang.50000.json','["霧闢天光遠，春迴日道臨。", "草濃河畔色，槐結路旁陰。", "欲映君王史，先標胄子襟；經明如何（可）[一]拾，自有致雲心。", "（《國秀集》卷下、《全唐詩》卷二○三皆收此詩爲校書郎荆冬倩之作，作孟詩恐誤。", "）（[一]依劉校。", "）。"]'),
('18c18f8c-a68d-4f9e-9e9c-96d7805b7ea7','遇崔二[一]有別（伯三八六二下同）','高適','唐','唐诗','tang','','[]','大國多任士[二]，（蔣、項皆云「任士」不誤，用《莊子·秋水》語。',205,'全唐诗/poet.tang.50000.json','["大國多任士[二]，（蔣、項皆云「任士」不誤，用《莊子·秋水》語。", "）明時遺此人。", "頤頷尚豐盈，毛骨未合迍。", "逸足望千里，商歌悲四隣。", "誰謂多才富，却令家道貧。", "秋風吹別馬，攜手更傷神。", "（[一]《適集》卷一有「效古贈崔二」，應是一人。", "《贈崔二》有云：「君負縱橫才，如何尚顦顇。", "」又云：「窮達自有時，夫子莫下淚。", "」這次「遇崔二」，還是「明時遺此人」，所以還歎息着說「誰謂多才富，却令家道貧！」[二]「任士」劉疑「佳士」。", "）。"]'),
('ca3fae3b-b5ad-408c-afa9-c83bb861d6b5','奉寄平原顏太守（幷序）','高適','唐','唐诗','tang','','[]','皇皇平原守，駟馬出關東。',313,'全唐诗/poet.tang.50000.json','["皇皇平原守，駟馬出關東。", "銀印垂腰下，天書在篋中。", "自承到官後，高枕揚清風。", "豪富已低首，逋逃還力農。", "始余梁宋間，甘予（與）[一]麋鹿同。", "散髮對浮雲，浩歌追釣翁，如何顧疵賤，遂肯偕窮通。", "耿介出憲司，慨然見羣公，賦詩感知己，獨立争愚蒙。", "金石誰不仰，波瀾殊未窮；微軀枉多價，朽木慚良工。", "上將拓邊西，薄才忝從戎，豈論濟代心，願効匹夫雄。", "驊騮滿長皂，弱翮依彫籠，行軍動若飛，旋斾信嚴終[二]。", "屢陪投醪醉，竊賀銘山功；雖無汗馬勞，且熟沙塞空。", "去去勿復道，所思積深衷。", "一爲天崖（涯）[三]客，三見南飛鴻，應念蕭關外，飄颻隨轉蓬。", "（[一]依俞校。", "[二]劉云：「嚴助終軍也。", "二人乃漢武帝時文士有武略者。", "蘇東坡詩：一時冠蓋盡嚴終。", "」[三]依劉校。", "）。"]'),
('17dfa7e6-fa10-4fa9-a689-e7c66a676a1c','雙六頭賦送李參軍','高適','唐','唐诗','tang','','["\u9ec4\u6cb3"]','有物兮四方故城，六面砥平，白質黑文，花攢星明。',506,'全唐诗/poet.tang.50000.json','["有物兮四方故城，六面砥平，白質黑文，花攢星明。", "主張爾手談，決斷爾心争，推得失似關乎天命，而消息乃用乎人情。", "若行之尤[一]，思之精，雖邂逅而小比[二]，（「小比」，蔣云作「小屯」是，「屯」、「亨」，皆《易》用語；項云「比」爲「北」之形訛，賭戲中敗者稱「北」，或稱「奔北」。", "）必指掌而大亨。", "李侯李侯保令名，無怨𥎪於垂成。", "（「𥎪」，蔣、項皆云當作「敗」。", "）朝影入平川，川長復垂柳[三]，（劉開揚云此二句乃誤鈔《自淇涉黃河途中作十三首》之文，當刪。", "）明年有一擲分[四]，（項疑「分」字爲衍文。", "）君不先鳴誰先鳴？", "（[一]游國恩先生云：「『尤』字似係『久』字之誤。", "」俞云：「行之尤不誤。", "這是一種近乎雙六的賭具，行之尤者行之最，言他這碁走得很好，雖然有時會失着，但轉眼反手〖指掌〗間，又亨通了。", "若作久，便與下文指掌大亨不合。", "」[二]俞云：「『小比』疑當作『小疵』。", "」劉云：「當作『小屯』。", "」[三]劉云：「『柳』字不叶韻，疑是『平』之誤，此句說古練不已。", "」[四]「明年有一擲分」不成句，疑「分」字是衍文。", "俞云：「似亦不誤，說明年還有一擲的機會〖大約指官場的攷績等事〗，您一定便得意的。", "『分』字仄聲。", "」劉疑「有」當作「儻有」。", "）。"]'),
('f8446984-8188-4fc3-bf8d-6fa2e36b41b1','自武威赴臨洮謁大夫不及因書即事寄河西隴右幕下諸公（伯二五五二下同）（「巔」，蔣、劉、項皆云當作「顛」。）','高適','唐','唐诗','tang','','[]','浩蕩去鄉縣，飄颻瞻節旄。',321,'全唐诗/poet.tang.50000.json','["浩蕩去鄉縣，飄颻瞻節旄。", "揚鞭發武威，落日至臨洮。", "主人未相識，客子心忉忉。", "顧見征戰歸，始知士馬豪。", "戈鋋耀崖谷，聲氣如風濤。", "隱軫戎旅間，功業競相褒。", "獻狀陳首級，饗軍烹太牢。", "俘囚駈面縛，長幼隨巔毛。", "（「巔」，蔣、劉、項皆云當作「顛」。", "）氈裘何蒙茸，血食本羶臊。", "漢將乃兒戲，秦人空自勞。", "立馬眺洪河，驚風吹但白蒿。", "雲屯寒色苦，雪合羣山高。", "遠戍際天末，邊烽連賊壕。", "我本江海遊，逝將心利逃[一]。", "一朝感推薦，萬里從英旄（髦）[二]。", "飛鳴蓋殊倫，俯仰忝諸曹。", "鷰鴿（頷）[三]知有待，龍泉惟所操。", "相士慙入幕，懷賢願同袍。", "清掄揮塵尾，乘酣持蟹螯。", "此行豈易酬，深意方鬱陶。", "微効儻不遂，終然辭佩刀。", "（[一]俞云：「『心利逃』不可解，疑當作『名利逃』。", "」[二]依劉校。"]'),
('bfdab5f3-2ada-4af1-9d4a-7afff67a1f4e','同李司倉早春宴睢陽東亭（得花）','高適','唐','唐诗','tang','','[]','春臯宜晚景，芳樹雜流霞。',49,'全唐诗/poet.tang.50000.json','["春臯宜晚景，芳樹雜流霞。", "鸎鷰知三月，池臺稱百花。", "竹根初帶笋，槐色正開牙。", "且莫催行騎，歸時有月華。", "。"]'),
('265fb983-0933-4bb2-93ad-ec8c869db2d6','在哥舒大夫幕下請辭退託興奉詩（伯三八一二。下同）','高適','唐','唐诗','tang','','[]','自從嫁與君，不省一日樂。',105,'全唐诗/poet.tang.50000.json','["自從嫁與君，不省一日樂。", "遣妾作歌舞，好時還道惡。", "不是妾無堪，君家婦難作。", "下堂辭君去，去後君莫錯。", "（項云：「《才調集》卷六李白《寒女吟》，後幅與此詩大略相同。", "」《寒女吟》收《全唐詩續補遺》李白名下，兹不重錄。", "）。"]'),
('e979977b-e698-4a76-b540-89181852cb36','閨情（爲落殊蕃陳上相知人）','高適','唐','唐诗','tang','','[]','自從淪落到天涯，一片真心戀着□。',248,'全唐诗/poet.tang.50000.json','["自從淪落到天涯，一片真心戀着□。", "（缺字，檢原卷似應爲「查」字。", "）顦顇不緣思舊國，行渧（啼）只是爲寃家。", "（〖1〗右兩首，同寫在一卷上。", "第一首標題作「高適在哥舒大夫幕下請辭退，託興奉詩」，疑是後人依託或擬作，細玩修辭與用意，也不像高適的作品，因爲是使用高適的故事，故附於此。", "《閨情》原卷不題撰人，「顦顇不緣思舊國」，也一定不是高適的話，蓋與前一首同爲一個淪落在敦煌的文人所作，因此，也連類附及。", "「爲落殊蕃陳上相知人」的閨情以後，還有四首閨情，好像是妓女的歌辭。", "也不著撰人，不知是否佚詩，姑附於後：）。"]'),
('4413e116-18be-4c17-b9c1-eb8891418c6f','閨情（爲落殊蕃陳上相知人） 閨情 一','高適','唐','唐诗','tang','','[]','相隨萬里泣胡風，疋偶將期一世終。',32,'全唐诗/poet.tang.50000.json','["相隨萬里泣胡風，疋偶將期一世終。", "早知中路生離別，悔不深憐沙磧中。"]'),
('2fc43627-717f-49b2-ada4-3968d56dbd62','閨情（爲落殊蕃陳上相知人） 閨情 二','高適','唐','唐诗','tang','','[]','不須推道委人猜，只是君心自不開。',32,'全唐诗/poet.tang.50000.json','["不須推道委人猜，只是君心自不開。", "今夜閨門憑莫閉，孤魂擬向夢中來。"]'),
('995bd4ec-ccf7-4cb5-a118-30c57cdf3848','閨情（爲落殊蕃陳上相知人） 閨情 三','高適','唐','唐诗','tang','','[]','祗今桃李正堪攀，所恨枝高引手難。',32,'全唐诗/poet.tang.50000.json','["祗今桃李正堪攀，所恨枝高引手難。", "原君垂下方便葉，袖卷將歸看復看。"]'),
('09aed716-c9ab-4b67-84cf-9af750523942','閨情（爲落殊蕃陳上相知人） 閨情 四','高適','唐','唐诗','tang','','[]','自處長信宮，每向孤燈泣。',25,'全唐诗/poet.tang.50000.json','["自處長信宮，每向孤燈泣。", "閨門鎮不開，夢從何處入。", "。"]'),
('6c3a10b7-5781-4817-bae2-fc8604d3dea1','登觀鵲樓（伯三六一九）','暢諸','唐','唐诗','tang','','[]','城樓多峻極，列酌恣登攀。',226,'全唐诗/poet.tang.50000.json','["城樓多峻極，列酌恣登攀。", "逈林飛鳥上，高榭代人間。", "天勢圍平野，河流入斷山。", "今年菊花事，併是送君還。", "（暢諸作此詩，《文苑英華》卷七一○收李韓《河中鸛鵲樓集序》已稱及，宋司馬光《續詩話》、沈括《夢溪筆談》卷十五僅錄中四句，亦云暢諸作。", "至《唐詩紀事》卷二七始誤爲暢當，《全唐詩》沿之。", "岑仲勉《讀全唐詩札記》考證較詳，可參看。", "宋人所見此詩前二句，作「迥臨飛鳥上，高謝世人間」，與此處三、四兩句稍異，蔣、均云以「臨」、「謝」爲是，「代人」即「世人」，避太宗諱改。）"]'),
('688029b2-32fa-4e96-80c6-565efb07fc22','秦婦吟[一]','韋莊','唐','唐诗','tang','','[]','中和癸卯春三月，洛陽城外花如雪。',438,'全唐诗/poet.tang.50000.json','["中和癸卯春三月，洛陽城外花如雪。", "東西南北路人絶，綠楊悄悄香塵滅。", "路旁忽見如花人，獨向綠楊陰下歇。", "鳳側鸞欹鬢脚斜，紅攢黛歛眉心折。", "「借問女郎何處來？", "」含嚬欲語聲先咽。", "回頭歛袂謝行人；喪亂漂淪何堪說！三年陷賊留秦地，依稀記得秦中事。", "君能爲妾解金鞍，妾亦與君停玉趾。", "「前年庚子臈月五，正閉金籠教鸚鵡。", "斜開鸞鏡嬾梳頭，閑憑雕欄慵不語。", "忽看門外起紅塵，已見街中攂金鼓。", "居人走出半倉惶，朝士歸來尚疑誤。", "是時西面官軍入，擬[二]向潼關爲警急；皆言博野自相持，盡道賊軍來未及。", "須臾主父乘奔至，下馬入門癡似醉。", "適逢紫蓋去蒙塵，已見白旗來匝地。", "扶羸攜幼競相呼，上屋緣牆不知次，南鄰走入北鄰藏，東鄰走向西鄰避；北鄰諸婦咸相湊，戶外崩騰如走獸。", "轟轟崐崐乾坤動，（「崐崐」，蔣云當作「輥輥」。", "）萬馬雷聲從地涌。", "火迸金星上九天，十二官街煙烘烔。", "日輪西下寒光白，上帝無言空脈脈。", "陰雲暈氣若重圍，宦者流星如血色。", "紫氣潛[三]隨帝座移，妖光暗射台星拆。", "（「拆」，項校作「坼」。", "）家家流血如泉沸，處處寃聲聲動地。"]'),
('c82bb788-f5ef-46f5-9dfa-8341e072941d','秋晴過李三山池（斯二七一七下同）','馬吉甫','唐','唐诗','tang','','[]','山遊[□]未狎，朝隱遂爲羣。',87,'全唐诗/poet.tang.50000.json','["山遊[□]未狎，朝隱遂爲羣。", "地僻煙霞異，心閑出處分。", "褰開弄晴景，披拂喜朝聞，（「聞」，蔣當作「雰」。", "）野興浮黃菊，林棲臥白雲。", "窺臨苔壁古，歌嘯竹亭曛。", "迴想幽巖路。", "知予復解紛。"]'),
('37ce1aac-9c8a-4afa-902b-808e9ef39104','秋夜懷友','馬吉甫','唐','唐诗','tang','','[]','故人在天末，空庭明月時。',51,'全唐诗/poet.tang.50000.json','["故人在天末，空庭明月時。", "白雲勞悟（寤）寐，芳樹歇華滋。", "蟋蟀鳴秋草，蜘蛛弄曉絲。", "菊花應可汎，留興待□□。"]'),
('f883e8a4-165a-4ff0-88a3-9651affeb2e7','同獨孤九秋閨','馬吉甫','唐','唐诗','tang','','[]','閨樹紅滋變，庭蕪白（下缺）。',14,'全唐诗/poet.tang.50000.json','["閨樹紅滋變，庭蕪白（下缺）。"]'),
('245de53e-c50c-45a6-ad1d-9b702eb51178','送薛大入洛（伯三七七一下同）','房元陽','唐','唐诗','tang','','[]','驚年嗟未極，別緒復相依。',48,'全唐诗/poet.tang.50000.json','["驚年嗟未極，別緒復相依。", "雁隨春北度，人共水東歸。", "夜月臨軒盡，殘燈入曉微。", "哀怨一罷曲，幽桂徒芳菲。"]'),
('fcbf28f4-547e-4e22-9066-2b8da2ef7aa8','秋夜彈碁鼓琴歌','房元陽','唐','唐诗','tang','','[]','流月泛豔兮露色圓，（「圓」，項云當作「團」。',103,'全唐诗/poet.tang.50000.json','["流月泛豔兮露色圓，（「圓」，項云當作「團」。", "）拂孤□兮弄清絲（絃）[一]。", "幽態窈窕兮斷復連，驚風中路兮迢[二]流年。", "浮榮輕薄兮欲何賢，流商激楚兮不能宣。", "（[一]依劉校。", "[二]俞疑「迢」當是「送」字之誤。", "）。"]'),
('85211e57-51c0-46d3-a2f6-68fd332a26f5','','侯休祥','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.50000.json','["。"]'),
('23233a74-d2d0-4540-bfa9-d9772f7ea65e','□鏡（斯五五五下同）（題中缺字，項云據首句看，應是「覽」字。）','侯休祥','唐','唐诗','tang','','[]','忽覽今朝鏡，殊非李（昔）[一]是容。',101,'全唐诗/poet.tang.50000.json','["忽覽今朝鏡，殊非李（昔）[一]是容。", "（「李」，原卷作「昔」。", "）自看由（猶）□識，何況故人逢？", "（[一]余疑「李」爲「昔」字之誤，俞云：「昔日固是，但李字與昔音形均無關係，似只可存疑，或前舊均有可能。", "」）。"]'),
('151bfba0-7805-4f57-b3d3-994a86059c89','塞外','梁去惑','唐','唐诗','tang','','[]','塞北長寒地，由來□物華。',12,'全唐诗/poet.tang.50000.json','["塞北長寒地，由來□物華。"]'),
('29cab8af-523d-4309-b989-dc12de412fc0','春夜山亭','房旭','唐','唐诗','tang','','[]','夜靜琴還靜，年春酒復春。',24,'全唐诗/poet.tang.50000.json','["夜靜琴還靜，年春酒復春。", "何曾山水地，風月不□□。"]'),
('c21e1942-71dd-4d46-adda-30393e25e054','詠螢','樂仲卿','唐','唐诗','tang','','[]','□□光華淺，摶風羽翼徽。',25,'全唐诗/poet.tang.50000.json','["□□光華淺，摶風羽翼徽。", "不能欺暗室，所以帶明飛。", "。"]'),
('cc6047bd-a8e4-462a-9178-cbcd3df830ce','別宋侍御','嚴嶷','唐','唐诗','tang','','[]','水國南連楚，沙場北近胡。',24,'全唐诗/poet.tang.50000.json','["水國南連楚，沙場北近胡。", "春風萬里別，明月兩鄉孤。"]'),
('e9b368fb-2140-4a90-b126-0175ed4c43d6','七夕臥病','鄭愿','唐','唐诗','tang','','[]','玉露三秋早，反河七夕初。',120,'全唐诗/poet.tang.50000.json','["玉露三秋早，反河七夕初。", "不應須臥疾，爲曝腹中書。", "（〖1〗鄭愿，《新唐書·宰相世系表》載爲鄭氏南祖房清河令文睿子，無仕歷。", "《郎官石柱題名》其名兩見，司勳員外郎在盧象後，李嘉祐前，金部郎中在裴眺、鄭楚客間，以諸人時代推，應爲天寶、大曆間人。", "）。"]'),
('df260ca2-a64c-46df-8412-f28b1e2bc94d','守歲','鄭愿','唐','唐诗','tang','','[]','吾家貴主鳳樓開，故歲□更亂箭催。',65,'全唐诗/poet.tang.50000.json','["吾家貴主鳳樓開，故歲□更亂箭催。", "願奉神仙長獻酒，請留哥（歌）吹遂（逐）[一]行□。", "（[一]依劉校。", "劉並疑行下所缺當是「盃」字。", "）。"]'),
('9b7fca10-a376-4e86-97d1-11e69bf55f2e','過王濬墓（二首）','李休烈','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.50000.json','["。"]'),
('ca26858c-ce9f-4d0a-a9cd-c696090bb130','過王濬墓（二首） 一','李休烈','唐','唐诗','tang','','[]','青史高遺迹，黃壚掩舊封。',48,'全唐诗/poet.tang.50000.json','["青史高遺迹，黃壚掩舊封。", "寧知陌上□[一]，（項云據《晉書·羊祜傳》，當補「獸」字。", "）何羨水中龍。"]'),
('42d30611-03f7-4a67-8fe9-ab1fdf72da37','過王濬墓（二首） 二','李休烈','唐','唐诗','tang','','[]','樵採徒爲禁，英威豈得從。',52,'全唐诗/poet.tang.50000.json','["樵採徒爲禁，英威豈得從。", "定知[□]路蟻，（項疑闕字在「路」字下。", "）不畏水中龍。", "（[一]劉疑「虎」字。", "）。"]'),
('fd2561bd-5e74-4b2c-9636-318b3aedfdc4','詠暗','孟嬰','唐','唐诗','tang','','[]','鑿壁方將□，投珠忽見疑。',24,'全唐诗/poet.tang.50000.json','["鑿壁方將□，投珠忽見疑。", "始言纓可絕，誰謂室無欺。"]'),
('3c102b3b-99f2-4234-97d9-762570fef9c9','詠鵲','□嘉惠','唐','唐诗','tang','','[]','繞樹棲難定，填河尚未期。',24,'全唐诗/poet.tang.50000.json','["繞樹棲難定，填河尚未期。", "舊來能□語，試爲報歸時。"]'),
('2d6c114a-b7fc-44c0-a6ec-529ffbaa234f','送陳先生還嵩山','鄭韞玉','唐','唐诗','tang','','[]','玉臺金闕□微微，仙鶴聯翩何歲歸。',93,'全唐诗/poet.tang.50000.json','["玉臺金闕□微微，仙鶴聯翩何歲歸。", "欲識人間相望處，嵩高山上白雲飛。", "（〖1〗《新唐書·宰相世系表》鄭氏北祖房有韞玉，爲侍御史歡子，不載仕歷，鄭珣瑜、鄭餘慶爲其從昆，知應爲貞元、元和間人。", "）。"]'),
('8369b663-f67c-4d3c-8d13-490e8265dee9','及第後讀書院詠物[一]十首上禮部李侍郎 簾鈎','樊鑄','唐','唐诗','tang','','[]','成器屈雖深，君門幸許臨。',65,'全唐诗/poet.tang.50000.json','["成器屈雖深，君門幸許臨。", "卷時懷勁節，舒後抱虛心。", "就曲全□保，能剛□匪侵。", "倚身當盡力，不欲負工金。", "（[一]原作物詠，依劉校互乙。", "）。"]'),
('97eedc19-338b-43e5-bb96-da40d1d8ad5c','及第後讀書院詠物[一]十首上禮部李侍郎 鞭鞘','樊鑄','唐','唐诗','tang','','[]','幸約策爲名，提攜道正（上）[一]行。',64,'全唐诗/poet.tang.50000.json','["幸約策爲名，提攜道正（上）[一]行。", "卜隣貞幹並，□質真繩幷。", "節峻根堪託，柔多指可縈。", "希看着鞭處，下下振聲明。", "（[一]依劉校。", "）。"]'),
('3f9d18a0-6304-4f15-95f1-9b186b25fe81','及第後讀書院詠物[一]十首上禮部李侍郎 箭括','樊鑄','唐','唐诗','tang','','[]','刻□□材圓，相成□不偏。',48,'全唐诗/poet.tang.50000.json','["刻□□材圓，相成□不偏。", "守規心已正，受省禮仍全。", "有節通貞幹，無邪抱直弦。", "向非兼羽翼，何得札俱穿。"]'),
('ff988a0a-afe4-4a06-ba87-c839abc3dc69','及第後讀書院詠物[一]十首上禮部李侍郎 門扂','樊鑄','唐','唐诗','tang','','[]','扃要政攸敦，防非道久尊。',48,'全唐诗/poet.tang.50000.json','["扃要政攸敦，防非道久尊。", "掄材矩已中，善閉契□存。", "只慎樞機動，寧矝開闔恩。", "自非蒙一拔，何得入龍門。"]'),
('e9845e41-ba38-4332-9ef3-c57e7592a309','及第後讀書院詠物[一]十首上禮部李侍郎 錀匙','樊鑄','唐','唐诗','tang','','[]','開物務便成，通幽自有程。',48,'全唐诗/poet.tang.50000.json','["開物務便成，通幽自有程。", "退藏緣遇暗，入用爲逢明。", "契理關潛受，知機力不爭。", "賴因相啟發，遂得振金聲。"]'),
('682bdadf-8d41-40a1-9c70-f6b6bee6c279','及第後讀書院詠物[一]十首上禮部李侍郎 藥臼[一]','樊鑄','唐','唐诗','tang','','[]','器重性仍堅，登庸響即傳。',79,'全唐诗/poet.tang.50000.json','["器重性仍堅，登庸響即傳。", "口因良藥苦，心爲中規圓。", "繼務精三代，輪攻孕十全。", "終齊善救理，莫謂枉陶甄。", "（[一]劉云：「『臼』與『救』同，聲爲上去，故可作音源。", "」）。"]'),
('2ac80bef-9f79-40f7-8cda-37a53eef3a75','及第後讀書院詠物[一]十首上禮部李侍郎 濾水羅','樊鑄','唐','唐诗','tang','','[]','經緯既縱橫，偏承啟沃情。',134,'全唐诗/poet.tang.50000.json','["經緯既縱橫，偏承啟沃情。", "含虛素心淨，樂水智囊成。", "密㥀（緻）[一]能藏垢，疏通自去盈。", "不問垂善濾，何問下流清。", "（[一]余疑「㥀」是「緻」通用俗字，或音誤。", "俞云：「校作『緻』，較遠，疑當作『慎』，因濾水羅正不必密緻也。", "密慎與下文疎通對文。", "」按俞先生說較好。", "劉校與俞同。", "）。"]'),
('ab37945f-35ee-4adb-98bb-61fa2e3dc009','及第後讀書院詠物[一]十首上禮部李侍郎 井轆轤','樊鑄','唐','唐诗','tang','','[]','有幸奉陶甄，時行即轉圓。',64,'全唐诗/poet.tang.50000.json','["有幸奉陶甄，時行即轉圓。", "從繩每合轍，遇坎本（奉）[一]周旋。", "□是循環正，何曾汲引偏。", "已承鈞軸力，不慮墜諸泉。", "（[一]依劉校。", "）。"]'),
('69eb713b-debc-48c6-8f58-b1304b84df2f','及第後讀書院詠物[一]十首上禮部李侍郎 塼道','樊鑄','唐','唐诗','tang','','[]','入用因埏埴，時行任比方。',19,'全唐诗/poet.tang.50000.json','["入用因埏埴，時行任比方。", "連階（下缺）。"]'),
('c5b4a22d-9d2b-466a-984f-4542b7b87aeb','及第後讀書院詠物[一]十首上禮部李侍郎 □□（伯三四八○）','樊鑄','唐','唐诗','tang','','[]','鑄劍本來殺讎[一]人，懷珠本來報國士。',146,'全唐诗/poet.tang.50000.json','["鑄劍本來殺讎[一]人，懷珠本來報國士。", "信知善惡皆相報，如何不肯樹桃李。", "物情飜覆難可論，莫言權勢長頭[二]存。", "鼎食却爲農桑子，布衣還啟丞相門。", "丈夫立身須自省，知禍知福如形影。", "乍可惠人一飯恩，不得唾人千里井。", "（[一]原作「讎殺」，依劉校互乙。", "[二]劉云：「『長頭』二字乃俗語。", "『頭』，尾聲。", "」）。"]'),
('73301ed1-90ac-47d4-9cb4-71b57578f215','登岐州城樓','皇甫斌','唐','唐诗','tang','','[]','岐雍三秦地，登臨實壯哉！客心關外斷，秋氣隴頭來。',48,'全唐诗/poet.tang.50000.json','["岐雍三秦地，登臨實壯哉！客心關外斷，秋氣隴頭來。", "歸目浮雲蔽，寒衣早雁催。", "他鄉有時菊，留賞故人盃。"]'),
('c436ab6b-20b3-4a59-9b95-a60ebabb5fbe','秋夜（伯三六一九。又三八八五）','桓顒','唐','唐诗','tang','','[]','數夜獨無歡，客心恆不安。',73,'全唐诗/poet.tang.50000.json','["數夜獨無歡，客心恆不安。", "近城聞鼓異（易），遠寺[一]聽鐘難。", "月照窗邊暖，風吹簾外寒。", "齊能羅帳裏，獨坐抱琴彈。", "（[一]原作「寺遠」，依劉校互乙。", "）。"]'),
('e7e4d2f0-31ec-4781-8a6c-1708f7fe618a','無題（伯三一九七）','盧茂欽','唐','唐诗','tang','','[]','躺遊仙院覩靈臺，羅綺分明塑匠裁。',117,'全唐诗/poet.tang.50000.json','["躺遊仙院覩靈臺，羅綺分明塑匠裁。", "高綰綠鬟{髟/云}（雲）髻重，手垂羅袖牡丹開。", "（「手垂」，項目疑當作「平垂」，與「高綰」爲對。", "）容儀一見情難捨，玉貌重看意嬾迴。", "若表懇成（誠）心所志，願將恣貌夢中來。", "（「恣」，蔣、項皆云當作「姿」。", "）。"]'),
('e18f811c-17a3-487e-b435-a6381cb79c8a','觀岳壽寺松因課留題（斯七六）','劉延堅','唐','唐诗','tang','','[]','植來高節歲經霜，濃翠穿雲出上方。',81,'全唐诗/poet.tang.50000.json','["植來高節歲經霜，濃翠穿雲出上方。", "花界静標千樹秀，禪心閑對四時涼。", "根磻蘚石龍形老，（「磻」，蔣、項皆云當作「蟠」。", "）乳滴金沙琥珀香。", "爲愛奇材看在盡，題詩留在遠公房。"]'),
('6eea6be4-7440-4134-84c3-f0e6696da634','寓止觀中因抒感懷','劉延堅','唐','唐诗','tang','','[]','伯陽宮館好煙霞，知换浮生幾歲華。',64,'全唐诗/poet.tang.50000.json','["伯陽宮館好煙霞，知换浮生幾歲華。", "雖訪靈芝身不遠，未逢真訣道還賒。", "玉清難測無窮景，金露能摧有限花。", "南待總拋榮辱了，始應親近得仙家。"]'),
('423e0c01-5407-4c3f-8b1a-25eaf9c85d13','登靈巖寺（伯三六一九）','沙門日進','唐','唐诗','tang','','[]','靈岳多奇勢，茲山負聖圖。',146,'全唐诗/poet.tang.50000.json','["靈岳多奇勢，茲山負聖圖。", "谷中清溜響，峯際白雲孤。", "石壁連霄漢，長松落澗枯。", "澄心香閣下，煩慮寂然無。", "（斯三八一卷《龍興寺毗沙門天王靈驗記》，錄「大蕃歲次辛巳潤二月十五日」事，署「本寺大德僧日進附口抄」。", "疑即本詩作者。", "「大蕃歲次辛巳」即唐貞元十七年〖八○一〗。", "龍興寺爲敦煌名剎，遺書中記載較多。", "）。"]'),
('c987e46b-4ec1-40ae-a454-553d40735424','秦箏怨（伯三八八五）','宋家娘子','唐','唐诗','tang','','[]','玳瑁秦箏裏，聲聲怨別離。',48,'全唐诗/poet.tang.50000.json','["玳瑁秦箏裏，聲聲怨別離。", "只緣多苦調，欲奏淚還垂。", "妾意如絃直，君心學柱移。", "蹔時停不弄，音調早參差。"]'),
('ddca4880-a42d-4a45-b3de-56508296f058','春尋花柳得情（三八一二）','宋家娘子','唐','唐诗','tang','','[]','美人林裏趁鵶兒，銀甲花間不覺遺。',33,'全唐诗/poet.tang.50000.json','["美人林裏趁鵶兒，銀甲花間不覺遺。", "連忙借問嬌鸚鵡，鳥鳥銜將與阿誰？。"]'),
('59da975c-ad0a-4cc9-b249-21b056316559','前言','王重民輯錄，劉脩業整理。','唐','唐诗','tang','','[]','有三（重民）據敦煌殘卷補《全唐詩》的整理工作，曾化過二十多年的心血。',1173,'全唐诗/poet.tang.50000.json','["有三（重民）據敦煌殘卷補《全唐詩》的整理工作，曾化過二十多年的心血。", "按照原來計劃，全稿分爲三卷：「卷一均有作者姓氏，專補《全唐詩》；卷二均失作者姓氏，凡殘詩集依集編次，凡選詩（指單篇的）依詩編次；卷三爲敦煌人作品（詠敦煌者如《敦煌廿詠》亦入此卷）。", "」其中卷一曾以《補全唐詩》爲題，發表於《中華文史論叢》一九六三年第三期。", "卷二、卷三的遺稿，雖已基本就緒，則因他不幸逝世，未能最後定稿。", "在他生前，曾將其中一部份請王堯同志校閱；有三逝世後，又經舒學同志整理，題爲《敦煌唐人詩集殘卷》，發表在《文物資料叢刊》第一期（一九七七年）上。", "最近，我在整理有三輯錄的敦煌殘卷詩集時，又發現了《補全唐詩》卷一漏編的有作者姓氏的詩，一是李翔的《涉道詩》，據有三生前考定，李翔生活的時代比韓愈稍晚；另一即馬雲奇被吐蕃俘虜時寫的紀行詩，已收入《敦煌唐人詩集殘卷》。", "此外還有原來擬編入《補全唐詩》卷二、卷三的部份已輯錄的遺稿，其中有「殘詩集」、「單篇」詩，還有「敦煌人作品」。", "現依照有三生前計劃，重新整理，並將發表於《文物資料叢刊》部份亦一併輯入各卷，並改了其中未校出的錯字。", "按照有三原來計劃，本拾遺編次如下：卷一殘詩集（《補全唐詩》漏編）李翔《涉道詩》（伯三八六六）廿八首馬雲奇詩集殘卷（伯二五五五）十三首卷二佚名的詩殘詩集（伯二五五五）五十九首王昭君怨諸詞人連句（伯二七四八）一首謁法門寺真身五十韵（伯三四四五）一首無題（斯五五五八）一首卷三敦煌人作品敦煌廿詠並序附一首共二十一首凡六寫本，其原編號如下：原卷（伯二七四八）、甲卷（伯三九二九）、乙卷（伯二九八三）、丙卷（伯三八七○）、丁卷（斯六一六七）、戊卷（伯二六九○背）詠敦煌詩（伯五○○七）三首每種詩題下註明所據卷子號碼，有兩個寫本者，亦一一註明，連同校記文字，附各詩之後。", "詩有異文，略作校勘；原有錯字，用括號註出，不清楚的字，用方框表示。", "但敦煌殘卷的詩，鈔寫多用俗字，如「軀」作「𨈬」，「鎖」作「鏁」，此外還有「總」字常作「惣」，「閉」字常作「閇」，今即逕改，不加註。", "在整理工作中，借力於舒學同志的《敦煌唐人詩集殘卷》整理稿不少；馬蹄疾同志對整理工作提了建設性的意見，並爲校讀了前言；初稿寫出後，請陰法魯同志校閱，給我提出了很好的意見，並校出一些錯誤的字；《中華文史論叢》編輯同志爲此稿發表作了很多工作，謹一併在此致謝。", "整理工作中所校錄文字，有不當之處，誠望指正。", "劉脩業記於有三逝世五週年祭時公元一九八○年四月十六日此整理稿初次發表時，對伯二五五五卷馬雲奇詩及佚名詩的考定與分析，是採用舒學同志的原序，撮要迻錄附於詩後。", "有三生前對這些詩亦有考釋，似覺得對這七十二首詩的寫作背景及所反映時代特色的考定與分析較爲符合實際，故此次編集時，已請本書責任編輯將馬雲奇及佚名詩後的說明作了修訂。", "劉脩業一九八三年一月三日又記。"]'),
('f54266ff-9369-4655-920c-9a56a2a06417','','李翔','唐','唐诗','tang','','[]','（《涉道詩》二十八首〖伯三八六六〗）。',19,'全唐诗/poet.tang.50000.json','["（《涉道詩》二十八首〖伯三八六六〗）。"]'),
('45ebc19f-70f0-4e18-80d3-e66aa770dae8','看縉雲山圖','李翔','唐','唐诗','tang','','[]','謂見仙都二十年，（謂，項疑當作「未」。',76,'全唐诗/poet.tang.50000.json','["謂見仙都二十年，（謂，項疑當作「未」。", "）忽逢圖畫頓欣然。", "雲巖不似人間世，物象翻疑洞裏天。", "迥壓鰲頭當海眼，直侵鵬路倚星躔。", "頂湖縱去無多地，空見霜流百丈泉。"]'),
('9525d9ff-afb5-4d41-8282-a1ee245d52a5','百步橋','李翔','唐','唐诗','tang','','[]','亘險凌虛百步橋，古應從此上千（干）霄。',86,'全唐诗/poet.tang.50000.json','["亘險凌虛百步橋，古應從此上千（干）霄。", "（「古應」，項疑當作「故應」。", "）不辭宛轉峰千仞，且喜分明路一條。", "銀漢攀緣知必到，月宮斟酌去非遙。", "牽牛漫更勞烏鵲，歲歲填河綠頂爑（焦）。"]'),
('5071d3f2-4f87-4842-b9fc-aff90fba57c5','投龍池','李翔','唐','唐诗','tang','','[]','虎眼渦盤石窟中，古今俱向此投龍。',67,'全唐诗/poet.tang.50000.json','["虎眼渦盤石窟中，古今俱向此投龍。", "奫淪不啻深千丈，肹（肸）蠁皆應到九重。", "洞穴昔聞通地府，風雲今得遇靈蹤。", "無因犯世間雷雨，池面連天拔一峰。"]'),
('d94be113-93a0-41ff-88c5-74474f44631a','頂湖','李翔','唐','唐诗','tang','','[]','萬仞峰頭鑿一湖，更誰來此用功夫。',51,'全唐诗/poet.tang.50000.json','["萬仞峰頭鑿一湖，更誰來此用功夫。", "張霞鱲（鬣）是星河鯉，濯火領多日御烏。", "往往風波聞下界，時時花雨護仙都。"]'),
('f583912d-b45d-4a3b-9299-f14eec0b33a8','石鶴','李翔','唐','唐诗','tang','','[]','白石孤標逸鶴形，古人隨類巧安名。',64,'全唐诗/poet.tang.50000.json','["白石孤標逸鶴形，古人隨類巧安名。", "巖花落處見朱頂，夜雨來時聞唳聲。", "遼海未曾重寄語，緱山今更請寬程。", "若教衛懿如今在，也遣軒車到此迎。"]'),
('952663f4-dcc2-4359-87fc-bdc6cb8ab378','謝公石罇','李翔','唐','唐诗','tang','','[]','康樂雲樓跡尚存，竹亭猶仰古窪罇。',64,'全唐诗/poet.tang.50000.json','["康樂雲樓跡尚存，竹亭猶仰古窪罇。", "苔封四面迷山象，露滴中心認酒痕。", "巖月舊來曾伴飲，澗泉今咽共誰論。", "無因訪得逃堯客，求取風瓢掛石門。"]'),
('f72c0a42-7bfc-4a5d-bdb3-47a0ae347d91','童子山','李翔','唐','唐诗','tang','','[]','童子山形也不孤，勢疑高拱從（聳）（僊）都。',100,'全唐诗/poet.tang.50000.json','["童子山形也不孤，勢疑高拱從（聳）（僊）都。", "雲生石肘如擎帔，月到巖心似捧壼。", "豈可繞壇操鳯節，争教侍（持）燭秉麟鬚。", "（項云「侍」字似不誤，猶「侍酒」、「侍書」之「侍」也。", "）桑田若更成東海，始肯隨師化此軀。"]'),
('5cc56693-c573-4887-af9b-ee7a4e1d5438','嚴尚書重浚橫泉井','李翔','唐','唐诗','tang','','[]','古甃千尋鎖綠苔，老蛟曾遯（遁）此中來。',71,'全唐诗/poet.tang.50000.json','["古甃千尋鎖綠苔，老蛟曾遯（遁）此中來。", "厭聆羽客提鋒入，喜見將軍杖（仗）節開。", "玉液洞通甘似醴，金瓶輪下殷如雷，更聞堪療羣生疾，願倚崇欄飲一杯。", "。"]'),
('6c289403-1a7a-4999-abea-a2007d73c984','許真君鐵柱','李翔','唐','唐诗','tang','','[]','恐老蛟重作患深[一]，獨埋鐵柱至如今。',91,'全唐诗/poet.tang.50000.json','["恐老蛟重作患深[一]，獨埋鐵柱至如今。", "根牢直下蟠江底，勢壯長留鎮郡心。", "神鬼每聞趨夜後，風雷不敢犯塘陰。", "無因更走橫泉窟，壓斷祈精氣永沉。", "（[一]首句有誤，疑當作「深恐老蛟重作患」。", "）。"]'),
('67aaf6ce-ab3a-4b12-87b9-8cc998c5f223','題麻姑山廟','李翔','唐','唐诗','tang','','[]','險翠峨霄壓上游，大仙曾向此幽求。',64,'全唐诗/poet.tang.50000.json','["險翠峨霄壓上游，大仙曾向此幽求。", "雲埋三級壇空在，月照千尋水自流。", "偃蓋鶴還清露滴，古池龍睡碧蓮秋。", "桑田未必翻爲海，香火何人解繼修。"]'),
('28958c31-0d3d-4757-bbf3-0511f02f2c03','軍山前馬退石','李翔','唐','唐诗','tang','','[]','山亘南豐石亘山，石橫山路馬登難。',64,'全唐诗/poet.tang.50000.json','["山亘南豐石亘山，石橫山路馬登難。", "非論蹇步須回駕，縱使追風亦解鞍。", "恐是龍宮通洞府，莫應猿嶺建星壇。", "何因不許超驤輩，踏着連雲大麓端。"]'),
('3f8002ae-3229-4887-8438-03ae13fadddf','馬明生遇王婉羅','李翔','唐','唐诗','tang','','[]','徹骨金瘡分已休，謝神妃護到靈丘。',70,'全唐诗/poet.tang.50000.json','["徹骨金瘡分已休，謝神妃護到靈丘。", "供丞（承）洞府知何地，灑掃雲房不記秋。", "金鎖玉函雖照燿，寶書真篆敢規（窺）求。", "龍胎未肯傳初學，又逐安期萬里游。"]'),
('d98076a5-e805-4f4e-b53c-ab15f7eb432d','登臨川仙臺觀南亭','李翔','唐','唐诗','tang','','[]','獨倚危欄愛景晴，古松壇殿半陰橫。',65,'全唐诗/poet.tang.50000.json','["獨倚危欄愛景晴，古松壇殿半陰橫。", "東山有路干雲險，汝水無波到底清。", "歸洞鬬龍收雨脚，拂簷行雁起秋聲。", "開襟正是忘機處，不覺疏鐘遍郡城。", "。"]'),
('de9915a8-402c-4658-a060-967242c56716','謝梁尊師見訪不遇','李翔','唐','唐诗','tang','','[]','曉斸（斲）黃精晝未還（項云「斸」字不誤，不必改。',82,'全唐诗/poet.tang.50000.json','["曉斸（斲）黃精晝未還（項云「斸」字不誤，不必改。", "），豈知仙老降柴關。", "一聲歸鶴唳江口，數片白雲遺竹間。", "悵望有慚勞羽駕，差池不得禮冰顏。", "秋風獨倚書齋立，遙想真暉對暮山。"]'),
('8bb4163b-fad9-4446-bd9f-1f482b1cc20e','魏夫人歸大霍山','李翔','唐','唐诗','tang','','[]','受錫南歸大霍宮，衆真同會絳房中。',64,'全唐诗/poet.tang.50000.json','["受錫南歸大霍宮，衆真同會絳房中。", "裘披鳯錦千花麗，斾綽龍霞八景紅。", "羽帔儼排三洞客，仙歌凝韵九天風。", "元君未許人先起，更待雲璈一曲終。"]'),
('6296651d-15d5-4f47-bb90-6cf2b1b14e62','馮雙禮珠彈雲璈以答歌','李翔','唐','唐诗','tang','','[]','王母詞終薦碧桃，答歌仙子奏雲璈。',85,'全唐诗/poet.tang.50000.json','["王母詞終薦碧桃，答歌仙子奏雲璈。", "調凌空洞音初起，曲麗鈞天韵更高。", "霞斷已翔煙際鶴，風生欲抃海心鰲。", "瑤池侍女争回首，無隈琅英墜節毛。", "（項云「無隈」當作「無限」，形近而誤。", "）。"]'),
('308e2373-6855-417a-aeb1-8ea9962be459','魏夫人受大洞真經','李翔','唐','唐诗','tang','','[]','太極仙公降上清，爲傳三十九章經。',67,'全唐诗/poet.tang.50000.json','["太極仙公降上清，爲傳三十九章經。", "先教稽首丞（承）明詔，次遣齋心向洞冥。", "妙句只令巖下讀，真文不許世間聽。", "寶函鈿軸披尋遍，始駕龍車謁帝庭。"]'),
('3015c3d8-71dd-4c12-955a-272ad6993d5a','衛叔卿不賓漢武帝','李翔','唐','唐诗','tang','','[]','鑾殿仙卿頓紫雲，武皇非意欲相臣。',64,'全唐诗/poet.tang.50000.json','["鑾殿仙卿頓紫雲，武皇非意欲相臣。", "便迴太華三峰路，不喜咸陽萬乘春。", "涉險漫勞中禁使，投壺多是上清人。", "猶教度世依方術，莫戀浮榮誤爾身。"]'),
('d00dfa0b-316c-4478-864a-a9b6fbc900bd','獻龍虎山張天師','李翔','唐','唐诗','tang','','[]','東漢天師直下孫，久依科戒住玄門。',64,'全唐诗/poet.tang.50000.json','["東漢天師直下孫，久依科戒住玄門。", "寰中有位逢皆拜，世上無人見不尊。", "三洞吏兵潛稽首，六宮魔幻暗銷魂。", "可能授與長生籙，浩劫銘肌敢忘恩。"]'),
('af868f62-2f43-4ef6-ac7d-7237d2dcf4ad','小有王君別西域總真','李翔','唐','唐诗','tang','','[]','從事明真入洞臺，便祛秋骨月致仙材。',65,'全唐诗/poet.tang.50000.json','["從事明真入洞臺，便祛秋骨月致仙材。", "絳宮玄圃皆尋遍，龜岫龍洲盡到來。", "聞啟玉皇過九奏，教詔金液語千回。", "謂言得道輕離別，重感師恩泣更哀。"]'),
('e101ee7c-d8d2-4ffa-88a4-b8f18b9e6c4b','寄題尋真觀','李翔','唐','唐诗','tang','','[]','見說尋真地勢雄，面臨湖北倚高峰。',64,'全唐诗/poet.tang.50000.json','["見說尋真地勢雄，面臨湖北倚高峰。", "奔濤入夏雷聲迅，險嶂凌秋黛色濃。", "壇上步虛頻降鶴，洞中投簡數驚龍。", "何勞更訪桃源路，水曲雲深千萬重。"]'),
('70b9acce-940d-490a-b47b-98f2f50356ab','題金泉山謝自然傳後','李翔','唐','唐诗','tang','','[]','暫謫歸天固有程，虛皇還召赴三清。',231,'全唐诗/poet.tang.50000.json','["暫謫歸天固有程，虛皇還召赴三清。", "簫歌近向峰頭合，羽駕低臨洞口迎。", "自换玉衣期上帝，豈關金格注生名。", "門人未得隨師去，雲外空聞好住生[一]。", "（[一]北京圖書館藏敦煌卷子「乃」字七四號《辭孃贊》〖伯二九一九號同〗，是出家的青年辭別父母兄弟的唱辭，如首兩句云：「兒欲入山修道去，好住孃，兄弟努力好看孃，好住孃。", "」謝自然死了，弟子們不能隨他去，在離別之際所唱的「好住」聲，應該和佛教徒的「好住孃」相類似。", "大概受戒的青年道徒在離別父母兄弟的時候，也有這一類的「好住」唱辭。", "）。"]'),
('4781fa5e-6ec8-48cc-a4c2-157bb3e7dfb6','宿西山凌雲觀','李翔','唐','唐诗','tang','','[]','掩映真居不易求，自驚何路到蓬丘。',48,'全唐诗/poet.tang.50000.json','["掩映真居不易求，自驚何路到蓬丘。", "庭心月近石壇古，海面風微山殿秋。", "控鶴嶺高星半隔，伏龍崗轉水分流。"]'),
('e69b8459-17f4-4ffb-8e5c-9666aa21b597','秋日過龍興觀墨池','李翔','唐','唐诗','tang','','[]','獨登仙館欲從誰？聞者（有）王君舊墨池。',76,'全唐诗/poet.tang.50000.json','["獨登仙館欲從誰？聞者（有）王君舊墨池。", "苔蘚已侵行履跡，窪坳猶是古來規。", "竹梢聲認（識）揮毫日，殿角陰疑洗硯時。", "{口歎}（歎）倚壇邊紅葉樹，霜鐘欲盡下山遲。"]'),
('f81b6982-1fa1-4634-943f-e16614a78185','寄麻姑山喻供奉','李翔','唐','唐诗','tang','','[]','羽客乘風下九天，撥雲親自揀林泉。',94,'全唐诗/poet.tang.50000.json','["羽客乘風下九天，撥雲親自揀林泉。", "檐吞海魄迎真氣，路繞巖根謁古仙。", "道豚（遁）早爲三洞伏，（項云「豚」應作「勝」，因「勝」字別體作「𬛊」而誤。", "）詩成曾被六宮傳。", "如今萬事皆輕棄，只待還丹駐鶴年。"]'),
('4e2f895b-17df-4675-ab98-07b931cab41d','覽鍊師張殷儒詩','李翔','唐','唐诗','tang','','[]','石井峰高劈曙雲，雲開山露見張君。',65,'全唐诗/poet.tang.50000.json','["石井峰高劈曙雲，雲開山露見張君。", "心藏定遠握中策，袖貯懷沙江上文。", "巨壑波翻鯨少敵，老松巢迥鶴難羣。", "無端示我青霞句，吟斷秋風到日曛。", "。"]'),
('e7c2d733-2f49-466a-9bcb-23ea2279e90d','西林寺與樵（焦）鍊師賦得階下泉','李翔','唐','唐诗','tang','','[]','迴廊折漩（旋）繞空階，暗西寧舟霜瀉峭崖。',68,'全唐诗/poet.tang.50000.json','["迴廊折漩（旋）繞空階，暗西寧舟霜瀉峭崖。", "蕙帶客尋經遠澗，麻衣僧引到高齋。", "流分曉月光難駐，響入清琴韵易諧。", "時有真官訪衰病，每同觀聽蕩幽懷。"]'),
('5bd04b45-6fc0-4977-bb76-930f8b439699','舞鳯石','李翔','唐','唐诗','tang','','[]','遠見麻姑戲瑞禽，每來教舞此壇心。',485,'全唐诗/poet.tang.50000.json','["遠見麻姑戲瑞禽，每來教舞此壇心。", "基離地面三千丈，勢倚雲根一萬尋。", "煙海日搖雙翅影，洞天風散九韻音。", "自從越叟分明說，便想羅浮直至今。", "（〖1〗上面這些詩寫辰一小冊上，線裝，僅存五葉，共二十八首。", "後有殘闕，原書葉數、詩數不知多少。", "總題《涉道詩》，下題撰人李翔姓名。", "李翔的時代和事跡無所考，這個詩集也不見於著錄。", "所歌詠酬答的都是道山道觀，當時道教的天師、尊師、鍊師、總真以及供奉和道教史上的著名人物事跡等。", "這應該是一部現存最古的道徒詩集。", "〖2〗詩中所表現的山名和地名，多在今江西、江蘇、浙江三省，主要是在龍虎山、茅山、天台山之間，李翔大概就是這一地區以內的人。", "他的時代，大概是第九世紀末年或第十世紀初年的人。", "謝自然是貞元十一年〖七九五〗十一月十二日卒於梁州西門外金泉山的，韓愈〖七六八--八二四〗有《謝自然詩》〖《昌黎先生集》卷一〗，李翔有《題謝自然傳後》〖傳爲郡守李堅所作〗，所以李翔時代，疑比韓愈稍晚。", "〖日本《道教研究》第一冊刊吳其昱《李翔及其涉道詩》推定李翔爲唐高祖九世孫，江王李元祥之後，曾官莆田尉，約於咸通間在世，所據爲《新唐書》卷七○下《宗室世系表》，可備一說。", "〗）。"]'),
('a178a159-d4b8-4a37-b523-3d63a1ee60ed','懷素師草書歌','馬雲奇','唐','唐诗','tang','','[]','懷素才年三十餘，不出湖南學草書。',289,'全唐诗/poet.tang.50000.json','["懷素才年三十餘，不出湖南學草書。", "大夸羲獻將齊德，功比鍾繇也不如。", "疇昔闍梨名蓋代，隱秀於今墨池在，賀老遥聞怯後生，張巔（顛）不敢稱先輩。", "一昨江南投亞相，盡日花堂書草障，含毫勢若斬蛟龍，㭫（握）管還同斷犀象。", "興來索筆縱橫掃，滿坐詞人皆道好。", "一點三峯巨石懸，長畫萬歲枯松倒。", "叫噉（喊）忙忙禮不拘，萬字千行意轉殊。", "紫塞傍窺鴻雁翼，醒前猶自記華章，醉後無論絹與牆，眼看筆掉頭還掉，只見文狂心不狂。", "自倚能書堪入貢，一盞一回捻筆弄，壁上颼颼風雨飛，行間屹屹龍蛇動。", "在身文翰兩相宜，還如明鏡對西施。", "三秋月澹青江水，二月花開綠樹枝。", "聞到懷書西入秦，客中相送轉相親；君王必是收狂客，寄語江潭一路人。"]'),
('453616d8-6117-4e9d-bf11-29a4db400c9f','白雲歌（予時落殊俗隨蕃軍望之感此而作）','馬雲奇','唐','唐诗','tang','','[]','遥望白雲出海灣，變成萬狀須臾間。',467,'全唐诗/poet.tang.50000.json','["遥望白雲出海灣，變成萬狀須臾間。", "忽散鳥飛趁不及，唯只清風隨往還。", "生復滅兮滅復生，將欲凝兮旋已征；因悟悠悠寄寰宇，何須擾擾徇功名。", "滅復生兮生復滅，左之盈兮右之缺；從來舉事皆爾爲，何不含情自怡悅。", "殊方節物異長安，盛夏雲光也自寒。", "遠戍只將煙正起，橫峰更似雪猶殘。", "白雲片片映青山，白雲不盡青山盡。", "展轉霏微度碧空，碧空不見浮雲近。", "漸覺雲低駐馬看，聯綿縹渺拂征鞍。", "一不一兮幾紛紛，散不散兮何漫漫。", "東西南北□□馳，上下高低恣所宜。", "影碧池冰螢□底，光浮綠樹霰凝枝。", "欲謂白雲必從龍，飛來飛去龍不見；欲謂白雲不從龍，乍輕乍重誰能變。", "一重未過一重摧，一畔縈巖一畔開。", "欒巴𠹀（噀）酒應隨去，子晉吹笙定伴來。", "披襟引袖遽迎風，欲□吹雲置袖中；雲飛入袖將爲滿，袖卷看雲依舊空。", "雷殷殷兮雨曚曚，成陰澗下雲之功。", "倏然雲晴銷四極，所潤寧知白雲力。", "大賢濟世徒自勞，一朝運否誰相憶。", "不知白雲何所以，年年歲歲從山起；雲收未必歸石中，石暗翻埋在雲裏。", "世人遷變比白雲，白雲無心但氛氳。", "白雲生滅比世人，世人有心多苦辛。", "旋生旋滅何窮已，有心無心只如此。", "當須體道有貞素，不用浮榮說非是。"]'),
('581d92d5-ab54-4d09-bda6-9e89b4628d84','送游大德赴甘州口號（此便代書寄呈將軍）','馬雲奇','唐','唐诗','tang','','[]','支公張掖去何如？異俗多嫌不寄書。',32,'全唐诗/poet.tang.50000.json','["支公張掖去何如？異俗多嫌不寄書。", "數人四海皆兄弟，爲報殷勤好在無。"]'),
('dc2e95ed-3e49-42cc-94dc-aa3f305ae76e','九日同諸公殊俗之作','馬雲奇','唐','唐诗','tang','','[]','一人歌唱數人啼，拭泪相看意轉迷。',81,'全唐诗/poet.tang.50000.json','["一人歌唱數人啼，拭泪相看意轉迷。", "不見書傳清（青）海北，只知魂斷隴山西。", "登高乍似雲霄近，寓目仍驚草樹低。", "菊酒何須頻勸酌，自然心醉已如泥。", "（太常妻曰一日不齋醉如泥）。"]'),
('4ca64d64-e6c3-4320-b42a-ba0ee8d5d6a8','俯吐蕃禁門觀田判官贈向將軍真言口號（項云「俯」當作「附」，下奪「近」字，「附近」爲接近、靠近之意。）','馬雲奇','唐','唐诗','tang','','[]','怪來偏得主君憐，料取分明在眼前。',32,'全唐诗/poet.tang.50000.json','["怪來偏得主君憐，料取分明在眼前。", "說相未應驚䴏鴒，看心且愛直如弦。"]'),
('18db8c47-4cb2-4d42-b518-4e16537fee34','題周奉御','馬雲奇','唐','唐诗','tang','','[]','明王道得腹心臣，百萬人中獨一人。',32,'全唐诗/poet.tang.50000.json','["明王道得腹心臣，百萬人中獨一人。", "階下往來三逕跡，門前桃李四時春。"]'),
('6b29bf83-e81c-4821-8000-6ba3b18cd626','贈鄧郎將四弟','馬雲奇','唐','唐诗','tang','','[]','把袂相歡意最濃，十年言笑得朋從。',32,'全唐诗/poet.tang.50000.json','["把袂相歡意最濃，十年言笑得朋從。", "憐君節操曾無易，只是青山一樹松。"]'),
('2775ca59-6375-4f03-91b1-8c73890ee69b','同前已（以）詩代書','馬雲奇','唐','唐诗','tang','','[]','故（古）來同病總相憐，不似今人見眼前。',35,'全唐诗/poet.tang.50000.json','["故（古）來同病總相憐，不似今人見眼前。", "且隨浮俗貪趨世，肯料寒灰亦重燃。"]'),
('3f8e0f98-1667-426e-865f-0719d7d509bb','途中憶兒女之作','馬雲奇','唐','唐诗','tang','','[]','髮為思鄉白，形因泣淚枯。',24,'全唐诗/poet.tang.50000.json','["髮為思鄉白，形因泣淚枯。", "爾曹應有夢，知我斷腸無。"]'),
('630d6306-b7f8-4998-9dcf-7bfa01928423','至淡河同前之作','馬雲奇','唐','唐诗','tang','','[]','念爾兼辭國，緘愁欲渡河；到來河更闊，應爲涕流多。',24,'全唐诗/poet.tang.50000.json','["念爾兼辭國，緘愁欲渡河；到來河更闊，應爲涕流多。"]'),
('e9c2848d-4e07-48f6-b088-df255899a11b','被蕃軍中拘係之作','馬雲奇','唐','唐诗','tang','','[]','何事逐漂蓬，悠悠過鑿空！世窮途運榮（蹇），戰苦不成功。',56,'全唐诗/poet.tang.50000.json','["何事逐漂蓬，悠悠過鑿空！世窮途運榮（蹇），戰苦不成功。", "泪滴東流水，心遥北翥鴻。", "可能忠孝節，長遣門閫（困）西戎。", "。"]'),
('7bd5933b-ff5e-47bc-ac25-0656ff8457df','諸公破落官蕃中製作','馬雲奇','唐','唐诗','tang','','[]','別來心事幾悠悠；恨續長波曉夜流。',32,'全唐诗/poet.tang.50000.json','["別來心事幾悠悠；恨續長波曉夜流。", "欲知起望相思意，看取山雲一段愁。"]'),
('f295b590-92a8-490a-a408-d1f8e6a23ac3','贈樂使君','馬雲奇','唐','唐诗','tang','','[]','知君桃李遍成蹊，故託喬林此處棲。',1063,'全唐诗/poet.tang.50000.json','["知君桃李遍成蹊，故託喬林此處棲。", "雖然灌木凌雲秀，會有寒鵶夜夜啼。", "（〖1〗以上十三首詩從伯二五五五殘卷中錄出。", "第一首下題名馬雲奇。", "因爲這些詩格調相似，其中有多首詠及被吐蕃拘繫之事，故可定爲一人作品。", "這個殘卷中還有五十九首伕名詩〖已編入第二卷〗，也是唐代中期我國國內民族戰爭中被吐蕃拘繫的敦煌漢族人所寫。", "這些詩，過去未見著錄，《全唐詩》也沒有收入。", "有三生前在巴黎圖書館將這一殘卷全文錄出，以後又作過整理加工，惜未最後定稿。", "現據舒學同志的整理稿校對後輯入本卷。", "〖2〗馬雲奇的生平目前雖無資料可查，但從這十三首的內容來看，尤其是從第一首《懷素師草書歌》所寫的懷素情況來看，詩的寫作時間與卷二那五十九首伕名詩大致相近，即在公元七五八--七八一年吐蕃逐漸侵吞河隴地區，而西州、沙州尚爲唐軍堅守之時。", "（對馬雲奇詩及卷二無名氏殘詩集的作者近年有些學者提出了不同看法。", "現摘錄柴劍虹、潘重規的文章如次，以供參考。", "〖3〗）（柴劍虹《敦煌伯二五五五卷「馬雲奇詩」辨》〖刊《中華文史論叢》一九八四年第二輯〗認爲，伯二五五五卷中馬雲奇的詩只有《懷素師草書歌》一首，其餘十二首與另外五十九首一樣，均是一位佚名的落蕃人所作。", "他指出，該卷第一部分正面抄唐人詩一百五十六首，文兩篇，背面抄詩三十二首，應是唐人詩文選集殘卷。", "從抄寫情況看，正面顯係一人筆跡。", "那五十九首坆名詩抄寫格式稍異，大多數詩題完整，且高出一格抄，內容又緊密銜接，作者自抄的可能性很大。", "背面所抄，署名馬雲奇的只有《懷素師草書歌》一首，此詩詩題低兩格抄，署名又和詩題空兩格，且用大字抄寫。", "《白雲歌》等十二首抄於此詩之左，並無署名，而且馬上改變了抄寫格式，字體也縮小了一倍，詩題頂格。", "這十二首詩從抄寫格式到內容、風格均與馬雲奇《懷素師草書歌》迥異，卻與寫卷正面那五十九首佚名詩連貫一氣。", "他將兩組詩相比較後，認爲有兩點值得注意：第一，作者身世相同，詩的內容一致；第二，有些詩句極爲相仿，似出一人之手，兩組詩可能爲同一人所作。", "他並推測這兩組詩的作者，可能即爲緊接前五十九首詩抄錄劉商《胡笳十八拍》後又自加一拍的「落蕃人毛押牙」。", "關於馬雲奇，柴劍虹考證其《懷素師草書歌》應作於大曆六年冬至九年春之間。", "並推測其可能到過河西一帶，蘇聯藏敦煌殘卷中有岑參《敦煌馬太守後亭歌》，這位馬太守是否馬雲奇，尚有待確定。", "〖4〗潘重規《敦煌唐人陷蕃詩集殘卷作者的新探測》〖刊一九八五年六月出版的《漢學研究》第三卷第一期〗一文，爲作者在巴黎國家圖書館東方稿本部披閱敦煌原卷後寫成，也認爲馬雲奇是陷蕃詩集作者之一的說法是錯誤的。"]'),
('9bc3755e-b428-4b67-8cf1-6857cb409407','冬出敦煌郡入退渾國朝發馬圈之作','佚名','唐','唐诗','tang','','[]','西行過馬圈，北望近陽關。',51,'全唐诗/poet.tang.50000.json','["西行過馬圈，北望近陽關。", "迴首見城郭，黯然林樹間。", "野烟暝村墅，初是慘寒山。", "步步鍼（緘）愁色，迢迢惟夢還。"]'),
('bee2b4b7-bcfd-43b2-aecd-9c3b6c9a694a','至墨離海奉懷敦煌知己','佚名','唐','唐诗','tang','','[]','朝行傍海涯，暮宿幕爲家。',48,'全唐诗/poet.tang.50000.json','["朝行傍海涯，暮宿幕爲家。", "千山空皓雪，萬里盡黃沙。", "戎俗途將近，知音道已賒。", "迴瞻雲嶺外，揮涕獨咨嗟。"]'),
('84c1a0b9-9ed3-469a-9743-7505cd200201','冬日書情','佚名','唐','唐诗','tang','','[]','殊鄉寂寞使人悲，異域留連不暇歸。',64,'全唐诗/poet.tang.50000.json','["殊鄉寂寞使人悲，異域留連不暇歸。", "萬里山河非舊國，一川戎俗是新知。", "寒天落景光陰促，雪海穹廬物色稀。", "爲客終朝長下泣，誰憐曉夕老容儀。"]'),
('0b117f24-432a-4e59-b1d8-ace91acb96de','登山奉懷知己','佚名','唐','唐诗','tang','','[]','閑步陟高崗，相思淚數行。',56,'全唐诗/poet.tang.50000.json','["閑步陟高崗，相思淚數行。", "陣雲橫北塞，煞（原作「𭣦」）氣暝南荒。", "極目悲無限，樵心恨未遑。", "黯然鄉國處，空見路茫茫。", "。"]'),
('9af724a5-782c-4862-9795-a89c704fe5b5','夏中忽見飛雪之作','佚名','唐','唐诗','tang','','[]','三冬自北來，九夏未南迴，青溪雖郁郁，白雲尚皚皚。',55,'全唐诗/poet.tang.50000.json','["三冬自北來，九夏未南迴，青溪雖郁郁，白雲尚皚皚。", "海闇山恒暝，愁雲霧不開，唯余鄉國意，朝夕思難裁（原作「栽」）。"]'),
('02ea8feb-8f55-47be-8d65-33ea4bd8d76b','夏（原作「冬」）日野望','佚名','唐','唐诗','tang','','[]','出戶過河梁，登高試望鄉。',48,'全唐诗/poet.tang.50000.json','["出戶過河梁，登高試望鄉。", "雲隨愁處斷，川逐思彌長。", "晚吹低藂草，遥山落夕陽。", "徘徊噎不語，空使淚沾裳。"]'),
('23285c3e-ed77-404a-b9e3-c9c3d4f6f465','夏日途中即事','佚名','唐','唐诗','tang','','[]','何事鎮駈駈？馳驂傍海隅。',48,'全唐诗/poet.tang.50000.json','["何事鎮駈駈？馳驂傍海隅。", "溪邊論宿處，澗下指飡厨。", "萬里山河異，千般物色殊。", "愁來竟不語，馬上但長吁。"]'),
('d4cf0583-4e72-43c8-bff4-66df70a1ff9e','青海臥疾之作 一','佚名','唐','唐诗','tang','','[]','數日穹廬臥疾時，百方投藥力將微。',65,'全唐诗/poet.tang.50000.json','["數日穹廬臥疾時，百方投藥力將微。", "驚魂漫漫迷山際，怯魄悠悠傍海涯。", "旋知命與浮雲合，可嘆身同朝露晞。", "男兒到此須甘分，何假含啼枕上悲！。"]'),
('6d4d45e4-c86a-43ff-b8dc-c8245cc70fd0','青海臥疾之作 二','佚名','唐','唐诗','tang','','[]','邂逅遇迍蒙，人情詎見通？',48,'全唐诗/poet.tang.50000.json','["邂逅遇迍蒙，人情詎見通？", "昔時曾虎步，即日似禽籠。", "有命如朝露，天依類斷蓬。", "緬懷知我者，榮辱杳難同。"]'),
('49b3eb43-2c02-4a01-938a-f18dc752fe28','秋夜','佚名','唐','唐诗','tang','','[]','一夜秋聲傍海多，五更寒色早來過。',33,'全唐诗/poet.tang.50000.json','["一夜秋聲傍海多，五更寒色早來過。", "自然覊旅腸堪斷，況復猜嫌被網羅。", "。"]'),
('d5b6f006-5259-4f22-a2f5-42580244ddb0','青海望敦煌之作','佚名','唐','唐诗','tang','','[]','西北指流沙，東南路轉遐。',58,'全唐诗/poet.tang.50000.json','["西北指流沙，東南路轉遐。", "獨晴留海畔，歸望阻天涯。", "九夏呈芳草，三時有雪花。", "未能刷（原作「{帀刂}」）羽去，空此羨城鵶。"]'),
('ca0a77c8-cc4f-43b5-8bd3-15e2a092ccab','首秋聞雁幷懷敦煌知己','佚名','唐','唐诗','tang','','[]','戎庭節物由來早，倐忽霜秋被寒草。',63,'全唐诗/poet.tang.50000.json','["戎庭節物由來早，倐忽霜秋被寒草。", "旅雁噰噰□□□，覊人夜夜心如擣。", "與君離別恨經年，何事音書遂黯然。", "腸斷祇今□□□，知西北泣雲烟。"]'),
('a4573161-4108-4a5c-9047-01999836d277','秋中雨雪','佚名','唐','唐诗','tang','','[]','䟃𧽼雨雪下長川，浩蕩風波近海□。',16,'全唐诗/poet.tang.50000.json','["䟃𧽼雨雪下長川，浩蕩風波近海□。"]'),
('3bbd60e1-28cf-4a3b-ae30-7e48efe08a54','臨水聞雁','佚名','唐','唐诗','tang','','[]','□來臨水弔愁容，忽覩愁容淚滿胸。',75,'全唐诗/poet.tang.50000.json','["□來臨水弔愁容，忽覩愁容淚滿胸。", "肝膽隳離凡幾度，雲山阻□況千重。", "（闕字，項補「隔」。", "）心殊語異情難識，東步西馳意不從。", "覊紲祇今腸自斷，更聞哀雁叫噰噰。"]'),
('7e2ef05b-1d4b-487f-b074-56917b2d0637','秋中霖雨','佚名','唐','唐诗','tang','','[]','寒雨霖霖竟不停，覊愁寂寂夜何寧？',64,'全唐诗/poet.tang.50000.json','["寒雨霖霖竟不停，覊愁寂寂夜何寧？", "山遥塞闊阻鄉國，草白風悲感客情。", "西瞻瀚海腸堪斷，東望咸秦思轉盈。", "才薄孰知無所用，獨嗟戎俗滯微名。"]'),
('7b426457-5aa7-4e8a-91a5-24464c4dead8','夢到沙州奉懷殿下','佚名','唐','唐诗','tang','','[]','一從淪陷自天涯，數度恓（原作「栖」）惶怨別家。',167,'全唐诗/poet.tang.50000.json','["一從淪陷自天涯，數度恓（原作「栖」）惶怨別家。", "將謂飄零長失路，誰知運合至流沙。", "浪漫有幸達人主，惟恨天才遇尚賒。", "日夕恩波沾雨露，縱橫顧盼益光華。", "光華遠近誰不羨，常思刷羽摶風便。", "忽使三冬告別離，山河萬里誠難見。", "昨來魂夢傍陽關，省到敦煌奉玉顏。", "舞席歌樓似登陟，綺筳花柳記躋攀。", "總緣宿昔承言笑，此夜論心豈蹔閑。", "睡裏不知迴早晚，覺時只覺泪斑斑。"]'),
('5848dbc6-1e20-4e4c-9a4b-db4e0dc314e3','秋夜望月 一','佚名','唐','唐诗','tang','','[]','皎皎山頭月欲低，月猒覊愁睡轉迷。',32,'全唐诗/poet.tang.50000.json','["皎皎山頭月欲低，月猒覊愁睡轉迷。", "忽覺淚流痕尚在，不知夢裏向誰啼。"]'),
('a3eebb63-b26a-4b57-a67e-97e9d98bf575','秋夜望月 二','佚名','唐','唐诗','tang','','[]','愁眠枕上泪痕多，況復寒更月色過。',32,'全唐诗/poet.tang.50000.json','["愁眠枕上泪痕多，況復寒更月色過。", "與君萬里難相見，不然一度夢中羅。"]'),
('aa055b9a-c639-4113-aa9a-203e5ee55bce','秋（原作「夏」）日非所書情','佚名','唐','唐诗','tang','','[]','自從去歲別流沙，獨恨今秋歸望賒。',128,'全唐诗/poet.tang.50000.json','["自從去歲別流沙，獨恨今秋歸望賒。", "將謂西南窮地角，誰言東北到天涯。", "山河遠近多穹帳，戎俗迢觀少物華。", "六月尚聞飛雪片，三春豈見有烟花。", "凌晨倏閃奔雷電，薄暮斯須歛霽霞，傍對崇山形屹屹，前臨巨壑勢呀呀。", "昨來覊思憂如擣，即日愁腸亂似麻。", "爲客已遭迍否事，不知何計得還家。"]'),
('94ab29b0-062c-4fa6-ba6b-205ec986e920','憶故人 一','佚名','唐','唐诗','tang','','[]','別君彼此兩平安，別後恓惶凡幾般。',32,'全唐诗/poet.tang.50000.json','["別君彼此兩平安，別後恓惶凡幾般。", "雖然更寄新書去，憶時捻取舊詩看。"]'),
('8e4474bf-6792-4a6a-aa17-45346e9734d0','憶故人 二','佚名','唐','唐诗','tang','','[]','一更獨坐淚成河，半夜想思愁轉多。',32,'全唐诗/poet.tang.50000.json','["一更獨坐淚成河，半夜想思愁轉多。", "左右不聞君語笑，以橫只見唱戎歌。"]'),
('7f394308-23e0-4d88-9555-ac1197a0e22a','夜度赤嶺懷諸知己','佚名','唐','唐诗','tang','','[]','山行夜誠實寐，拂曉遂登高。',104,'全唐诗/poet.tang.50000.json','["山行夜誠實寐，拂曉遂登高。", "迴首望知己，思君心郁陶。", "不聞龍虎嘯，但見豺狼號。", "寒氣凝如練，秋風勁似刀。", "深溪多渌水，斷岸饒黃蒿。", "驛使□靡歇，人疲馬亦勞。", "獨嗟時不利，詩筆雖（原作「唯」）然操。", "更憶綢繆者，何當慰我曹。"]'),
('8b7e1161-fd94-4d71-82e9-b172a76f35a3','晚次白水古戍見枯骨之作','佚名','唐','唐诗','tang','','[]','深山古戍寂無人，崩壁荒丘接鬼鄰。',71,'全唐诗/poet.tang.50000.json','["深山古戍寂無人，崩壁荒丘接鬼鄰。", "意氣丹誠□□□，惟餘白骨變灰塵。", "漢家封壘徒千所，失守時更歷幾春。", "此日覊愁腸自斷，□□到此轉悲辛（原作「新」）。"]'),
('2a80f55b-a84c-45f4-8286-635796ddf950','晚秋至臨蕃被禁之作','佚名','唐','唐诗','tang','','[]','一到荒城恨轉深，數朝長嘆意雖任。',74,'全唐诗/poet.tang.50000.json','["一到荒城恨轉深，數朝長嘆意雖任。", "昔日三軍雄鎮地，今時百（白）草遍城陰。", "隤墉窮巷無人跡，獨樹孤墳有鳥吟。", "邂逅流移千里外，誰念恓（原作「栖」）惶一片心。"]'),
('935687a0-584b-4aec-8bba-f666a199a126','晚秋登城之作 一','佚名','唐','唐诗','tang','','[]','孤城落日一登臨，感激戎庭萬里心。',64,'全唐诗/poet.tang.50000.json','["孤城落日一登臨，感激戎庭萬里心。", "鄉國雲山遮不見，風光慘澹益愁深。", "漂流空嘆東溪水，倏忽仍嗟西嶺陰。", "留滯只今寒暑變，誰憐客子獨悲吟。"]'),
('ced75eb6-a564-44db-b0e6-a4bbdffb7485','晚秋登城之作 二','佚名','唐','唐诗','tang','','[]','東山日色片光殘，西嶺雲各暝草寒。',64,'全唐诗/poet.tang.50000.json','["東山日色片光殘，西嶺雲各暝草寒。", "谷口穹廬遥邐迤，磎邊牛馬暮盤跚。", "目前愁見川至窄，望處心迷興不寬。", "鄉國未知何所在，路逢相識問看看。"]'),
('8d9e824c-d542-4f6a-b3f1-2af8f51aeb24','秋夜聞風水','佚名','唐','唐诗','tang','','[]','夜來枕席喧風水，忽坐長嘆恨無已，爲客愁多在九秋，況復淪流更千里。',32,'全唐诗/poet.tang.50000.json','["夜來枕席喧風水，忽坐長嘆恨無已，爲客愁多在九秋，況復淪流更千里。"]'),
('a770a703-e847-4d96-b89f-996b4a31dd4f','望敦煌','佚名','唐','唐诗','tang','','[]','數迴瞻望敦煌道，千里茫茫盡白草。',32,'全唐诗/poet.tang.50000.json','["數迴瞻望敦煌道，千里茫茫盡白草。", "男兒留滯蹔時間，不應便向戎庭老。"]'),
('6bfdc643-8b73-4bc2-b744-370e7632325b','晚秋覊情','佚名','唐','唐诗','tang','','[]','悄焉獨立思疇昔，忽爾傷心泪旋滴。',198,'全唐诗/poet.tang.50000.json','["悄焉獨立思疇昔，忽爾傷心泪旋滴。", "常時遊涉事文華，今日覊縲困戎敵。", "知音好識竟何在，黯然已矣山河隔，吊影慙魂嗟一身，夕往朝朝（來）絕三益。", "非論邂逅離朋友，抑亦淪濟彫羽翮。", "自憐銷瘦衣漸寬，誰念恓惶心轉窄。", "近來殊俗盈衢路，尚見蒿萊遍街陌，屋宇摧殘無箇存，猶是唐家舊踪跡。", "城邊谷口色蒼茫，木落霜飛風析（淅）瀝。", "凌晨煞氣半天紅，薄暮寒雲滿山白。", "覊紲時深情憤怒，漂泊鄉遥心感激。", "不憂懦節向戎夷，只恨更長愁寂寂。"]'),
('d193c4c5-ccde-4960-960e-45b3639e8c2e','困中登山','佚名','唐','唐诗','tang','','[]','戎庭悶且閑，誰復解愁顏。',48,'全唐诗/poet.tang.50000.json','["戎庭悶且閑，誰復解愁顏。", "步步或登嶺，悠悠時往還。", "野禽噪河曲，村犬吠林間。", "西北望君處，躊踷日暝山。"]'),
('6e9bc072-ea36-4a84-8526-abd8b52c0057','有恨久囚','佚名','唐','唐诗','tang','','[]','人易千般去，余嗟獨未還。',24,'全唐诗/poet.tang.50000.json','["人易千般去，余嗟獨未還。", "空知泣山月，寧覺鬢蒼斑。"]'),
('73c79244-cc31-43a2-80a8-6267e8b7d69e','冬夜非所','佚名','唐','唐诗','tang','','[]','長夜閉荒城，更深恨轉盈。',48,'全唐诗/poet.tang.50000.json','["長夜閉荒城，更深恨轉盈。", "星濟數道赤，月出半山明。", "不聞村犬吠，空聽虎狼聲。", "愁臥眠雖着，時時夢裏驚。"]'),
('f0c58c20-7458-4d58-bc1f-6356c60d54f3','忽有故人相問以詩代書達知己兩首','佚名','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.50000.json','["。"]'),
('75bb6ce0-a44e-410c-aa23-55756f6df010','忽有故人相問以詩代書達知己兩首 一','佚名','唐','唐诗','tang','','[]','忽聞數子訪覊人，問着感言是德鄰。',32,'全唐诗/poet.tang.50000.json','["忽聞數子訪覊人，問着感言是德鄰。", "與君咫尺不相見，空知日夕淚沾巾。"]'),
('60111969-42a9-43d5-b879-76318d8b1273','忽有故人相問以詩代書達知己兩首 二','佚名','唐','唐诗','tang','','[]','自閉荒城恨有餘，未知君意復何如？非論阻礙難相見，亦恐猜慊不寄書。',32,'全唐诗/poet.tang.50000.json','["自閉荒城恨有餘，未知君意復何如？非論阻礙難相見，亦恐猜慊不寄書。"]'),
('2dc60e5c-6dbc-43bc-9dd6-528ab3a212f7','得信酬迴','佚名','唐','唐诗','tang','','[]','人迴忽得信，具委書中情。',48,'全唐诗/poet.tang.50000.json','["人迴忽得信，具委書中情。", "覊思頓雖豁，憶君心轉盈。", "自憐飄泊者，邂逅閉荒城。", "欲識肝腸斷，更深聽叫聲。"]'),
('a4240a32-199c-479d-8885-12984bfcc0c0','聞城哭聲有作','佚名','唐','唐诗','tang','','[]','昨聞河畔哭哀哀，見說分離凡幾迴。',64,'全唐诗/poet.tang.50000.json','["昨聞河畔哭哀哀，見說分離凡幾迴。", "昔別長男居異域，今殤小子瘞泉臺。", "覊愁對此腸堪斷，客舍聞之心轉摧。", "漂泊自然無限苦，況復存亡有去來。"]'),
('6a2d9455-ff6a-433d-a9d5-e4eae7c69053','除夜','佚名','唐','唐诗','tang','','[]','荒城何獨淚澘然，聞說今宵（原作「霄」）是改年。',71,'全唐诗/poet.tang.50000.json','["荒城何獨淚澘然，聞說今宵（原作「霄」）是改年。", "親故睽携長已矣，幽縲寂寞鎮愁煎。", "更深腸絕誰人念，夜永心傷空自憐。", "爲恨漂零無計力，空知日夕仰穹天。"]'),
('355b0eeb-afcd-4677-a198-9ab96bdfd70e','春宵（原作「霄」）有懷','佚名','唐','唐诗','tang','','[]','獨坐春宵（原作「霄」）月見高，月下思君心郁陶。',39,'全唐诗/poet.tang.50000.json','["獨坐春宵（原作「霄」）月見高，月下思君心郁陶。", "躊躇不覺三更盡，空見豺狼數遍號。"]'),
('69c943a6-a8e9-47ae-8fd8-86d88637ee34','久憾縲紲之作','佚名','唐','唐诗','tang','','[]','一從命駕赴戎鄉，幾度躬先亘法梁。',72,'全唐诗/poet.tang.50000.json','["一從命駕赴戎鄉，幾度躬先亘法梁。", "吐納共欽澎湃注，縱（原作「踪」）橫競揖慧風颺。", "今時有恨同蘭艾，即日無辜比冶長。", "黠虜莫能分玉石，終朝誰念淚沾裳。", "。"]'),
('3aee7aef-570f-45a7-b346-d1ff60cfb1eb','非所寄王都護姨夫','佚名','唐','唐诗','tang','','[]','敦煌數度訪來人，握手千回問懿親。',71,'全唐诗/poet.tang.50000.json','["敦煌數度訪來人，握手千回問懿親。", "蓬轉已聞過海畔，莎居見說傍河津。", "戎庭事事皆違意，虜口朝朝計苦辛。", "縲紲儻逢恩降日，宿心言豁（原作「豁」）在他辰。"]'),
('d304f6a1-9dda-45e6-bf26-53b802315f77','哭押牙四寂','佚名','唐','唐诗','tang','','[]','哀哉存歿苦難量，共恨淪流處異鄉。',64,'全唐诗/poet.tang.50000.json','["哀哉存歿苦難量，共恨淪流處異鄉。", "可嘆生涯光景促，旋嗟死路夜何長！空令肝膽摧林竹，每使心魂痛渭陽。", "縲紲時深腸自斷，更聞凶變淚沾裳。"]'),
('8500887d-6a36-499b-a92d-f537290b8f80','□□','佚名','唐','唐诗','tang','','[]','白日走風沙，黃昏飛雪花。',55,'全唐诗/poet.tang.50000.json','["白日走風沙，黃昏飛雪花。", "愁雲闇□畔，寒色暝天涯。", "縲紲今將久，歸期恨路賒（原作「㖠」）。", "時時眠夢裏，往往見還家。"]'),
('cc2e8a04-c10f-4b19-a7ae-80620d30dd35','感藂草初生','佚名','唐','唐诗','tang','','[]','覊客絕知聞，急難阻投杖。',48,'全唐诗/poet.tang.50000.json','["覊客絕知聞，急難阻投杖。", "泪與泉俱流，愁將草齊長。", "縲紲淹歲年，歸期唯夢想。", "春色縱芳菲，片心終郁怏。"]'),
('25c2efd7-faa5-4b26-963b-8b6eac1fcc62','春日覊情','佚名','唐','唐诗','tang','','[]','鄉山臨海岸，別業近天堄。',104,'全唐诗/poet.tang.50000.json','["鄉山臨海岸，別業近天堄。", "地接龍塠北，川連雁塞西。", "童年方剃削，弱冠導羣迷。", "儒釋雙披（原作「柀」）翫，聲名獨見躋。", "須緣隨墾請，今乃恨暌携。", "寂寂空愁坐，遲遲落日低。", "觸槐常有志，折檻爲無蹊。", "薄暮荒城外，依稀聞遠鷄。", "。"]'),
('9f0687c4-7fce-4931-9246-4f3855dbd527','□□','佚名','唐','唐诗','tang','','[]','恨到荒城一閉關，鄉園阻隔萬重山。',32,'全唐诗/poet.tang.50000.json','["恨到荒城一閉關，鄉園阻隔萬重山。", "咫尺音書猶不達，夢魂何處得歸還。"]'),
('3d7b1f88-33d2-4b96-93e4-b524381c42cb','□□','佚名','唐','唐诗','tang','','[]','憤悶屢縱橫，愁深百計生。',48,'全唐诗/poet.tang.50000.json','["憤悶屢縱橫，愁深百計生。", "相思凡幾度，慷慨至三更。", "虜塞饒白刾，戎鄉多紫荆。", "關山爾許遠，魂夢若爲行。"]'),
('f137fcf6-bc4e-4811-8295-996d48d3d1c4','晚秋 一','佚名','唐','唐诗','tang','','[]','戎庭縲紲向窮秋，寒暑更遷歲欲周。',64,'全唐诗/poet.tang.50000.json','["戎庭縲紲向窮秋，寒暑更遷歲欲周。", "斑斑淚下皆成血，片片雲來盡帶愁，朝朝心逐東溪水，夜夜魂隨西月流。", "數度恓惶猶未了，一生榮樂可能休。"]'),
('e7d67e74-af4a-41db-896a-bcc83bb7e01f','晚秋 二','佚名','唐','唐诗','tang','','[]','天涯地角一何長，雁塞龍塠萬里疆。',32,'全唐诗/poet.tang.50000.json','["天涯地角一何長，雁塞龍塠萬里疆。", "每恨淪流經數載，更嗟縲紲泣千行。"]'),
('70a42a5f-4e1b-4845-9c73-114ad9d94734','晚秋 三','佚名','唐','唐诗','tang','','[]','縲紲戎庭恨有餘，蠶知君意復何如？一介耻無蘇子節，數回羞寄李陵書。',32,'全唐诗/poet.tang.50000.json','["縲紲戎庭恨有餘，蠶知君意復何如？一介耻無蘇子節，數回羞寄李陵書。"]'),
('6f3fd8ef-1897-4446-9fa0-cd5134bfc792','晚秋 四','佚名','唐','唐诗','tang','','[]','髪爲多愁白，心緣久客悲。',24,'全唐诗/poet.tang.50000.json','["髪爲多愁白，心緣久客悲。", "更遭縲紲事，因此改容儀。"]'),
('bb7d6cd3-092b-4da3-a10d-e699182119c9','晚秋 五','佚名','唐','唐诗','tang','','[]','春來漸覺沒心情，愁見豺狼夜叫聲；君但遠聽腸應斷，況僕覊縲在此城。',32,'全唐诗/poet.tang.50000.json','["春來漸覺沒心情，愁見豺狼夜叫聲；君但遠聽腸應斷，況僕覊縲在此城。"]'),
('d95a0663-55a3-4f11-ad0e-79fad6fb56ee','晚秋 六','佚名','唐','唐诗','tang','','[]','日月千回數，君名萬遍呼。',12,'全唐诗/poet.tang.50000.json','["日月千回數，君名萬遍呼。"]'),
('a1d29876-b6a7-4f77-8054-48f918b1f4c2','晚秋 七','佚名','唐','唐诗','tang','','[]','白日歡情少，黃昏愁轉多。',12,'全唐诗/poet.tang.50000.json','["白日歡情少，黃昏愁轉多。"]'),
('dbdffc1e-d6ae-4d78-8b66-760fb8b0149a','逢故人之作','佚名','唐','唐诗','tang','','[]','故人相見汾酒龍鐘，總爲情懷昔日濃。',34,'全唐诗/poet.tang.50000.json','["故人相見汾酒龍鐘，總爲情懷昔日濃。", "隨頭盡見新白髪，何曾有箇舊顏容！。"]'),
('4a28374b-df67-4c03-97b8-eb16bc314212','題故人所居','佚名','唐','唐诗','tang','','[]','與君昔離別，星歲爲三周；今日覯顏色，蒼然雙鬢秋。',72,'全唐诗/poet.tang.50000.json','["與君昔離別，星歲爲三周；今日覯顏色，蒼然雙鬢秋。", "茅居枕河滸，耕鑿傍山丘。", "往往登憇逕，時時或飯牛。", "一身尚栖屑，庶身安無憂？", "相見未言語，唏吁先淚流。"]'),
('0d26bb0e-3608-45ab-ba54-96b1a431d139','非所夜聞笛','佚名','唐','唐诗','tang','','[]','夜聞羌（原作「嗟」）笛吹，愁雜豺狼□。',62,'全唐诗/poet.tang.50000.json','["夜聞羌（原作「嗟」）笛吹，愁雜豺狼□。", "涕淚落如雨，肝腸痛似刀。", "更深新月落，坐久明星高。", "感激不遑寐，連宵（原作「霄」）思我曹。"]'),
('8ecd0d25-b3ab-462a-b7e7-680721620c5a','感興臨蕃馴雁','佚名','唐','唐诗','tang','','[]','感兹馴雁色蒼蒼，徘徊顧步貌昂昂。',71,'全唐诗/poet.tang.50000.json','["感兹馴雁色蒼蒼，徘徊顧步貌昂昂。", "不見銜蘆避繒繳，空聞落翮困堤塘。", "差池爲失衡（原作「衝」）陽伴，邂逅飄零虜塞傍。", "引頸長鳴望雲路，何時刷羽接歸行。"]'),
('6d4a8d67-b776-425c-b10d-3edcf3d4a8a0','閨情 一','佚名','唐','唐诗','tang','','[]','千回萬轉夢難成，萬遍千回夢里驚；總爲相思愁不寐，縱然愁寐忽天明。',32,'全唐诗/poet.tang.50000.json','["千回萬轉夢難成，萬遍千回夢里驚；總爲相思愁不寐，縱然愁寐忽天明。"]'),
('cf0dd458-397c-44dd-b767-5df1feae9334','閨情 二','佚名','唐','唐诗','tang','','[]','百度看星月，千回望五更。',497,'全唐诗/poet.tang.50000.json','["百度看星月，千回望五更。", "自知無夜分，乞顧早天明。", "（〖1〗以上五十九首詩，與卷一所著錄的馬雲奇詩一道鈔寫在伯二五五五殘卷上，按其內容和編次，當是一人所寫，可惜這個作者的姓名已不可考知。", "從詩的內容看來，這個作者很可能是一位身遭吐蕃拘禁的敦煌使臣。", "這些詩所表現的時間和地點，約在唐代宗大曆元年〖七六五〗凉州陷於吐蕃到德宗建）（中二年〖七八一〗敦煌淪陷之間。", "作者在冬日從敦煌馬圈口堰出發，出使吐谷渾，經過墨離海，次年夏到青海，却不幸被拘禁，失去了人身自由；又經過臨水，度赤嶺，次白水戍，到達被吐蕃佔據的臨蕃。", "他所經歷的時間，正是吐蕃極盛、河隴淪陷，安西、北庭與中原音訊斷絕之時，因此詩中所反映的思想狀況，代表了當時西北邊塞廣大文人士子的心情。", "同時，這些詩實際上又是當時河隴地區的紀行詩，詩中所描述的邊塞地區的自然風貌、游牧地帶的典型景物以及被吐蕃攻陷後的邊鎮守捉的荒涼景象，在別的唐人邊塞詩中均不多見，因此，它們無論在歷史，或文學史，或民族文化交流的研究上，都有着不可忽視的寶貴價值。", "〖有關伯二五五五殘詩卷，可參看柴劍虹《敦煌唐人詩文選集殘卷〖伯二五五五〗補錄》，見《文學遺產》一九八三年第四期。", "〗）。"]'),
('283fc635-8449-46c0-954f-3c3342c9f29c','王昭君怨諸詞人連句（伯二七四八）一首','佚名','唐','唐诗','tang','','[]','掖庭嬌幸在蛾眉，争用黃金寫艷姿。',230,'全唐诗/poet.tang.50000.json','["掖庭嬌幸在蛾眉，争用黃金寫艷姿。", "始言恩寵由君意，誰謂容顏信畫師。", "微軀一自入深宮，春華幾度落秋風。", "君恩不惜便（更）衣處，妾貌應殊畫壁中。", "聞道和親將我敞（撇），選貌披圖遍宮掖。", "圖中容貌既不如，選後君王空悔惜。", "始知王意本相親，自恨丹青每誤身。", "昔是宮中薄命妾，今成塞外斷腸人。", "九重恩愛應長謝，萬里關山愁遠嫁。", "飛來北地不勝春，月照南庭空度夜。", "夜中含涕獨嬋娟，遥念君邊與朔邊。", "毳幕不同羅帳日，氈裘非復錦衾年。", "長安高闕三千里，一望能令一心死。", "秋來懷抱既不堪，況復南飛雁聲起。"]'),
('58ef8d29-bd0b-4539-97c7-d6612ead3a36','謁法門寺真身五十韻（伯三四四五）一首','佚名','唐','唐诗','tang','','[]','瞻禮喜成悲，傷着（嗟）不遇師。',303,'全唐诗/poet.tang.50000.json','["瞻禮喜成悲，傷着（嗟）不遇師。", "矌因修曩劫，火寂掩俱尼（尸）。", "神光分皎皎，雁塔起巍巍。", "弘願無偏儻，從後請不疑。", "人天重敬禮，神鬼悉交馳。", "入海人難覩，騰波世莫窺。", "供僧添聖福，稱象等毫釐。", "鐵網牽沙岸，金甌出水湄。", "輪王欣却得，將帥盡忘疲。", "震日國絕大，岐陽地不卑。", "累朝曾出現，近代盛修持。", "萬遍磨不磷，千回湼不緇。", "任從將火試，幾見陷金錘。", "皓色豈能幷，晶光盡總虧。", "真身無點𭼩（黶），珪璧有瑕雌（疵）。", "安福樓前現，天涯海畔知。", "懿宗親禮處，軍（君）主見同時。", "截舌還能語，剜精復舊肥。", "石光呈瑞質，木有寶燈儀。", "塔主重修建，檀那各捨資。", "才興運人力，早已感神祇。", "一夜風雷吼，五更砂石吹。", "不勞人力置，自有聖賢爲。", "海得龍王護，藥叉將主司。"]'),
('dee14858-f9c9-4219-ac9b-750a1a109c8a','無題（斯五五五八）一首','佚名','唐','唐诗','tang','','[]','池臺樓觀非吾宅，百年還同一宿客；無常忽至即分籬（離），各自東西如路陌。',351,'全唐诗/poet.tang.50000.json','["池臺樓觀非吾宅，百年還同一宿客；無常忽至即分籬（離），各自東西如路陌。", "唯有冤家不相放，罪福前途相執當；冥官依業斷形（刑）名，遮莫王公及宰相。", "生鬬英雄死論福，貴販（賤）更無別地獄。", "天堂不是選家門，但使回心修作福。", "君不見閻浮流轉暫時間，何須苦欲求名利；徒勞積業自綊（挾）身，隨陷三途覓富貴。", "過去王侯數百千，若個久住得長年；良賤有生皆有死，一朝命盡總虛然。", "空來空去皈本體，直爲迷情不開解。", "貪多畏小不知休，總是阿鼻地獄債。", "切見愚癡世上人，金（今）生不惜未來身；朝朝暮暮多愁苦，積寶如山猶許（訴）貧。", "唯富唯悕（恡）轉更貪，子細尋思幾許堪；多求積貯蒙遼（繚）亂，死去只得一錢含。", "一去冥冥百不知，忽然與世即分離；萬物怨（宛）然無一分，唯有善惡並相隨。", "一切恩情今隔斷，何得哭泣相呼唤！生死異路當頭行，各自歸家更覓伴。", "。"]'),
('63283489-7140-4cc4-beab-b3243bbb304a','敦煌廿詠（並序） 一、三危山詠','敦煌人作品[一]','唐','唐诗','tang','','[]','三危[七]鎮羣望，岫崿凌穹蒼。',51,'全唐诗/poet.tang.50000.json','["三危[七]鎮羣望，岫崿凌穹蒼。", "萬古不毛髪，四時含雪霜。", "巖連九隴險，地竄三苗鄉。", "風雨暗溪谷，令人心自傷。"]'),
('5b7b7d99-6581-4b45-b43e-d7defa1432cb','敦煌廿詠（並序） 二、白龍堆詠','敦煌人作品[一]','唐','唐诗','tang','','[]','傳道神沙異，喧寒[也自鳴][八]。',66,'全唐诗/poet.tang.50000.json','["傳道神沙異，喧寒[也自鳴][八]。", "[勢]疑天鼓[九]動，殷似地雷驚。", "九[削棱還峻]，人躋刃不平。", "更尋[一○]掊井處，時[見白龍行]。"]'),
('24f02f29-53d6-4eb3-bfe4-5baa60950a94','敦煌廿詠（並序） 三、莫高窟詠[二]','敦煌人作品[一]','唐','唐诗','tang','','[]','雪嶺干青漢，雲樓架碧空，重開千佛剎[一二]，旁出四天宮。',56,'全唐诗/poet.tang.50000.json','["雪嶺干青漢，雲樓架碧空，重開千佛剎[一二]，旁出四天宮。", "瑞鳥含珠影，靈花吐蕙藂（叢）。", "洗心游勝境，從此去塵蒙。", "。"]'),
('5a4643b8-2991-41db-b627-ce76f522a290','敦煌廿詠（並序） 四、貳師泉詠','敦煌人作品[一]','唐','唐诗','tang','','[]','賢哉李廣利，爲將討匈奴。',58,'全唐诗/poet.tang.50000.json','["賢哉李廣利，爲將討匈奴。", "路指[一三]三危迥，山連萬里枯。", "抽刀刺石壁，發矢落金烏。", "志感飛泉湧，能領士馬[甦][一四]。"]'),
('645a308e-8543-48b5-a675-1211614e9c61','敦煌廿詠（並序） 五、渥洼池天馬詠','敦煌人作品[一]','唐','唐诗','tang','','[]','渥洼爲小海，伊昔獻龍媒。',56,'全唐诗/poet.tang.50000.json','["渥洼爲小海，伊昔獻龍媒。", "花裏牽絲去，雲間曳練來。", "勝驤走[一五]天闕，滅沒下章臺。", "一入重泉底，千金市不迴[一六]。"]'),
('d51aae04-acd9-4134-b255-51be47bbdc9a','敦煌廿詠（並序） 六、陽關戍詠','敦煌人作品[一]','唐','唐诗','tang','','[]','萬里通西域，千秋尚有名。',40,'全唐诗/poet.tang.50000.json','["萬里通西域，千秋尚有名。", "平沙迷舊路，眢井引前程。", "馬色[一七]無人間，晨鷄吏不聽。"]'),
('a0e1c583-e8a3-436a-a3db-7284ae811aa1','敦煌廿詠（並序） 七、水精堂詠','敦煌人作品[一]','唐','唐诗','tang','','[]','陽關臨絕漠，中有水精堂。',56,'全唐诗/poet.tang.50000.json','["陽關臨絕漠，中有水精堂。", "暗磧鋪銀地，平沙散玉羊。", "體明同夜月，色淨含[一八]秋霜。", "可則棄胡塞[一九]，終歸還帝鄉。"]'),
('a642e67a-afa9-4c28-8ec8-a291e6951110','敦煌廿詠（並序） 八、玉女泉詠','敦煌人作品[一]','唐','唐诗','tang','','[]','用（周）人祭滛（瑤）水，黍稷信非馨。',54,'全唐诗/poet.tang.50000.json','["用（周）人祭滛（瑤）水，黍稷信非馨。", "西豹追河伯，蛟龍遂隱形。", "紅粧隨洛浦，綠鬢逐浮萍。", "尚有銷金冶，何曾玉女靈。"]'),
('c6fc1403-cc00-4c66-8f59-4b030005dd9f','敦煌廿詠（並序） 九、瑟瑟詠[二○]','敦煌人作品[一]','唐','唐诗','tang','','[]','瑟瑟焦山下，悠悠採幾年。',52,'全唐诗/poet.tang.50000.json','["瑟瑟焦山下，悠悠採幾年。", "爲珠懸寶髻[二一]，作璞間金鈿。", "色入青霄裏，光浮黑磧邊。", "世人偏重此，誰念楚材賢。"]'),
('5546aa12-cf16-4683-aa3a-8aafc279f41a','敦煌廿詠（並序） 十、李廟詠','敦煌人作品[一]','唐','唐诗','tang','','[]','昔時[二二]興聖帝，遺廟在敦煌。',52,'全唐诗/poet.tang.50000.json','["昔時[二二]興聖帝，遺廟在敦煌。", "叱咤雄千古，英威静一方。", "牧童歌塚上，狐兔穴墳傍。", "晉史傳韜略，留名播五涼。"]'),
('6c16caf8-8249-466e-bebc-da5c0bb937b1','敦煌廿詠（並序） 十一、貞女臺詠[二三]','敦煌人作品[一]','唐','唐诗','tang','','[]','貞女誰家女？',56,'全唐诗/poet.tang.50000.json','["貞女誰家女？", "孤標坐[二四]此臺。", "青蛾隨月轉[二五]，紅粉向花開。", "二八無人識，千秋已作灰。", "潔身終不嫁，非爲乏良媒。"]'),
('1b069a77-e2b1-4faa-877c-3815300144d8','敦煌廿詠（並序） 十二、安城祅詠[二六]','敦煌人作品[一]','唐','唐诗','tang','','[]','版築安城日，神祠與此興。',54,'全唐诗/poet.tang.50000.json','["版築安城日，神祠與此興。", "一州祈景祚，萬類仰休徵。", "蘋藻來（釆）無乏，精靈若有憑。", "更看雲祭處，朝夕酒如繩（澠）。"]'),
('41757dd8-3bbb-4763-b8a4-53ad001585c9','敦煌廿詠（並序） 十三、墨池詠','敦煌人作品[一]','唐','唐诗','tang','','[]','昔人精篆素，盡妙許張芝。',48,'全唐诗/poet.tang.50000.json','["昔人精篆素，盡妙許張芝。", "草聖雄千古，芳名冠一時。", "舒箋行鳥迹，研墨染魚緇。", "長想臨池處，興來聊詠詩。"]'),
('beecc6e1-1682-4a49-9a03-c86501e35bd4','敦煌廿詠（並序） 十四、半壁樹詠','敦煌人作品[一]','唐','唐诗','tang','','[]','半壁生奇木，盤根到水涯。',51,'全唐诗/poet.tang.50000.json','["半壁生奇木，盤根到水涯。", "高柯寵（籠）宿霧，密葉隱朝霞。", "二月含青翠，三秋帶紫花。", "森森神樹下，祈賽不應賒。"]'),
('bd207664-89ca-4b33-adfa-0cd38f372b56','敦煌廿詠（並序） 十五、三攢草詠','敦煌人作品[一]','唐','唐诗','tang','','[]','池草三[二七]攢別，能芳二月[春]。',73,'全唐诗/poet.tang.50000.json','["池草三[二七]攢別，能芳二月[春]。", "渌（綠）苔生[二八]水嫩[二九]，翠色出泥新[三○]。", "弄[三一]舞飡花蝶，潛驚觸釣鱗。", "芳菲觀不厭，留興待詩人。"]'),
('11dddae7-85fc-491c-8a2f-7cb4ef7c736a','敦煌廿詠（並序） 十六、賀拔堂詠','敦煌人作品[一]','唐','唐诗','tang','','[]','英雄傳賀拔，割據王[三二]敦煌。',44,'全唐诗/poet.tang.50000.json','["英雄傳賀拔，割據王[三二]敦煌。", "五郡徵般匠，千金造寢堂。", "綺檐安獸瓦，粉壁架鴻[三三]梁。"]'),
('aeaf2ad5-abad-4d11-afbf-018e5f285f0e','敦煌廿詠（並序） 十七、望京門詠','敦煌人作品[一]','唐','唐诗','tang','','[]','郭門望京處，樓上啟重闉。',56,'全唐诗/poet.tang.50000.json','["郭門望京處，樓上啟重闉。", "水北通西域，橋東路入秦。", "黃沙吐雙徑[三四]，白草生[三五]三春。", "不見中華使，翩翩起虜塵。"]'),
('9711d6f5-569b-48c1-b3c0-7d5c37e34893','敦煌廿詠（並序） 十八、相似樹詠','敦煌人作品[一]','唐','唐诗','tang','','[]','兩樹夾招提，三春引影低。',47,'全唐诗/poet.tang.50000.json','["兩樹夾招提，三春引影低。", "葉中微有字，階下已成蹊。", "含氣同修短，分條德且齊。", "不容凡鳥坐，應欲俟棲。"]'),
('694dc15d-1d26-45cb-96d4-7ec6c4c2d9d7','敦煌廿詠（並序） 十九、鑿壁井詠','敦煌人作品[一]','唐','唐诗','tang','','[]','嘗聞鑿壁井，茲水最爲靈。',53,'全唐诗/poet.tang.50000.json','["嘗聞鑿壁井，茲水最爲靈。", "色帶三春渌，芳傳一味清。", "玄言稱上善，圖錄著高名。", "德重勝銖兩，諸流量[三六]且輕。", "。"]'),
('7c8ec13f-3747-4e24-9c24-b49274e01b3f','敦煌廿詠（並序） 二十、分流泉詠','敦煌人作品[一]','唐','唐诗','tang','','[]','地湧澄泉美，環城本自奇。',48,'全唐诗/poet.tang.50000.json','["地湧澄泉美，環城本自奇。", "一源分異派，兩道入湯池。", "波上青蘋合，洲前翠柳垂。", "況逢佳景處，從此遂忘疲。"]'),
('d7b349ca-0bae-41a1-9347-e09dc2aa1f43','敦煌廿詠（並序） [附]題隱士詠[三七]','敦煌人作品[一]','唐','唐诗','tang','','[]','青溪逐水薫漁樵，策杖褰衣屢驀橋。',534,'全唐诗/poet.tang.50000.json','["青溪逐水薫漁樵，策杖褰衣屢驀橋。", "鳥坐春池雙影近，人呼幽谷兩聲遥。", "祥煙五色飛仙電，瑞草千藂（叢）間藥苗。", "河畔曲肱而取飲，嫌煩且棄樹中瓢。", "（[一]以上詩凡六寫本，其原編號及校次如下：原卷〖伯二七四八〗、甲卷〖伯三九二九〗、乙卷〖伯二九八三〗、丙卷〖伯三八七○〗。", "卷末多《題隱士詠》一首，幷有「咸通十二年十一月廿日學生劉文端寫記」一行。", "丁卷〖斯六一六七〗、戊卷〖伯二六九○〗僅存第一首，不校。", "甲卷題作「敦煌古蹟廿詠」，乙卷「廿詠」作「二十詠」。", "[二]「三危」，甲、乙、丁三卷作「峗山」。", "[三]原卷無「向」字，依乙、丙、丁三卷補。", "[四]「二」，甲卷作「三」。", "[五]「短」下原卷有「見」字，依乙、丙、丁三卷刪。", "[六]乙、丙、丁二卷無「矣」字。", "[七]「三危」，甲、乙、丁三卷作「峗山」。", "[八]原卷殘缺處，元用甲、乙、丙、丁四卷補之。", "凡校補字，均括以[]，如[也自鳴]和以下括弧內均是。", "[九]「鼓」，甲、乙兩卷作「轂」。", "[一○]「尋」，甲卷作「看」。", "[一一]詩題丁卷作「靈巖莫高窟詠」。", "[一二]「剎」，原卷作「日」，依甲、乙、丙、丁四卷改。", "[一三]「指」，甲卷作「至」。", "[一四]「甦」字原闕，據甲、乙兩卷補。", "丙、丁卷「甦」作「蘇」。", "[一五]「走」原作「奏」，依甲、乙、丙、丁四卷改。"]'),
('abf3d806-da7e-4bb3-8e80-3000bec03428','敦煌（伯五○○七）三首 □□（原卷此首詩題作《敦煌》。）','敦煌人作品[一]','唐','唐诗','tang','','[]','萬頃平田四畔沙，漢朝城壘屬蕃家。',67,'全唐诗/poet.tang.50000.json','["萬頃平田四畔沙，漢朝城壘屬蕃家。", "歌謠再復歸唐國，道舞春風楊柳花。", "仕女上（尚）□天寶髻，水流依舊種桑麻。", "雄軍往往施鼙鼓，鬬將徒勞獫狁誇。"]'),
('6aec44b9-a998-487f-9001-88841d7ed5ff','敦煌（伯五○○七）三首 壽昌','敦煌人作品[一]','唐','唐诗','tang','','[]','會稽磧畔亦疆場，迥出平田築壽昌。',67,'全唐诗/poet.tang.50000.json','["會稽磧畔亦疆場，迥出平田築壽昌。", "沙幕霧深鳴□雁，草枯猶未及重陽。", "狐裘上（尚）冷搜紅髓，絺葛那堪臥□霜。", "鄒曾不行文墨少，移楓徒哭說西王。"]'),
('417d296f-52cb-49b9-8419-ef18c9b6ea3e','敦煌（伯五○○七）三首 僕固天王乾符三年四月廿四日打破伊州……（此缺數字）錄打劫酒泉後却□斷（下缺）','敦煌人作品[一]','唐','唐诗','tang','','[]','爲言回鶻倚兇（下缺）（〖1〗以上詩三首，都作於唐大中二年〖公元八四八年〗張義潮起義以後。',201,'全唐诗/poet.tang.50000.json','["爲言回鶻倚兇（下缺）（〖1〗以上詩三首，都作於唐大中二年〖公元八四八年〗張義潮起義以後。", "「歌謠再復歸唐國」，即詠此事。", "第三首詩題有歷史價值。", "僕固天王殆即北庭廻鶻首領僕固俊。", "此詩應是當時當地人所作，所以稱他爲「天王」。", "乾符三年〖八七六〗打破伊州事，不見史書記載。", "可惜詩題殘缺，詩文僅存六字，以致意義不夠明顯。", "這時候，僕固俊受張義潮的指揮，打敗了吐蕃不久。", "這次〖八七六〗打伊州，想他是受張義潮的命令的。", "）。"]'),
('164c3f4a-c71a-4048-a772-3f5f9e7eae67','敦煌唐人詩集殘卷考釋','王重民','唐','唐诗','tang','','[]','右詩五十九首，鈔寫在伯二五五五卷，按其內容和編次，當是一個作者的詩集，可惜這個作者的姓名不可考了。',899,'全唐诗/poet.tang.50000.json','["右詩五十九首，鈔寫在伯二五五五卷，按其內容和編次，當是一個作者的詩集，可惜這個作者的姓名不可考了。", "這五十九首詩所表現的時間和地點，是在某一年的冬天，作者被吐蕃所俘虜，從敦煌經過陽關的南面進入退渾國界，便折向東南行，第二年夏天到達青海。", "在青海附近好像停留了一個較短的時期，到了秋天，又經過赤嶺、白水被挾到臨蕃。", "在臨蕃，大約住了一年多的時間（從第二年秋住到第四年春）。", "作者被吐蕃俘虜的年代，是可以根據上述行程作推測的。", "從敦煌入退渾國，又經赤嶺到臨蕃，這些地方，正值短時期的被吐蕃侵擾或占據。", "所以作詩的年代，不應早於走元七六○年放棄安西四鎮以前，也不能晚的七八五年敦煌陷蕃以後。", "作者最後所經過和被囚繫的地方：赤嶺、白水和臨蕃，都在隴西郡的鄯城，赤嶺一向是唐蕃交界上互市的地方，還立有交界碑。", "白水是唐兵駐守的地方，叫做綏戎職。", "可是作者在白水看到的是「漢家封壘徒千所，失守時更歷幾春。", "」「今時百草遍城陰，隤墉窮巷無人迹，獨樹狐墳有鳥吟」，則又應該是在鄯城陷蕃的時候。", "按公元七四一年吐蕃曾攻陷鄯城的振武軍，七六三年，隴州全部陷入吐蕃。", "所以，若作進一步的推求，這些詩頗有可能是七四一--七六三的二十二年間之內或稍前時代的作品。", "作者「夢到沙州奉懷殿下」一詩很重要，也很難解。", "因爲在封建時代對所「奉懷」的稱「殿下」不應是對將軍或主帥的稱呼，也不可能是皇帝，難解就在這個地方。", "考《新唐書》卷八十《太宗諸子列傳》和卷二百十六《吐蕃列傳》，信安王李禕曾在七二七--九年間，奉詔與「河西隴右」諸軍攻吐蕃，拓地至千里，因此，我頗疑猜作者所奉懷的殿下，就是信安王李禕。", "這一推測如不錯，則作者被俘的年代，度該是七二七--七六三年中間。", "作者的身世，據《春日羈情》詩說「童身方剃削，弱冠導羣迷。", "儒釋雙披玩，聲名獨見躋」。", "《晚秋羈情》詩又說「悄焉獨立思疇昔，忽爾傷心淚旋滴。", "常時游涉事文華，今日羈縲困戎敵」。", "可見是一個學通儒釋，頗有文華的人，所以能夠被來到沙州的這位「殿下」「李禕」所賞識，叫他做了僧官或隨從官員。", "但不幸被吐蕃所俘虜。", "被俘的原因不明白，由於同時被俘的人不少，可能是以地方人民和僧道的代表資格，去與吐蕃軍議和，因而被虜的。"]'),
('0ba8d1b3-343e-471a-8b4c-d45e67c09e7a','自序','孫望輯錄','唐','唐诗','tang','','[]','李唐以文學第士，尤重聲律，碩儒俊彥，罔不規斯道，三百年間，詩人千計，騰聲飛實，郁郁彬彬，故論詩者必稱李唐焉。',852,'全唐诗/poet.tang.50000.json','["李唐以文學第士，尤重聲律，碩儒俊彥，罔不規斯道，三百年間，詩人千計，騰聲飛實，郁郁彬彬，故論詩者必稱李唐焉。", "自昔唐人選集，有殷璠（《河嶽英靈集》，丹陽進士殷璠撰，分上中下三卷，凡二十四家詩。", "）元結（《篋中集》，元結次山編，一卷，凡七人，詩二十四首。", "）高正臣（《高氏三宴詩集》三卷，所載皆因人會宴之詩，以一會爲一卷，與宴者凡二十一人。", "）芮挺章（《國秀集》三卷，芮挺章編，凡九十人，詩二百二十篇。", "實八十五人，詩二百十一首。", "）令狐楚（《御覽詩》一卷，一名《唐歌詩》，一名《選進集》，一名《元和御覽》，凡三十家，詩二百八十九首。", "）高仲武（《中興間氣集》二卷，高仲武編，凡二十六人，詩一百四十首。", "實存一百二十二首。", "）姚合（《極玄集》，姚合編，凡二十一家，詩百首。", "實存九十九首。", "）諸家，顧拘於朋從，或偏一體，或囿一方。", "而張爲《主客》（《主客圖》一卷，張爲撰，凡八十四家詩。", "）之作，乃更離章摘句，一詩之不獲悉闚，罔論詳該。", "宋明稍事蒐輯，《英華》《類苑》，（《文苑英華》一千卷，宋太平興國七年，李昉、扈蒙、徐鉉、宋白等奉敕編。", "《唐詩類苑》二百卷，明張之象纂。", "）篇什粗備，然而期分類從，終不見一代一家體要；其散逸秘本，放失集外者，且未能廣事搜求，脫漏泰半，後世惜之。", "逮有清康熙盛朝，朝野右文，裒輯之風特著；翰林院羣彥，奉命啟芸閣之珍藏，殫精校讐，年餘而成《全唐詩》九百卷，（康熙四十四年三月十九日始，四十五年十月初一日書成。", "）都詩四萬八千九百首。", "自唐開國以迄五代，凡有所作，靡不苛索專集，旁稽野史，雖隻句莫遺，而後百世鉅觀，斯克厥成，其有功藝文，不謂大且備乎！然其軼在桑島，湮於金石，又有非當時諸公所能及者。", "天明中，（天明，日本光格天皇年號，共八年，當清乾隆四十六年至五十三年。", "）日人上毛河世寧，（即市河寬齋，字子静，號半江，上毛野國人。", "）曾羅彼邦舊籍，參采《千載佳句》、《文鏡秘府》諸書，撰《全唐詩逸》三卷，（《全唐詩逸》三卷，凡百二十餘家詩，前有淡海竺常序。", "）雖斷篇零章，不無搜玉之功，鮑清溪既刊入《知不足齋叢書》矣。"]'),
('3794013b-98f7-44ba-bde0-cd0826ec4cfa','遊仙篇','武則天','唐','唐诗','tang','','[]','絳宮珠闕敞仙家，蜺裳羽旆自淩霞。',649,'全唐诗/poet.tang.50000.json','["絳宮珠闕敞仙家，蜺裳羽旆自淩霞。", "碧落晨飄紫芝蓋，黃庭夕轉綵雲車。", "周旋宇宙殊非遠，窵望蓬壺停翠幰。", "千齡一日未言[賒]（{目佘}），億歲嬰孩誰謂晚？", "逶迤鳯舞時相向，變囀鸞歌引清唱。", "金漿既取玉杯斟，玉酒還用金膏釀。", "駐逈遊天域，排空[聊]憩息。", "宿志慕三元，翹心祈五色。", "[仙]儲本性諒難求，聖迹奇術秘[玄]（元）猷。", "願[允]丹[誠]賜靈藥，方期久視御隆周。", "（見趙紹祖《金石續鈔》卷一）（〖1〗案石刻題作《雜言遊仙篇》，下署「御製，奉宸大夫臣薛曜書。", "」〖2〗趙紹祖《金石續鈔》跋尾：「末句云：『方期久視御隆周。", "』則此詩久視元年作而刻之於石者也。", "武氏此詩不見於他書，而今古金石家亦未有著於錄者，故存之。", "」〖3〗又按詩中日，原作●；天，原作●；聖，原作●；附注中臣，原作●，均武后所製新字。", "〖4〗此詩又見收於武億《偃師金石遺文記》卷上、乾隆《偃師縣志》卷二七武億撰《金石錄》上〖此即將前列武億書收入〗、孫星衍《續古文苑》卷四、王昶《金石萃編》卷六三，另畢沅《中州金石記》亦著錄，但未錄原文。", "上列各本，錄文）（稍有出入，校如次：「窵望」，上列四書皆作「寫望」；「{目佘}」四書皆作「賒」，今據改；「相向」，武億錄作「相尚」；「聊憇息」之「聊」字，「仙儲」之「仙」字，《金石續鈔》原缺，據尚書補；「本性」之「性」字，武億及王昶錄本皆缺；「玄猷」之「玄」字，《金石續鈔》作「元」，武億錄作「玄」，《金石萃編》及《續古文苑》皆注明爲廟諱，故據改；「願允丹誠」之「允」、「誠」二字，諸本皆缺，惟《續古文苑》不缺，今據補。", "）。"]'),
('6b0ae5b9-9af9-4ed8-9b3f-0d38d60c76f2','南安夕陽山真寂寺題詩','宣宗皇帝李忱','唐','唐诗','tang','','[]','惟愛禪林秋月空，誰能歸去宿龍宮。',159,'全唐诗/poet.tang.50000.json','["惟愛禪林秋月空，誰能歸去宿龍宮。", "夜深聞法餐甘露，喜在蓮花法界中。", "（見明檇李陳懋仁撰《泉南雜志》卷上。", "）（按陳懋仁，字無功，所著《泉南雜志》錄唐人詩若干首，謂「《萬首唐人絕句》中於吾郡及泉州有未收者，余錄其詩於左。", "如此備補遺。", "」又原詩題注曰：「居邸時遁於此」，蓋謂李忱曾遁居真寂寺也。", "又詩末注曰：「見《泉州府志》」。", "）。"]'),
('6765d742-50e8-4186-873b-d9349f65790e','排衙石詩刻（幷序）','錢鏐','唐','唐诗','tang','','[]','□□□□□□□，□南一劍定長鯨。',423,'全唐诗/poet.tang.50000.json','["□□□□□□□，□南一劍定長鯨。", "□□□□□□□，□帝匡扶立正聲。", "□□□□□□□，□輝争不伏神明。", "□□□□□□□，□建瑶壇玉京。", "□□□□□□□，□□常爇不曾停。", "□□□□□□□，□□恆傳寶藏經。", "□□□□□□□，□□今爲顯真靈。", "□□□□□□□，□□□來鎮上清。", "（見《兩浙金石志》。", "）（見《兩浙金石志》卷四。", "《六藝之一錄》卷一一○收此詩，第二句「□南」作「東南」，第六句「伏神明」作「仗神明」。", "）（〖1〗阮元《兩浙金石志》跋：「右詩刻在錢唐縣鳯凰山排衙石上。", "前刻新的序十行，行書，徑一寸，文多磨滅。", "序後一行僅存王字，當是武肅系銜。", "詩則七言八韻，共九行，十六句，上半截亦闕。", "按《咸淳臨安志》云：『舊傳錢武肅王鑿山，見怪石排列兩行，如從衛拱立趨向，因名排衙石，及刻詩石上。", "』即謂此也，惜其文未載。", "《十國春秋》云：『武肅暇時，命諸子諷誦詩賦，或以所製詩賜丞相將吏，亦間能書寫畫墨竹，然不以呫嗶廢正務。", "』是武肅性躭吟咏，此刻可以窺見一斑。", "其書亦剛勁有法度。", "」）。"]'),
('5b7cf60e-ce5a-4b6a-8fe7-2d0327072cf5','遼東侍宴山夜臨秋同賦臨韻應詔','褚遂良','唐','唐诗','tang','','[]','涿野軒皇陳，丹浦帝堯心。',120,'全唐诗/poet.tang.50000.json','["涿野軒皇陳，丹浦帝堯心。", "彎弧射封豕，解網縱前禽。", "慿高御爽節，流月揚清陰。", "霧匝長城險，雲歸渤澥深。", "飜垗入層漢，落雁警遥岑。", "露條疏更響，涼蟬寂不吟。", "三韓初静亂，八桂始披襟。", "商飚泛輕武，自澗引衣簮。", "酒漾投川醁，歌傳芳樹音。", "邊烽良永□，麾旆竦成林。"]'),
('9162ac10-62a4-4245-8515-b3f28ed16219','春日侍宴望海應詔','褚遂良','唐','唐诗','tang','','[]','從軍渡蓬海，萬里正蒼蒼。',132,'全唐诗/poet.tang.50000.json','["從軍渡蓬海，萬里正蒼蒼。", "縈波迴地軸，激浪上天潢。", "夕雲類鵬徙，春濤疑蓋張。", "天吳静無際，金駕儼成行。", "戈船凌白日，鞭石[耿]（秋）虹梁。", "電舉[朝]（潮）宗外，風驅韓貊鄉。", "之罘初播雨，遼碣始分光。", "麾城湛□□，□□□□□。", "同文漸邊服，入塞佇歌倡。", "（據《翰林學士集》校改。", "）。"]'),
('f2c60919-22f8-45ae-ac93-4f22ac37520d','奉和行經破薛舉戰地應詔','褚遂良','唐','唐诗','tang','','[]','王功先美化，帝略蘊戎昭。',254,'全唐诗/poet.tang.50000.json','["王功先美化，帝略蘊戎昭。", "魚驪（友人蔣禮來同志謂當作魚麗，本《左傳》。", "）入丹浦，龍戰起鳴條。", "長劍星光落，高旗月影搖。", "（《翰林學士集》此句缺「摇」字。", "）昔往摧勍寇，今巡奏短簫。", "旌門麗霜景，帳殿含秋飇。", "□池水未結，（「□池」，《翰林學士集》作「□沲」，上字下半殘存，疑爲「河」字。", "）官渡柳初凋。", "邊烽夕霧卷，關陳曉雲銷。", "鴻名兼轍跡，至聖俯唐堯。", "睿藻煙霞焕，天聲宮羽調。", "平分共飲德，率土更聞韶。", "（以上三詩載《武林往哲遺著》。", "）（以上三詩皆出日本尾張國真福寺藏唐卷子本《翰林學士集》。", "此集清末田貴陽陳田攜歸影刻傳世。", "）。"]'),
('b8219776-bf6d-4493-a5a1-dc82ecc5dbcd','湘潭偶題詩','褚遂良','唐','唐诗','tang','','[]','遠山酋萃（友人蔣禮垗同志謂當作「𡺚崒」。',214,'全唐诗/poet.tang.50000.json','["遠山酋萃（友人蔣禮垗同志謂當作「𡺚崒」。", "）翠凝烟，爛漫桐花二月天。", "游徧九衢燈火夜，歸來月挂海棠前。", "（此詩載《槐廬叢書》、《金石錄補》卷二十二。", "《全唐詩續補遺》卷一據《佘山詩話》錄此詩，今刪去。", "首句「酋萃」二字，《佘山詩話》正作「𡺚崒」，與蔣說合。", "明陳繼儒《妮古錄》卷一謂宋咸淳中邑令趙必穆於池中得斷碑，上刻此詩。", "首句二字亦作「𡺚崒」。", "錄此詩後云「餘皆莫辨」。", "）（〖1〗《槐廬叢書》、《金石錄補》按此爲褚遂良貶潭州都督時所作。", "）。"]'),
('9c4fc132-1779-443b-b35a-00d4a7ad42df','春旦直疏','王績','唐','唐诗','tang','','[]','春夜猶自長，高窗來月明。',155,'全唐诗/poet.tang.50000.json','["春夜猶自長，高窗來月明。", "耿耿不能寐，振衣步前楹。", "懷抱蹔無擾，自覺形神清。", "遐想太古事，俯察今世情。", "淳薄何不同，運數之所成。", "歎息萬重隔，已聞晨雞鳴。", "迴看東南隅，□□□□□。", "誰知忘機者，寂泊存其精。", "（見《分門纂類唐歌詩》殘本第一冊《天地山川類》十三頁。", "）（見五卷本《王無功文集》卷二，第十三句「迴看」作「迴首」。", "）。"]'),
('8a400257-d1bc-487f-9d5c-dbd3c5fcf8a4','句','榮九思','唐','唐诗','tang','','[]','丹青飾成慶，玉帛擅專諸。',210,'全唐诗/poet.tang.50000.json','["丹青飾成慶，玉帛擅專諸。", "（見《資治通鑑》卷一九一《唐紀七》武德七年六月壬戌下胡三省注。", "）（見《資治通鑑考異》卷九。", "）（〖1〗《資治通鑑》胡三省注引《實錄》云：「元吉見秦王有大功，每懷妬害，言論醜惡，譖害日甚。", "每謂建成曰：『當爲大哥手刃之。", "』建成性頗仁厚，初止之。", "元吉數言不已，建成後亦許之。", "元吉因令速發，遂與建成各募壯士，多匿罪人，賞賜之，圖行不軌。", "其記室榮九思爲詩以剌之曰：『丹青飾成慶，玉帛擅專諸。", "』而弗悟也。", "」）。"]'),
('0a980a3b-ebe7-4b94-91eb-e88ac3ac567f','漳州新城秋宴','陳元光','唐','唐诗','tang','','[]','地險行臺壯，天清景幕新。',124,'全唐诗/poet.tang.50000.json','["地險行臺壯，天清景幕新。", "鴻飛青嶂杳，鷺點碧波真。", "風肅天如水，霜高月散銀。", "嬋娟争潑眼，廉潔正成隣。", "東湧滄溟玉，西呈翠巘珍。", "畫船拖素練，朱榭映紅雲。", "琥珀盃方酌，鮫綃席未塵。", "秦簫吹引鳯，鄒律奏生春。", "縹{糹耳少}纖歌遏，婆娑妙舞神。", "會知冥漠處，百怪惱精魂。"]'),
('736276bd-a0a1-4beb-8838-284b41d5bd99','曉發佛潭橋','陳元光','唐','唐诗','tang','','[]','朝暾催上道，兔魄欲西沈。',105,'全唐诗/poet.tang.50000.json','["朝暾催上道，兔魄欲西沈。", "去雁長空沒，飛花曲徑深。", "事沿橋樹往，詩落海鷗吟。", "馬鬣嘶風聳，龍旂閃電臨。", "峯攢仙掌巧，露重將袍陰。", "農唤耕春早，僧迎展拜欽。", "看看葵日麗，照破艷陽心。", "（以上二詩見沈定均《漳州府志·藝文志》）。"]'),
('97b73f2b-b409-4e1d-8827-ea76d363ee6a','句','陳元光','唐','唐诗','tang','','[]','參軍許天正，是用紀邦勛。',68,'全唐诗/poet.tang.50000.json','["參軍許天正，是用紀邦勛。", "（按《全唐詩》卷四五許天正《和陳元光平潮寇詩》。", "題注曰：「元光贈詩云『參軍許天正，是用紀邦勛。", "』天正和之。", "」）。"]'),
('784de624-96ba-47ce-afe3-a10681eef3dd','歸閒詩二十韵','丁儒','唐','唐诗','tang','','[]','漳北遥開郡，泉南久罷屯。',255,'全唐诗/poet.tang.50000.json','["漳北遥開郡，泉南久罷屯。", "歸尋初旅寓，喜作舊鄉鄰。", "好鳥鳴簷竹，村黎愛幕臣。", "土音今聽慣，民俗始知淳。", "烽火無傳警，江山已淨塵。", "天開一歲暖，花發四時春。", "雜卉三冬綠，嘉禾兩度新。", "俚歌聲靡曼，秫酒味溫醇。", "錦苑來丹荔，清波出素鱗。", "芭蕉金剖潤，龍眼玉生津。", "蜜取花間[露]（液），柑藏樹上珍。", "醉宜藷蔗瀝，睡穩木棉[茵]（溫）。", "茉莉香籬落，榕陰浹里闉。", "雪霜偏避地，風景獨推閩。", "辭國來諸屬，於兹締六親。", "追隨情語好，問餽[歲]（幾）時頻。", "相訪朝和夕，渾忘越與秦。", "功成在炎域，事定有閒身。", "詞賦聊酬和，才名任隱淪。", "呼童多種植，長是此方人。"]'),
('ae318279-80da-405d-be06-9fc2143c6f1a','冬日到泉郡次九龍江與諸公唱和[十三韻]','丁儒','唐','唐诗','tang','','[]','迢遞千重險，崎嶇一路通。',199,'全唐诗/poet.tang.50000.json','["迢遞千重險，崎嶇一路通。", "山深迷白日，林冬豁蒼穹。", "正值嚴冬際，渾如春晝中。", "泉醴開名郡，江清穩臥龍。", "天涯寒不至，地角氣偏融。", "橘列丹青樹，槿抽錦繡叢。", "秋餘甘菊艷，歲迫麗春紅。", "麥隴披藍遠，榕庄拔翠雄。", "減衣遊別塢，赤脚走邨童。", "日出喧鳥鵲，沙晴落雁鴻。", "池澌含晚照，嶺黛徹寒空。", "風景無終始，乾坤有異同。", "但思鄉國迥，薄暮起心[忡]（冲）。", "（以上二詩見《漳州府志》引《白石丁氏譜》。", "二詩據清刻《白石丁氏譜》校改。", "）。"]'),
('68013d99-8214-4455-a01b-864702ad92b5','','王梵志','唐','唐诗','tang','','[]','（案《全唐詩》無王梵志詩，生平事跡不可考。',276,'全唐诗/poet.tang.50000.json','["（案《全唐詩》無王梵志詩，生平事跡不可考。", "《太平廣記》所載，神誕不可信。", "劉復《燉煌掇瑣》據巴黎國家圖書館藏二七一八號燉煌卷子錄出梵志詩一卷，另以三二六六號殘卷校之。", "今即自劉本錄出，而取鄭振鐸本《梵志詩拾遺》補其缺。", "〖王梵志詩卷子原爲三卷，上所云即其首卷，二卷今佚，三卷胡適藏之。", "關本《拾遺》，即三卷中一部分。", "〗此外余又見唐釋皎然《詩式》及宋陳巖肖《庚溪詩話》引梵志詩各一首，今幷錄附於後。", "〖張錫厚《王梵志詩校輯》卷四云與伯二七一八卷同一系統的敦煌卷子共有十二本。", "今即據其所錄，幷參據今人增校意見，作出校記。", "今人校訂意見皆據郭在貽《王梵志詩彙校》。", "〗）。"]'),
('3f0e6218-6122-4aec-b2ad-1d2087312a03','一','王梵志','唐','唐诗','tang','','[]','兄弟須和順，叔姪莫輕欺。',75,'全唐诗/poet.tang.50000.json','["兄弟須和順，叔姪莫輕欺。", "財物同[箱櫃]，（二字據諸本補。", "）[房]中莫畜私。", "（「房」字，據伯三五五八、伯三六五六卷補。", "「畜」，伯二八四二卷作「蓄」。", "）。"]'),
('798cf745-b669-4fb3-b0e6-4bcb02567380','二','王梵志','唐','唐诗','tang','','[]','夜眠須在後，起則每須先。',24,'全唐诗/poet.tang.50000.json','["夜眠須在後，起則每須先。", "家中懃檢校，衣食莫令偏。"]'),
('041d246a-3b2e-4a83-91c9-2e60952dc3a1','三','王梵志','唐','唐诗','tang','','[]','兄弟相憐愛，同生莫異居。',42,'全唐诗/poet.tang.50000.json','["兄弟相憐愛，同生莫異居。", "爲人欲得別，（「人」，伯三六五六卷作「若」。", "）此則是兵奴。", "。"]'),
('c43baa05-5165-41b3-855e-92d5ae4e8824','四','王梵志','唐','唐诗','tang','','[]','好事須相讓，惡事莫相堆。',77,'全唐诗/poet.tang.50000.json','["好事須相讓，惡事莫相堆。", "（「堆」，伯二八四二卷作「推」。", "）{亻|口/工}（鄭校本作「但」。", "）能辨此意，禍去福招來。", "（「招來」，斯三三九三卷作「將來」。", "）。"]'),
('50b07a6f-713e-4b02-a0ef-86bd5d006a79','五','王梵志','唐','唐诗','tang','','[]','昔日田真「分」，（「分」，據伯三五五八卷補。',64,'全唐诗/poet.tang.50000.json','["昔日田真「分」，（「分」，據伯三五五八卷補。", "）庭荆當即衰。", "平章却不異，其樹復還滋。", "（「復」伯三七一六、伯三六五六卷作「重」。", "）。"]'),
('94fa414b-00aa-442b-bef0-792d90e76a8a','六','王梵志','唐','唐诗','tang','','[]','孔懷須敬重，同氣並連枝。',24,'全唐诗/poet.tang.50000.json','["孔懷須敬重，同氣並連枝。", "不見恆山鳥，孔子惡聞離。"]'),
('cec898e4-2ece-4b12-b416-c18289f4d2ac','七','王梵志','唐','唐诗','tang','','[]','兄弟寶難得，（「寶」，張錫厚錄作「實」。',94,'全唐诗/poet.tang.50000.json','["兄弟寶難得，（「寶」，張錫厚錄作「實」。", "）他人不可嗔。", "（「嗔」，伯三五五八、斯三三九三卷作「親」。", "）{亻|口/工}（關校本作但。", "）尋莊子語，手足斷難論。", "（「斷」，伯三五五八卷作「但」。", "）。"]'),
('6a305166-2a40-4dec-a0e6-fbe0ab689a53','八','王梵志','唐','唐诗','tang','','[]','尊人相逐出，子莫向前行。',51,'全唐诗/poet.tang.50000.json','["尊人相逐出，子莫向前行。", "識事須相逢，（「須相逢」，伯三六五六、伯二八四二卷作「相逢見」。", "）情知乏禮生。"]'),
('5da398d8-1483-4cc5-92e4-b21933933647','九','王梵志','唐','唐诗','tang','','[]','尊人共客語，側立在傍聽。',24,'全唐诗/poet.tang.50000.json','["尊人共客語，側立在傍聽。", "莫向前頭鬧，喧亂作鵶鳴。"]'),
('bba21f14-67d5-4200-8574-618d281a4502','十','王梵志','唐','唐诗','tang','','[]','主人無床枕，坐旦捉㺃（鄭本作「狗」。',128,'全唐诗/poet.tang.50000.json','["主人無床枕，坐旦捉㺃（鄭本作「狗」。", "）狐。", "（「狐」，項楚校作「親」。", "）莫學痛才漢，（「痛才漢」，伯三七一六、伯三六五六、伯三三九三卷作「庸才漢」，伯二八四二卷作「用庸漢」。", "）無事棄他門。", "（「棄他門」，伯三六五六卷作「去他門」，伯二八四二卷作「尋他朋」。", "）。"]'),
('1ead8e10-f2bc-45fe-a978-9b826648b4d0','十一','王梵志','唐','唐诗','tang','','[]','立身行孝道，有事莫爲●。',93,'全唐诗/poet.tang.50000.json','["立身行孝道，有事莫爲●。", "（「有事」，伯三五五八、伯三七一六卷作「省事」。", "）行使長無過，（「行使」，伯三六五六卷作「但使」，伯三七一六卷作「但知」，斯三三九三卷作「但能」。", "）耶孃高枕眠。", "。"]'),
('5c0619b5-684a-447f-8aac-08df0dd32ebb','十二','王梵志','唐','唐诗','tang','','[]','耶孃行不正，不事任依從。',66,'全唐诗/poet.tang.50000.json','["耶孃行不正，不事任依從。", "（「不事」，伯三七一六、斯三三九三卷作「萬事」。", "）打駡但知默，（「默」，伯二八四二卷作「恩」。", "）無應即是能。"]'),
('3d495c18-c699-42d9-b303-d41bfd54ce1e','十三','王梵志','唐','唐诗','tang','','[]','尊人嗔約束，共語莫江降。',102,'全唐诗/poet.tang.50000.json','["尊人嗔約束，共語莫江降。", "（「江降」，伯三七一六卷作「江絳」，伯三六五六卷作「{馬工}{馬降}」，張錫厚疑應作「𤢐𤝷」。", "）縱有些些理，無煩說矩（鄭校本云似應作短長。", "〖「矩長」，伯三七一六卷作「短長」。", "〗）。"]'),
('da4ad4b3-38e0-45f5-9e16-1e28fc342ddb','十四','王梵志','唐','唐诗','tang','','[]','有事須相問，平章莫自專。',24,'全唐诗/poet.tang.50000.json','["有事須相問，平章莫自專。", "和同相用語，莫取婦兒言。"]'),
('c72be849-6592-49e8-88a8-8f7a56c74b97','十五','王梵志','唐','唐诗','tang','','[]','耶孃年七十，不得遠東西。',73,'全唐诗/poet.tang.50000.json','["耶孃年七十，不得遠東西。", "出後傾危起，（「起」，伯三五五八、伯三七一六、斯三三九三卷作「去」。", "）元知兒故違。", "（「故違」，伯三六五六卷作「固違」。", "）。"]'),
('ee1014b0-3efa-464c-9bc6-c5ac01f395e3','十六','王梵志','唐','唐诗','tang','','[]','耶孃絕年邁，不得離傍邊。',65,'全唐诗/poet.tang.50000.json','["耶孃絕年邁，不得離傍邊。", "曉夜專看待，（「看待」，伯三六五六卷作「看侍」。", "）仍須省睡眠。", "（「省睡眠」，斯三三九三卷作「更省眠」。", "）。"]');
